import random
import string
import hashlib
import os
import time
users = {}
reset_tokens = {}
def hash_password(password, salt):
    return hashlib.sha256((password + salt).encode()).hexdigest()
def register(username, password):
    if username in users:
        return "Username already exists."
    salt = os.urandom(16).hex()
    hashed = hash_password(password, salt)
    users[username] = {"password": hashed, "salt": salt, "email": f"{username}@example.com"}
    return f"User '{username}' registered successfully."
def generate_token(length=6):
    return ''.join(random.choices(string.digits, k=length))
def request_password_reset(username):
    if username not in users:
        return "User not found."
    token = generate_token()
    expiry = time.time() + 300
    reset_tokens[username] = {"token": token, "expiry": expiry}
    print(f"[EMAIL SIMULATION] Reset token for '{username}': {token} (valid for 5 minutes)")
    return "Password reset token sent to your email."
def verify_token(username, token):
    if username not in reset_tokens:
        return False, "No reset request found for this user."
    reset_data = reset_tokens[username]
    if time.time() > reset_data["expiry"]:
        del reset_tokens[username]
        return False, "Token has expired."
    if reset_data["token"] != token:
        return False, "Invalid token."
    return True, "Token verified."
def reset_password(username, token, new_password):
    is_valid, message = verify_token(username, token)
    if not is_valid:
        return message
    if len(new_password) < 8:
        return "Password must be at least 8 characters."
    salt = os.urandom(16).hex()
    hashed = hash_password(new_password, salt)
    users[username]["password"] = hashed
    users[username]["salt"] = salt
    del reset_tokens[username]
    return "Password reset successfully."
def login(username, password):
    if username not in users:
        return "User not found."
    stored = users[username]["password"]
    salt = users[username]["salt"]
    if hash_password(password, salt) == stored:
        return f"Welcome, {username}! Login successful."
    return "Invalid password."
def main():
    while True:
        print("\n1. Register\n2. Login\n3. Forgot Password\n4. Reset Password\n5. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            username = input("Enter username: ")
            password = input("Enter password: ")
            print(register(username, password))
        elif choice == "2":
            username = input("Enter username: ")
            password = input("Enter password: ")
            print(login(username, password))
        elif choice == "3":
            username = input("Enter username: ")
            print(request_password_reset(username))
        elif choice == "4":
            username = input("Enter username: ")
            token = input("Enter reset token: ")
            new_password = input("Enter new password: ")
            print(reset_password(username, token, new_password))
        elif choice == "5":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

