import hashlib
import os
import time
users = {}
active_sessions = {}
def hash_password(password, salt):
    return hashlib.sha256((password + salt).encode()).hexdigest()
def register(username, password, role="user"):
    if username in users:
        return "Username already exists."
    salt = os.urandom(16).hex()
    hashed = hash_password(password, salt)
    users[username] = {"password": hashed, "salt": salt, "role": role, "locked": False, "attempts": 0}
    return f"User '{username}' registered successfully with role '{role}'."
def login(username, password):
    if username not in users:
        return "User not found."
    user = users[username]
    if user["locked"]:
        return "Account is locked. Contact admin."
    if hash_password(password, user["salt"]) == user["password"]:
        user["attempts"] = 0
        session_token = os.urandom(16).hex()
        active_sessions[session_token] = {"username": username, "role": user["role"], "login_time": time.time()}
        return f"Login successful. Session token: {session_token}"
    else:
        user["attempts"] += 1
        if user["attempts"] >= 3:
            user["locked"] = True
            return "Too many failed attempts. Account locked."
        return f"Invalid password. {3 - user['attempts']} attempt(s) remaining."
def logout(session_token):
    if session_token in active_sessions:
        username = active_sessions[session_token]["username"]
        del active_sessions[session_token]
        return f"User '{username}' logged out successfully."
    return "Invalid session token."
def get_session(session_token):
    if session_token in active_sessions:
        return active_sessions[session_token]
    return None
def unlock_account(admin_token, username):
    session = get_session(admin_token)
    if not session or session["role"] != "admin":
        return "Access denied. Admins only."
    if username not in users:
        return "User not found."
    users[username]["locked"] = False
    users[username]["attempts"] = 0
    return f"Account '{username}' unlocked successfully."
def list_users(admin_token):
    session = get_session(admin_token)
    if not session or session["role"] != "admin":
        return "Access denied. Admins only."
    return {u: {"role": users[u]["role"], "locked": users[u]["locked"]} for u in users}
def view_sessions(admin_token):
    session = get_session(admin_token)
    if not session or session["role"] != "admin":
        return "Access denied. Admins only."
    return {token: data for token, data in active_sessions.items()}
def main():
    register("admin", "Admin@1234", role="admin")
    register("alice", "Alice@1234", role="user")
    register("bob", "Bob@1234", role="user")
    admin_token = None
    while True:
        print("\n1. Register\n2. Login\n3. Logout\n4. Unlock Account (Admin)\n5. List Users (Admin)\n6. View Sessions (Admin)\n7. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            username = input("Enter username: ")
            password = input("Enter password: ")
            role = input("Enter role (user/admin): ")
            print(register(username, password, role))
        elif choice == "2":
            username = input("Enter username: ")
            password = input("Enter password: ")
            result = login(username, password)
            print(result)
            if "Session token" in result:
                token = result.split(": ")[-1]
                if users[username]["role"] == "admin":
                    admin_token = token
        elif choice == "3":
            token = input("Enter session token: ")
            print(logout(token))
        elif choice == "4":
            username = input("Enter username to unlock: ")
            print(unlock_account(admin_token, username))
        elif choice == "5":
            print(list_users(admin_token))
        elif choice == "6":
            print(view_sessions(admin_token))
        elif choice == "7":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

class AuthSystem:
    def __init__(self):
        self.users = {}
    def register(self, username, password):
        if username in self.users:
            return "User already exists."
        self.users[username] = password
        return "Registration successful."
    def login(self, username, password):
        if self.users.get(username) == password:
            return f"Welcome, {username}!"
        return "Access denied."
