import hashlib
import os
import json
USERS_FILE = "users.json"
def hash_password(password, salt):
    return hashlib.sha256((password + salt).encode()).hexdigest()
def load_users():
    if not os.path.exists(USERS_FILE):
        return {}
    with open(USERS_FILE, "r") as f:
        return json.load(f)
def save_users(users):
    with open(USERS_FILE, "w") as f:
        json.dump(users, f, indent=4)
def register(username, password):
    users = load_users()
    if username in users:
        return "Username already exists."
    salt = os.urandom(16).hex()
    hashed = hash_password(password, salt)
    users[username] = {"password": hashed, "salt": salt}
    save_users(users)
    return f"User '{username}' registered successfully."
def login(username, password):
    users = load_users()
    if username not in users:
        return "User not found."
    user = users[username]
    if hash_password(password, user["salt"]) == user["password"]:
        return f"Welcome, {username}! Login successful."
    return "Invalid password."
def delete_user(username):
    users = load_users()
    if username not in users:
        return "User not found."
    del users[username]
    save_users(users)
    return f"User '{username}' deleted successfully."
def list_users():
    users = load_users()
    if not users:
        return "No users found."
    return "\n".join([f"- {u}" for u in users])
def main():
    while True:
        print("\n1. Register\n2. Login\n3. Delete User\n4. List Users\n5. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            username = input("Enter username: ")
            password = input("Enter password: ")
            print(register(username, password))
        elif choice == "2":
            username = input("Enter username: ")
            password = input("Enter password: ")
            print(login(username, password))
        elif choice == "3":
            username = input("Enter username to delete: ")
            print(delete_user(username))
        elif choice == "4":
            print(list_users())
        elif choice == "5":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

def authenticate_from_file(filepath, username, password):
    try:
        with open(filepath, 'r') as f:
            for line in f:
                stored_user, stored_pass = line.strip().split(',')
                if stored_user == username and stored_pass == password:
                    return True
    except FileNotFoundError:
        print("Database file not found.")
    return False
