import json
import hashlib
import os
def load_users_from_file(filename):
    try:
        with open(filename, 'r') as f:
            return json.load(f)
    except FileNotFoundError:
        return {}
def save_users_to_file(filename, users):
    with open(filename, 'w') as f:
        json.dump(users, f, indent=2)
def hash_password(password, salt=None):
    if salt is None:
        salt = os.urandom(32).hex()
    pwd_hash = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000).hex()
    return pwd_hash, salt
def register_user(filename, username, password):
    users = load_users_from_file(filename)
    if username in users:
        return False, "Username already exists"
    pwd_hash, salt = hash_password(password)
    users[username] = {'password_hash': pwd_hash, 'salt': salt}
    save_users_to_file(filename, users)
    return True, "Registration successful"
def authenticate_user(filename, username, password):
    users = load_users_from_file(filename)
    if username not in users:
        return False, "Invalid username or password"
    user_data = users[username]
    salt = user_data['salt']
    stored_hash = user_data['password_hash']
    pwd_hash, _ = hash_password(password, salt)
    if pwd_hash == stored_hash:
        return True, "Authentication successful"
    else:
        return False, "Invalid username or password"
def update_password(filename, username, old_password, new_password):
    is_valid, message = authenticate_user(filename, username, old_password)
    if not is_valid:
        return False, "Current password is incorrect"
    users = load_users_from_file(filename)
    pwd_hash, salt = hash_password(new_password)
    users[username] = {'password_hash': pwd_hash, 'salt': salt}
    save_users_to_file(filename, users)
    return True, "Password updated successfully"
def delete_user(filename, username, password):
    is_valid, message = authenticate_user(filename, username, password)
    if not is_valid:
        return False, "Password is incorrect"
    users = load_users_from_file(filename)
    del users[username]
    save_users_to_file(filename, users)
    return True, "User deleted successfully"
def list_users(filename):
    users = load_users_from_file(filename)
    return list(users.keys())

