import hashlib
import os
import json
import re
USERS_FILE = "users.json"
def hash_password(password, salt):
    return hashlib.sha256((password + salt).encode()).hexdigest()
def load_users():
    if not os.path.exists(USERS_FILE):
        return {}
    with open(USERS_FILE, "r") as f:
        return json.load(f)
def save_users(users):
    with open(USERS_FILE, "w") as f:
        json.dump(users, f, indent=4)
def validate_email(email):
    return re.match(r"^[\w\.-]+@[\w\.-]+\.\w+$", email)
def validate_password(password):
    if len(password) < 8:
        return False, "Password must be at least 8 characters."
    if not re.search("[A-Z]", password):
        return False, "Password must contain at least one uppercase letter."
    if not re.search("[a-z]", password):
        return False, "Password must contain at least one lowercase letter."
    if not re.search("[0-9]", password):
        return False, "Password must contain at least one digit."
    if not re.search("[!@#$%^&*(),.?\":{}|<>]", password):
        return False, "Password must contain at least one special character."
    return True, "Password is valid."
def signup(username, email, password, confirm_password):
    users = load_users()
    if username in users:
        return "Username already exists."
    if not validate_email(email):
        return "Invalid email format."
    for user in users.values():
        if user["email"] == email:
            return "Email already registered."
    if password != confirm_password:
        return "Passwords do not match."
    is_valid, message = validate_password(password)
    if not is_valid:
        return message
    salt = os.urandom(16).hex()
    hashed = hash_password(password, salt)
    users[username] = {"email": email, "password": hashed, "salt": salt}
    save_users(users)
    return f"User '{username}' signed up successfully."
def login(username, password):
    users = load_users()
    if username not in users:
        return "User not found."
    user = users[username]
    attempts = user.get("attempts", 0)
    if user.get("locked"):
        return "Account is locked due to too many failed attempts."
    if hash_password(password, user["salt"]) == user["password"]:
        user["attempts"] = 0
        save_users(users)
        return f"Welcome, {username}! Login successful."
    else:
        attempts += 1
        user["attempts"] = attempts
        if attempts >= 3:
            user["locked"] = True
            save_users(users)
            return "Too many failed attempts. Account locked."
        save_users(users)
        return f"Invalid password. {3 - attempts} attempt(s) remaining."
def forgot_password(username, email, new_password, confirm_password):
    users = load_users()
    if username not in users:
        return "User not found."
    if users[username]["email"] != email:
        return "Email does not match."
    if new_password != confirm_password:
        return "Passwords do not match."
    is_valid, message = validate_password(new_password)
    if not is_valid:
        return message
    salt = os.urandom(16).hex()
    hashed = hash_password(new_password, salt)
    users[username]["password"] = hashed
    users[username]["salt"] = salt
    users[username]["attempts"] = 0
    users[username]["locked"] = False
    save_users(users)
    return "Password reset successfully."
def main():
    while True:
        print("\n1. Signup\n2. Login\n3. Forgot Password\n4. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            username = input("Enter username: ")
            email = input("Enter email: ")
            password = input("Enter password: ")
            confirm_password = input("Confirm password: ")
            print(signup(username, email, password, confirm_password))
        elif choice == "2":
            username = input("Enter username: ")
            password = input("Enter password: ")
            print(login(username, password))
        elif choice == "3":
            username = input("Enter username: ")
            email = input("Enter registered email: ")
            new_password = input("Enter new password: ")
            confirm_password = input("Confirm new password: ")
            print(forgot_password(username, email, new_password, confirm_password))
        elif choice == "4":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

