import hashlib
import os
import json
import time
import uuid
USERS_FILE = "users.json"
SESSIONS_FILE = "sessions.json"
SESSION_TIMEOUT = 300
def hash_password(password, salt):
    return hashlib.sha256((password + salt).encode()).hexdigest()
def load_users():
    if not os.path.exists(USERS_FILE):
        return {}
    with open(USERS_FILE, "r") as f:
        return json.load(f)
def save_users(users):
    with open(USERS_FILE, "w") as f:
        json.dump(users, f, indent=4)
def load_sessions():
    if not os.path.exists(SESSIONS_FILE):
        return {}
    with open(SESSIONS_FILE, "r") as f:
        return json.load(f)
def save_sessions(sessions):
    with open(SESSIONS_FILE, "w") as f:
        json.dump(sessions, f, indent=4)
def register(username, password):
    users = load_users()
    if username in users:
        return "Username already exists."
    salt = os.urandom(16).hex()
    hashed = hash_password(password, salt)
    users[username] = {"password": hashed, "salt": salt}
    save_users(users)
    return f"User '{username}' registered successfully."
def login(username, password):
    users = load_users()
    if username not in users:
        return "User not found."
    user = users[username]
    if hash_password(password, user["salt"]) != user["password"]:
        return "Invalid password."
    sessions = load_sessions()
    session_id = str(uuid.uuid4())
    sessions[session_id] = {"username": username, "created_at": time.time(), "last_active": time.time()}
    save_sessions(sessions)
    return f"Login successful. Session ID: {session_id}"
def is_session_valid(session_id):
    sessions = load_sessions()
    if session_id not in sessions:
        return False, "Session not found."
    session = sessions[session_id]
    if time.time() - session["last_active"] > SESSION_TIMEOUT:
        del sessions[session_id]
        save_sessions(sessions)
        return False, "Session expired."
    sessions[session_id]["last_active"] = time.time()
    save_sessions(sessions)
    return True, session["username"]
def logout(session_id):
    sessions = load_sessions()
    if session_id not in sessions:
        return "Session not found."
    username = sessions[session_id]["username"]
    del sessions[session_id]
    save_sessions(sessions)
    return f"User '{username}' logged out successfully."
def get_profile(session_id):
    valid, result = is_session_valid(session_id)
    if not valid:
        return result
    users = load_users()
    username = result
    return f"Logged in as: {username}"
def list_active_sessions():
    sessions = load_sessions()
    active = {sid: data for sid, data in sessions.items() if time.time() - data["last_active"] <= SESSION_TIMEOUT}
    if not active:
        return "No active sessions."
    return "\n".join([f"Session: {sid} | User: {data['username']}" for sid, data in active.items()])
def main():
    current_session = None
    while True:
        print("\n1. Register\n2. Login\n3. Logout\n4. View Profile\n5. List Active Sessions\n6. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            username = input("Enter username: ")
            password = input("Enter password: ")
            print(register(username, password))
        elif choice == "2":
            username = input("Enter username: ")
            password = input("Enter password: ")
            result = login(username, password)
            print(result)
            if "Session ID" in result:
                current_session = result.split(": ")[-1]
        elif choice == "3":
            if not current_session:
                print("No active session.")
            else:
                print(logout(current_session))
                current_session = None
        elif choice == "4":
            if not current_session:
                print("No active session.")
            else:
                print(get_profile(current_session))
        elif choice == "5":
            print(list_active_sessions())
        elif choice == "6":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

import uuid
import time
class SessionManager:
    def __init__(self):
        self.users = {"admin": "secret"}
        self.sessions = {}
    def login(self, username, password):
        if self.users.get(username) == password:
            session_id = str(uuid.uuid4())
            self.sessions[session_id] = {"user": username, "expiry": time.time() + 3600}
            return session_id
        return None
