import re
def verify_password_length(password, min_length=8, max_length=128):
    if len(password) < min_length:
        return False, f"Password must be at least {min_length} characters"
    if len(password) > max_length:
        return False, f"Password must not exceed {max_length} characters"
    return True, "Length requirement met"
def verify_uppercase(password):
    if re.search("[A-Z]", password):
        return True, "Contains uppercase letters"
    return False, "Must contain at least one uppercase letter"
def verify_lowercase(password):
    if re.search("[a-z]", password):
        return True, "Contains lowercase letters"
    return False, "Must contain at least one lowercase letter"
def verify_digits(password):
    if re.search("[0-9]", password):
        return True, "Contains digits"
    return False, "Must contain at least one digit"
def verify_special_characters(password):
    if re.search("[!@#$%^&*()_+\-=\[\]{};:'\",.<>?/\\|`~]", password):
        return True, "Contains special characters"
    return False, "Must contain at least one special character"
def verify_no_spaces(password):
    if " " in password:
        return False, "Password must not contain spaces"
    return True, "No spaces found"
def verify_no_common_patterns(password):
    common_patterns = ['123456', '654321', 'password', 'qwerty', 'abc123', '111111', '000000']
    for pattern in common_patterns:
        if pattern.lower() in password.lower():
            return False, f"Password contains common pattern: {pattern}"
    return True, "No common patterns detected"
def verify_password_strength(password):
    checks = [
        verify_password_length(password),
        verify_uppercase(password),
        verify_lowercase(password),
        verify_digits(password),
        verify_special_characters(password),
        verify_no_spaces(password),
        verify_no_common_patterns(password)
    ]
    results = {
        'length': checks[0],
        'uppercase': checks[1],
        'lowercase': checks[2],
        'digits': checks[3],
        'special_characters': checks[4],
        'no_spaces': checks[5],
        'no_common_patterns': checks[6]
    }
    all_valid = all(check[0] for check in checks)
    if all_valid:
        strength = "Strong"
    elif sum(1 for check in checks if check[0]) >= 5:
        strength = "Medium"
    else:
        strength = "Weak"
    return all_valid, strength, results
def get_password_feedback(password):
    is_valid, strength, results = verify_password_strength(password)
    feedback = []
    for check_name, (is_passed, message) in results.items():
        if not is_passed:
            feedback.append(message)
    return {'is_valid': is_valid, 'strength': strength, 'feedback': feedback, 'details': results}

import sqlite3
import hashlib
import os
import re
def create_connection():
    conn = sqlite3.connect("userdata.db")
    conn.row_factory = sqlite3.Row
    return conn
def create_table():
    conn = create_connection()
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            email TEXT UNIQUE NOT NULL,
            password TEXT NOT NULL,
            salt TEXT NOT NULL,
            age INTEGER NOT NULL,
            role TEXT NOT NULL DEFAULT 'user',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    """)
    conn.commit()
    conn.close()
def hash_password(password, salt):
    return hashlib.sha256((password + salt).encode()).hexdigest()
def validate_email(email):
    return re.match(r"^[\w\.-]+@[\w\.-]+\.\w+$", email)
def validate_password(password):
    if len(password) < 8:
        return False, "Password must be at least 8 characters."
    if not re.search("[A-Z]", password):
        return False, "Password must contain at least one uppercase letter."
    if not re.search("[a-z]", password):
        return False, "Password must contain at least one lowercase letter."
    if not re.search("[0-9]", password):
        return False, "Password must contain at least one digit."
    if not re.search("[!@#$%^&*(),.?\":{}|<>]", password):
        return False, "Password must contain at least one special character."
    return True, "Valid"
def validate_age(age):
    return age.isdigit() and 1 <= int(age) <= 120
def validate_role(role):
    return role in ["user", "admin", "moderator"]
def insert_user(username, email, password, age, role="user"):
    if not username or len(username) < 3:
        return "Username must be at least 3 characters."
    if not validate_email(email):
        return "Invalid email format."
    is_valid, message = validate_password(password)
    if not is_valid:
        return message
    if not validate_age(str(age)):
        return "Invalid age. Must be between 1 and 120."
    if not validate_role(role):
        return "Invalid role. Choose from: user, admin, moderator."
    salt = os.urandom(16).hex()
    hashed = hash_password(password, salt)
    conn = create_connection()
    cursor = conn.cursor()
    try:
        cursor.execute("""
            INSERT INTO users (username, email, password, salt, age, role)
            VALUES (?, ?, ?, ?, ?, ?)
        """, (username, email, hashed, salt, int(age), role))
        conn.commit()
        return f"User '{username}' inserted successfully."
    except sqlite3.IntegrityError as e:
        if "username" in str(e):
            return "Username already exists."
        if "email" in str(e):
            return "Email already exists."
        return f"Database error: {e}"
    finally:
        conn.close()
def insert_bulk_users(users_list):
    results = []
    for user in users_list:
        result = insert_user(*user)
        results.append(f"{user[0]}: {result}")
    return results
def fetch_all_users():
    conn = create_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT id, username, email, age, role, created_at FROM users")
    rows = cursor.fetchall()
    conn.close()
    return [dict(row) for row in rows]
def display_users(users):
    if not users:
        print("No users found.")
        return
    for user in users:
        print("\n--- User ---")
        for key, value in user.items():
            print(f"{key.capitalize()}: {value}")
def main():
    create_table()
    while True:
        print("\n1. Insert Single User\n2. Insert Bulk Users\n3. View All Users\n4. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            username = input("Enter username: ")
            email = input("Enter email: ")
            password = input("Enter password: ")
            age = input("Enter age: ")
            role = input("Enter role (user/admin/moderator): ")
            print(insert_user(username, email, password, age, role))
        elif choice == "2":
            bulk_users = [
                ("alice", "alice@example.com", "Alice@1234", 25, "admin"),
                ("bob", "bob@example.com", "Bob@1234", 30, "user"),
                ("charlie", "charlie@example.com", "Charlie@1234", 22, "moderator")
            ]
            results = insert_bulk_users(bulk_users)
            for result in results:
                print(result)
        elif choice == "3":
            display_users(fetch_all_users())
        elif choice == "4":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

