from flask import Flask, request, jsonify
from functools import wraps
import sqlite3
import hashlib
import os
import re
import jwt
import datetime
app = Flask(__name__)
SECRET_KEY = os.urandom(24).hex()
def create_connection():
    conn = sqlite3.connect("rest_api.db")
    conn.row_factory = sqlite3.Row
    return conn
def create_tables():
    conn = create_connection()
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            email TEXT UNIQUE NOT NULL,
            password TEXT NOT NULL,
            salt TEXT NOT NULL,
            role TEXT NOT NULL DEFAULT 'user',
            is_active INTEGER NOT NULL DEFAULT 1,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    """)
    conn.commit()
    conn.close()
def hash_password(password, salt):
    return hashlib.sha256((password + salt).encode()).hexdigest()
def validate_email(email):
    return re.match(r"^[\w\.-]+@[\w\.-]+\.\w+$", email)
def validate_password(password):
    if len(password) < 8:
        return False, "Password must be at least 8 characters."
    if not re.search("[A-Z]", password):
        return False, "Password must contain at least one uppercase letter."
    if not re.search("[a-z]", password):
        return False, "Password must contain at least one lowercase letter."
    if not re.search("[0-9]", password):
        return False, "Password must contain at least one digit."
    if not re.search("[!@#$%^&*(),.?\":{}|<>]", password):
        return False, "Password must contain at least one special character."
    return True, "Valid"
def generate_token(user_id, username, role):
    payload = {
        "user_id": user_id,
        "username": username,
        "role": role,
        "exp": datetime.datetime.utcnow() + datetime.timedelta(hours=1)
    }
    return jwt.encode(payload, SECRET_KEY, algorithm="HS256")
def decode_token(token):
    try:
        return jwt.decode(token, SECRET_KEY, algorithms=["HS256"]), None
    except jwt.ExpiredSignatureError:
        return None, "Token has expired."
    except jwt.InvalidTokenError:
        return None, "Invalid token."
def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get("Authorization")
        if not token:
            return jsonify({"error": "Token is missing."}), 401
        if token.startswith("Bearer "):
            token = token[7:]
        payload, error = decode_token(token)
        if error:
            return jsonify({"error": error}), 401
        request.user = payload
        return f(*args, **kwargs)
    return decorated
def admin_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get("Authorization")
        if not token:
            return jsonify({"error": "Token is missing."}), 401
        if token.startswith("Bearer "):
            token = token[7:]
        payload, error = decode_token(token)
        if error:
            return jsonify({"error": error}), 401
        if payload.get("role") != "admin":
            return jsonify({"error": "Admin access required."}), 403
        request.user = payload
        return f(*args, **kwargs)
    return decorated
@app.route("/api/register", methods=["POST"])
def register():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided."}), 400
    username = data.get("username", "").strip()
    email = data.get("email", "").strip()
    password = data.get("password", "")
    confirm_password = data.get("confirm_password", "")
    role = data.get("role", "user")
    if not username or len(username) < 3:
        return jsonify({"error": "Username must be at least 3 characters."}), 400
    if not validate_email(email):
        return jsonify({"error": "Invalid email format."}), 400
    if password != confirm_password:
        return jsonify({"error": "Passwords do not match."}), 400
    is_valid, message = validate_password(password)
    if not is_valid:
        return jsonify({"error": message}), 400
    if role not in ["user", "admin", "moderator"]:
        return jsonify({"error": "Invalid role."}), 400
    salt = os.urandom(16).hex()
    hashed = hash_password(password, salt)
    conn = create_connection()
    cursor = conn.cursor()
    try:
        cursor.execute("INSERT INTO users (username, email, password, salt, role) VALUES (?, ?, ?, ?, ?)", (username, email, hashed, salt, role))
        conn.commit()
        return jsonify({"message": f"User '{username}' registered successfully."}), 201
    except sqlite3.IntegrityError as e:
        if "username" in str(e):
            return jsonify({"error": "Username already exists."}), 409
        if "email" in str(e):
            return jsonify({"error": "Email already registered."}), 409
        return jsonify({"error": "Database error."}), 500
    finally:
        conn.close()
@app.route("/api/login", methods=["POST"])
def login():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided."}), 400
    username = data.get("username", "").strip()
    password = data.get("password", "")
    if not username or not password:
        return jsonify({"error": "Username and password are required."}), 400
    conn = create_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT * FROM users WHERE username = ?", (username,))
    user = cursor.fetchone()
    conn.close()
    if not user:
        return jsonify({"error": "User not found."}), 404
    if not user["is_active"]:
        return jsonify({"error": "Account is deactivated."}), 403
    if hash_password(password, user["salt"]) != user["password"]:
        return jsonify({"error": "Invalid password."}), 401
    token = generate_token(user["id"], user["username"], user["role"])
    return jsonify({"message": "Login successful.", "token": token, "role": user["role"]}), 200
