from flask import Flask, jsonify, request, send_from_directory
from datetime import datetime
from werkzeug.utils import secure_filename
import os
import uuid
app = Flask(__name__)
UPLOAD_FOLDER = "uploads"
MAX_CONTENT_LENGTH = 16 * 1024 * 1024
ALLOWED_EXTENSIONS = {"png", "jpg", "jpeg", "gif", "pdf", "txt", "csv", "xlsx", "docx", "zip"}
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_CONTENT_LENGTH
os.makedirs(UPLOAD_FOLDER, exist_ok=True)
uploaded_files = []
def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS
def get_file_size(file_path):
    size = os.path.getsize(file_path)
    if size < 1024:
        return f"{size} B"
    elif size < 1024 * 1024:
        return f"{size / 1024:.2f} KB"
    else:
        return f"{size / (1024 * 1024):.2f} MB"
@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({"error": "No file provided"}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No file selected"}), 400
    if not allowed_file(file.filename):
        return jsonify({"error": f"File type not allowed. Allowed types: {', '.join(ALLOWED_EXTENSIONS)}"}), 400
    original_filename = secure_filename(file.filename)
    file_extension = original_filename.rsplit('.', 1)[1].lower()
    unique_filename = f"{uuid.uuid4().hex}.{file_extension}"
    file_path = os.path.join(UPLOAD_FOLDER, unique_filename)
    file.save(file_path)
    file_entry = {
        "id": len(uploaded_files) + 1,
        "original_filename": original_filename,
        "stored_filename": unique_filename,
        "file_extension": file_extension,
        "file_size": get_file_size(file_path),
        "upload_path": file_path,
        "uploaded_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    uploaded_files.append(file_entry)
    return jsonify({"message": "File uploaded successfully", "file": file_entry}), 201
@app.route('/upload/multiple', methods=['POST'])
def upload_multiple_files():
    if 'files' not in request.files:
        return jsonify({"error": "No files provided"}), 400
    files = request.files.getlist('files')
    if not files:
        return jsonify({"error": "No files selected"}), 400
    uploaded = []
    failed = []
    for file in files:
        if file.filename == '':
            failed.append({"filename": "unknown", "error": "Empty filename"})
            continue
        if not allowed_file(file.filename):
            failed.append({"filename": file.filename, "error": "File type not allowed"})
            continue
        original_filename = secure_filename(file.filename)
        file_extension = original_filename.rsplit('.', 1)[1].lower()
        unique_filename = f"{uuid.uuid4().hex}.{file_extension}"
        file_path = os.path.join(UPLOAD_FOLDER, unique_filename)
        file.save(file_path)
        file_entry = {
            "id": len(uploaded_files) + 1,
            "original_filename": original_filename,
            "stored_filename": unique_filename,
            "file_extension": file_extension,
            "file_size": get_file_size(file_path),
            "upload_path": file_path,
            "uploaded_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        uploaded_files.append(file_entry)
        uploaded.append(file_entry)
    return jsonify({
        "message": "Multiple file upload complete",
        "uploaded": uploaded,
        "failed": failed,
        "total_uploaded": len(uploaded),
        "total_failed": len(failed)
    }), 201
@app.route('/files', methods=['GET'])
def get_files():
    extension = request.args.get('extension', '').lower()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 10, type=int)
    result = uploaded_files
    if extension:
        result = [f for f in result if f['file_extension'] == extension]
    total = len(result)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = result[start:end]
    return jsonify({
        "total": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "files": paginated
    })
@app.route('/files/<int:file_id>', methods=['GET'])
def get_file(file_id):
    file = next((f for f in uploaded_files if f['id'] == file_id), None)
    if not file:
        return jsonify({"error": "File not found"}), 404
    return jsonify(file)
@app.route('/files/<int:file_id>/download', methods=['GET'])
def download_file(file_id):
    file = next((f for f in uploaded_files if f['id'] == file_id), None)
    if not file:
        return jsonify({"error": "File not found"}), 404
    return send_from_directory(UPLOAD_FOLDER, file['stored_filename'], as_attachment=True, download_name=file['original_filename'])
@app.route('/files/<int:file_id>', methods=['DELETE'])
def delete_file(file_id):
    global uploaded_files
    file = next((f for f in uploaded_files if f['id'] == file_id), None)
    if not file:
        return jsonify({"error": "File not found"}), 404
    if os.path.exists(file['upload_path']):
        os.remove(file['upload_path'])
    uploaded_files = [f for f in uploaded_files if f['id'] != file_id]
    return jsonify({"message": f"File with id {file_id} deleted successfully"})
@app.route('/files/summary', methods=['GET'])
def get_summary():
    total = len(uploaded_files)
    if total == 0:
        return jsonify({"message": "No files uploaded yet"})
    extension_counts = {}
    for f in uploaded_files:
        extension_counts[f['file_extension']] = extension_counts.get(f['file_extension'], 0) + 1
    return jsonify({
        "total_files": total,
        "extension_breakdown": extension_counts,
        "allowed_extensions": list(ALLOWED_EXTENSIONS)
    })
if __name__ == '__main__':
    app.run(debug=True)

