from flask import Flask, jsonify, request
from datetime import datetime
import re
app = Flask(__name__)
comments = []
reactions = []
def validate_email(email):
    pattern = r'^[\w\.-]+@[\w\.-]+\.\w+$'
    return re.match(pattern, email) is not None
VALID_REACTIONS = ["like", "love", "haha", "sad", "angry", "wow"]
@app.route('/comments', methods=['POST'])
def add_comment():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    name = data.get('name', '').strip()
    email = data.get('email', '').strip()
    post_id = data.get('post_id')
    content = data.get('content', '').strip()
    parent_id = data.get('parent_id', None)
    errors = {}
    if not name:
        errors['name'] = "Name is required"
    if not email:
        errors['email'] = "Email is required"
    elif not validate_email(email):
        errors['email'] = "Invalid email format"
    if not post_id:
        errors['post_id'] = "Post ID is required"
    if not content:
        errors['content'] = "Content is required"
    elif len(content) < 2:
        errors['content'] = "Content must be at least 2 characters"
    if parent_id:
        parent = next((c for c in comments if c['id'] == parent_id), None)
        if not parent:
            errors['parent_id'] = "Parent comment not found"
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    new_comment = {
        "id": len(comments) + 1,
        "post_id": post_id,
        "parent_id": parent_id,
        "name": name,
        "email": email,
        "content": content,
        "status": "active",
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "updated_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    comments.append(new_comment)
    return jsonify({"message": "Comment added successfully", "comment": new_comment}), 201
@app.route('/comments', methods=['GET'])
def get_comments():
    post_id = request.args.get('post_id', type=int)
    status = request.args.get('status', '').lower()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 10, type=int)
    result = comments
    if post_id:
        result = [c for c in result if c['post_id'] == post_id]
    if status:
        result = [c for c in result if c['status'] == status]
    total = len(result)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = result[start:end]
    return jsonify({
        "total": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "comments": paginated
    })
@app.route('/comments/<int:comment_id>', methods=['GET'])
def get_comment(comment_id):
    comment = next((c for c in comments if c['id'] == comment_id), None)
    if not comment:
        return jsonify({"error": "Comment not found"}), 404
    replies = [c for c in comments if c['parent_id'] == comment_id]
    comment_reactions = [r for r in reactions if r['comment_id'] == comment_id]
    reaction_counts = {}
    for r in comment_reactions:
        reaction_counts[r['reaction']] = reaction_counts.get(r['reaction'], 0) + 1
    return jsonify({"comment": comment, "replies": replies, "reactions": reaction_counts})
@app.route('/comments/<int:comment_id>', methods=['PUT'])
def update_comment(comment_id):
    comment = next((c for c in comments if c['id'] == comment_id), None)
    if not comment:
        return jsonify({"error": "Comment not found"}), 404
    data = request.get_json()
    content = data.get('content', '').strip()
    if not content or len(content) < 2:
        return jsonify({"error": "Content must be at least 2 characters"}), 400
    comment['content'] = content
    comment['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Comment updated successfully", "comment": comment})
@app.route('/comments/<int:comment_id>/status', methods=['PATCH'])
def update_comment_status(comment_id):
    comment = next((c for c in comments if c['id'] == comment_id), None)
    if not comment:
        return jsonify({"error": "Comment not found"}), 404
    data = request.get_json()
    new_status = data.get('status', '').strip().lower()
    valid_statuses = ["active", "hidden", "flagged", "deleted"]
    if new_status not in valid_statuses:
        return jsonify({"error": f"Status must be one of: {', '.join(valid_statuses)}"}), 400
    comment['status'] = new_status
    comment['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Comment status updated successfully", "comment": comment})
@app.route('/comments/<int:comment_id>/react', methods=['POST'])
def react_to_comment(comment_id):
    comment = next((c for c in comments if c['id'] == comment_id), None)
    if not comment:
        return jsonify({"error": "Comment not found"}), 404
    data = request.get_json()
    user_email = data.get('email', '').strip()
    reaction = data.get('reaction', '').strip().lower()
    if not user_email or not validate_email(user_email):
        return jsonify({"error": "Valid email is required"}), 400
    if reaction not in VALID_REACTIONS:
        return jsonify({"error": f"Reaction must be one of: {', '.join(VALID_REACTIONS)}"}), 400
    existing = next((r for r in reactions if r['comment_id'] == comment_id and r['email'] == user_email), None)
    if existing:
        existing['reaction'] = reaction
        existing['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        return jsonify({"message": "Reaction updated successfully", "reaction": existing})
    new_reaction = {
        "id": len(reactions) + 1,
        "comment_id": comment_id,
        "email": user_email,
        "reaction": reaction,
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "updated_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    reactions.append(new_reaction)
    return jsonify({"message": "Reaction added successfully", "reaction": new_reaction}), 201
@app.route('/comments/<int:comment_id>', methods=['DELETE'])
def delete_comment(comment_id):
    global comments, reactions
    comment = next((c for c in comments if c['id'] == comment_id), None)
    if not comment:
        return jsonify({"error": "Comment not found"}), 404
    comments = [c for c in comments if c['id'] != comment_id and c['parent_id'] != comment_id]
    reactions = [r for r in reactions if r['comment_id'] != comment_id]
    return jsonify({"message": f"Comment with id {comment_id} and its replies deleted successfully"})
@app.route('/comments/summary', methods=['GET'])
def get_summary():
    total = len(comments)
    if total == 0:
        return jsonify({"message": "No comments available"})
    status_counts = {}
    for c in comments:
        status_counts[c['status']] = status_counts.get(c['status'], 0) + 1
    top_level = [c for c in comments if c['parent_id'] is None]
    replies = [c for c in comments if c['parent_id'] is not None]
    return jsonify({
        "total_comments": total,
        "top_level_comments": len(top_level),
        "total_replies": len(replies),
        "total_reactions": len(reactions),
        "status_breakdown": status_counts
    })
if __name__ == '__main__':
    app.run(debug=True)

