from flask import Flask, jsonify, request
from datetime import datetime
import re
app = Flask(__name__)
feedbacks = []
VALID_CATEGORIES = ["general", "bug", "feature", "complaint", "compliment"]
VALID_RATINGS = [1, 2, 3, 4, 5]
def validate_email(email):
    pattern = r'^[\w\.-]+@[\w\.-]+\.\w+$'
    return re.match(pattern, email) is not None
@app.route('/feedback', methods=['POST'])
def submit_feedback():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    name = data.get('name', '').strip()
    email = data.get('email', '').strip()
    category = data.get('category', '').strip().lower()
    rating = data.get('rating')
    subject = data.get('subject', '').strip()
    message = data.get('message', '').strip()
    errors = {}
    if not name:
        errors['name'] = "Name is required"
    if not email:
        errors['email'] = "Email is required"
    elif not validate_email(email):
        errors['email'] = "Invalid email format"
    if not category:
        errors['category'] = "Category is required"
    elif category not in VALID_CATEGORIES:
        errors['category'] = f"Category must be one of: {', '.join(VALID_CATEGORIES)}"
    if rating is None:
        errors['rating'] = "Rating is required"
    elif rating not in VALID_RATINGS:
        errors['rating'] = "Rating must be between 1 and 5"
    if not subject:
        errors['subject'] = "Subject is required"
    if not message:
        errors['message'] = "Message is required"
    elif len(message) < 10:
        errors['message'] = "Message must be at least 10 characters"
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    feedback_entry = {
        "id": len(feedbacks) + 1,
        "name": name,
        "email": email,
        "category": category,
        "rating": rating,
        "subject": subject,
        "message": message,
        "status": "pending",
        "submitted_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    feedbacks.append(feedback_entry)
    return jsonify({"message": "Feedback submitted successfully", "feedback": feedback_entry}), 201
@app.route('/feedbacks', methods=['GET'])
def get_feedbacks():
    category = request.args.get('category', '').lower()
    rating = request.args.get('rating', type=int)
    status = request.args.get('status', '').lower()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 5, type=int)
    result = feedbacks
    if category:
        result = [f for f in result if f['category'] == category]
    if rating:
        result = [f for f in result if f['rating'] == rating]
    if status:
        result = [f for f in result if f['status'] == status]
    total = len(result)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = result[start:end]
    return jsonify({
        "total": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "feedbacks": paginated
    })
@app.route('/feedbacks/<int:feedback_id>', methods=['GET'])
def get_feedback(feedback_id):
    feedback = next((f for f in feedbacks if f['id'] == feedback_id), None)
    if not feedback:
        return jsonify({"error": "Feedback not found"}), 404
    return jsonify(feedback)
@app.route('/feedbacks/<int:feedback_id>/status', methods=['PATCH'])
def update_status(feedback_id):
    feedback = next((f for f in feedbacks if f['id'] == feedback_id), None)
    if not feedback:
        return jsonify({"error": "Feedback not found"}), 404
    data = request.get_json()
    new_status = data.get('status', '').strip().lower()
    valid_statuses = ["pending", "reviewed", "resolved", "closed"]
    if new_status not in valid_statuses:
        return jsonify({"error": f"Status must be one of: {', '.join(valid_statuses)}"}), 400
    feedback['status'] = new_status
    feedback['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Status updated successfully", "feedback": feedback})
@app.route('/feedbacks/<int:feedback_id>', methods=['DELETE'])
def delete_feedback(feedback_id):
    global feedbacks
    feedback = next((f for f in feedbacks if f['id'] == feedback_id), None)
    if not feedback:
        return jsonify({"error": "Feedback not found"}), 404
    feedbacks = [f for f in feedbacks if f['id'] != feedback_id]
    return jsonify({"message": f"Feedback with id {feedback_id} deleted successfully"})
@app.route('/feedbacks/summary', methods=['GET'])
def get_summary():
    total = len(feedbacks)
    if total == 0:
        return jsonify({"message": "No feedbacks available"})
    avg_rating = sum(f['rating'] for f in feedbacks) / total
    category_counts = {}
    for f in feedbacks:
        category_counts[f['category']] = category_counts.get(f['category'], 0) + 1
    status_counts = {}
    for f in feedbacks:
        status_counts[f['status']] = status_counts.get(f['status'], 0) + 1
    return jsonify({
        "total_feedbacks": total,
        "average_rating": round(avg_rating, 2),
        "category_breakdown": category_counts,
        "status_breakdown": status_counts
    })
if __name__ == '__main__':
    app.run(debug=True)

