from flask import Flask, jsonify, request
from datetime import datetime
import re
app = Flask(__name__)
posts = []
comments = []
def slugify(title):
    title = title.lower()
    title = re.sub(r'[^a-z0-9\s-]', '', title)
    title = re.sub(r'\s+', '-', title.strip())
    return title
@app.route('/posts', methods=['GET'])
def get_posts():
    category = request.args.get('category', '').lower()
    author = request.args.get('author', '').lower()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 5, type=int)
    result = posts
    if category:
        result = [p for p in result if p['category'].lower() == category]
    if author:
        result = [p for p in result if p['author'].lower() == author]
    total = len(result)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = result[start:end]
    return jsonify({
        "total": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "posts": paginated
    })
@app.route('/posts/<int:post_id>', methods=['GET'])
def get_post(post_id):
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    post_comments = [c for c in comments if c['post_id'] == post_id]
    return jsonify({"post": post, "comments": post_comments})
@app.route('/posts', methods=['POST'])
def create_post():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    title = data.get('title', '').strip()
    content = data.get('content', '').strip()
    author = data.get('author', '').strip()
    category = data.get('category', 'General').strip()
    tags = data.get('tags', [])
    errors = {}
    if not title:
        errors['title'] = "Title is required"
    if not content:
        errors['content'] = "Content is required"
    if not author:
        errors['author'] = "Author is required"
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    new_post = {
        "id": len(posts) + 1,
        "title": title,
        "slug": slugify(title),
        "content": content,
        "author": author,
        "category": category,
        "tags": tags,
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "updated_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    posts.append(new_post)
    return jsonify({"message": "Post created successfully", "post": new_post}), 201
@app.route('/posts/<int:post_id>', methods=['PUT'])
def update_post(post_id):
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    data = request.get_json()
    post['title'] = data.get('title', post['title'])
    post['content'] = data.get('content', post['content'])
    post['category'] = data.get('category', post['category'])
    post['tags'] = data.get('tags', post['tags'])
    post['slug'] = slugify(post['title'])
    post['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Post updated successfully", "post": post})
@app.route('/posts/<int:post_id>', methods=['DELETE'])
def delete_post(post_id):
    global posts, comments
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    posts = [p for p in posts if p['id'] != post_id]
    comments = [c for c in comments if c['post_id'] != post_id]
    return jsonify({"message": f"Post with id {post_id} deleted successfully"})
@app.route('/posts/<int:post_id>/comments', methods=['POST'])
def add_comment(post_id):
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    data = request.get_json()
    name = data.get('name', '').strip()
    comment_text = data.get('comment', '').strip()
    if not name or not comment_text:
        return jsonify({"error": "Name and comment are required"}), 400
    new_comment = {
        "id": len(comments) + 1,
        "post_id": post_id,
        "name": name,
        "comment": comment_text,
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    comments.append(new_comment)
    return jsonify({"message": "Comment added successfully", "comment": new_comment}), 201
@app.route('/posts/search', methods=['GET'])
def search_posts():
    query = request.args.get('q', '').lower()
    if not query:
        return jsonify({"error": "Search query is required"}), 400
    results = [p for p in posts if query in p['title'].lower() or query in p['content'].lower()]
    return jsonify({"total": len(results), "results": results})
if __name__ == '__main__':
    app.run(debug=True)

from flask import Flask, request, jsonify
import sqlite3
app = Flask(__name__)
def db_query(query, args=(), one=False):
    conn = sqlite3.connect("blog.db")
    cursor = conn.cursor()
    cursor.execute(query, args)
    rv = cursor.fetchall()
    conn.commit()
    conn.close()
    return (rv[0] if rv else None) if one else rv
@app.route("/posts", methods=["GET"])
def get_posts():
    posts = db_query("SELECT * FROM posts")
    return jsonify([{"id": r[0], "title": r[1], "content": r[2]} for r in posts])
@app.route("/posts", methods=["POST"])
def add_post():
    data = request.json
    db_query("INSERT INTO posts (title, content) VALUES (?, ?)", (data["title"], data["content"]))
    return jsonify({"status": "post created"}), 201
@app.route("/posts/<int:post_id>", methods=["DELETE"])
def delete_post(post_id):
    db_query("DELETE FROM posts WHERE id = ?", (post_id,))
    return jsonify({"status": "post deleted"})
if __name__ == "__main__":
    conn = sqlite3.connect("blog.db")
    conn.execute("CREATE TABLE IF NOT EXISTS posts (id INTEGER PRIMARY KEY, title TEXT, content TEXT)")
    conn.close()
    app.run(debug=True)

