from flask import Flask, jsonify, request
from datetime import datetime
import re
app = Flask(__name__)
contacts = []
def validate_email(email):
    pattern = r'^[\w\.-]+@[\w\.-]+\.\w+$'
    return re.match(pattern, email) is not None
def validate_phone(phone):
    pattern = r'^\+?[\d\s\-\(\)]{7,15}$'
    return re.match(pattern, phone) is not None
@app.route('/contact', methods=['POST'])
def submit_contact():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    name = data.get('name', '').strip()
    email = data.get('email', '').strip()
    phone = data.get('phone', '').strip()
    subject = data.get('subject', '').strip()
    message = data.get('message', '').strip()
    errors = {}
    if not name:
        errors['name'] = "Name is required"
    if not email:
        errors['email'] = "Email is required"
    elif not validate_email(email):
        errors['email'] = "Invalid email format"
    if phone and not validate_phone(phone):
        errors['phone'] = "Invalid phone number format"
    if not subject:
        errors['subject'] = "Subject is required"
    if not message:
        errors['message'] = "Message is required"
    elif len(message) < 10:
        errors['message'] = "Message must be at least 10 characters"
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    contact_entry = {
        "id": len(contacts) + 1,
        "name": name,
        "email": email,
        "phone": phone,
        "subject": subject,
        "message": message,
        "submitted_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    contacts.append(contact_entry)
    return jsonify({"message": "Contact form submitted successfully", "contact": contact_entry}), 201
@app.route('/contacts', methods=['GET'])
def get_contacts():
    return jsonify({"total": len(contacts), "contacts": contacts})
@app.route('/contacts/<int:contact_id>', methods=['GET'])
def get_contact(contact_id):
    contact = next((c for c in contacts if c['id'] == contact_id), None)
    if not contact:
        return jsonify({"error": "Contact not found"}), 404
    return jsonify(contact)
@app.route('/contacts/<int:contact_id>', methods=['DELETE'])
def delete_contact(contact_id):
    global contacts
    contact = next((c for c in contacts if c['id'] == contact_id), None)
    if not contact:
        return jsonify({"error": "Contact not found"}), 404
    contacts = [c for c in contacts if c['id'] != contact_id]
    return jsonify({"message": f"Contact with id {contact_id} deleted successfully"})
if __name__ == '__main__':
    app.run(debug=True)

