from flask import Flask, render_template_string, request
app = Flask(__name__)
HTML_TEMPLATE = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>User Input Display</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 600px; margin: 50px auto; padding: 20px; background-color: #f4f4f4; }
        h1 { text-align: center; color: #333; }
        form { background: #fff; padding: 20px; border-radius: 8px; box-shadow: 0 2px 5px rgba(0,0,0,0.1); }
        input, textarea { width: 100%; padding: 10px; margin: 10px 0; border: 1px solid #ccc; border-radius: 4px; box-sizing: border-box; }
        button { width: 100%; padding: 10px; background-color: #4CAF50; color: white; border: none; border-radius: 4px; cursor: pointer; font-size: 16px; }
        button:hover { background-color: #45a049; }
        .result { background: #fff; padding: 20px; margin-top: 20px; border-radius: 8px; box-shadow: 0 2px 5px rgba(0,0,0,0.1); }
        .result h2 { color: #4CAF50; }
        .field { margin: 10px 0; padding: 10px; background: #f9f9f9; border-left: 4px solid #4CAF50; border-radius: 4px; }
        .label { font-weight: bold; color: #555; }
        .value { color: #333; margin-top: 5px; }
    </style>
</head>
<body>
    <h1>User Input Display</h1>
    <form method="POST">
        <label>Name:</label>
        <input type="text" name="name" placeholder="Enter your name" value="{{ form_data.get('name', '') }}">
        <label>Email:</label>
        <input type="email" name="email" placeholder="Enter your email" value="{{ form_data.get('email', '') }}">
        <label>Age:</label>
        <input type="number" name="age" placeholder="Enter your age" value="{{ form_data.get('age', '') }}">
        <label>Message:</label>
        <textarea name="message" rows="4" placeholder="Enter your message">{{ form_data.get('message', '') }}</textarea>
        <button type="submit">Submit</button>
    </form>
    {% if form_data %}
    <div class="result">
        <h2>Submitted Data:</h2>
        {% for key, value in form_data.items() %}
        <div class="field">
            <div class="label">{{ key.capitalize() }}:</div>
            <div class="value">{{ value }}</div>
        </div>
        {% endfor %}
    </div>
    {% endif %}
</body>
</html>
"""
