from flask import Flask, render_template_string, request, redirect, url_for, flash, jsonify
import sqlite3
from datetime import datetime
app = Flask(__name__)
app.secret_key = 'your_secret_key_here'
def get_db_connection():
    connection = sqlite3.connect("users_input.db")
    connection.row_factory = sqlite3.Row
    return connection
def init_db():
    connection = get_db_connection()
    cursor = connection.cursor()
    cursor.execute("CREATE TABLE IF NOT EXISTS entries (id INTEGER PRIMARY KEY, full_name TEXT, email TEXT, phone TEXT, age INTEGER, country TEXT, message TEXT, interests TEXT, created_at TEXT)")
    connection.commit()
    connection.close()
html_template = """
<!DOCTYPE html>
