        .btn:hover { background: #764ba2; }
        .btn-reset { background: #999; margin-top: 10px; }
        .btn-reset:hover { background: #777; }
        .display-section { background: white; padding: 30px; border-radius: 10px; box-shadow: 0 10px 30px rgba(0,0,0,0.2); }
        .display-section h2 { margin-bottom: 20px; color: #333; }
        .filters { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 20px; }
        .filters input, .filters select { padding: 10px; border: 2px solid #ddd; border-radius: 5px; }
        .entries-table { width: 100%; border-collapse: collapse; margin-top: 20px; }
        .entries-table th { background: #667eea; color: white; padding: 12px; text-align: left; }
        .entries-table td { padding: 12px; border-bottom: 1px solid #ddd; }
        .entries-table tr:hover { background: #f5f5f5; }
        .entries-table .actions { display: flex; gap: 5px; }
        .btn-small { padding: 5px 10px; font-size: 0.85em; }
        .btn-delete { background: #e74c3c; }
        .btn-delete:hover { background: #c0392b; }
        .btn-edit { background: #f39c12; }
