        .stats { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 15px; margin-bottom: 20px; }
        .stat-card { background: #f9f9f9; padding: 15px; border-radius: 5px; text-align: center; border-left: 4px solid #667eea; }
        .stat-card .number { font-size: 2em; font-weight: bold; color: #667eea; }
        .stat-card .label { color: #666; font-size: 0.9em; }
        @media (max-width: 768px) {
            .content { grid-template-columns: 1fr; }
            .checkbox-group { grid-template-columns: 1fr; }
            .filters { grid-template-columns: 1fr; }
