                        <label for="country">Country</label>
                        <select id="country" name="country">
                            <option value="">Select a country</option>
                            <option value="USA">USA</option>
                            <option value="UK">UK</option>
                            <option value="Canada">Canada</option>
                            <option value="Australia">Australia</option>
                            <option value="India">India</option>
                            <option value="Other">Other</option>
                        </select>
                    </div>
                    <div class="form-group">
                        <label>Interests</label>
                        <div class="checkbox-group">
                            <div class="checkbox-item">
                                <input type="checkbox" id="tech" name="interests" value="Technology">
                                <label for="tech">Technology</label>
                            </div>
                            <div class="checkbox-item">
                                <input type="checkbox" id="sports" name="interests" value="Sports">
                                <label for="sports">Sports</label>
                            </div>
                            <div class="checkbox-item">
                                <input type="checkbox" id="music" name="interests" value="Music">
                                <label for="music">Music</label>
                            </div>
                            <div class="checkbox-item">
                                <input type="checkbox" id="travel" name="interests" value="Travel">
                                <label for="travel">Travel</label>
                            </div>
                            <div class="checkbox-item">
                                <input type="checkbox" id="books" name="interests" value="Books">
                                <label for="books">Books</label>
                            </div>
                            <div class="checkbox-item">
                                <input type="checkbox" id="cooking" name="interests" value="Cooking">
                                <label for="cooking">Cooking</label>
                            </div>
                        </div>
                    </div>
                    <div class="form-group">
                        <label for="message">Message *</label>
                        <textarea id="message" name="message" rows="4" required></textarea>
                    </div>
                    <button type="submit" class="btn">Submit</button>
                    <button type="reset" class="btn btn-reset">Clear</button>
                </form>
            </div>
            <div class="display-section">
                <h2>Submitted Entries</h2>
                <div class="stats">
                    <div class="stat-card">
                        <div class="number">{{ total_entries }}</div>
                        <div class="label">Total Entries</div>
                    </div>
                    <div class="stat-card">
                        <div class="number">{{ unique_emails }}</div>
                        <div class="label">Unique Emails</div>
                    </div>
                    <div class="stat-card">
                        <div class="number">{{ avg_age }}</div>
                        <div class="label">Average Age</div>
                    </div>
                </div>
                <div class="filters">
                    <input type="text" id="search" placeholder="Search by name or email...">
                    <select id="country-filter">
                        <option value="">All Countries</option>
                        <option value="USA">USA</option>
                        <option value="UK">UK</option>
                        <option value="Canada">Canada</option>
                        <option value="Australia">Australia</option>
                        <option value="India">India</option>
                        <option value="Other">Other</option>
                    </select>
