                {% if entries %}
                <table class="entries-table">
                    <thead>
                        <tr>
                            <th>Name</th>
                            <th>Email</th>
                            <th>Phone</th>
                            <th>Age</th>
                            <th>Country</th>
                            <th>Submitted</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody id="entries-body">
                        {% for entry in entries %}
                        <tr class="entry-row" data-name="{{ entry.full_name }}" data-email="{{ entry.email }}" data-country="{{ entry.country }}">
                            <td>{{ entry.full_name }}</td>
                            <td>{{ entry.email }}</td>
                            <td>{{ entry.phone }}</td>
                            <td>{{ entry.age }}</td>
                            <td>{{ entry.country }}</td>
                            <td>{{ entry.created_at }}</td>
                            <td class="actions">
                                <button class="btn btn-small btn-edit" onclick="viewEntry({{ entry.id }})">View</button>
                                <a href="{{ url_for('delete_entry', entry_id=entry.id) }}" class="btn btn-small btn-delete" onclick="return confirm('Delete this entry?')">Delete</a>
                            </td>
                        </tr>
                        {% endfor %}
                    </tbody>
                </table>
                {% else %}
                <div class="no-data">No entries yet. Submit your information to get started!</div>
                {% endif %}
            </div>
        </div>
    </div>
    <script>
        document.getElementById('search').addEventListener('keyup', filterTable);
        document.getElementById('country-filter').addEventListener('change', filterTable);
        function filterTable() {
            const searchValue = document.getElementById('search').value.toLowerCase();
            const countryValue = document.getElementById('country-filter').value;
            const rows = document.querySelectorAll('.entry-row');
            rows.forEach(row => {
                const name = row.getAttribute('data-name').toLowerCase();
                const email = row.getAttribute('data-email').toLowerCase();
                const country = row.getAttribute('data-country');
                const matchesSearch = name.includes(searchValue) || email.includes(searchValue);
                const matchesCountry = !countryValue || country === countryValue;
                row.style.display = matchesSearch && matchesCountry ? '' : 'none';
            });
        }
        function viewEntry(entryId) {
            fetch(`/api/entry/${entryId}`)
                .then(response => response.json())
                .then(data => alert(`Name: ${data.full_name}\nEmail: ${data.email}\nPhone: ${data.phone}\nAge: ${data.age}\nCountry: ${data.country}\nInterests: ${data.interests}\nMessage: ${data.message}`))
                .catch(error => alert('Error loading entry'));
        }
    </script>
</body>
</html>
"""
@app.route('/')
def index():
    connection = get_db_connection()
    cursor = connection.cursor()
    cursor.execute("SELECT * FROM entries ORDER BY created_at DESC")
    entries = cursor.fetchall()
    cursor.execute("SELECT COUNT(*) as count FROM entries")
    total_entries = cursor.fetchone()['count']
    cursor.execute("SELECT COUNT(DISTINCT email) as count FROM entries")
    unique_emails = cursor.fetchone()['count']
    cursor.execute("SELECT AVG(age) as avg FROM entries WHERE age IS NOT NULL")
    avg_age_result = cursor.fetchone()
    avg_age = round(avg_age_result['avg']) if avg_age_result['avg'] else 0
    connection.close()
    return render_template_string(html_template, entries=entries, total_entries=total_entries, unique_emails=unique_emails, avg_age=avg_age)
@app.route('/submit', methods=['POST'])
def submit_entry():
    full_name = request.form.get('full_name')
    email = request.form.get('email')
    phone = request.form.get('phone')
    age = request.form.get('age')
    country = request.form.get('country')
    message = request.form.get('message')
    interests = request.form.getlist('interests')
    interests_str = ', '.join(interests) if interests else ''
    if not full_name or not email or not message:
        flash('Please fill all required fields', 'error')
        return redirect(url_for('index'))
    connection = get_db_connection()
    cursor = connection.cursor()
    now = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    cursor.execute("INSERT INTO entries (full_name, email, phone, age, country, message, interests, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)", (full_name, email, phone, age or None, country, message, interests_str, now))
    connection.commit()
    connection.close()
    flash('Entry submitted successfully!', 'success')
    return redirect(url_for('index'))
@app.route('/delete/<int:entry_id>')
def delete_entry(entry_id):
    connection = get_db_connection()
    cursor = connection.cursor()
    cursor.execute("DELETE FROM entries WHERE id = ?", (entry_id,))
    connection.commit()
    connection.close()
    flash('Entry deleted successfully!', 'success')
    return redirect(url_for('index'))
@app.route('/api/entry/<int:entry_id>')
def get_entry(entry_id):
    connection = get_db_connection()
    cursor = connection.cursor()
    cursor.execute("SELECT * FROM entries WHERE id = ?", (entry_id,))
    entry = cursor.fetchone()
    connection.close()
    if entry:
        return jsonify(dict(entry)), 200
    else:
        return jsonify({"error": "Entry not found"}), 404
@app.route('/api/search')
def search_entries():
    query = request.args.get('q', '').lower()
    connection = get_db_connection()
    cursor = connection.cursor()
    cursor.execute("SELECT * FROM entries WHERE full_name LIKE ? OR email LIKE ? ORDER BY created_at DESC", (f"%{query}%", f"%{query}%"))
    entries = cursor.fetchall()
    connection.close()
    return jsonify([dict(entry) for entry in entries]), 200
if __name__ == '__main__':
    init_db()
    app.run(debug=True, port=5000)

