    {"id": 2, "title": "Data Science Basics", "category": "Technology", "author": "Bob", "year": 2019},
    {"id": 3, "title": "Machine Learning Guide", "category": "Technology", "author": "Carol", "year": 2021},
    {"id": 4, "title": "Cooking Masterclass", "category": "Lifestyle", "author": "David", "year": 2018},
    {"id": 5, "title": "Travel Around the World", "category": "Lifestyle", "author": "Eva", "year": 2022},
    {"id": 6, "title": "Financial Freedom", "category": "Finance", "author": "Frank", "year": 2020},
    {"id": 7, "title": "Health and Wellness", "category": "Health", "author": "Grace", "year": 2021},
    {"id": 8, "title": "Art of Photography", "category": "Arts", "author": "Henry", "year": 2019},
]
@app.route('/search', methods=['GET'])
def search():
    query = request.args.get('q', '').lower()
    category = request.args.get('category', '').lower()
    author = request.args.get('author', '').lower()
    year = request.args.get('year', type=int)
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 5, type=int)
    results = data
    if query:
        results = [item for item in results if query in item['title'].lower()]
    if category:
        results = [item for item in results if category == item['category'].lower()]
    if author:
        results = [item for item in results if author == item['author'].lower()]
    if year:
        results = [item for item in results if item['year'] == year]
    total = len(results)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = results[start:end]
    return jsonify({
        "query": request.args.get('q', ''),
        "total_results": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "results": paginated
    })
@app.route('/search/categories', methods=['GET'])
def get_categories():
    categories = list(set(item['category'] for item in data))
    return jsonify({"categories": categories})
@app.route('/search/suggestions', methods=['GET'])
def suggestions():
    query = request.args.get('q', '').lower()
    if not query:
        return jsonify({"suggestions": []})
    suggested = [item['title'] for item in data if query in item['title'].lower()]
    return jsonify({"suggestions": suggested})
if __name__ == '__main__':
    app.run(debug=True)

