import os
import logging
from datetime import datetime
class LogManager:
    def __init__(self, log_file_path):
        self.log_file_path = log_file_path
        self.ensure_log_file_exists()
    def ensure_log_file_exists(self):
        log_dir = os.path.dirname(self.log_file_path)
        if log_dir and not os.path.exists(log_dir):
            os.makedirs(log_dir)
        if not os.path.exists(self.log_file_path):
            with open(self.log_file_path, 'w', encoding='utf-8') as file:
                file.write("Log file created at " + datetime.now().strftime("%Y-%m-%d %H:%M:%S") + "\n")
                file.write("="*80 + "\n")
    def append_log(self, level, message):
        timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        log_entry = f"[{timestamp}] [{level}] {message}"
        try:
            with open(self.log_file_path, 'a', encoding='utf-8') as file:
                file.write(log_entry + "\n")
            print(f"Log appended: {log_entry}")
        except IOError as e:
            print(f"Error appending to log file: {str(e)}")
    def log_info(self, message):
        self.append_log("INFO", message)
    def log_warning(self, message):
        self.append_log("WARNING", message)
    def log_error(self, message):
        self.append_log("ERROR", message)
    def log_debug(self, message):
        self.append_log("DEBUG", message)
    def log_success(self, message):
        self.append_log("SUCCESS", message)
    def read_logs(self):
        try:
            with open(self.log_file_path, 'r', encoding='utf-8') as file:
                content = file.read()
            return content
        except IOError as e:
            print(f"Error reading log file: {str(e)}")
            return None
    def get_last_n_logs(self, n):
        try:
            with open(self.log_file_path, 'r', encoding='utf-8') as file:
                lines = file.readlines()
            last_lines = lines[-n:] if n <= len(lines) else lines
            return ''.join(last_lines)
        except IOError as e:
            print(f"Error reading log file: {str(e)}")
            return None
    def search_logs(self, search_term):
        try:
            with open(self.log_file_path, 'r', encoding='utf-8') as file:
                lines = file.readlines()
            matching_lines = [line for line in lines if search_term.lower() in line.lower()]
            return matching_lines
        except IOError as e:
            print(f"Error searching logs: {str(e)}")
            return []
    def get_logs_by_level(self, level):
        try:
            with open(self.log_file_path, 'r', encoding='utf-8') as file:
                lines = file.readlines()
            level_logs = [line for line in lines if f"[{level}]" in line]
            return level_logs
        except IOError as e:
            print(f"Error filtering logs: {str(e)}")
            return []
    def clear_logs(self):
        try:
            with open(self.log_file_path, 'w', encoding='utf-8') as file:
                file.write("Logs cleared at " + datetime.now().strftime("%Y-%m-%d %H:%M:%S") + "\n")
                file.write("="*80 + "\n")
            print("Log file cleared successfully")
        except IOError as e:
            print(f"Error clearing log file: {str(e)}")
    def get_log_statistics(self):
        try:
            with open(self.log_file_path, 'r', encoding='utf-8') as file:
                lines = file.readlines()
            info_count = sum(1 for line in lines if "[INFO]" in line)
            warning_count = sum(1 for line in lines if "[WARNING]" in line)
            error_count = sum(1 for line in lines if "[ERROR]" in line)
            debug_count = sum(1 for line in lines if "[DEBUG]" in line)
            success_count = sum(1 for line in lines if "[SUCCESS]" in line)
            total_logs = len(lines) - 2
            return {"INFO": info_count, "WARNING": warning_count, "ERROR": error_count, "DEBUG": debug_count, "SUCCESS": success_count, "TOTAL": total_logs}
        except IOError as e:
            print(f"Error calculating statistics: {str(e)}")
            return {}
def simple_log_append(log_file_path, level, message):
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    log_entry = f"[{timestamp}] [{level}] {message}"
    try:
        with open(log_file_path, 'a', encoding='utf-8') as file:
            file.write(log_entry + "\n")
        print(f"Logged: {log_entry}")
    except IOError as e:
        print(f"Error appending to log: {str(e)}")
def log_user_activity(log_file_path, username, activity):
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    log_entry = f"[{timestamp}] USER: {username} | ACTIVITY: {activity}"
    try:
        with open(log_file_path, 'a', encoding='utf-8') as file:
            file.write(log_entry + "\n")
        print(f"Activity logged: {log_entry}")
    except IOError as e:
        print(f"Error logging activity: {str(e)}")
def log_system_event(log_file_path, event_type, event_description):
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    log_entry = f"[{timestamp}] EVENT: {event_type} | DETAILS: {event_description}"
    try:
        with open(log_file_path, 'a', encoding='utf-8') as file:
            file.write(log_entry + "\n")
        print(f"Event logged: {log_entry}")
    except IOError as e:
        print(f"Error logging event: {str(e)}")
def main():
    log_file = "application.log"
    log_manager = LogManager(log_file)
    while True:
        print("\n" + "="*60)
        print("LOG MANAGEMENT SYSTEM")
        print("="*60)
        print("1. Log information message")
        print("2. Log warning message")
        print("3. Log error message")
        print("4. Log debug message")
        print("5. Log user activity")
