        print("7. View all logs")
        print("8. View last N logs")
        print("9. Search logs")
        print("10. Filter logs by level")
        print("11. View log statistics")
        print("12. Clear logs")
        print("13. Exit")
        choice = input("\nSelect an option (1-13): ").strip()
        if choice == '1':
