            log_manager.log_info(message)
        elif choice == '2':
            message = input("Enter warning message: ").strip()
            log_manager.log_warning(message)
        elif choice == '3':
            message = input("Enter error message: ").strip()
            log_manager.log_error(message)
        elif choice == '4':
            message = input("Enter debug message: ").strip()
            log_manager.log_debug(message)
        elif choice == '5':
            username = input("Enter username: ").strip()
            activity = input("Enter activity: ").strip()
            log_user_activity(log_file, username, activity)
        elif choice == '6':
            event_type = input("Enter event type: ").strip()
            event_desc = input("Enter event description: ").strip()
            log_system_event(log_file, event_type, event_desc)
        elif choice == '7':
            logs = log_manager.read_logs()
            if logs:
                print("\n" + "="*60)
                print("ALL LOGS:")
