                print(f"\nLogs containing '{search_term}':")
                print("="*60)
                for result in results:
                    print(result.rstrip())
                print("="*60)
            else:
                print(f"No logs found containing '{search_term}'")
        elif choice == '10':
            print("Log levels: INFO, WARNING, ERROR, DEBUG, SUCCESS")
            level = input("Enter log level to filter: ").strip().upper()
            results = log_manager.get_logs_by_level(level)
            if results:
                print(f"\nLogs with level [{level}]:")
