import os
import fnmatch
def search_files(root_dir, keyword, file_pattern="*"):
    matches = []
    for dirpath, dirnames, filenames in os.walk(root_dir):
        for filename in filenames:
            if fnmatch.fnmatch(filename, file_pattern):
                file_path = os.path.join(dirpath, filename)
                try:
                    with open(file_path, 'r', errors='ignore') as f:
                        for line_num, line in enumerate(f, start=1):
                            if keyword.lower() in line.lower():
                                matches.append((file_path, line_num, line.strip()))
                except Exception as e:
                    print(f"Could not read {file_path}: {e}")
    return matches
root_directory = "."
search_keyword = "error"
file_type = "*.txt"
results = search_files(root_directory, search_keyword, file_type)
print(f"Search Results for '{search_keyword}' in '{file_type}' files:")
print("=" * 50)
if results:
    for file_path, line_num, line in results:
        print(f"File: {file_path}")
        print(f"Line {line_num}: {line}")
        print("-" * 50)
else:
    print("No matches found.")

import os
def search_files(directory, extension):
    if not os.path.isdir(directory):
        print("Directory not found.")
        return
    matches = []
    for root, dirs, files in os.walk(directory):
        for file in files:
            if file.endswith(extension):
                matches.append(os.path.join(root, file))
    if matches:
        print(f"Found {len(matches)} files:")
        for path in matches:
            print(path)
    else:
        print("No matching files found.")
search_dir = input("Enter directory: ")
