search_files(search_dir, search_ext)

import os
import re
from pathlib import Path
from datetime import datetime
class FileSearchTool:
    def __init__(self):
        self.search_results = []
    def search_by_name(self, directory, filename_pattern, recursive=True):
        self.search_results = []
        try:
            if recursive:
                for root, dirs, files in os.walk(directory):
                    for file in files:
                        if re.search(filename_pattern, file, re.IGNORECASE):
                            file_path = os.path.join(root, file)
                            file_size = os.path.getsize(file_path)
                            mod_time = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
                            self.search_results.append({"path": file_path, "name": file, "size": file_size, "modified": mod_time})
            else:
                if not os.path.isdir(directory):
                    print(f"Error: '{directory}' is not a valid directory")
                    return
                for file in os.listdir(directory):
                    file_path = os.path.join(directory, file)
                    if os.path.isfile(file_path) and re.search(filename_pattern, file, re.IGNORECASE):
                        file_size = os.path.getsize(file_path)
                        mod_time = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
                        self.search_results.append({"path": file_path, "name": file, "size": file_size, "modified": mod_time})
            return self.search_results
        except Exception as e:
            print(f"Error during search: {str(e)}")
            return []
    def search_by_content(self, directory, search_text, recursive=True, case_sensitive=False):
        self.search_results = []
        try:
            flags = 0 if case_sensitive else re.IGNORECASE
            if recursive:
                for root, dirs, files in os.walk(directory):
                    for file in files:
                        if file.endswith(('.txt', '.py', '.java', '.cpp', '.js', '.html', '.css', '.log', '.json', '.csv', '.xml')):
                            file_path = os.path.join(root, file)
                            try:
                                with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
                                    lines = f.readlines()
                                    for line_num, line in enumerate(lines, 1):
                                        if re.search(search_text, line, flags):
                                            self.search_results.append({"file": file_path, "line_number": line_num, "content": line.strip()})
                            except Exception:
                                pass
            else:
                if not os.path.isdir(directory):
                    print(f"Error: '{directory}' is not a valid directory")
                    return
                for file in os.listdir(directory):
                    file_path = os.path.join(directory, file)
                    if os.path.isfile(file_path) and file.endswith(('.txt', '.py', '.java', '.cpp', '.js', '.html', '.css', '.log', '.json', '.csv', '.xml')):
                        try:
                            with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
                                lines = f.readlines()
                                for line_num, line in enumerate(lines, 1):
                                    if re.search(search_text, line, flags):
                                        self.search_results.append({"file": file_path, "line_number": line_num, "content": line.strip()})
                        except Exception:
                            pass
            return self.search_results
        except Exception as e:
            print(f"Error during search: {str(e)}")
            return []
    def search_by_extension(self, directory, extension, recursive=True):
        self.search_results = []
        try:
            if not extension.startswith('.'):
                extension = '.' + extension
            if recursive:
                for root, dirs, files in os.walk(directory):
                    for file in files:
                        if file.endswith(extension):
                            file_path = os.path.join(root, file)
                            file_size = os.path.getsize(file_path)
                            mod_time = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
                            self.search_results.append({"path": file_path, "name": file, "size": file_size, "modified": mod_time})
            else:
                if not os.path.isdir(directory):
                    print(f"Error: '{directory}' is not a valid directory")
                    return
                for file in os.listdir(directory):
                    file_path = os.path.join(directory, file)
                    if os.path.isfile(file_path) and file.endswith(extension):
                        file_size = os.path.getsize(file_path)
                        mod_time = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
                        self.search_results.append({"path": file_path, "name": file, "size": file_size, "modified": mod_time})
            return self.search_results
        except Exception as e:
            print(f"Error during search: {str(e)}")
            return []
    def search_by_size(self, directory, min_size_kb=0, max_size_kb=None, recursive=True):
        self.search_results = []
        try:
            min_size_bytes = min_size_kb * 1024
            max_size_bytes = max_size_kb * 1024 if max_size_kb else float('inf')
            if recursive:
                for root, dirs, files in os.walk(directory):
                    for file in files:
                        file_path = os.path.join(root, file)
                        file_size = os.path.getsize(file_path)
                        if min_size_bytes <= file_size <= max_size_bytes:
                            mod_time = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
                            self.search_results.append({"path": file_path, "name": file, "size": file_size, "modified": mod_time})
            else:
                if not os.path.isdir(directory):
                    print(f"Error: '{directory}' is not a valid directory")
                    return
                for file in os.listdir(directory):
                    file_path = os.path.join(directory, file)
                    if os.path.isfile(file_path):
                        file_size = os.path.getsize(file_path)
                        if min_size_bytes <= file_size <= max_size_bytes:
                            mod_time = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
                            self.search_results.append({"path": file_path, "name": file, "size": file_size, "modified": mod_time})
            return self.search_results
        except Exception as e:
            print(f"Error during search: {str(e)}")
            return []
    def search_by_date(self, directory, days_old=None, recursive=True):
        self.search_results = []
        try:
            current_time = datetime.now().timestamp()
            if days_old:
                cutoff_time = current_time - (days_old * 86400)
            else:
                cutoff_time = 0
            if recursive:
                for root, dirs, files in os.walk(directory):
                    for file in files:
                        file_path = os.path.join(root, file)
                        mod_time = os.path.getmtime(file_path)
                        if mod_time <= cutoff_time:
                            mod_time_str = datetime.fromtimestamp(mod_time).strftime("%Y-%m-%d %H:%M:%S")
                            file_size = os.path.getsize(file_path)
                            self.search_results.append({"path": file_path, "name": file, "size": file_size, "modified": mod_time_str})
            else:
                if not os.path.isdir(directory):
                    print(f"Error: '{directory}' is not a valid directory")
                    return
                for file in os.listdir(directory):
                    file_path = os.path.join(directory, file)
                    if os.path.isfile(file_path):
                        mod_time = os.path.getmtime(file_path)
                        if mod_time <= cutoff_time:
                            mod_time_str = datetime.fromtimestamp(mod_time).strftime("%Y-%m-%d %H:%M:%S")
                            file_size = os.path.getsize(file_path)
                            self.search_results.append({"path": file_path, "name": file, "size": file_size, "modified": mod_time_str})
            return self.search_results
        except Exception as e:
            print(f"Error during search: {str(e)}")
            return []
    def display_results(self):
        if not self.search_results:
            print("No files found matching the search criteria.")
            return
        print("\n" + "="*100)
        print(f"Found {len(self.search_results)} file(s)")
        print("="*100)
        if "file" in self.search_results[0]:
            for idx, result in enumerate(self.search_results, 1):
                print(f"{idx}. File: {result['file']}")
                print(f"   Line {result['line_number']}: {result['content']}")
        else:
            for idx, result in enumerate(self.search_results, 1):
                size_kb = result['size'] / 1024
                print(f"{idx}. {result['path']}")
                print(f"   Size: {size_kb:.2f} KB | Modified: {result['modified']}")
        print("="*100 + "\n")
    def export_results(self, export_file):
        if not self.search_results:
            print("No results to export.")
            return
        try:
            with open(export_file, 'w', encoding='utf-8') as f:
                f.write(f"Search Results - {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                f.write("="*100 + "\n\n")
                for idx, result in enumerate(self.search_results, 1):
                    if "file" in result:
                        f.write(f"{idx}. {result['file']} (Line {result['line_number']})\n")
                        f.write(f"   {result['content']}\n\n")
                    else:
                        size_kb = result['size'] / 1024
                        f.write(f"{idx}. {result['path']}\n")
                        f.write(f"   Size: {size_kb:.2f} KB | Modified: {result['modified']}\n\n")
            print(f"Results exported to {export_file}")
        except Exception as e:
            print(f"Error exporting results: {str(e)}")
def main():
    tool = FileSearchTool()
    while True:
        print("\n" + "="*60)
        print("FILE SEARCH TOOL")
        print("="*60)
        print("1. Search by filename")
        print("2. Search by file content")
        print("3. Search by file extension")
        print("4. Search by file size")
        print("5. Search by modification date")
        print("6. Display last search results")
        print("7. Export results to file")
