            tool.display_results()
        elif choice == '2':
            directory = input("Enter directory path: ").strip()
            if not os.path.isdir(directory):
                print(f"Error: '{directory}' is not a valid directory")
                continue
            search_text = input("Enter text to search: ").strip()
            case_sensitive_input = input("Case sensitive? (yes/no): ").strip().lower()
            case_sensitive = case_sensitive_input == 'yes'
            recursive_input = input("Search recursively? (yes/no): ").strip().lower()
            recursive = recursive_input != 'no'
            results = tool.search_by_content(directory, search_text, recursive, case_sensitive)
            tool.display_results()
        elif choice == '3':
            directory = input("Enter directory path: ").strip()
            if not os.path.isdir(directory):
                print(f"Error: '{directory}' is not a valid directory")
                continue
            extension = input("Enter file extension (e.g., txt, pdf, jpg): ").strip()
            recursive_input = input("Search recursively? (yes/no): ").strip().lower()
            recursive = recursive_input != 'no'
            results = tool.search_by_extension(directory, extension, recursive)
            tool.display_results()
        elif choice == '4':
            directory = input("Enter directory path: ").strip()
            if not os.path.isdir(directory):
                print(f"Error: '{directory}' is not a valid directory")
                continue
            min_size = float(input("Enter minimum file size in KB (default 0): ") or 0)
            max_size_input = input("Enter maximum file size in KB (leave empty for no limit): ").strip()
            max_size = float(max_size_input) if max_size_input else None
            recursive_input = input("Search recursively? (yes/no): ").strip().lower()
            recursive = recursive_input != 'no'
            results = tool.search_by_size(directory, min_size, max_size, recursive)
            tool.display_results()
        elif choice == '5':
            directory = input("Enter directory path: ").strip()
            if not os.path.isdir(directory):
                print(f"Error: '{directory}' is not a valid directory")
                continue
            days = input("Enter number of days old (files older than this): ").strip()
            days_old = int(days) if days else None
            recursive_input = input("Search recursively? (yes/no): ").strip().lower()
            recursive = recursive_input != 'no'
            results = tool.search_by_date(directory, days_old, recursive)
            tool.display_results()
        elif choice == '6':
            tool.display_results()
        elif choice == '7':
            export_file = input("Enter export file path: ").strip()
            tool.export_results(export_file)
        elif choice == '8':
            print("Exiting File Search Tool. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-8.")
if __name__ == '__main__':
    main()

