import os
import re
from datetime import datetime
from collections import Counter, defaultdict
class LogAnalyzer:
    def __init__(self, log_file_path):
        self.log_file_path = log_file_path
        self.log_entries = []
        self.parse_logs()
    def parse_logs(self):
        try:
            with open(self.log_file_path, 'r', encoding='utf-8') as file:
                lines = file.readlines()
            for line in lines:
                if line.strip() and not line.startswith('='):
                    self.log_entries.append(line.strip())
        except IOError as e:
            print(f"Error reading log file: {str(e)}")
    def get_total_entries(self):
        return len(self.log_entries)
    def get_log_levels(self):
        levels = Counter()
        for entry in self.log_entries:
            match = re.search(r'\[(INFO|WARNING|ERROR|DEBUG|SUCCESS)\]', entry)
            if match:
                levels[match.group(1)] += 1
        return dict(levels)
    def get_errors(self):
        errors = [entry for entry in self.log_entries if '[ERROR]' in entry]
        return errors
    def get_warnings(self):
        warnings = [entry for entry in self.log_entries if '[WARNING]' in entry]
        return warnings
    def get_info_logs(self):
        infos = [entry for entry in self.log_entries if '[INFO]' in entry]
        return infos
    def get_debug_logs(self):
        debug = [entry for entry in self.log_entries if '[DEBUG]' in entry]
        return debug
    def search_logs(self, search_term):
        results = [entry for entry in self.log_entries if search_term.lower() in entry.lower()]
        return results
    def get_logs_by_time_range(self, start_time, end_time):
        try:
            start_dt = datetime.strptime(start_time, "%Y-%m-%d %H:%M:%S")
            end_dt = datetime.strptime(end_time, "%Y-%m-%d %H:%M:%S")
            results = []
            for entry in self.log_entries:
                match = re.search(r'\[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\]', entry)
                if match:
                    entry_time = datetime.strptime(match.group(1), "%Y-%m-%d %H:%M:%S")
                    if start_dt <= entry_time <= end_dt:
                        results.append(entry)
            return results
        except ValueError:
            print("Invalid date format. Use: YYYY-MM-DD HH:MM:SS")
            return []
    def get_error_count(self):
        return len(self.get_errors())
    def get_warning_count(self):
        return len(self.get_warnings())
    def get_critical_logs(self):
        critical = [entry for entry in self.log_entries if '[ERROR]' in entry or 'CRITICAL' in entry.upper()]
        return critical
    def extract_usernames(self):
        usernames = []
        for entry in self.log_entries:
            match = re.search(r'USER:\s*(\w+)', entry)
            if match:
                usernames.append(match.group(1))
        return list(set(usernames))
    def get_user_activities(self, username):
        activities = [entry for entry in self.log_entries if f'USER: {username}' in entry]
        return activities
    def extract_ip_addresses(self):
        ip_pattern = r'\b(?:\d{1,3}\.){3}\d{1,3}\b'
        ips = []
        for entry in self.log_entries:
            matches = re.findall(ip_pattern, entry)
            ips.extend(matches)
        return list(set(ips))
    def get_failed_login_attempts(self):
        failed_logins = [entry for entry in self.log_entries if 'login' in entry.lower() and 'failed' in entry.lower()]
        return failed_logins
    def get_exception_logs(self):
        exceptions = [entry for entry in self.log_entries if 'Exception' in entry or 'Error' in entry]
        return exceptions
    def count_occurrences(self, pattern):
        count = 0
        for entry in self.log_entries:
            if re.search(pattern, entry, re.IGNORECASE):
                count += 1
        return count
    def get_most_common_words(self, limit=10):
        all_words = []
        for entry in self.log_entries:
            words = re.findall(r'\b\w+\b', entry)
            all_words.extend([word.lower() for word in words if len(word) > 3])
        word_counts = Counter(all_words)
        return word_counts.most_common(limit)
    def get_log_summary(self):
        levels = self.get_log_levels()
        total = self.get_total_entries()
        error_count = self.get_error_count()
        warning_count = self.get_warning_count()
        return {
            "total_entries": total,
            "error_count": error_count,
            "warning_count": warning_count,
            "log_levels": levels,
            "error_percentage": (error_count / total * 100) if total > 0 else 0,
            "warning_percentage": (warning_count / total * 100) if total > 0 else 0
        }
    def export_analysis(self, output_file):
        try:
            with open(output_file, 'w', encoding='utf-8') as file:
                file.write("LOG ANALYSIS REPORT\n")
                file.write("="*80 + "\n")
                file.write(f"Generated: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                file.write(f"Log File: {self.log_file_path}\n\n")
                summary = self.get_log_summary()
                file.write("SUMMARY\n")
                file.write("-"*80 + "\n")
                file.write(f"Total Entries: {summary['total_entries']}\n")
                file.write(f"Errors: {summary['error_count']} ({summary['error_percentage']:.2f}%)\n")
                file.write(f"Warnings: {summary['warning_count']} ({summary['warning_percentage']:.2f}%)\n\n")
                file.write("LOG LEVELS\n")
                file.write("-"*80 + "\n")
                for level, count in summary['log_levels'].items():
                    file.write(f"{level}: {count}\n")
                file.write("\n")
                errors = self.get_errors()
                if errors:
                    file.write("ERRORS\n")
                    file.write("-"*80 + "\n")
                    for idx, error in enumerate(errors[:20], 1):
                        file.write(f"{idx}. {error}\n")
                    if len(errors) > 20:
                        file.write(f"... and {len(errors) - 20} more errors\n")
                    file.write("\n")
                warnings = self.get_warnings()
                if warnings:
                    file.write("WARNINGS\n")
                    file.write("-"*80 + "\n")
                    for idx, warning in enumerate(warnings[:20], 1):
                        file.write(f"{idx}. {warning}\n")
                    if len(warnings) > 20:
                        file.write(f"... and {len(warnings) - 20} more warnings\n")
                    file.write("\n")
                common_words = self.get_most_common_words(10)
                file.write("MOST COMMON WORDS\n")
                file.write("-"*80 + "\n")
                for word, count in common_words:
                    file.write(f"{word}: {count}\n")
            print(f"Analysis exported to {output_file}")
        except IOError as e:
            print(f"Error exporting analysis: {str(e)}")
    def display_summary(self):
        summary = self.get_log_summary()
        print("\n" + "="*60)
        print("LOG ANALYSIS SUMMARY")
        print("="*60)
        print(f"Total Entries: {summary['total_entries']}")
        print(f"Errors: {summary['error_count']} ({summary['error_percentage']:.2f}%)")
        print(f"Warnings: {summary['warning_count']} ({summary['warning_percentage']:.2f}%)")
        print("\nLog Levels:")
        for level, count in summary['log_levels'].items():
            print(f"  {level}: {count}")
        print("="*60 + "\n")
def main():
    log_file = input("Enter log file path: ").strip()
    if not os.path.exists(log_file):
