import csv
import json
from datetime import datetime
from collections import defaultdict, Counter
class CSVParser:
    def __init__(self, csv_file_path):
        self.csv_file_path = csv_file_path
        self.data = []
        self.headers = []
        self.parse_csv()
    def parse_csv(self):
        try:
            with open(self.csv_file_path, 'r', encoding='utf-8') as file:
                reader = csv.DictReader(file)
                self.headers = reader.fieldnames if reader.fieldnames else []
                for row in reader:
                    self.data.append(row)
        except IOError as e:
            print(f"Error reading CSV file: {str(e)}")
        except Exception as e:
            print(f"Error parsing CSV file: {str(e)}")
    def get_total_rows(self):
        return len(self.data)
    def get_headers(self):
        return self.headers
    def get_row(self, index):
        if 0 <= index < len(self.data):
            return self.data[index]
        return None
    def get_column(self, column_name):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return []
        return [row.get(column_name, '') for row in self.data]
    def filter_rows(self, column_name, value):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return []
        return [row for row in self.data if row.get(column_name) == value]
    def filter_rows_contains(self, column_name, substring):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return []
        return [row for row in self.data if substring.lower() in row.get(column_name, '').lower()]
    def filter_rows_numeric(self, column_name, min_value=None, max_value=None):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return []
        results = []
        for row in self.data:
            try:
                value = float(row.get(column_name, 0))
                if (min_value is None or value >= min_value) and (max_value is None or value <= max_value):
                    results.append(row)
            except ValueError:
                pass
        return results
    def sort_by_column(self, column_name, reverse=False):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return []
        try:
            return sorted(self.data, key=lambda x: float(x.get(column_name, 0)), reverse=reverse)
        except ValueError:
            return sorted(self.data, key=lambda x: x.get(column_name, ''), reverse=reverse)
    def get_unique_values(self, column_name):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return []
        unique_values = list(set(row.get(column_name, '') for row in self.data))
        return sorted(unique_values)
    def count_value_occurrences(self, column_name):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return {}
        value_counts = Counter(row.get(column_name, '') for row in self.data)
        return dict(value_counts)
    def get_statistics(self, column_name):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return {}
        values = []
        for row in self.data:
            try:
                values.append(float(row.get(column_name, 0)))
            except ValueError:
                pass
        if not values:
            return {}
        return {
            "count": len(values),
            "sum": sum(values),
            "average": sum(values) / len(values),
            "min": min(values),
            "max": max(values)
        }
    def group_by_column(self, column_name):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return {}
        grouped = defaultdict(list)
        for row in self.data:
            key = row.get(column_name, 'Unknown')
            grouped[key].append(row)
        return dict(grouped)
    def get_duplicate_rows(self, column_name):
        if column_name not in self.headers:
            print(f"Column '{column_name}' not found")
            return []
        value_counts = Counter(row.get(column_name, '') for row in self.data)
        duplicates = [row for row in self.data if value_counts[row.get(column_name, '')] > 1]
        return duplicates
    def search_rows(self, search_term):
        results = []
        for row in self.data:
            for value in row.values():
                if search_term.lower() in str(value).lower():
                    results.append(row)
                    break
        return results
    def export_to_json(self, output_file):
        try:
            with open(output_file, 'w', encoding='utf-8') as file:
                json.dump(self.data, file, indent=2)
            print(f"Data exported to {output_file}")
        except IOError as e:
            print(f"Error exporting to JSON: {str(e)}")
    def export_filtered_csv(self, output_file, filtered_data):
        try:
            if not filtered_data:
                print("No data to export")
                return
            with open(output_file, 'w', newline='', encoding='utf-8') as file:
                writer = csv.DictWriter(file, fieldnames=self.headers)
                writer.writeheader()
                writer.writerows(filtered_data)
            print(f"Filtered data exported to {output_file}")
        except IOError as e:
            print(f"Error exporting to CSV: {str(e)}")
    def get_summary(self):
        summary = {
            "total_rows": len(self.data),
            "total_columns": len(self.headers),
            "column_names": self.headers,
            "file_path": self.csv_file_path
        }
        return summary
    def display_data(self, limit=10):
        if not self.data:
            print("No data to display")
            return
        print("\n" + "="*100)
        print(f"Displaying {min(limit, len(self.data))} of {len(self.data)} rows")
        print("="*100)
        for idx, row in enumerate(self.data[:limit], 1):
            print(f"\nRow {idx}:")
            for header, value in row.items():
                print(f"  {header}: {value}")
        print("="*100 + "\n")
    def display_table(self, limit=10):
        if not self.data:
            print("No data to display")
            return
        print("\n" + "-"*100)
        header_str = " | ".join([f"{h:20}" for h in self.headers])
        print(header_str)
        print("-"*100)
        for row in self.data[:limit]:
            row_str = " | ".join([f"{str(row.get(h, ''))[:19]:20}" for h in self.headers])
            print(row_str)
        if len(self.data) > limit:
            print(f"... and {len(self.data) - limit} more rows")
        print("-"*100 + "\n")
def main():
    csv_file = input("Enter CSV file path: ").strip()
    if not csv_file:
        print("Error: File path cannot be empty")
        return
    try:
        parser = CSVParser(csv_file)
    except Exception as e:
        print(f"Error: {str(e)}")
        return
    if not parser.data:
        print("Error: CSV file is empty or could not be parsed")
        return
    while True:
        print("\n" + "="*60)
        print("CSV PARSER")
        print("="*60)
        print("1. Display summary")
        print("2. Display all data (table format)")
        print("3. Display all data (detailed format)")
        print("4. Get column data")
        print("5. Filter by exact value")
        print("6. Filter by text contains")
        print("7. Filter by numeric range")
        print("8. Sort by column")
        print("9. Get unique values")
        print("10. Count value occurrences")
        print("11. Get statistics")
        print("12. Group by column")
        print("13. Find duplicate rows")
        print("14. Search rows")
        print("15. Export to JSON")
        print("16. Export filtered data to CSV")
        print("17. Exit")
        choice = input("\nSelect an option (1-17): ").strip()
        if choice == '1':
            summary = parser.get_summary()
            print("\n" + "="*60)
            print("CSV SUMMARY")
            print("="*60)
            for key, value in summary.items():
                print(f"{key}: {value}")
            print("="*60)
        elif choice == '2':
            limit = input("Enter number of rows to display (default 10): ").strip()
            limit = int(limit) if limit else 10
            parser.display_table(limit)
        elif choice == '3':
            limit = input("Enter number of rows to display (default 10): ").strip()
            limit = int(limit) if limit else 10
            parser.display_data(limit)
        elif choice == '4':
            column = input("Enter column name: ").strip()
            data = parser.get_column(column)
            print(f"\nColumn '{column}' data:")
            print("="*60)
            for idx, value in enumerate(data[:20], 1):
                print(f"{idx}. {value}")
            if len(data) > 20:
                print(f"... and {len(data) - 20} more values")
            print("="*60)
        elif choice == '5':
            column = input("Enter column name: ").strip()
            value = input("Enter value to filter: ").strip()
            results = parser.filter_rows(column, value)
            print(f"\nFound {len(results)} row(s):")
            print("="*60)
            for idx, row in enumerate(results[:10], 1):
                print(f"{idx}. {row}")
            if len(results) > 10:
                print(f"... and {len(results) - 10} more rows")
            print("="*60)
        elif choice == '6':
            column = input("Enter column name: ").strip()
            substring = input("Enter text to search: ").strip()
            results = parser.filter_rows_contains(column, substring)
            print(f"\nFound {len(results)} row(s) containing '{substring}':")
            print("="*60)
            for idx, row in enumerate(results[:10], 1):
                print(f"{idx}. {row}")
            if len(results) > 10:
                print(f"... and {len(results) - 10} more rows")
            print("="*60)
        elif choice == '7':
            column = input("Enter column name: ").strip()
            min_val = input("Enter minimum value (or leave empty): ").strip()
            max_val = input("Enter maximum value (or leave empty): ").strip()
            min_val = float(min_val) if min_val else None
            max_val = float(max_val) if max_val else None
            results = parser.filter_rows_numeric(column, min_val, max_val)
            print(f"\nFound {len(results)} row(s) in range:")
            print("="*60)
            for idx, row in enumerate(results[:10], 1):
                print(f"{idx}. {row}")
            if len(results) > 10:
                print(f"... and {len(results) - 10} more rows")
            print("="*60)
        elif choice == '8':
            column = input("Enter column name: ").strip()
            reverse_input = input("Sort descending? (yes/no): ").strip().lower()
            reverse = reverse_input == 'yes'
            results = parser.sort_by_column(column, reverse)
            print(f"\nSorted by '{column}' (descending={reverse}):")
            print("="*60)
            for idx, row in enumerate(results[:10], 1):
                print(f"{idx}. {row}")
            if len(results) > 10:
                print(f"... and {len(results) - 10} more rows")
            print("="*60)
        elif choice == '9':
            column = input("Enter column name: ").strip()
            unique_vals = parser.get_unique_values(column)
            print(f"\nUnique values in '{column}':")
            print("="*60)
            for idx, val in enumerate(unique_vals[:20], 1):
                print(f"{idx}. {val}")
            if len(unique_vals) > 20:
                print(f"... and {len(unique_vals) - 20} more values")
            print("="*60)
        elif choice == '10':
            column = input("Enter column name: ").strip()
            counts = parser.count_value_occurrences(column)
            print(f"\nValue counts for '{column}':")
            print("="*60)
            for idx, (value, count) in enumerate(sorted(counts.items(), key=lambda x: x[1], reverse=True)[:10], 1):
                print(f"{idx}. {value}: {count}")
            if len(counts) > 10:
                print(f"... and {len(counts) - 10} more values")
            print("="*60)
        elif choice == '11':
            column = input("Enter column name: ").strip()
            stats = parser.get_statistics(column)
            if stats:
                print(f"\nStatistics for '{column}':")
                print("="*60)
                for key, value in stats.items():
                    print(f"{key}: {value:.2f}" if isinstance(value, float) else f"{key}: {value}")
                print("="*60)
            else:
                print("Could not calculate statistics for this column")
        elif choice == '12':
            column = input("Enter column name: ").strip()
            grouped = parser.group_by_column(column)
            print(f"\nGrouped by '{column}':")
            print("="*60)
            for idx, (key, rows) in enumerate(list(grouped.items())[:10], 1):
                print(f"{idx}. {key}: {len(rows)} row(s)")
            if len(grouped) > 10:
                print(f"... and {len(grouped) - 10} more groups")
            print("="*60)
        elif choice == '13':
            column = input("Enter column name: ").strip()
            duplicates = parser.get_duplicate_rows(column)
            print(f"\nDuplicate rows by '{column}':")
            print("="*60)
            for idx, row in enumerate(duplicates[:10], 1):
                print(f"{idx}. {row}")
            if len(duplicates) > 10:
                print(f"... and {len(duplicates) - 10} more duplicates")
            print("="*60)
        elif choice == '14':
            search_term = input("Enter search term: ").strip()
            results = parser.search_rows(search_term)
            print(f"\nFound {len(results)} row(s) containing '{search_term}':")
            print("="*60)
            for idx, row in enumerate(results[:10], 1):
                print(f"{idx}. {row}")
            if len(results) > 10:
                print(f"... and {len(results) - 10} more rows")
            print("="*60)
        elif choice == '15':
            output_file = input("Enter output JSON file path: ").strip()
            parser.export_to_json(output_file)
        elif choice == '16':
            column = input("Enter column name to filter by: ").strip()
            value = input("Enter value: ").strip()
            filtered = parser.filter_rows(column, value)
            if filtered:
                output_file = input("Enter output CSV file path: ").strip()
                parser.export_filtered_csv(output_file, filtered)
            else:
                print("No data to export")
        elif choice == '17':
            print("Exiting CSV Parser. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-17.")
if __name__ == '__main__':
    main()

import json
def save_to_json(data, filename="output.json"):
    try:
        with open(filename, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=4)
        print(f"Data successfully saved to {filename}")
    except Exception as e:
        print(f"Error saving JSON: {e}")
