import json
import os
from datetime import datetime
class JSONWriter:
    def __init__(self):
        self.data = {}
    def write_simple_json(self, file_path, data):
        try:
            with open(file_path, 'w', encoding='utf-8') as file:
                json.dump(data, file, indent=2)
            print(f"JSON data written to {file_path}")
        except IOError as e:
            print(f"Error writing to file: {str(e)}")
    def write_formatted_json(self, file_path, data):
        try:
            with open(file_path, 'w', encoding='utf-8') as file:
                json.dump(data, file, indent=4, sort_keys=True)
            print(f"Formatted JSON written to {file_path}")
        except IOError as e:
            print(f"Error writing to file: {str(e)}")
    def write_compact_json(self, file_path, data):
        try:
            with open(file_path, 'w', encoding='utf-8') as file:
                json.dump(data, file, separators=(',', ':'))
            print(f"Compact JSON written to {file_path}")
        except IOError as e:
            print(f"Error writing to file: {str(e)}")
    def append_to_json(self, file_path, new_data):
        try:
            if os.path.exists(file_path):
                with open(file_path, 'r', encoding='utf-8') as file:
                    existing_data = json.load(file)
            else:
                existing_data = {}
            if isinstance(existing_data, dict) and isinstance(new_data, dict):
                existing_data.update(new_data)
            with open(file_path, 'w', encoding='utf-8') as file:
                json.dump(existing_data, file, indent=2)
            print(f"Data appended to {file_path}")
        except IOError as e:
            print(f"Error appending to file: {str(e)}")
        except json.JSONDecodeError:
            print("Error: Invalid JSON in existing file")
    def write_json_array(self, file_path, data_list):
        try:
            with open(file_path, 'w', encoding='utf-8') as file:
                json.dump(data_list, file, indent=2)
            print(f"JSON array written to {file_path}")
        except IOError as e:
            print(f"Error writing to file: {str(e)}")
    def write_user_data_to_json(self, file_path):
        print("Enter user data (type 'done' to finish):")
        user_data = {}
        while True:
            key = input("Enter key (or 'done' to finish): ").strip()
            if key.lower() == 'done':
                break
            value = input(f"Enter value for '{key}': ").strip()
            user_data[key] = value
        if user_data:
            self.write_formatted_json(file_path, user_data)
        else:
            print("No data to write")
    def write_multiple_users_to_json(self, file_path):
        num_users = int(input("Enter number of users: "))
        users = []
        for i in range(num_users):
            print(f"\nUser {i+1}:")
            user = {}
            user['id'] = i + 1
            user['name'] = input("Name: ").strip()
            user['email'] = input("Email: ").strip()
            user['phone'] = input("Phone: ").strip()
            user['age'] = int(input("Age: "))
            user['city'] = input("City: ").strip()
            user['joined_date'] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            users.append(user)
        self.write_json_array(file_path, users)
    def write_product_catalog(self, file_path):
        num_products = int(input("Enter number of products: "))
        products = []
        for i in range(num_products):
            print(f"\nProduct {i+1}:")
            product = {}
            product['id'] = i + 1
            product['name'] = input("Product name: ").strip()
            product['category'] = input("Category: ").strip()
            product['price'] = float(input("Price: "))
            product['stock'] = int(input("Stock quantity: "))
            product['description'] = input("Description: ").strip()
            product['rating'] = float(input("Rating (0-5): "))
            products.append(product)
        catalog = {
            "catalog": products,
            "total_products": len(products),
            "generated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        }
        self.write_formatted_json(file_path, catalog)
    def write_config_file(self, file_path):
        config = {
            "app_name": input("App name: ").strip(),
            "app_version": input("App version: ").strip(),
            "debug": input("Debug mode (true/false): ").strip().lower() == 'true',
            "database": {
                "host": input("Database host: ").strip(),
                "port": int(input("Database port: ")),
                "name": input("Database name: ").strip(),
                "username": input("Database username: ").strip()
            },
            "server": {
                "host": input("Server host: ").strip(),
                "port": int(input("Server port: "))
            }
        }
        self.write_formatted_json(file_path, config)
    def write_survey_response(self, file_path):
        survey = {
            "respondent_name": input("Respondent name: ").strip(),
            "respondent_email": input("Respondent email: ").strip(),
            "survey_date": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "questions": []
        }
        num_questions = int(input("Enter number of questions: "))
        for i in range(num_questions):
            question = input(f"Question {i+1}: ").strip()
            answer = input(f"Answer to question {i+1}: ").strip()
            rating = int(input(f"Rate this answer (1-5): "))
            survey["questions"].append({
                "question_number": i + 1,
                "question": question,
                "answer": answer,
                "rating": rating
            })
        self.write_formatted_json(file_path, survey)
    def write_nested_json(self, file_path):
        data = {
            "company": {
                "name": input("Company name: ").strip(),
                "founded": int(input("Year founded: ")),
                "employees": []
            }
        }
        num_employees = int(input("Number of employees: "))
        for i in range(num_employees):
            print(f"\nEmployee {i+1}:")
            employee = {
                "id": i + 1,
                "name": input("Name: ").strip(),
                "position": input("Position: ").strip(),
                "department": input("Department: ").strip(),
                "salary": float(input("Salary: "))
            }
            data["company"]["employees"].append(employee)
        self.write_formatted_json(file_path, data)
    def write_event_log(self, file_path):
        events = []
        print("Enter event logs (type 'done' to finish):")
        counter = 1
        while True:
            event_type = input("Event type (or 'done' to finish): ").strip()
            if event_type.lower() == 'done':
                break
            event = {
                "event_id": counter,
                "type": event_type,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "description": input("Event description: ").strip(),
                "severity": input("Severity (low/medium/high): ").strip()
            }
            events.append(event)
            counter += 1
        if events:
            log_data = {
                "total_events": len(events),
                "events": events,
                "generated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.write_json_array(file_path, log_data)
        else:
            print("No events to write")
    def write_report(self, file_path):
        report = {
            "report_title": input("Report title: ").strip(),
            "generated_date": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "report_type": input("Report type: ").strip(),
            "sections": []
        }
        num_sections = int(input("Number of sections: "))
        for i in range(num_sections):
            section = {
                "section_number": i + 1,
                "title": input(f"Section {i+1} title: ").strip(),
                "content": input(f"Section {i+1} content: ").strip()
            }
            report["sections"].append(section)
        self.write_formatted_json(file_path, report)
    def merge_json_files(self, file_list, output_file):
        try:
            merged_data = []
            for file_path in file_list:
                if os.path.exists(file_path):
                    with open(file_path, 'r', encoding='utf-8') as file:
                        data = json.load(file)
                        merged_data.append(data)
            with open(output_file, 'w', encoding='utf-8') as file:
                json.dump(merged_data, file, indent=2)
            print(f"JSON files merged into {output_file}")
        except IOError as e:
            print(f"Error merging files: {str(e)}")
        except json.JSONDecodeError:
            print("Error: Invalid JSON in one or more files")
    def convert_csv_to_json(self, csv_file, json_file):
        try:
            import csv
            data = []
            with open(csv_file, 'r', encoding='utf-8') as csvfile:
                reader = csv.DictReader(csvfile)
                for row in reader:
                    data.append(row)
            self.write_json_array(json_file, data)
        except IOError as e:
            print(f"Error converting CSV to JSON: {str(e)}")
def main():
