from flask import Flask,request,jsonify
import os
app=Flask(__name__)
UPLOAD_FOLDER="uploads"
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)
@app.route("/upload",methods=["POST"])
def upload():
    file=request.files.get("file")
    if not file:
        return jsonify({"message":"No file provided"})
    path=os.path.join(UPLOAD_FOLDER,file.filename)
    file.save(path)
    return jsonify({"message":"File uploaded","filename":file.filename})
if __name__=="__main__":
    app.run(debug=True)

import os
import shutil
from pathlib import Path
from datetime import datetime
import mimetypes
import hashlib
class FileUploadHandler:
    def __init__(self, upload_directory):
        self.upload_directory = upload_directory
        self.allowed_extensions = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif', 'doc', 'docx', 'zip', 'xlsx', 'csv', 'json', 'mp3', 'mp4', 'avi', 'mov'}
        self.max_file_size = 50 * 1024 * 1024
        self.upload_history = []
        self.create_upload_directory()
    def create_upload_directory(self):
        if not os.path.exists(self.upload_directory):
            os.makedirs(self.upload_directory)
            print(f"Created upload directory: {self.upload_directory}")
    def is_allowed_file(self, filename):
        return '.' in filename and filename.rsplit('.', 1)[1].lower() in self.allowed_extensions
    def get_file_size(self, file_path):
        return os.path.getsize(file_path)
    def get_file_extension(self, filename):
        return filename.rsplit('.', 1)[1].lower() if '.' in filename else 'unknown'
    def get_file_mime_type(self, filename):
        mime_type, _ = mimetypes.guess_type(filename)
        return mime_type or 'application/octet-stream'
    def calculate_file_hash(self, file_path):
        sha256_hash = hashlib.sha256()
        with open(file_path, 'rb') as f:
            for byte_block in iter(lambda: f.read(4096), b""):
                sha256_hash.update(byte_block)
        return sha256_hash.hexdigest()
    def upload_file(self, source_file_path):
        if not os.path.exists(source_file_path):
            print(f"Error: Source file '{source_file_path}' does not exist")
            return None
        if not os.path.isfile(source_file_path):
            print(f"Error: '{source_file_path}' is not a file")
            return None
        filename = os.path.basename(source_file_path)
        if not self.is_allowed_file(filename):
            print(f"Error: File type '{self.get_file_extension(filename)}' is not allowed")
            return None
        file_size = self.get_file_size(source_file_path)
        if file_size > self.max_file_size:
            print(f"Error: File size ({file_size / 1024 / 1024:.2f}MB) exceeds maximum ({self.max_file_size / 1024 / 1024:.2f}MB)")
            return None
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S_")
        new_filename = timestamp + filename
        destination_file_path = os.path.join(self.upload_directory, new_filename)
        try:
            shutil.copy2(source_file_path, destination_file_path)
            file_hash = self.calculate_file_hash(destination_file_path)
            upload_info = {
                "original_name": filename,
                "new_name": new_filename,
                "file_path": destination_file_path,
                "file_size": file_size,
                "file_extension": self.get_file_extension(filename),
                "mime_type": self.get_file_mime_type(filename),
                "file_hash": file_hash,
                "upload_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.upload_history.append(upload_info)
            print(f"File uploaded successfully: {new_filename}")
            return upload_info
        except Exception as e:
            print(f"Error uploading file: {str(e)}")
            return None
    def upload_multiple_files(self, source_directory):
        if not os.path.isdir(source_directory):
            print(f"Error: '{source_directory}' is not a valid directory")
            return []
        uploaded_files = []
        for filename in os.listdir(source_directory):
            file_path = os.path.join(source_directory, filename)
            if os.path.isfile(file_path):
                upload_info = self.upload_file(file_path)
                if upload_info:
                    uploaded_files.append(upload_info)
        print(f"Uploaded {len(uploaded_files)} file(s)")
        return uploaded_files
    def delete_uploaded_file(self, file_name):
        file_path = os.path.join(self.upload_directory, file_name)
        if not os.path.exists(file_path):
            print(f"Error: File '{file_name}' not found in upload directory")
            return False
        try:
            os.remove(file_path)
            print(f"File deleted: {file_name}")
            return True
        except Exception as e:
            print(f"Error deleting file: {str(e)}")
            return False
    def get_uploaded_files(self):
        if not os.path.exists(self.upload_directory):
            return []
        files = []
        for filename in os.listdir(self.upload_directory):
            file_path = os.path.join(self.upload_directory, filename)
            if os.path.isfile(file_path):
                file_size = self.get_file_size(file_path)
                mod_time = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
                files.append({
                    "filename": filename,
                    "file_path": file_path,
                    "file_size": file_size,
                    "modified_time": mod_time
                })
        return files
    def get_file_info(self, file_name):
        file_path = os.path.join(self.upload_directory, file_name)
        if not os.path.exists(file_path):
            print(f"Error: File '{file_name}' not found")
            return None
        file_size = self.get_file_size(file_path)
        file_hash = self.calculate_file_hash(file_path)
        mod_time = datetime.fromtimestamp(os.path.getmtime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
        created_time = datetime.fromtimestamp(os.path.getctime(file_path)).strftime("%Y-%m-%d %H:%M:%S")
        return {
            "filename": file_name,
            "file_path": file_path,
            "file_size": file_size,
            "file_size_mb": file_size / 1024 / 1024,
            "file_extension": self.get_file_extension(file_name),
            "mime_type": self.get_file_mime_type(file_name),
            "file_hash": file_hash,
            "modified_time": mod_time,
            "created_time": created_time
        }
    def get_directory_statistics(self):
        if not os.path.exists(self.upload_directory):
            return None
        total_files = 0
        total_size = 0
        file_types = {}
        for filename in os.listdir(self.upload_directory):
            file_path = os.path.join(self.upload_directory, filename)
            if os.path.isfile(file_path):
                total_files += 1
                total_size += self.get_file_size(file_path)
                ext = self.get_file_extension(filename)
                file_types[ext] = file_types.get(ext, 0) + 1
        return {
            "upload_directory": self.upload_directory,
            "total_files": total_files,
            "total_size_bytes": total_size,
            "total_size_mb": total_size / 1024 / 1024,
            "file_types": file_types
        }
    def rename_uploaded_file(self, old_name, new_name):
        old_path = os.path.join(self.upload_directory, old_name)
        new_path = os.path.join(self.upload_directory, new_name)
        if not os.path.exists(old_path):
            print(f"Error: File '{old_name}' not found")
            return False
        if os.path.exists(new_path):
            print(f"Error: File '{new_name}' already exists")
            return False
        try:
            os.rename(old_path, new_path)
            print(f"File renamed: {old_name} -> {new_name}")
            return True
        except Exception as e:
            print(f"Error renaming file: {str(e)}")
            return False
    def move_file(self, file_name, destination_directory):
        if not os.path.exists(destination_directory):
            os.makedirs(destination_directory)
        source_path = os.path.join(self.upload_directory, file_name)
        destination_path = os.path.join(destination_directory, file_name)
        if not os.path.exists(source_path):
            print(f"Error: File '{file_name}' not found")
            return False
        try:
            shutil.move(source_path, destination_path)
            print(f"File moved: {file_name} to {destination_directory}")
            return True
        except Exception as e:
            print(f"Error moving file: {str(e)}")
            return False
    def copy_file(self, file_name, destination_directory):
        if not os.path.exists(destination_directory):
            os.makedirs(destination_directory)
        source_path = os.path.join(self.upload_directory, file_name)
        destination_path = os.path.join(destination_directory, file_name)
        if not os.path.exists(source_path):
            print(f"Error: File '{file_name}' not found")
            return False
        try:
            shutil.copy2(source_path, destination_path)
            print(f"File copied: {file_name} to {destination_directory}")
            return True
        except Exception as e:
            print(f"Error copying file: {str(e)}")
            return False
    def empty_upload_directory(self):
        try:
            for filename in os.listdir(self.upload_directory):
                file_path = os.path.join(self.upload_directory, filename)
                if os.path.isfile(file_path):
                    os.remove(file_path)
            print("Upload directory emptied")
            return True
        except Exception as e:
            print(f"Error emptying directory: {str(e)}")
            return False
    def search_files_by_extension(self, extension):
        files = []
        for filename in os.listdir(self.upload_directory):
            if filename.endswith(f".{extension}"):
                file_path = os.path.join(self.upload_directory, filename)
                file_size = self.get_file_size(file_path)
                files.append({"filename": filename, "file_size": file_size})
        return files
    def get_upload_history(self):
        return self.upload_history
    def display_uploaded_files(self):
        files = self.get_uploaded_files()
        if not files:
            print("No files in upload directory")
            return
        print("\n" + "="*100)
        print("UPLOADED FILES")
        print("="*100)
        for idx, file_info in enumerate(files, 1):
            size_mb = file_info['file_size'] / 1024 / 1024
            print(f"{idx}. {file_info['filename']}")
            print(f"   Size: {size_mb:.2f}MB | Modified: {file_info['modified_time']}")
        print("="*100 + "\n")
def main():
