                print("\n" + "="*60)
                print("DIRECTORY STATISTICS")
                print("="*60)
                for key, value in stats.items():
                    print(f"{key}: {value}")
                print("="*60)
        elif choice == '6':
            old_name = input("Enter current file name: ").strip()
            new_name = input("Enter new file name: ").strip()
            handler.rename_uploaded_file(old_name, new_name)
        elif choice == '7':
            file_name = input("Enter file name to delete: ").strip()
            confirm = input("Are you sure? (yes/no): ").strip().lower()
            if confirm == 'yes':
                handler.delete_uploaded_file(file_name)
        elif choice == '8':
            file_name = input("Enter file name to copy: ").strip()
            dest_dir = input("Enter destination directory: ").strip()
            handler.copy_file(file_name, dest_dir)
        elif choice == '9':
            file_name = input("Enter file name to move: ").strip()
            dest_dir = input("Enter destination directory: ").strip()
            handler.move_file(file_name, dest_dir)
        elif choice == '10':
            extension = input("Enter file extension (without dot): ").strip()
            files = handler.search_files_by_extension(extension)
            if files:
                print(f"\nFound {len(files)} file(s) with .{extension} extension:")
                print("="*60)
                for idx, file_info in enumerate(files, 1):
                    size_mb = file_info['file_size'] / 1024 / 1024
                    print(f"{idx}. {file_info['filename']} ({size_mb:.2f}MB)")
                print("="*60)
            else:
                print(f"No files found with .{extension} extension")
        elif choice == '11':
            history = handler.get_upload_history()
            if history:
                print("\nUPLOAD HISTORY")
                print("="*80)
                for idx, item in enumerate(history, 1):
                    print(f"{idx}. {item['original_name']} -> {item['new_name']}")
                    print(f"   Size: {item['file_size'] / 1024:.2f}KB | Time: {item['upload_time']}")
                print("="*80)
            else:
                print("No upload history")
        elif choice == '12':
            confirm = input("Empty upload directory? (yes/no): ").strip().lower()
            if confirm == 'yes':
                handler.empty_upload_directory()
        elif choice == '13':
            print("Exiting File Upload Handler. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-13.")
