import configparser
import json
import os
from datetime import datetime
class ConfigReader:
    def __init__(self, config_file_path):
        self.config_file_path = config_file_path
        self.config = configparser.ConfigParser()
        self.load_config()
    def load_config(self):
        if not os.path.exists(self.config_file_path):
            print(f"Error: Config file '{self.config_file_path}' does not exist")
            return False
        try:
            self.config.read(self.config_file_path)
            print(f"Config file loaded: {self.config_file_path}")
            return True
        except Exception as e:
            print(f"Error loading config file: {str(e)}")
            return False
    def get_value(self, section, key, default=None):
        try:
            return self.config.get(section, key)
        except (configparser.NoSectionError, configparser.NoOptionError):
            return default
    def get_int(self, section, key, default=0):
        try:
            return self.config.getint(section, key)
        except (configparser.NoSectionError, configparser.NoOptionError, ValueError):
            return default
    def get_float(self, section, key, default=0.0):
        try:
            return self.config.getfloat(section, key)
        except (configparser.NoSectionError, configparser.NoOptionError, ValueError):
            return default
    def get_boolean(self, section, key, default=False):
        try:
            return self.config.getboolean(section, key)
        except (configparser.NoSectionError, configparser.NoOptionError, ValueError):
            return default
    def get_section(self, section):
        try:
            return dict(self.config.items(section))
        except configparser.NoSectionError:
            return {}
    def get_all_sections(self):
        return self.config.sections()
    def has_section(self, section):
        return self.config.has_section(section)
    def has_option(self, section, option):
        return self.config.has_option(section, option)
    def get_all_options(self, section):
        try:
            return self.config.options(section)
        except configparser.NoSectionError:
            return []
    def set_value(self, section, key, value):
        if not self.config.has_section(section):
            self.config.add_section(section)
        self.config.set(section, key, str(value))
    def save_config(self):
        try:
            with open(self.config_file_path, 'w') as configfile:
                self.config.write(configfile)
            print(f"Config file saved: {self.config_file_path}")
            return True
        except Exception as e:
            print(f"Error saving config file: {str(e)}")
            return False
    def display_config(self):
        if not self.config.sections():
            print("Config file is empty")
            return
        print("\n" + "="*80)
        print("CONFIGURATION FILE CONTENTS")
        print("="*80)
        for section in self.config.sections():
            print(f"\n[{section}]")
            for option in self.config.options(section):
                value = self.config.get(section, option)
                print(f"  {option} = {value}")
        print("="*80 + "\n")
    def display_section(self, section):
        if not self.config.has_section(section):
            print(f"Section '{section}' not found")
            return
        print("\n" + "="*60)
        print(f"SECTION: [{section}]")
        print("="*60)
        for option in self.config.options(section):
            value = self.config.get(section, option)
            print(f"{option} = {value}")
        print("="*60 + "\n")
class JSONConfigReader:
    def __init__(self, config_file_path):
        self.config_file_path = config_file_path
        self.config = {}
        self.load_config()
    def load_config(self):
        if not os.path.exists(self.config_file_path):
            print(f"Error: Config file '{self.config_file_path}' does not exist")
            return False
        try:
            with open(self.config_file_path, 'r', encoding='utf-8') as file:
                self.config = json.load(file)
            print(f"JSON config file loaded: {self.config_file_path}")
            return True
        except Exception as e:
            print(f"Error loading JSON config: {str(e)}")
            return False
    def get_value(self, key_path, default=None):
        keys = key_path.split('.')
        value = self.config
        for key in keys:
            if isinstance(value, dict) and key in value:
                value = value[key]
            else:
                return default
        return value
    def set_value(self, key_path, value):
        keys = key_path.split('.')
        current = self.config
        for key in keys[:-1]:
            if key not in current:
                current[key] = {}
            current = current[key]
        current[keys[-1]] = value
    def get_all(self):
        return self.config
    def save_config(self):
        try:
            with open(self.config_file_path, 'w', encoding='utf-8') as file:
                json.dump(self.config, file, indent=2)
            print(f"JSON config file saved: {self.config_file_path}")
            return True
        except Exception as e:
            print(f"Error saving JSON config: {str(e)}")
            return False
    def display_config(self):
        print("\n" + "="*80)
        print("JSON CONFIGURATION FILE CONTENTS")
        print("="*80)
        print(json.dumps(self.config, indent=2))
        print("="*80 + "\n")
class ConfigValidator:
    def __init__(self):
        self.errors = []
        self.warnings = []
    def validate_config(self, config_reader):
        self.errors = []
        self.warnings = []
        if not config_reader.get_all_sections():
            self.errors.append("Config file has no sections")
            return False
        return True
    def validate_required_section(self, config_reader, section):
        if not config_reader.has_section(section):
            self.errors.append(f"Required section '{section}' not found")
            return False
        return True
    def validate_required_option(self, config_reader, section, option):
        if not config_reader.has_option(section, option):
            self.errors.append(f"Required option '{option}' in section '{section}' not found")
            return False
        return True
    def validate_value_type(self, value, expected_type):
        if expected_type == 'int':
            try:
                int(value)
                return True
            except ValueError:
                self.errors.append(f"Value '{value}' is not an integer")
                return False
        elif expected_type == 'float':
            try:
                float(value)
                return True
            except ValueError:
                self.errors.append(f"Value '{value}' is not a float")
                return False
        elif expected_type == 'bool':
            if value.lower() in ['true', 'false', 'yes', 'no', '0', '1']:
                return True
            self.errors.append(f"Value '{value}' is not a boolean")
            return False
        return True
    def get_errors(self):
        return self.errors
    def get_warnings(self):
        return self.warnings
    def display_validation_result(self):
        print("\n" + "="*60)
        print("VALIDATION RESULTS")
        print("="*60)
        if self.errors:
            print("ERRORS:")
            for idx, error in enumerate(self.errors, 1):
                print(f"  {idx}. {error}")
        else:
            print("No errors found")
        if self.warnings:
            print("\nWARNINGS:")
            for idx, warning in enumerate(self.warnings, 1):
                print(f"  {idx}. {warning}")
        else:
            print("No warnings found")
        print("="*60 + "\n")
def create_sample_ini_config(file_path):
