def main():
    while True:
        print("\n" + "="*60)
        print("CONFIG FILE READER")
        print("="*60)
        print("1. Read INI config file")
        print("2. Read JSON config file")
        print("3. Create sample INI config")
        print("4. Create sample JSON config")
        print("5. Exit")
        choice = input("\nSelect an option (1-5): ").strip()
        if choice == '1':
            config_file = input("Enter INI config file path: ").strip()
            reader = ConfigReader(config_file)
            if reader.load_config():
                while True:
                    print("\n1. Display all config")
                    print("2. Display specific section")
                    print("3. Get specific value")
                    print("4. List sections")
                    print("5. Validate config")
                    print("6. Back to main menu")
                    sub_choice = input("Select option: ").strip()
                    if sub_choice == '1':
                        reader.display_config()
                    elif sub_choice == '2':
                        section = input("Enter section name: ").strip()
                        reader.display_section(section)
                    elif sub_choice == '3':
                        section = input("Enter section: ").strip()
                        key = input("Enter key: ").strip()
                        value = reader.get_value(section, key)
                        print(f"{key} = {value}")
                    elif sub_choice == '4':
                        sections = reader.get_all_sections()
                        print("\nSections:")
                        for section in sections:
                            print(f"  - [{section}]")
                    elif sub_choice == '5':
                        validator = ConfigValidator()
                        validator.validate_config(reader)
                        validator.display_validation_result()
                    elif sub_choice == '6':
                        break
        elif choice == '2':
            config_file = input("Enter JSON config file path: ").strip()
            reader = JSONConfigReader(config_file)
            if reader.load_config():
                while True:
                    print("\n1. Display all config")
                    print("2. Get specific value")
                    print("3. Set value")
                    print("4. Save config")
                    print("5. Back to main menu")
                    sub_choice = input("Select option: ").strip()
                    if sub_choice == '1':
                        reader.display_config()
                    elif sub_choice == '2':
                        key_path = input("Enter key path (e.g., database.host): ").strip()
                        value = reader.get_value(key_path)
