                        reader.save_config()
                    elif sub_choice == '5':
                        break
        elif choice == '3':
            file_path = input("Enter output file path for sample INI config: ").strip()
            create_sample_ini_config(file_path)
        elif choice == '4':
            file_path = input("Enter output file path for sample JSON config: ").strip()
            create_sample_json_config(file_path)
        elif choice == '5':
            print("Exiting Config File Reader. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-5.")
if __name__ == '__main__':
    main()

import subprocess
import shlex
import platform
import os
def execute_command(command):
    system = platform.system()
    if system == "Windows":
        shell = True
    else:
        shell = False
    try:
        if shell:
            process = subprocess.Popen(
                command,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=True,
                text=True
            )
        else:
            args = shlex.split(command)
            process = subprocess.Popen(
                args,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=False,
                text=True
            )
        stdout, stderr = process.communicate(timeout=30)
        return {
            "command": command,
            "return_code": process.returncode,
            "stdout": stdout.strip(),
            "stderr": stderr.strip(),
            "success": process.returncode == 0
        }
    except subprocess.TimeoutExpired:
        process.kill()
        return {"command": command, "error": "Command timed out", "success": False}
    except FileNotFoundError:
        return {"command": command, "error": "Command not found", "success": False}
    except Exception as e:
        return {"command": command, "error": str(e), "success": False}
def display_result(result):
    print("=" * 50)
    print(f"Command   : {result['command']}")
    print(f"Success   : {result['success']}")
    if 'return_code' in result:
        print(f"Return Code: {result['return_code']}")
    if result.get('stdout'):
        print(f"Output    :\n{result['stdout']}")
    if result.get('stderr'):
        print(f"Error     :\n{result['stderr']}")
    if result.get('error'):
        print(f"Exception : {result['error']}")
    print("=" * 50)
system = platform.system()
if system == "Windows":
    commands = ["dir", "echo Hello from Windows", "whoami", "systeminfo"]
else:
    commands = ["ls -la", "echo Hello from Linux", "whoami", "uname -a", "df -h", "uptime"]
print(f"Running on: {system}")
print(f"Current Directory: {os.getcwd()}")
for cmd in commands:
    result = execute_command(cmd)
    display_result(result)

import subprocess
def run_command(command):
    try:
        result = subprocess.run(command, shell=True, capture_output=True, text=True)
        if result.returncode == 0:
            print("--- Output ---")
            print(result.stdout)
        else:
            print("--- Error ---")
            print(result.stderr)
    except Exception as e:
        print(f"Execution failed: {e}")
user_cmd = input("Enter shell command: ")
run_command(user_cmd)

import subprocess
import os
import sys
import platform
from datetime import datetime
class CommandExecutor:
    def __init__(self):
        self.command_history = []
        self.os_type = platform.system()
    def execute_command(self, command):
        try:
            result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=30)
            output = result.stdout
            error = result.stderr
            return_code = result.returncode
            command_info = {
                "command": command,
                "output": output,
                "error": error,
                "return_code": return_code,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.command_history.append(command_info)
            return command_info
        except subprocess.TimeoutExpired:
            error_info = {
                "command": command,
                "output": "",
                "error": "Command execution timed out",
                "return_code": -1,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.command_history.append(error_info)
            return error_info
        except Exception as e:
            error_info = {
                "command": command,
                "output": "",
                "error": str(e),
                "return_code": -1,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.command_history.append(error_info)
            return error_info
    def execute_command_with_input(self, command, input_data):
        try:
            result = subprocess.run(command, shell=True, input=input_data, capture_output=True, text=True, timeout=30)
            output = result.stdout
            error = result.stderr
            return_code = result.returncode
            return {
                "command": command,
                "output": output,
                "error": error,
                "return_code": return_code
            }
        except Exception as e:
            return {"error": str(e)}
    def execute_multiple_commands(self, commands):
        results = []
        for command in commands:
            result = self.execute_command(command)
            results.append(result)
        return results
    def get_system_info(self):
        info = {
            "os": platform.system(),
            "platform": platform.platform(),
            "processor": platform.processor(),
            "python_version": platform.python_version(),
            "machine": platform.machine()
        }
        return info
    def list_directory(self, path="."):
        try:
            items = os.listdir(path)
            return sorted(items)
        except Exception as e:
            return None
    def get_current_directory(self):
        return os.getcwd()
    def change_directory(self, path):
        try:
            os.chdir(path)
            print(f"Changed directory to: {os.getcwd()}")
            return True
        except Exception as e:
            print(f"Error changing directory: {str(e)}")
            return False
    def create_directory(self, path):
        try:
            os.makedirs(path, exist_ok=True)
            print(f"Directory created: {path}")
            return True
        except Exception as e:
            print(f"Error creating directory: {str(e)}")
            return False
    def remove_directory(self, path):
        try:
            os.rmdir(path)
            print(f"Directory removed: {path}")
            return True
        except Exception as e:
            print(f"Error removing directory: {str(e)}")
            return False
    def remove_file(self, path):
        try:
            os.remove(path)
            print(f"File removed: {path}")
            return True
        except Exception as e:
            print(f"Error removing file: {str(e)}")
            return False
    def get_file_info(self, path):
        try:
            stat_info = os.stat(path)
            return {
                "path": path,
                "size": stat_info.st_size,
                "created": datetime.fromtimestamp(stat_info.st_ctime).strftime("%Y-%m-%d %H:%M:%S"),
                "modified": datetime.fromtimestamp(stat_info.st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
                "is_file": os.path.isfile(path),
                "is_dir": os.path.isdir(path)
            }
        except Exception as e:
            return {"error": str(e)}
    def search_files(self, directory, pattern):
        try:
            results = []
            for root, dirs, files in os.walk(directory):
                for file in files:
                    if pattern.lower() in file.lower():
                        results.append(os.path.join(root, file))
            return results
        except Exception as e:
            print(f"Error searching files: {str(e)}")
            return []
    def get_disk_usage(self, path="."):
        try:
            if self.os_type == "Windows":
                result = subprocess.run(f"dir {path}", shell=True, capture_output=True, text=True)
                return result.stdout
            else:
                result = subprocess.run(f"du -sh {path}", shell=True, capture_output=True, text=True)
                return result.stdout
        except Exception as e:
            return f"Error: {str(e)}"
    def get_memory_usage(self):
        try:
            if self.os_type == "Windows":
                result = subprocess.run("wmic OS get TotalVisibleMemorySize,FreePhysicalMemory", shell=True, capture_output=True, text=True)
                return result.stdout
            else:
                result = subprocess.run("free -h", shell=True, capture_output=True, text=True)
                return result.stdout
        except Exception as e:
            return f"Error: {str(e)}"
    def get_cpu_usage(self):
        try:
            if self.os_type == "Windows":
                result = subprocess.run("wmic cpu get loadpercentage", shell=True, capture_output=True, text=True)
                return result.stdout
            else:
                result = subprocess.run("top -bn1 | grep 'Cpu(s)'", shell=True, capture_output=True, text=True)
                return result.stdout
        except Exception as e:
            return f"Error: {str(e)}"
    def list_processes(self):
        try:
            if self.os_type == "Windows":
                result = subprocess.run("tasklist", shell=True, capture_output=True, text=True)
                return result.stdout
            else:
                result = subprocess.run("ps aux", shell=True, capture_output=True, text=True)
                return result.stdout
        except Exception as e:
            return f"Error: {str(e)}"
    def kill_process(self, process_name):
        try:
            if self.os_type == "Windows":
                result = subprocess.run(f"taskkill /IM {process_name} /F", shell=True, capture_output=True, text=True)
            else:
                result = subprocess.run(f"pkill -f {process_name}", shell=True, capture_output=True, text=True)
            return result.stdout
        except Exception as e:
            return f"Error: {str(e)}"
    def get_network_info(self):
        try:
            if self.os_type == "Windows":
                result = subprocess.run("ipconfig", shell=True, capture_output=True, text=True)
                return result.stdout
            else:
                result = subprocess.run("ifconfig", shell=True, capture_output=True, text=True)
                return result.stdout
        except Exception as e:
            return f"Error: {str(e)}"
    def ping_host(self, host):
        try:
            if self.os_type == "Windows":
                result = subprocess.run(f"ping -n 4 {host}", shell=True, capture_output=True, text=True, timeout=10)
            else:
                result = subprocess.run(f"ping -c 4 {host}", shell=True, capture_output=True, text=True, timeout=10)
            return result.stdout
        except Exception as e:
            return f"Error: {str(e)}"
    def get_command_history(self):
        return self.command_history
    def display_command_output(self, result):
        print("\n" + "="*80)
        print(f"Command: {result['command']}")
        print(f"Timestamp: {result['timestamp']}")
        print(f"Return Code: {result['return_code']}")
        print("="*80)
        if result['output']:
            print("OUTPUT:")
            print(result['output'])
        if result['error']:
            print("ERROR:")
            print(result['error'])
        print("="*80 + "\n")
    def display_history(self):
        if not self.command_history:
            print("No command history")
            return
        print("\n" + "="*80)
        print("COMMAND HISTORY")
        print("="*80)
        for idx, item in enumerate(self.command_history, 1):
            print(f"{idx}. {item['command']}")
            print(f"   Status: {'Success' if item['return_code'] == 0 else 'Failed'} | Time: {item['timestamp']}")
        print("="*80 + "\n")
def main():
    executor = CommandExecutor()
    print(f"System: {executor.os_type}")
    while True:
        print("\n" + "="*60)
        print("SHELL COMMAND EXECUTOR")
        print("="*60)
        print("1. Execute custom command")
        print("2. List directory")
        print("3. Get current directory")
        print("4. Change directory")
        print("5. Create directory")
        print("6. Remove directory")
        print("7. Remove file")
        print("8. Get file info")
        print("9. Search files")
        print("10. System information")
        print("11. Disk usage")
        print("12. Memory usage")
        print("13. CPU usage")
        print("14. List processes")
        print("15. Kill process")
        print("16. Network information")
        print("17. Ping host")
        print("18. Command history")
        print("19. Exit")
        choice = input("\nSelect an option (1-19): ").strip()
        if choice == '1':
            command = input("Enter command to execute: ").strip()
            result = executor.execute_command(command)
            executor.display_command_output(result)
        elif choice == '2':
            path = input("Enter directory path (default current): ").strip() or "."
            items = executor.list_directory(path)
            if items:
                print(f"\nContents of {path}:")
                print("="*60)
                for item in items[:30]:
                    print(f"  {item}")
                if len(items) > 30:
                    print(f"  ... and {len(items) - 30} more items")
                print("="*60)
            else:
                print("Error listing directory or directory is empty")
        elif choice == '3':
            print(f"Current directory: {executor.get_current_directory()}")
        elif choice == '4':
            path = input("Enter directory path: ").strip()
            executor.change_directory(path)
        elif choice == '5':
            path = input("Enter directory path to create: ").strip()
            executor.create_directory(path)
        elif choice == '6':
            path = input("Enter directory path to remove: ").strip()
            executor.remove_directory(path)
        elif choice == '7':
            path = input("Enter file path to remove: ").strip()
            confirm = input("Are you sure? (yes/no): ").strip().lower()
            if confirm == 'yes':
                executor.remove_file(path)
        elif choice == '8':
            path = input("Enter file path: ").strip()
            info = executor.get_file_info(path)
            if "error" not in info:
                print("\n" + "="*60)
                print("FILE INFORMATION")
                print("="*60)
                for key, value in info.items():
                    print(f"{key}: {value}")
                print("="*60)
            else:
                print(f"Error: {info['error']}")
        elif choice == '9':
            directory = input("Enter search directory: ").strip() or "."
            pattern = input("Enter search pattern: ").strip()
            results = executor.search_files(directory, pattern)
            if results:
                print(f"\nFound {len(results)} file(s):")
                print("="*60)
                for result in results[:20]:
                    print(f"  {result}")
                if len(results) > 20:
                    print(f"  ... and {len(results) - 20} more files")
                print("="*60)
            else:
                print("No files found")
        elif choice == '10':
            info = executor.get_system_info()
            print("\n" + "="*60)
            print("SYSTEM INFORMATION")
            print("="*60)
            for key, value in info.items():
                print(f"{key}: {value}")
            print("="*60)
        elif choice == '11':
            usage = executor.get_disk_usage()
            print("\nDisk Usage:")
            print("="*60)
            print(usage)
            print("="*60)
        elif choice == '12':
            memory = executor.get_memory_usage()
            print("\nMemory Usage:")
            print("="*60)
            print(memory)
            print("="*60)
        elif choice == '13':
            cpu = executor.get_cpu_usage()
            print("\nCPU Usage:")
            print("="*60)
            print(cpu)
            print("="*60)
        elif choice == '14':
            processes = executor.list_processes()
            print("\nProcesses:")
            print("="*60)
            lines = processes.split('\n')
            for line in lines[:20]:
                print(line)
            if len(lines) > 20:
                print(f"... and {len(lines) - 20} more processes")
            print("="*60)
        elif choice == '15':
            process_name = input("Enter process name to kill: ").strip()
            confirm = input("Are you sure? (yes/no): ").strip().lower()
            if confirm == 'yes':
                result = executor.kill_process(process_name)
                print(result)
        elif choice == '16':
            network = executor.get_network_info()
            print("\nNetwork Information:")
            print("="*60)
            print(network[:500])
            print("="*60)
        elif choice == '17':
            host = input("Enter host to ping: ").strip()
            result = executor.ping_host(host)
            print("\nPing Result:")
            print("="*60)
            print(result)
            print("="*60)
        elif choice == '18':
            executor.display_history()
        elif choice == '19':
            print("Exiting Shell Command Executor. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-19.")
if __name__ == '__main__':
    main()

import subprocess
import platform
import socket
import statistics
from datetime import datetime
import re
class PingUtility:
    def __init__(self):
        self.os_type = platform.system()
        self.ping_history = []
    def ping_host(self, host, count=4, timeout=5):
        if self.os_type == "Windows":
            command = f"ping -n {count} -w {timeout * 1000} {host}"
        else:
            command = f"ping -c {count} -W {timeout * 1000} {host}"
        try:
            result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=timeout * count + 5)
            output = result.stdout
            error = result.stderr
            return_code = result.returncode
            ping_result = self.parse_ping_output(output, host)
            ping_result["raw_output"] = output
            ping_result["return_code"] = return_code
            ping_result["timestamp"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            self.ping_history.append(ping_result)
            return ping_result
        except Exception as e:
            error_result = {
                "host": host,
                "status": "error",
                "error": str(e),
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.ping_history.append(error_result)
            return error_result
    def parse_ping_output(self, output, host):
        result = {
            "host": host,
            "status": "unknown",
            "packets_sent": 0,
            "packets_received": 0,
            "packets_lost": 0,
            "loss_percentage": 0.0,
            "min_time": None,
            "max_time": None,
            "avg_time": None,
            "response_times": []
        }
        if "Reply from" in output or "bytes from" in output:
            result["status"] = "reachable"
        elif "Destination host unreachable" in output or "No route to host" in output:
            result["status"] = "unreachable"
        elif "Request timed out" in output or "100% packet loss" in output:
            result["status"] = "timeout"
        elif "unknown host" in output.lower() or "name or service not known" in output.lower():
            result["status"] = "unknown_host"
        else:
            result["status"] = "unknown"
        if self.os_type == "Windows":
            packets_match = re.search(r"Packets: Sent = (\d+), Received = (\d+), Lost = (\d+)", output)
            if packets_match:
                result["packets_sent"] = int(packets_match.group(1))
                result["packets_received"] = int(packets_match.group(2))
                result["packets_lost"] = int(packets_match.group(3))
                if result["packets_sent"] > 0:
                    result["loss_percentage"] = (result["packets_lost"] / result["packets_sent"]) * 100
            time_match = re.search(r"Minimum = (\d+)ms, Maximum = (\d+)ms, Average = (\d+)ms", output)
            if time_match:
                result["min_time"] = int(time_match.group(1))
                result["max_time"] = int(time_match.group(2))
                result["avg_time"] = int(time_match.group(3))
            response_times = re.findall(r"time[<=](\d+)ms", output)
            result["response_times"] = [int(t) for t in response_times]
        else:
            packets_match = re.search(r"(\d+) packets transmitted, (\d+) (?:packets )?received", output)
            if packets_match:
                result["packets_sent"] = int(packets_match.group(1))
                result["packets_received"] = int(packets_match.group(2))
                result["packets_lost"] = result["packets_sent"] - result["packets_received"]
                if result["packets_sent"] > 0:
                    result["loss_percentage"] = (result["packets_lost"] / result["packets_sent"]) * 100
            time_match = re.search(r"min/avg/max(?:/stddev)? = ([\d.]+)/([\d.]+)/([\d.]+)", output)
            if time_match:
                result["min_time"] = float(time_match.group(1))
                result["max_time"] = float(time_match.group(3))
                result["avg_time"] = float(time_match.group(2))
            response_times = re.findall(r"time=([\d.]+)\s*ms", output)
            result["response_times"] = [float(t) for t in response_times]
        return result
    def ping_multiple_hosts(self, hosts, count=4):
        results = {}
        for host in hosts:
            results[host] = self.ping_host(host, count)
        return results
    def continuous_ping(self, host, duration_seconds=60):
        start_time = datetime.now()
        end_time = start_time.timestamp() + duration_seconds
        results = []
        packet_number = 1
        try:
            while datetime.now().timestamp() < end_time:
                if self.os_type == "Windows":
                    command = f"ping -n 1 -w 5000 {host}"
                else:
                    command = f"ping -c 1 -W 5000 {host}"
                result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=10)
                output = result.stdout
                parsed = self.parse_ping_output(output, host)
                parsed["packet_number"] = packet_number
                parsed["timestamp"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                results.append(parsed)
                packet_number += 1
        except KeyboardInterrupt:
            print("\nPing interrupted by user")
        return results
    def resolve_hostname(self, hostname):
        try:
            ip_address = socket.gethostbyname(hostname)
            return {
                "hostname": hostname,
                "ip_address": ip_address,
                "status": "resolved"
            }
        except socket.gaierror:
            return {
                "hostname": hostname,
                "status": "unresolved",
                "error": "Hostname could not be resolved"
            }
        except Exception as e:
            return {
                "hostname": hostname,
                "status": "error",
                "error": str(e)
            }
    def reverse_dns_lookup(self, ip_address):
        try:
            hostname = socket.gethostbyaddr(ip_address)[0]
            return {
                "ip_address": ip_address,
                "hostname": hostname,
                "status": "resolved"
            }
        except socket.herror:
            return {
                "ip_address": ip_address,
                "status": "unresolved",
                "error": "Reverse DNS lookup failed"
            }
        except Exception as e:
            return {
                "ip_address": ip_address,
                "status": "error",
                "error": str(e)
            }
    def traceroute(self, host, max_hops=30):
        if self.os_type == "Windows":
            command = f"tracert -h {max_hops} {host}"
        else:
            command = f"traceroute -m {max_hops} {host}"
        try:
            result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=60)
            output = result.stdout
            return {
                "host": host,
                "traceroute": output,
                "status": "success"
            }
        except Exception as e:
            return {
                "host": host,
                "status": "error",
                "error": str(e)
            }
    def check_port(self, host, port, timeout=5):
        try:
            socket.create_connection((host, port), timeout=timeout)
            return {
                "host": host,
                "port": port,
                "status": "open"
            }
        except socket.timeout:
            return {
                "host": host,
                "port": port,
                "status": "timeout"
            }
        except socket.refused:
            return {
                "host": host,
                "port": port,
                "status": "closed"
            }
        except Exception as e:
            return {
                "host": host,
                "port": port,
                "status": "error",
                "error": str(e)
            }
    def check_ports(self, host, ports, timeout=5):
        results = {}
        for port in ports:
            results[port] = self.check_port(host, port, timeout)
        return results
    def get_network_stats(self):
        try:
            if self.os_type == "Windows":
                result = subprocess.run("netstat -an", shell=True, capture_output=True, text=True)
            else:
                result = subprocess.run("netstat -an", shell=True, capture_output=True, text=True)
            return result.stdout
        except Exception as e:
            return f"Error: {str(e)}"
    def get_ping_history(self):
        return self.ping_history
    def get_ping_statistics(self):
        if not self.ping_history:
            return None
        successful_pings = [p for p in self.ping_history if p.get("status") == "reachable"]
        if not successful_pings:
            return None
        response_times = []
        for ping in successful_pings:
            if ping.get("response_times"):
                response_times.extend(ping["response_times"])
        if not response_times:
            return None
        return {
            "total_pings": len(self.ping_history),
            "successful_pings": len(successful_pings),
            "failed_pings": len(self.ping_history) - len(successful_pings),
            "min_time": min(response_times),
            "max_time": max(response_times),
            "avg_time": statistics.mean(response_times),
            "std_dev": statistics.stdev(response_times) if len(response_times) > 1 else 0
        }
    def display_ping_result(self, result):
        print("\n" + "="*80)
        print(f"Ping to: {result['host']}")
        print(f"Timestamp: {result['timestamp']}")
        print("="*80)
        print(f"Status: {result['status']}")
        if result.get("packets_sent"):
            print(f"Packets: Sent={result['packets_sent']}, Received={result['packets_received']}, Lost={result['packets_lost']}")
            print(f"Loss: {result['loss_percentage']:.2f}%")
        if result.get("min_time") is not None:
            print(f"Times: Min={result['min_time']}ms, Max={result['max_time']}ms, Avg={result['avg_time']}ms")
        if result.get("error"):
            print(f"Error: {result['error']}")
        print("="*80 + "\n")
    def display_ping_history(self):
        if not self.ping_history:
            print("No ping history")
            return
        print("\n" + "="*80)
        print("PING HISTORY")
        print("="*80)
        for idx, item in enumerate(self.ping_history, 1):
            status_icon = "✓" if item.get("status") == "reachable" else "✗"
            print(f"{idx}. {status_icon} {item['host']} - {item['status']} ({item['timestamp']})")
            if item.get("avg_time"):
                print(f"   Response time: {item['avg_time']}ms")
        print("="*80 + "\n")
def main():
    ping_util = PingUtility()
    print(f"System: {ping_util.os_type}")
    while True:
        print("\n" + "="*60)
        print("PING UTILITY")
        print("="*60)
        print("1. Ping single host")
        print("2. Ping multiple hosts")
        print("3. Continuous ping")
        print("4. Traceroute")
        print("5. Resolve hostname")
        print("6. Reverse DNS lookup")
        print("7. Check port")
        print("8. Check multiple ports")
        print("9. View ping history")
        print("10. Ping statistics")
        print("11. Network statistics")
        print("12. Exit")
        choice = input("\nSelect an option (1-12): ").strip()
        if choice == '1':
            host = input("Enter host to ping: ").strip()
            count = input("Enter number of packets (default 4): ").strip()
            count = int(count) if count else 4
            result = ping_util.ping_host(host, count)
            ping_util.display_ping_result(result)
        elif choice == '2':
            hosts_input = input("Enter hosts to ping (comma-separated): ").strip()
            hosts = [h.strip() for h in hosts_input.split(',')]
            results = ping_util.ping_multiple_hosts(hosts)
            for host, result in results.items():
                ping_util.display_ping_result(result)
        elif choice == '3':
            host = input("Enter host to ping continuously: ").strip()
            duration = input("Enter duration in seconds (default 60): ").strip()
            duration = int(duration) if duration else 60
            print("Starting continuous ping (press Ctrl+C to stop)...")
            results = ping_util.continuous_ping(host, duration)
            print(f"\nCompleted {len(results)} ping(s)")
            for result in results[:10]:
                print(f"  {result['packet_number']}: {result['status']}")
            if len(results) > 10:
                print(f"  ... and {len(results) - 10} more packets")
        elif choice == '4':
            host = input("Enter host for traceroute: ").strip()
            result = ping_util.traceroute(host)
            print("\n" + "="*80)
            print(f"Traceroute to: {host}")
            print("="*80)
            print(result['traceroute'])
            print("="*80)
        elif choice == '5':
            hostname = input("Enter hostname to resolve: ").strip()
            result = ping_util.resolve_hostname(hostname)
            print("\n" + "="*60)
            print("DNS RESOLUTION")
            print("="*60)
            for key, value in result.items():
                print(f"{key}: {value}")
            print("="*60)
        elif choice == '6':
            ip_address = input("Enter IP address: ").strip()
            result = ping_util.reverse_dns_lookup(ip_address)
            print("\n" + "="*60)
            print("REVERSE DNS LOOKUP")
            print("="*60)
            for key, value in result.items():
                print(f"{key}: {value}")
            print("="*60)
        elif choice == '7':
            host = input("Enter host: ").strip()
            port = int(input("Enter port: ").strip())
            timeout = input("Enter timeout in seconds (default 5): ").strip()
            timeout = int(timeout) if timeout else 5
            result = ping_util.check_port(host, port, timeout)
            print("\n" + "="*60)
            print("PORT CHECK")
            print("="*60)
            for key, value in result.items():
                print(f"{key}: {value}")
            print("="*60)
        elif choice == '8':
            host = input("Enter host: ").strip()
            ports_input = input("Enter ports (comma-separated): ").strip()
            ports = [int(p.strip()) for p in ports_input.split(',')]
            results = ping_util.check_ports(host, ports)
            print("\n" + "="*60)
            print("PORT CHECK RESULTS")
            print("="*60)
            for port, result in results.items():
                print(f"Port {port}: {result['status']}")
            print("="*60)
        elif choice == '9':
            ping_util.display_ping_history()
        elif choice == '10':
            stats = ping_util.get_ping_statistics()
            if stats:
                print("\n" + "="*60)
                print("PING STATISTICS")
                print("="*60)
                for key, value in stats.items():
                    print(f"{key}: {value}")
                print("="*60)
            else:
                print("No statistics available")
        elif choice == '11':
            stats = ping_util.get_network_stats()
            print("\n" + "="*80)
            print("NETWORK STATISTICS")
            print("="*80)
            lines = stats.split('\n')
            for line in lines[:30]:
                print(line)
            if len(lines) > 30:
                print(f"... and {len(lines) - 30} more lines")
            print("="*80)
        elif choice == '12':
            print("Exiting Ping Utility. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-12.")
if __name__ == '__main__':
    main()

import psutil
import platform
import os
import time
from datetime import datetime
def get_system_info():
    uname = platform.uname()
    return {
        "system": uname.system,
        "node_name": uname.node,
        "release": uname.release,
        "version": uname.version,
        "machine": uname.machine,
        "processor": uname.processor
    }
def get_cpu_info():
    cpu_freq = psutil.cpu_freq()
    return {
        "physical_cores": psutil.cpu_count(logical=False),
        "total_cores": psutil.cpu_count(logical=True),
        "max_frequency": f"{cpu_freq.max:.2f} MHz" if cpu_freq else "N/A",
        "min_frequency": f"{cpu_freq.min:.2f} MHz" if cpu_freq else "N/A",
        "current_frequency": f"{cpu_freq.current:.2f} MHz" if cpu_freq else "N/A",
        "cpu_usage_per_core": [f"{x}%" for x in psutil.cpu_percent(percpu=True, interval=1)],
        "total_cpu_usage": f"{psutil.cpu_percent(interval=1)}%"
    }
def get_memory_info():
    virtual_mem = psutil.virtual_memory()
    swap_mem = psutil.swap_memory()
    return {
        "virtual_memory": {
            "total": f"{virtual_mem.total / (1024**3):.2f} GB",
            "available": f"{virtual_mem.available / (1024**3):.2f} GB",
            "used": f"{virtual_mem.used / (1024**3):.2f} GB",
            "percentage": f"{virtual_mem.percent}%"
        },
        "swap_memory": {
            "total": f"{swap_mem.total / (1024**3):.2f} GB",
            "free": f"{swap_mem.free / (1024**3):.2f} GB",
            "used": f"{swap_mem.used / (1024**3):.2f} GB",
            "percentage": f"{swap_mem.percent}%"
        }
    }
def get_disk_info():
    partitions = psutil.disk_partitions()
    disk_info = []
    for partition in partitions:
        try:
            usage = psutil.disk_usage(partition.mountpoint)
            disk_info.append({
                "device": partition.device,
                "mountpoint": partition.mountpoint,
                "file_system": partition.fstype,
                "total": f"{usage.total / (1024**3):.2f} GB",
                "used": f"{usage.used / (1024**3):.2f} GB",
                "free": f"{usage.free / (1024**3):.2f} GB",
                "percentage": f"{usage.percent}%"
            })
        except PermissionError:
            continue
    disk_io = psutil.disk_io_counters()
    return {
        "partitions": disk_info,
        "disk_io": {
            "total_read": f"{disk_io.read_bytes / (1024**3):.2f} GB",
            "total_write": f"{disk_io.write_bytes / (1024**3):.2f} GB"
        }
    }
def get_network_info():
    net_io = psutil.net_io_counters()
    interfaces = psutil.net_if_addrs()
    interface_info = {}
    for interface, addresses in interfaces.items():
        interface_info[interface] = []
        for address in addresses:
            interface_info[interface].append({
                "family": str(address.family),
                "address": address.address,
                "netmask": address.netmask,
                "broadcast": address.broadcast
            })
    return {
        "bytes_sent": f"{net_io.bytes_sent / (1024**2):.2f} MB",
        "bytes_received": f"{net_io.bytes_recv / (1024**2):.2f} MB",
        "packets_sent": net_io.packets_sent,
        "packets_received": net_io.packets_recv,
        "interfaces": interface_info
    }
def get_process_info(limit=10):
    processes = []
    for proc in psutil.process_iter(['pid', 'name', 'status', 'cpu_percent', 'memory_percent']):
        try:
            processes.append(proc.info)
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            continue
    processes = sorted(processes, key=lambda x: x['cpu_percent'], reverse=True)
    return processes[:limit]
def get_battery_info():
    battery = psutil.sensors_battery()
    if not battery:
        return {"status": "No battery detected"}
    return {
        "percentage": f"{battery.percent}%",
        "plugged_in": battery.power_plugged,
        "time_left": f"{battery.secsleft // 3600}h {(battery.secsleft % 3600) // 60}m" if battery.secsleft != psutil.POWER_TIME_UNLIMITED else "Unlimited"
    }
def display_monitor():
    print("=" * 60)
    print(f"  SYSTEM MONITORING TOOL")
    print(f"  Timestamp: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 60)
    print("\n[SYSTEM INFO]")
    for key, value in get_system_info().items():
        print(f"  {key.replace('_', ' ').title()}: {value}")
    print("\n[CPU INFO]")
    for key, value in get_cpu_info().items():
        print(f"  {key.replace('_', ' ').title()}: {value}")
    print("\n[MEMORY INFO]")
    mem = get_memory_info()
    print("  Virtual Memory:")
    for key, value in mem['virtual_memory'].items():
        print(f"    {key.replace('_', ' ').title()}: {value}")
    print("  Swap Memory:")
    for key, value in mem['swap_memory'].items():
        print(f"    {key.replace('_', ' ').title()}: {value}")
    print("\n[DISK INFO]")
    disk = get_disk_info()
    for partition in disk['partitions']:
        print(f"  Device: {partition['device']}")
        for key, value in partition.items():
            if key != 'device':
                print(f"    {key.replace('_', ' ').title()}: {value}")
    print("  Disk I/O:")
    for key, value in disk['disk_io'].items():
        print(f"    {key.replace('_', ' ').title()}: {value}")
    print("\n[NETWORK INFO]")
    net = get_network_info()
    print(f"  Bytes Sent     : {net['bytes_sent']}")
    print(f"  Bytes Received : {net['bytes_received']}")
    print(f"  Packets Sent   : {net['packets_sent']}")
    print(f"  Packets Received: {net['packets_received']}")
    print("\n[TOP 10 PROCESSES BY CPU USAGE]")
    print(f"  {'PID':<10} {'Name':<25} {'Status':<15} {'CPU%':<10} {'MEM%':<10}")
    print("  " + "-" * 70)
    for proc in get_process_info():
        print(f"  {proc['pid']:<10} {proc['name']:<25} {proc['status']:<15} {proc['cpu_percent']:<10} {round(proc['memory_percent'], 2):<10}")
    print("\n[BATTERY INFO]")
    for key, value in get_battery_info().items():
        print(f"  {key.replace('_', ' ').title()}: {value}")
    print("\n" + "=" * 60)
display_monitor()

