import psutil
import os
import signal
import platform
from datetime import datetime
def get_all_processes():
    processes = []
    for proc in psutil.process_iter(['pid', 'name', 'status', 'cpu_percent',
                                     'memory_percent', 'create_time', 'username',
                                     'num_threads', 'ppid']):
        try:
            info = proc.info
            info['create_time'] = datetime.fromtimestamp(info['create_time']).strftime('%Y-%m-%d %H:%M:%S')
            info['memory_percent'] = round(info['memory_percent'], 2)
            info['cpu_percent'] = round(info['cpu_percent'], 2)
            processes.append(info)
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            continue
    return processes
def get_process_by_pid(pid):
    try:
        proc = psutil.Process(pid)
        info = proc.as_dict(attrs=['pid', 'name', 'status', 'cpu_percent',
                                   'memory_percent', 'create_time', 'username',
                                   'num_threads', 'ppid', 'exe', 'cmdline',
                                   'open_files', 'connections'])
        info['create_time'] = datetime.fromtimestamp(info['create_time']).strftime('%Y-%m-%d %H:%M:%S')
        info['memory_percent'] = round(info['memory_percent'], 2)
        info['cpu_percent'] = round(info['cpu_percent'], 2)
        return info
    except psutil.NoSuchProcess:
        return {"error": f"Process with PID {pid} not found"}
    except psutil.AccessDenied:
        return {"error": f"Access denied to process with PID {pid}"}
def get_process_by_name(name):
    matched = []
    for proc in psutil.process_iter(['pid', 'name', 'status', 'cpu_percent', 'memory_percent']):
        try:
            if name.lower() in proc.info['name'].lower():
                proc.info['memory_percent'] = round(proc.info['memory_percent'], 2)
                proc.info['cpu_percent'] = round(proc.info['cpu_percent'], 2)
                matched.append(proc.info)
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            continue
    return matched
def kill_process(pid):
    try:
        proc = psutil.Process(pid)
        proc_name = proc.name()
        proc.kill()
        return {"success": True, "message": f"Process '{proc_name}' with PID {pid} killed successfully"}
    except psutil.NoSuchProcess:
        return {"success": False, "error": f"Process with PID {pid} not found"}
    except psutil.AccessDenied:
        return {"success": False, "error": f"Access denied to kill process with PID {pid}"}
    except Exception as e:
        return {"success": False, "error": str(e)}
def terminate_process(pid):
    try:
        proc = psutil.Process(pid)
        proc_name = proc.name()
        proc.terminate()
        return {"success": True, "message": f"Process '{proc_name}' with PID {pid} terminated successfully"}
    except psutil.NoSuchProcess:
        return {"success": False, "error": f"Process with PID {pid} not found"}
    except psutil.AccessDenied:
        return {"success": False, "error": f"Access denied to terminate process with PID {pid}"}
    except Exception as e:
        return {"success": False, "error": str(e)}
def suspend_process(pid):
    try:
        proc = psutil.Process(pid)
        proc_name = proc.name()
        proc.suspend()
        return {"success": True, "message": f"Process '{proc_name}' with PID {pid} suspended successfully"}
    except psutil.NoSuchProcess:
        return {"success": False, "error": f"Process with PID {pid} not found"}
    except psutil.AccessDenied:
        return {"success": False, "error": f"Access denied to suspend process with PID {pid}"}
    except Exception as e:
        return {"success": False, "error": str(e)}
def resume_process(pid):
    try:
        proc = psutil.Process(pid)
        proc_name = proc.name()
        proc.resume()
        return {"success": True, "message": f"Process '{proc_name}' with PID {pid} resumed successfully"}
    except psutil.NoSuchProcess:
        return {"success": False, "error": f"Process with PID {pid} not found"}
    except psutil.AccessDenied:
        return {"success": False, "error": f"Access denied to resume process with PID {pid}"}
    except Exception as e:
        return {"success": False, "error": str(e)}
def get_top_processes(sort_by='cpu', limit=10):
    valid_sort = ['cpu', 'memory']
    if sort_by not in valid_sort:
        return {"error": f"sort_by must be one of: {', '.join(valid_sort)}"}
    processes = get_all_processes()
    if sort_by == 'cpu':
        processes = sorted(processes, key=lambda x: x['cpu_percent'], reverse=True)
    elif sort_by == 'memory':
        processes = sorted(processes, key=lambda x: x['memory_percent'], reverse=True)
    return processes[:limit]
def display_processes(processes, title="PROCESS LIST"):
    print("=" * 90)
    print(f"  {title}")
    print(f"  Timestamp: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 90)
    print(f"  {'PID':<8} {'Name':<25} {'Status':<12} {'CPU%':<8} {'MEM%':<8} {'Threads':<10} {'User':<15}")
    print("  " + "-" * 88)
    for proc in processes:
        print(f"  {proc['pid']:<8} {proc['name']:<25} {proc['status']:<12} {proc['cpu_percent']:<8} {proc['memory_percent']:<8} {proc['num_threads']:<10} {str(proc['username']):<15}")
    print("=" * 90)
def display_process_detail(info):
    print("=" * 60)
    print(f"  PROCESS DETAIL")
    print("=" * 60)
    for key, value in info.items():
        if isinstance(value, list):
            print(f"  {key.replace('_', ' ').title()}:")
            for item in value:
                print(f"    {item}")
        else:
            print(f"  {key.replace('_', ' ').title()}: {value}")
    print("=" * 60)
print("\n[TOP 10 PROCESSES BY CPU USAGE]")
display_processes(get_top_processes(sort_by='cpu', limit=10), title="TOP 10 BY CPU")
print("\n[TOP 10 PROCESSES BY MEMORY USAGE]")
display_processes(get_top_processes(sort_by='memory', limit=10), title="TOP 10 BY MEMORY")
print("\n[SEARCH PROCESS BY NAME: 'python']")
python_processes = get_process_by_name('python')
if python_processes:
    display_processes(python_processes, title="PYTHON PROCESSES")
else:
    print("  No Python processes found.")
print("\n[CURRENT PROCESS DETAIL]")
current_pid = os.getpid()
current_proc = get_process_by_pid(current_pid)
display_process_detail(current_proc)

