import psutil
import platform
import subprocess
from datetime import datetime
import signal
import os
class ProcessManager:
    def __init__(self):
        self.os_type = platform.system()
        self.process_actions = []
    def get_all_processes(self):
        processes = []
        for proc in psutil.process_iter(['pid', 'name', 'status', 'memory_percent', 'cpu_percent']):
            try:
                pinfo = proc.as_dict(attrs=['pid', 'name', 'status', 'memory_percent', 'cpu_percent'])
                processes.append(pinfo)
            except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
                pass
        return processes
    def get_process_details(self, pid):
        try:
            proc = psutil.Process(pid)
            details = {
                "pid": proc.pid,
                "name": proc.name(),
                "status": proc.status(),
                "create_time": datetime.fromtimestamp(proc.create_time()).strftime("%Y-%m-%d %H:%M:%S"),
                "memory_info": proc.memory_info()._asdict(),
                "memory_percent": proc.memory_percent(),
                "cpu_num": proc.cpu_num(),
                "cpu_percent": proc.cpu_percent(interval=1),
                "num_threads": proc.num_threads(),
                "parent": proc.ppid(),
                "username": proc.username(),
                "cwd": proc.cwd()
            }
            return details
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
        except Exception as e:
            return {"error": str(e)}
    def get_process_by_name(self, name):
        processes = []
        for proc in psutil.process_iter(['pid', 'name']):
            try:
                if name.lower() in proc.info['name'].lower():
                    processes.append({
                        "pid": proc.info['pid'],
                        "name": proc.info['name']
                    })
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return processes
    def get_process_children(self, pid):
        try:
            proc = psutil.Process(pid)
            children = proc.children(recursive=True)
            child_list = []
            for child in children:
                try:
                    child_list.append({
                        "pid": child.pid,
                        "name": child.name(),
                        "status": child.status()
                    })
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass
            return child_list
        except psutil.NoSuchProcess:
            return []
    def get_top_processes(self, sort_by='memory', limit=10):
        processes = self.get_all_processes()
        if sort_by == 'memory':
            sorted_procs = sorted(processes, key=lambda x: x['memory_percent'], reverse=True)
        elif sort_by == 'cpu':
            sorted_procs = sorted(processes, key=lambda x: x['cpu_percent'], reverse=True)
        else:
            sorted_procs = processes
        return sorted_procs[:limit]
    def terminate_process(self, pid):
        try:
            proc = psutil.Process(pid)
            proc_name = proc.name()
            proc.terminate()
            try:
                proc.wait(timeout=3)
                result = {
                    "status": "terminated",
                    "pid": pid,
                    "name": proc_name,
                    "action_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                }
            except psutil.TimeoutExpired:
                proc.kill()
                result = {
                    "status": "killed",
                    "pid": pid,
                    "name": proc_name,
                    "action_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                }
            self.process_actions.append(result)
            return result
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
        except psutil.AccessDenied:
            return {"error": f"Access denied to terminate process {pid}"}
        except Exception as e:
            return {"error": str(e)}
    def kill_process(self, pid):
        try:
            proc = psutil.Process(pid)
            proc_name = proc.name()
            proc.kill()
            proc.wait()
            result = {
                "status": "killed",
                "pid": pid,
                "name": proc_name,
                "action_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.process_actions.append(result)
            return result
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
        except psutil.AccessDenied:
            return {"error": f"Access denied to kill process {pid}"}
        except Exception as e:
            return {"error": str(e)}
    def suspend_process(self, pid):
        try:
            proc = psutil.Process(pid)
            proc_name = proc.name()
            proc.suspend()
            result = {
                "status": "suspended",
                "pid": pid,
                "name": proc_name,
                "action_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.process_actions.append(result)
            return result
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
        except psutil.AccessDenied:
            return {"error": f"Access denied to suspend process {pid}"}
        except Exception as e:
            return {"error": str(e)}
    def resume_process(self, pid):
        try:
            proc = psutil.Process(pid)
            proc_name = proc.name()
            proc.resume()
            result = {
                "status": "resumed",
                "pid": pid,
                "name": proc_name,
                "action_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.process_actions.append(result)
            return result
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
        except psutil.AccessDenied:
            return {"error": f"Access denied to resume process {pid}"}
        except Exception as e:
            return {"error": str(e)}
    def terminate_by_name(self, name):
        processes = self.get_process_by_name(name)
        results = []
        for proc in processes:
            result = self.terminate_process(proc['pid'])
            results.append(result)
        return results
    def set_process_priority(self, pid, priority):
        try:
            proc = psutil.Process(pid)
            proc_name = proc.name()
            if priority == 'high':
                priority_value = psutil.HIGH_PRIORITY_CLASS if self.os_type == "Windows" else -5
            elif priority == 'normal':
                priority_value = psutil.NORMAL_PRIORITY_CLASS if self.os_type == "Windows" else 0
            elif priority == 'low':
                priority_value = psutil.LOW_PRIORITY_CLASS if self.os_type == "Windows" else 10
            else:
                return {"error": "Invalid priority"}
            if self.os_type == "Windows":
                proc.nice(priority_value)
            else:
                os.nice(priority_value)
            result = {
                "status": "priority_set",
                "pid": pid,
                "name": proc_name,
                "priority": priority,
                "action_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.process_actions.append(result)
            return result
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
        except Exception as e:
            return {"error": str(e)}
    def get_process_open_files(self, pid):
        try:
            proc = psutil.Process(pid)
            open_files = proc.open_files()
            files = []
            for file_obj in open_files:
                files.append({
                    "path": file_obj.path,
                    "mode": file_obj.mode,
                    "flags": file_obj.flags
                })
            return files
        except psutil.NoSuchProcess:
            return []
        except Exception as e:
            return []
    def get_process_connections(self, pid):
        try:
            proc = psutil.Process(pid)
            connections = proc.net_connections()
            conn_list = []
            for conn in connections:
                conn_list.append({
                    "fd": conn.fd,
                    "family": str(conn.family),
                    "type": str(conn.type),
                    "laddr": conn.laddr,
                    "raddr": conn.raddr,
                    "status": conn.status
                })
            return conn_list
        except psutil.NoSuchProcess:
            return []
        except Exception as e:
            return []
    def get_zombie_processes(self):
        zombie_procs = []
        for proc in psutil.process_iter(['pid', 'name', 'status']):
            try:
                if proc.info['status'] == psutil.STATUS_ZOMBIE:
                    zombie_procs.append({
                        "pid": proc.info['pid'],
                        "name": proc.info['name'],
                        "status": proc.info['status']
                    })
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return zombie_procs
    def get_process_tree(self, pid=None):
        if pid is None:
            pid = os.getpid()
        try:
            proc = psutil.Process(pid)
            tree = {
                "pid": proc.pid,
                "name": proc.name(),
                "children": []
            }
            for child in proc.children(recursive=True):
                try:
                    tree["children"].append({
                        "pid": child.pid,
                        "name": child.name()
                    })
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass
            return tree
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
    def search_processes(self, keyword):
        results = []
        for proc in psutil.process_iter(['pid', 'name', 'status', 'memory_percent', 'cpu_percent']):
            try:
                if keyword.lower() in proc.info['name'].lower():
                    results.append(proc.as_dict(attrs=['pid', 'name', 'status', 'memory_percent', 'cpu_percent']))
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return results
    def get_process_actions_history(self):
        return self.process_actions
    def display_all_processes(self, limit=20):
        processes = self.get_all_processes()
        print("\n" + "="*120)
        print(f"ALL PROCESSES (showing {min(limit, len(processes))} of {len(processes)})")
        print("="*120)
        print(f"{'PID':<10} {'Name':<40} {'Status':<15} {'Memory %':<15} {'CPU %':<10}")
        print("-"*120)
        for proc in processes[:limit]:
            print(f"{proc['pid']:<10} {proc['name']:<40} {proc['status']:<15} {proc['memory_percent']:<15.2f} {proc['cpu_percent']:<10.2f}")
        if len(processes) > limit:
            print(f"... and {len(processes) - limit} more processes")
        print("="*120 + "\n")
    def display_process_details(self, pid):
        details = self.get_process_details(pid)
        print("\n" + "="*80)
        print("PROCESS DETAILS")
        print("="*80)
        for key, value in details.items():
            if key != "memory_info":
                print(f"{key}: {value}")
        if "memory_info" in details:
            print("\nMemory Info:")
            for key, value in details["memory_info"].items():
                print(f"  {key}: {value / (1024**2):.2f} MB")
        print("="*80 + "\n")
    def display_top_processes(self, sort_by='memory', limit=10):
        processes = self.get_top_processes(sort_by, limit)
        print("\n" + "="*100)
        print(f"TOP {limit} PROCESSES (sorted by {sort_by})")
        print("="*100)
        print(f"{'PID':<10} {'Name':<40} {'Memory %':<15} {'CPU %':<10}")
        print("-"*100)
        for proc in processes:
            print(f"{proc['pid']:<10} {proc['name']:<40} {proc['memory_percent']:<15.2f} {proc['cpu_percent']:<10.2f}")
        print("="*100 + "\n")
    def display_process_tree(self, pid=None):
        tree = self.get_process_tree(pid)
        print("\n" + "="*80)
        print("PROCESS TREE")
        print("="*80)
        print(f"Root: {tree['name']} (PID: {tree['pid']})")
        if tree.get("children"):
            print(f"Children: {len(tree['children'])}")
            for child in tree["children"][:20]:
                print(f"  ├─ {child['name']} (PID: {child['pid']})")
            if len(tree["children"]) > 20:
                print(f"  └─ ... and {len(tree['children']) - 20} more children")
        print("="*80 + "\n")
def main():
    manager = ProcessManager()
    while True:
        print("\n" + "="*60)
        print("PROCESS MANAGER")
        print("="*60)
        print("1. Display all processes")
        print("2. Display process details")
        print("3. Search processes")
        print("4. Display top processes (by memory)")
        print("5. Display top processes (by CPU)")
        print("6. Terminate process")
        print("7. Kill process")
        print("8. Suspend process")
        print("9. Resume process")
        print("10. Terminate by name")
        print("11. Set process priority")
        print("12. Display process tree")
        print("13. Get zombie processes")
        print("14. View action history")
        print("15. Exit")
        choice = input("\nSelect an option (1-15): ").strip()
        if choice == '1':
            limit = input("Enter number of processes to display (default 20): ").strip()
            limit = int(limit) if limit else 20
            manager.display_all_processes(limit)
        elif choice == '2':
            pid = int(input("Enter PID: ").strip())
            manager.display_process_details(pid)
        elif choice == '3':
            keyword = input("Enter search keyword: ").strip()
            results = manager.search_processes(keyword)
            print(f"\nFound {len(results)} process(es)")
            print("="*100)
            print(f"{'PID':<10} {'Name':<40} {'Status':<15} {'Memory %':<15} {'CPU %':<10}")
            print("-"*100)
            for proc in results[:20]:
                print(f"{proc['pid']:<10} {proc['name']:<40} {proc['status']:<15} {proc['memory_percent']:<15.2f} {proc['cpu_percent']:<10.2f}")
            if len(results) > 20:
                print(f"... and {len(results) - 20} more processes")
            print("="*100)
        elif choice == '4':
            limit = input("Enter number of top processes (default 10): ").strip()
            limit = int(limit) if limit else 10
            manager.display_top_processes('memory', limit)
        elif choice == '5':
            limit = input("Enter number of top processes (default 10): ").strip()
            limit = int(limit) if limit else 10
            manager.display_top_processes('cpu', limit)
        elif choice == '6':
            pid = int(input("Enter PID to terminate: ").strip())
            confirm = input("Are you sure? (yes/no): ").strip().lower()
            if confirm == 'yes':
                result = manager.terminate_process(pid)
                print("\n" + str(result))
        elif choice == '7':
            pid = int(input("Enter PID to kill: ").strip())
            confirm = input("Are you sure? (yes/no): ").strip().lower()
            if confirm == 'yes':
                result = manager.kill_process(pid)
                print("\n" + str(result))
        elif choice == '8':
            pid = int(input("Enter PID to suspend: ").strip())
            result = manager.suspend_process(pid)
            print("\n" + str(result))
        elif choice == '9':
            pid = int(input("Enter PID to resume: ").strip())
            result = manager.resume_process(pid)
            print("\n" + str(result))
        elif choice == '10':
            name = input("Enter process name: ").strip()
            confirm = input("Terminate all matching processes? (yes/no): ").strip().lower()
            if confirm == 'yes':
                results = manager.terminate_by_name(name)
                print(f"\nTerminated {len(results)} process(es)")
                for result in results:
                    print(f"  {result}")
        elif choice == '11':
            pid = int(input("Enter PID: ").strip())
            priority = input("Enter priority (high/normal/low): ").strip().lower()
            result = manager.set_process_priority(pid, priority)
            print("\n" + str(result))
        elif choice == '12':
            pid_input = input("Enter PID (default current process): ").strip()
            pid = int(pid_input) if pid_input else None
            manager.display_process_tree(pid)
        elif choice == '13':
            zombie_procs = manager.get_zombie_processes()
            if zombie_procs:
                print(f"\nFound {len(zombie_procs)} zombie process(es)")
                print("="*60)
                for proc in zombie_procs:
                    print(f"  PID: {proc['pid']}, Name: {proc['name']}")
                print("="*60)
            else:
                print("No zombie processes found")
        elif choice == '14':
            history = manager.get_process_actions_history()
            if history:
                print("\nACTION HISTORY")
                print("="*80)
                for idx, action in enumerate(history, 1):
                    print(f"{idx}. {action}")
                print("="*80)
            else:
                print("No actions recorded")
        elif choice == '15':
            print("Exiting Process Manager. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-15.")
if __name__ == '__main__':
    main()

import argparse
import psutil
import platform
import os
import json
import csv
from datetime import datetime
def get_cpu_stats():
    freq = psutil.cpu_freq()
    return {
        "physical_cores": psutil.cpu_count(logical=False),
        "logical_cores": psutil.cpu_count(logical=True),
        "current_frequency": f"{freq.current:.2f} MHz" if freq else "N/A",
        "max_frequency": f"{freq.max:.2f} MHz" if freq else "N/A",
        "min_frequency": f"{freq.min:.2f} MHz" if freq else "N/A",
        "cpu_usage_total": f"{psutil.cpu_percent(interval=1)}%",
        "cpu_usage_per_core": [f"{x}%" for x in psutil.cpu_percent(percpu=True, interval=1)]
    }
def get_memory_stats():
    vm = psutil.virtual_memory()
    sw = psutil.swap_memory()
    return {
        "virtual_total": f"{vm.total / (1024**3):.2f} GB",
        "virtual_used": f"{vm.used / (1024**3):.2f} GB",
        "virtual_available": f"{vm.available / (1024**3):.2f} GB",
        "virtual_percent": f"{vm.percent}%",
        "swap_total": f"{sw.total / (1024**3):.2f} GB",
        "swap_used": f"{sw.used / (1024**3):.2f} GB",
        "swap_free": f"{sw.free / (1024**3):.2f} GB",
        "swap_percent": f"{sw.percent}%"
    }
def get_disk_stats():
    partitions = psutil.disk_partitions()
    disk_list = []
    for p in partitions:
        try:
            usage = psutil.disk_usage(p.mountpoint)
            disk_list.append({
                "device": p.device,
                "mountpoint": p.mountpoint,
                "fstype": p.fstype,
                "total": f"{usage.total / (1024**3):.2f} GB",
                "used": f"{usage.used / (1024**3):.2f} GB",
                "free": f"{usage.free / (1024**3):.2f} GB",
                "percent": f"{usage.percent}%"
            })
        except PermissionError:
            continue
    io = psutil.disk_io_counters()
    return {
        "partitions": disk_list,
        "total_read": f"{io.read_bytes / (1024**3):.2f} GB",
        "total_write": f"{io.write_bytes / (1024**3):.2f} GB"
    }
def get_network_stats():
    io = psutil.net_io_counters()
    return {
        "bytes_sent": f"{io.bytes_sent / (1024**2):.2f} MB",
        "bytes_received": f"{io.bytes_recv / (1024**2):.2f} MB",
        "packets_sent": io.packets_sent,
        "packets_received": io.packets_recv,
        "errors_in": io.errin,
        "errors_out": io.errout,
        "drop_in": io.dropin,
        "drop_out": io.dropout
    }
def get_system_stats():
    uname = platform.uname()
    boot_time = datetime.fromtimestamp(psutil.boot_time()).strftime('%Y-%m-%d %H:%M:%S')
    return {
        "system": uname.system,
        "node": uname.node,
        "release": uname.release,
        "version": uname.version,
        "machine": uname.machine,
        "processor": uname.processor,
        "boot_time": boot_time
    }
def get_process_stats(limit=10, sort_by='cpu'):
    procs = []
    for proc in psutil.process_iter(['pid', 'name', 'status', 'cpu_percent', 'memory_percent', 'username']):
        try:
            procs.append(proc.info)
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            continue
    if sort_by == 'memory':
        procs = sorted(procs, key=lambda x: x['memory_percent'], reverse=True)
    else:
        procs = sorted(procs, key=lambda x: x['cpu_percent'], reverse=True)
    return procs[:limit]
def display_table(title, data):
    print(f"\n{'=' * 55}")
    print(f"  {title}")
    print(f"{'=' * 55}")
    if isinstance(data, dict):
        for key, value in data.items():
            if isinstance(value, list):
                print(f"  {key.replace('_', ' ').title()}:")
                for item in value:
                    if isinstance(item, dict):
                        for k, v in item.items():
                            print(f"      {k.replace('_', ' ').title()}: {v}")
                        print()
                    else:
                        print(f"      {item}")
            else:
                print(f"  {key.replace('_', ' ').title():<30}: {value}")
    print(f"{'=' * 55}")
def display_processes(processes):
    print(f"\n{'=' * 80}")
    print(f"  TOP PROCESSES")
    print(f"{'=' * 80}")
    print(f"  {'PID':<8} {'Name':<25} {'Status':<12} {'CPU%':<8} {'MEM%':<8} {'User':<15}")
    print(f"  {'-' * 78}")
    for p in processes:
        print(f"  {p['pid']:<8} {p['name']:<25} {p['status']:<12} {round(p['cpu_percent'],2):<8} {round(p['memory_percent'],2):<8} {str(p['username']):<15}")
    print(f"{'=' * 80}")
def save_json(data, filename):
    with open(filename, 'w') as f:
        json.dump(data, f, indent=4)
    print(f"Stats saved to {filename}")
def save_csv(data, filename):
    flat = {}
    for key, value in data.items():
        if isinstance(value, dict):
            for k, v in value.items():
                flat[f"{key}_{k}"] = v
        elif not isinstance(value, list):
            flat[key] = value
    with open(filename, 'w', newline='') as f:
        writer = csv.DictWriter(f, fieldnames=flat.keys())
        writer.writeheader()
        writer.writerow(flat)
    print(f"Stats saved to {filename}")
def main():
    parser = argparse.ArgumentParser(description="CLI System Stats Tool")
    parser.add_argument('--cpu', action='store_true', help='Show CPU stats')
    parser.add_argument('--memory', action='store_true', help='Show memory stats')
    parser.add_argument('--disk', action='store_true', help='Show disk stats')
    parser.add_argument('--network', action='store_true', help='Show network stats')
    parser.add_argument('--system', action='store_true', help='Show system info')
    parser.add_argument('--processes', action='store_true', help='Show top processes')
    parser.add_argument('--all', action='store_true', help='Show all stats')
    parser.add_argument('--sort', choices=['cpu', 'memory'], default='cpu', help='Sort processes by cpu or memory')
    parser.add_argument('--limit', type=int, default=10, help='Number of top processes to display')
    parser.add_argument('--export-json', type=str, metavar='FILE', help='Export stats to JSON file')
    parser.add_argument('--export-csv', type=str, metavar='FILE', help='Export stats to CSV file')
    args = parser.parse_args()
    print(f"\nCLI Stats Tool | {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    all_stats = {}
    if args.cpu or args.all:
        cpu = get_cpu_stats()
        display_table("CPU STATS", cpu)
        all_stats['cpu'] = cpu
    if args.memory or args.all:
        mem = get_memory_stats()
        display_table("MEMORY STATS", mem)
        all_stats['memory'] = mem
    if args.disk or args.all:
        disk = get_disk_stats()
        display_table("DISK STATS", disk)
        all_stats['disk'] = disk
    if args.network or args.all:
        net = get_network_stats()
        display_table("NETWORK STATS", net)
        all_stats['network'] = net
    if args.system or args.all:
        sys_info = get_system_stats()
        display_table("SYSTEM INFO", sys_info)
        all_stats['system'] = sys_info
    if args.processes or args.all:
        procs = get_process_stats(limit=args.limit, sort_by=args.sort)
        display_processes(procs)
        all_stats['processes'] = procs
    if not any([args.cpu, args.memory, args.disk, args.network, args.system, args.processes, args.all]):
        print("\nNo option selected. Use --help for usage information.")
    if args.export_json and all_stats:
        save_json(all_stats, args.export_json)
    if args.export_csv and all_stats:
        save_csv(all_stats, args.export_csv)
if __name__ == '__main__':
    main()

import statistics
import sys
def calculate_stats():
    user_input = input("Enter numbers separated by spaces: ")
    try:
        data = [float(x) for x in user_input.split()]
        if not data:
            print("No data provided.")
            return
        results = {
            "Count": len(data),
            "Min": min(data),
            "Max": max(data),
            "Mean": statistics.mean(data),
            "Median": statistics.median(data),
            "StDev": statistics.stdev(data) if len(data) > 1 else 0.0
        }
        print("-" * 20)
        for label, value in results.items():
            print(f"{label:<10}: {value:.2f}")
    except ValueError:
        print("Error: Please enter valid numbers only.")
if __name__ == "__main__":
    calculate_stats()

import os
import sys
import json
import csv
from datetime import datetime
from pathlib import Path
import statistics
class StatsAnalyzer:
    def __init__(self):
        self.data = []
        self.file_path = None
    def load_csv(self, file_path):
        try:
            self.file_path = file_path
            self.data = []
            with open(file_path, 'r', encoding='utf-8') as file:
                reader = csv.DictReader(file)
                for row in reader:
                    self.data.append(row)
            print(f"Loaded {len(self.data)} rows from {file_path}")
            return True
        except Exception as e:
            print(f"Error loading CSV: {str(e)}")
            return False
    def load_json(self, file_path):
        try:
            self.file_path = file_path
            with open(file_path, 'r', encoding='utf-8') as file:
                self.data = json.load(file)
            if isinstance(self.data, dict):
                self.data = [self.data]
            print(f"Loaded {len(self.data)} records from {file_path}")
            return True
        except Exception as e:
            print(f"Error loading JSON: {str(e)}")
            return False
    def get_column_names(self):
        if not self.data:
            return []
        if isinstance(self.data[0], dict):
            return list(self.data[0].keys())
        return []
    def get_column_values(self, column_name):
        values = []
        for row in self.data:
            if isinstance(row, dict) and column_name in row:
                try:
                    values.append(float(row[column_name]))
                except ValueError:
                    pass
        return values
    def get_numeric_stats(self, column_name):
        values = self.get_column_values(column_name)
        if not values:
            return None
        stats = {
            "column": column_name,
            "count": len(values),
            "min": min(values),
            "max": max(values),
            "sum": sum(values),
            "mean": statistics.mean(values),
            "median": statistics.median(values),
            "stdev": statistics.stdev(values) if len(values) > 1 else 0,
            "variance": statistics.variance(values) if len(values) > 1 else 0,
            "q1": self.calculate_quartile(values, 0.25),
            "q3": self.calculate_quartile(values, 0.75)
        }
        return stats
    def calculate_quartile(self, sorted_values, quartile):
        sorted_values = sorted(sorted_values)
        index = quartile * (len(sorted_values) - 1)
        lower = int(index)
        upper = lower + 1
        weight = index - lower
        if upper >= len(sorted_values):
            return sorted_values[lower]
        return sorted_values[lower] * (1 - weight) + sorted_values[upper] * weight
    def get_all_stats(self):
        columns = self.get_column_names()
        all_stats = {}
        for column in columns:
            stats = self.get_numeric_stats(column)
            if stats:
                all_stats[column] = stats
        return all_stats
    def get_unique_values(self, column_name):
        unique_vals = set()
        for row in self.data:
            if isinstance(row, dict) and column_name in row:
                unique_vals.add(row[column_name])
        return sorted(list(unique_vals))
    def get_value_counts(self, column_name):
        counts = {}
        for row in self.data:
            if isinstance(row, dict) and column_name in row:
                value = row[column_name]
                counts[value] = counts.get(value, 0) + 1
        return dict(sorted(counts.items(), key=lambda x: x[1], reverse=True))
    def filter_data(self, column_name, value):
        filtered = []
        for row in self.data:
            if isinstance(row, dict) and row.get(column_name) == value:
                filtered.append(row)
        return filtered
    def filter_numeric(self, column_name, min_val=None, max_val=None):
        filtered = []
        for row in self.data:
            if isinstance(row, dict) and column_name in row:
                try:
                    val = float(row[column_name])
                    if (min_val is None or val >= min_val) and (max_val is None or val <= max_val):
                        filtered.append(row)
                except ValueError:
                    pass
        return filtered
    def group_by(self, column_name):
        groups = {}
        for row in self.data:
            if isinstance(row, dict) and column_name in row:
                key = row[column_name]
                if key not in groups:
                    groups[key] = []
                groups[key].append(row)
        return groups
    def get_group_stats(self, group_column, numeric_column):
        groups = self.group_by(group_column)
        group_stats = {}
        for group_name, group_rows in groups.items():
            values = []
            for row in group_rows:
                try:
                    values.append(float(row[numeric_column]))
                except (ValueError, KeyError):
                    pass
            if values:
                group_stats[group_name] = {
                    "count": len(values),
                    "mean": statistics.mean(values),
                    "median": statistics.median(values),
                    "min": min(values),
                    "max": max(values),
                    "sum": sum(values)
                }
        return group_stats
    def get_correlation(self, col1, col2):
        vals1 = self.get_column_values(col1)
        vals2 = self.get_column_values(col2)
        if len(vals1) != len(vals2) or len(vals1) < 2:
            return None
        mean1 = statistics.mean(vals1)
        mean2 = statistics.mean(vals2)
        numerator = sum((vals1[i] - mean1) * (vals2[i] - mean2) for i in range(len(vals1)))
        denom1 = sum((v - mean1) ** 2 for v in vals1)
        denom2 = sum((v - mean2) ** 2 for v in vals2)
        denominator = (denom1 * denom2) ** 0.5
        if denominator == 0:
            return 0
        return numerator / denominator
    def export_stats(self, output_file, stats_dict):
        try:
            with open(output_file, 'w', encoding='utf-8') as file:
                json.dump(stats_dict, file, indent=2)
            print(f"Stats exported to {output_file}")
            return True
        except Exception as e:
            print(f"Error exporting stats: {str(e)}")
            return False
    def display_summary(self):
        if not self.data:
            print("No data loaded")
            return
        print("\n" + "="*80)
        print("DATA SUMMARY")
        print("="*80)
        print(f"File: {self.file_path}")
        print(f"Total Records: {len(self.data)}")
        columns = self.get_column_names()
        print(f"Total Columns: {len(columns)}")
        print(f"Columns: {', '.join(columns[:10])}")
        if len(columns) > 10:
            print(f"... and {len(columns) - 10} more columns")
        print("="*80 + "\n")
    def display_column_stats(self, column_name):
        stats = self.get_numeric_stats(column_name)
        if not stats:
            print(f"No numeric data found in column '{column_name}'")
            return
        print("\n" + "="*80)
        print(f"STATISTICS FOR: {column_name}")
        print("="*80)
        print(f"Count: {stats['count']}")
        print(f"Min: {stats['min']:.2f}")
        print(f"Max: {stats['max']:.2f}")
        print(f"Mean: {stats['mean']:.2f}")
        print(f"Median: {stats['median']:.2f}")
        print(f"Std Dev: {stats['stdev']:.2f}")
        print(f"Variance: {stats['variance']:.2f}")
        print(f"Q1 (25%): {stats['q1']:.2f}")
        print(f"Q3 (75%): {stats['q3']:.2f}")
        print(f"Sum: {stats['sum']:.2f}")
        print("="*80 + "\n")
    def display_value_counts(self, column_name, limit=20):
        counts = self.get_value_counts(column_name)
        if not counts:
            print(f"No data found in column '{column_name}'")
            return
        print("\n" + "="*80)
        print(f"VALUE COUNTS FOR: {column_name}")
        print("="*80)
        print(f"{'Value':<40} {'Count':<15} {'Percentage':<15}")
        print("-"*80)
        total = sum(counts.values())
        for idx, (value, count) in enumerate(counts.items()):
            if idx >= limit:
                break
            percentage = (count / total) * 100
            print(f"{str(value):<40} {count:<15} {percentage:<15.2f}%")
        if len(counts) > limit:
            print(f"... and {len(counts) - limit} more values")
        print("="*80 + "\n")
    def display_group_stats(self, group_column, numeric_column):
        group_stats = self.get_group_stats(group_column, numeric_column)
        if not group_stats:
            print(f"No data found")
            return
        print("\n" + "="*100)
        print(f"GROUP STATISTICS: {group_column} (by {numeric_column})")
        print("="*100)
        print(f"{'Group':<30} {'Count':<10} {'Mean':<15} {'Median':<15} {'Min':<15} {'Max':<15}")
        print("-"*100)
        for group_name, stats in group_stats.items():
            print(f"{str(group_name):<30} {stats['count']:<10} {stats['mean']:<15.2f} {stats['median']:<15.2f} {stats['min']:<15.2f} {stats['max']:<15.2f}")
        print("="*100 + "\n")
    def display_all_stats(self):
        all_stats = self.get_all_stats()
        if not all_stats:
            print("No numeric columns found")
            return
        print("\n" + "="*100)
        print("ALL COLUMN STATISTICS")
        print("="*100)
        print(f"{'Column':<30} {'Count':<10} {'Mean':<15} {'Min':<15} {'Max':<15} {'Std Dev':<15}")
        print("-"*100)
        for column, stats in all_stats.items():
            print(f"{column:<30} {stats['count']:<10} {stats['mean']:<15.2f} {stats['min']:<15.2f} {stats['max']:<15.2f} {stats['stdev']:<15.2f}")
        print("="*100 + "\n")
def main():
    analyzer = StatsAnalyzer()
    while True:
        print("\n" + "="*60)
        print("CLI STATISTICS TOOL")
        print("="*60)
        print("1. Load CSV file")
        print("2. Load JSON file")
        print("3. Display data summary")
        print("4. Display all statistics")
        print("5. Display column statistics")
        print("6. Display value counts")
        print("7. Group by and analyze")
        print("8. Calculate correlation")
        print("9. Filter by value")
        print("10. Filter by numeric range")
        print("11. Get unique values")
        print("12. Export statistics")
        print("13. Exit")
        choice = input("\nSelect an option (1-13): ").strip()
        if choice == '1':
            file_path = input("Enter CSV file path: ").strip()
            analyzer.load_csv(file_path)
        elif choice == '2':
            file_path = input("Enter JSON file path: ").strip()
            analyzer.load_json(file_path)
        elif choice == '3':
            analyzer.display_summary()
        elif choice == '4':
            analyzer.display_all_stats()
        elif choice == '5':
            columns = analyzer.get_column_names()
            if columns:
                print("Available columns:")
                for idx, col in enumerate(columns, 1):
                    print(f"  {idx}. {col}")
                col_name = input("Enter column name: ").strip()
                analyzer.display_column_stats(col_name)
            else:
                print("No data loaded")
        elif choice == '6':
            columns = analyzer.get_column_names()
            if columns:
                print("Available columns:")
                for idx, col in enumerate(columns, 1):
                    print(f"  {idx}. {col}")
                col_name = input("Enter column name: ").strip()
                limit = input("Enter limit (default 20): ").strip()
                limit = int(limit) if limit else 20
                analyzer.display_value_counts(col_name, limit)
            else:
                print("No data loaded")
        elif choice == '7':
            columns = analyzer.get_column_names()
            if len(columns) >= 2:
                print("Available columns:")
                for idx, col in enumerate(columns, 1):
                    print(f"  {idx}. {col}")
                group_col = input("Enter group column: ").strip()
                numeric_col = input("Enter numeric column: ").strip()
                analyzer.display_group_stats(group_col, numeric_col)
            else:
                print("Need at least 2 columns")
