import subprocess
import shlex
import platform
import os
import json
from datetime import datetime
BLOCKED_COMMANDS = [
    "rm -rf /", "mkfs", "dd if=/dev/zero", ":(){:|:&};:",
    "chmod -R 777 /", "chown -R", "wget", "curl",
    "shutdown", "reboot", "halt", "poweroff"
]
COMMAND_HISTORY = []
def is_blocked(command):
    for blocked in BLOCKED_COMMANDS:
        if blocked.lower() in command.lower():
            return True
    return False
def log_command(command, result):
    entry = {
        "id": len(COMMAND_HISTORY) + 1,
        "command": command,
        "return_code": result.get("return_code"),
        "success": result.get("success"),
        "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    COMMAND_HISTORY.append(entry)
def execute_command(command):
    if not command.strip():
        return {"success": False, "error": "Empty command provided"}
    if is_blocked(command):
        return {"success": False, "error": f"Command '{command}' is blocked for safety reasons"}
    system = platform.system()
    try:
        if system == "Windows":
            process = subprocess.Popen(
                command,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=True,
                text=True,
                cwd=os.getcwd()
            )
        else:
            args = shlex.split(command)
            process = subprocess.Popen(
                args,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=False,
                text=True,
                cwd=os.getcwd()
            )
        stdout, stderr = process.communicate(timeout=30)
        result = {
            "command": command,
            "return_code": process.returncode,
            "stdout": stdout.strip(),
            "stderr": stderr.strip(),
            "success": process.returncode == 0,
            "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        log_command(command, result)
        return result
    except subprocess.TimeoutExpired:
        process.kill()
        result = {"command": command, "return_code": -1, "success": False, "error": "Command timed out after 30 seconds"}
        log_command(command, result)
        return result
    except FileNotFoundError:
        result = {"command": command, "return_code": -1, "success": False, "error": f"Command not found: {command.split()[0]}"}
        log_command(command, result)
        return result
    except PermissionError:
        result = {"command": command, "return_code": -1, "success": False, "error": "Permission denied"}
        log_command(command, result)
        return result
    except Exception as e:
        result = {"command": command, "return_code": -1, "success": False, "error": str(e)}
        log_command(command, result)
        return result
def display_result(result):
    print("\n" + "=" * 60)
    print(f"  Command   : {result.get('command')}")
    print(f"  Timestamp : {result.get('timestamp', 'N/A')}")
    print(f"  Status    : {'Success' if result.get('success') else 'Failed'}")
    if 'return_code' in result:
        print(f"  Return Code: {result.get('return_code')}")
    if result.get('stdout'):
        print(f"\n  Output:")
        for line in result['stdout'].splitlines():
            print(f"    {line}")
    if result.get('stderr'):
        print(f"\n  Error Output:")
        for line in result['stderr'].splitlines():
            print(f"    {line}")
    if result.get('error'):
        print(f"\n  Error: {result.get('error')}")
    print("=" * 60)
def display_history():
    if not COMMAND_HISTORY:
        print("\n  No command history available.")
        return
    print("\n" + "=" * 70)
    print("  COMMAND HISTORY")
    print("=" * 70)
    print(f"  {'ID':<6} {'Command':<30} {'Status':<10} {'Timestamp':<20}")
    print("  " + "-" * 68)
    for entry in COMMAND_HISTORY:
        status = "Success" if entry['success'] else "Failed"
        print(f"  {entry['id']:<6} {entry['command']:<30} {status:<10} {entry['timestamp']:<20}")
    print("=" * 70)
def interactive_shell():
    print("\n" + "=" * 60)
    print("  Interactive Command Executor")
    print(f"  System : {platform.system()}")
    print(f"  CWD    : {os.getcwd()}")
    print("  Type 'exit' to quit | 'history' to view history")
    print("=" * 60)
    while True:
        try:
            command = input("\n> Enter command: ").strip()
            if command.lower() == 'exit':
                print("\n  Exiting shell. Goodbye!")
                break
            elif command.lower() == 'history':
                display_history()
            elif command.lower() == 'clear history':
                COMMAND_HISTORY.clear()
                print("\n  Command history cleared.")
            elif command.lower().startswith('cd '):
                path = command[3:].strip()
                try:
                    os.chdir(path)
                    print(f"\n  Changed directory to: {os.getcwd()}")
                except FileNotFoundError:
                    print(f"\n  Error: Directory '{path}' not found.")
                except PermissionError:
                    print(f"\n  Error: Permission denied to access '{path}'.")
            elif command:
                result = execute_command(command)
                display_result(result)
            else:
                print("\n  No command entered.")
        except KeyboardInterrupt:
            print("\n\n  KeyboardInterrupt received. Type 'exit' to quit.")
        except EOFError:
            print("\n  EOF received. Exiting.")
            break
if __name__ == '__main__':
    interactive_shell()

import subprocess
import shlex
def execute_user_command():
    user_input = input("Enter command to run (e.g., ls -l): ")
    try:
        args = shlex.split(user_input)
        if not args:
            return
        result = subprocess.run(
            args,
            capture_output=True,
            text=True,
            shell=False,
            timeout=10
        )
        if result.returncode == 0:
            print("--- Success ---")
            print(result.stdout)
        else:
            print("--- Error ---")
            print(result.stderr)
    except FileNotFoundError:
        print("Error: Command not found.")
    except subprocess.TimeoutExpired:
        print("Error: Command timed out.")
    except Exception as e:
        print(f"Unexpected error: {e}")
if __name__ == "__main__":
    execute_user_command()

import subprocess
import os
import sys
import platform
from datetime import datetime
from pathlib import Path
class CommandExecutor:
    def __init__(self):
        self.os_type = platform.system()
        self.command_history = []
        self.current_directory = os.getcwd()
        self.aliases = {}
        self.variables = {}
    def execute(self, command):
        try:
            result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=30, cwd=self.current_directory)
            output = result.stdout
            error = result.stderr
            return_code = result.returncode
            command_info = {
                "command": command,
                "output": output,
                "error": error,
                "return_code": return_code,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "cwd": self.current_directory
            }
            self.command_history.append(command_info)
            return command_info
        except subprocess.TimeoutExpired:
            error_info = {
                "command": command,
                "output": "",
                "error": "Command execution timed out",
                "return_code": -1,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "cwd": self.current_directory
            }
            self.command_history.append(error_info)
            return error_info
        except Exception as e:
            error_info = {
                "command": command,
                "output": "",
                "error": str(e),
                "return_code": -1,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "cwd": self.current_directory
            }
            self.command_history.append(error_info)
            return error_info
    def execute_with_input(self, command, input_data):
        try:
            result = subprocess.run(command, shell=True, input=input_data, capture_output=True, text=True, timeout=30, cwd=self.current_directory)
            output = result.stdout
            error = result.stderr
            return_code = result.returncode
            return {
                "command": command,
                "output": output,
                "error": error,
                "return_code": return_code,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
        except Exception as e:
            return {"error": str(e)}
    def execute_multiple(self, commands):
        results = []
        for command in commands:
            result = self.execute(command)
            results.append(result)
        return results
    def pipe_commands(self, commands):
        try:
            process = subprocess.Popen(commands[0], shell=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, cwd=self.current_directory)
            for command in commands[1:]:
                process = subprocess.Popen(command, shell=True, stdin=process.stdout, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
            stdout, stderr = process.communicate()
            return {
                "output": stdout,
                "error": stderr,
                "return_code": process.returncode
            }
        except Exception as e:
            return {"error": str(e)}
    def cd(self, path):
        try:
            if path == "~":
                path = os.path.expanduser("~")
            elif path == "..":
                path = os.path.dirname(self.current_directory)
            elif path == "-":
                print("Previous directory tracking not implemented")
                return False
            os.chdir(path)
            self.current_directory = os.getcwd()
            print(f"Changed directory to: {self.current_directory}")
            return True
        except FileNotFoundError:
            print(f"Directory not found: {path}")
            return False
        except Exception as e:
            print(f"Error: {str(e)}")
            return False
    def pwd(self):
        return self.current_directory
    def ls(self, path=None):
        if path is None:
            path = self.current_directory
        try:
            items = os.listdir(path)
            return sorted(items)
        except Exception as e:
            return None
    def mkdir(self, path):
        try:
            os.makedirs(path, exist_ok=True)
            print(f"Directory created: {path}")
            return True
        except Exception as e:
            print(f"Error: {str(e)}")
            return False
    def rm(self, path):
        try:
            if os.path.isfile(path):
                os.remove(path)
                print(f"File deleted: {path}")
            elif os.path.isdir(path):
                import shutil
                shutil.rmtree(path)
                print(f"Directory deleted: {path}")
            return True
        except Exception as e:
            print(f"Error: {str(e)}")
            return False
    def cp(self, source, destination):
        try:
            import shutil
            if os.path.isfile(source):
                shutil.copy2(source, destination)
            elif os.path.isdir(source):
                shutil.copytree(source, destination)
            print(f"Copied {source} to {destination}")
            return True
        except Exception as e:
            print(f"Error: {str(e)}")
            return False
    def mv(self, source, destination):
        try:
            import shutil
            shutil.move(source, destination)
            print(f"Moved {source} to {destination}")
            return True
        except Exception as e:
            print(f"Error: {str(e)}")
            return False
    def cat(self, file_path):
        try:
            with open(file_path, 'r', encoding='utf-8') as file:
                content = file.read()
            return content
        except Exception as e:
            return f"Error: {str(e)}"
    def echo(self, text):
        return text
    def find(self, directory, pattern):
        try:
            results = []
            for root, dirs, files in os.walk(directory):
                for file in files:
                    if pattern.lower() in file.lower():
                        results.append(os.path.join(root, file))
            return results
        except Exception as e:
            return []
    def grep(self, pattern, file_path):
        try:
            matching_lines = []
            with open(file_path, 'r', encoding='utf-8', errors='ignore') as file:
                for line_num, line in enumerate(file, 1):
                    if pattern.lower() in line.lower():
                        matching_lines.append(f"{line_num}: {line.rstrip()}")
            return matching_lines
        except Exception as e:
            return []
    def wc(self, file_path):
        try:
            with open(file_path, 'r', encoding='utf-8', errors='ignore') as file:
                lines = file.readlines()
                words = sum(len(line.split()) for line in lines)
                chars = sum(len(line) for line in lines)
            return {
                "lines": len(lines),
                "words": words,
                "characters": chars
            }
        except Exception as e:
            return {"error": str(e)}
    def head(self, file_path, n=10):
        try:
            with open(file_path, 'r', encoding='utf-8') as file:
                lines = file.readlines()[:n]
            return ''.join(lines)
        except Exception as e:
            return f"Error: {str(e)}"
    def tail(self, file_path, n=10):
        try:
            with open(file_path, 'r', encoding='utf-8') as file:
                lines = file.readlines()[-n:]
            return ''.join(lines)
        except Exception as e:
            return f"Error: {str(e)}"
    def set_alias(self, alias, command):
        self.aliases[alias] = command
        print(f"Alias set: {alias} -> {command}")
    def get_alias(self, alias):
        return self.aliases.get(alias)
    def expand_alias(self, command):
        parts = command.split(maxsplit=1)
        if parts[0] in self.aliases:
            return self.aliases[parts[0]] + (f" {parts[1]}" if len(parts) > 1 else "")
        return command
    def set_variable(self, name, value):
        self.variables[name] = value
        print(f"Variable set: ${name} = {value}")
    def get_variable(self, name):
        return self.variables.get(name)
    def expand_variables(self, command):
        for var_name, var_value in self.variables.items():
            command = command.replace(f"${var_name}", str(var_value))
        return command
    def get_command_history(self, limit=20):
        return self.command_history[-limit:]
    def clear_history(self):
        self.command_history = []
        print("Command history cleared")
    def display_output(self, result):
        print("\n" + "="*80)
        print(f"Command: {result['command']}")
        print(f"Status: {'Success' if result['return_code'] == 0 else 'Failed'} (Code: {result['return_code']})")
        print(f"Directory: {result['cwd']}")
        print(f"Time: {result['timestamp']}")
        print("="*80)
        if result['output']:
            print("OUTPUT:")
            print(result['output'])
        if result['error']:
            print("ERROR:")
            print(result['error'])
        print("="*80 + "\n")
    def display_history(self):
        if not self.command_history:
            print("No command history")
            return
        print("\n" + "="*100)
        print("COMMAND HISTORY")
        print("="*100)
        print(f"{'#':<5} {'Timestamp':<25} {'Command':<50} {'Status':<10}")
        print("-"*100)
        for idx, item in enumerate(self.command_history[-20:], 1):
            status = "Success" if item['return_code'] == 0 else "Failed"
            cmd = item['command'][:47] + "..." if len(item['command']) > 50 else item['command']
            print(f"{idx:<5} {item['timestamp']:<25} {cmd:<50} {status:<10}")
        print("="*100 + "\n")
def main():
    executor = CommandExecutor()
    print(f"System: {executor.os_type}")
    print(f"Current Directory: {executor.pwd()}")
    print("\nEnter 'help' for available commands or 'exit' to quit")
    while True:
        prompt = f"{executor.pwd()}> "
        try:
            user_input = input(prompt).strip()
            if not user_input:
                continue
            if user_input.lower() == 'exit':
                print("Exiting command executor. Goodbye!")
                break
            elif user_input.lower() == 'help':
                print("\n" + "="*60)
                print("AVAILABLE COMMANDS")
                print("="*60)
                print("cd <path>          - Change directory")
                print("pwd                - Print working directory")
                print("ls [path]          - List directory contents")
                print("mkdir <path>       - Create directory")
                print("rm <path>          - Remove file/directory")
                print("cp <src> <dst>     - Copy file/directory")
                print("mv <src> <dst>     - Move file/directory")
                print("cat <file>         - Display file contents")
                print("echo <text>        - Print text")
                print("find <dir> <pattern> - Find files")
                print("grep <pattern> <file> - Search in file")
                print("wc <file>          - Word/line/character count")
                print("head [n] <file>    - Show first n lines")
                print("tail [n] <file>    - Show last n lines")
                print("history            - Show command history")
                print("clear              - Clear history")
                print("alias <name> <cmd> - Set command alias")
                print("var <name> <value> - Set variable")
                print("status             - Show current status")
                print("help               - Show this help")
                print("exit               - Exit program")
                print("="*60 + "\n")
            elif user_input.lower().startswith('cd '):
                path = user_input[3:].strip()
                executor.cd(path)
            elif user_input.lower() == 'pwd':
                print(executor.pwd())
            elif user_input.lower().startswith('ls'):
                path = user_input[2:].strip() or None
                items = executor.ls(path)
                if items:
                    print(f"\nContents of {path or executor.pwd()}:")
                    for item in items[:50]:
                        print(f"  {item}")
                    if len(items) > 50:
                        print(f"  ... and {len(items) - 50} more items")
            elif user_input.lower().startswith('mkdir '):
                path = user_input[6:].strip()
                executor.mkdir(path)
            elif user_input.lower().startswith('rm '):
                path = user_input[3:].strip()
                confirm = input("Are you sure? (yes/no): ").strip().lower()
                if confirm == 'yes':
                    executor.rm(path)
            elif user_input.lower().startswith('cp '):
                parts = user_input[3:].strip().split(maxsplit=1)
                if len(parts) == 2:
                    executor.cp(parts[0], parts[1])
            elif user_input.lower().startswith('mv '):
                parts = user_input[3:].strip().split(maxsplit=1)
                if len(parts) == 2:
                    executor.mv(parts[0], parts[1])
            elif user_input.lower().startswith('cat '):
                file_path = user_input[4:].strip()
                content = executor.cat(file_path)
                print(content)
            elif user_input.lower().startswith('echo '):
                text = user_input[5:].strip()
                print(executor.echo(text))
            elif user_input.lower().startswith('find '):
                parts = user_input[5:].strip().split(maxsplit=1)
                if len(parts) == 2:
                    results = executor.find(parts[0], parts[1])
                    print(f"Found {len(results)} file(s):")
                    for result in results[:20]:
                        print(f"  {result}")
                    if len(results) > 20:
                        print(f"  ... and {len(results) - 20} more files")
            elif user_input.lower().startswith('grep '):
                parts = user_input[5:].strip().split(maxsplit=1)
                if len(parts) == 2:
                    results = executor.grep(parts[0], parts[1])
                    if results:
                        for line in results[:20]:
                            print(line)
                        if len(results) > 20:
                            print(f"... and {len(results) - 20} more matches")
            elif user_input.lower().startswith('wc '):
                file_path = user_input[3:].strip()
                counts = executor.wc(file_path)
                if "error" not in counts:
                    print(f"Lines: {counts['lines']}, Words: {counts['words']}, Characters: {counts['characters']}")
            elif user_input.lower().startswith('head'):
                parts = user_input.split()
                if len(parts) >= 2:
                    n = int(parts[1]) if len(parts) > 2 else 10
                    file_path = parts[-1]
                    content = executor.head(file_path, n)
                    print(content)
            elif user_input.lower().startswith('tail'):
                parts = user_input.split()
                if len(parts) >= 2:
                    n = int(parts[1]) if len(parts) > 2 else 10
                    file_path = parts[-1]
                    content = executor.tail(file_path, n)
                    print(content)
            elif user_input.lower() == 'history':
                executor.display_history()
            elif user_input.lower() == 'clear':
                executor.clear_history()
            elif user_input.lower().startswith('alias '):
                parts = user_input[6:].strip().split(maxsplit=1)
                if len(parts) == 2:
                    executor.set_alias(parts[0], parts[1])
            elif user_input.lower().startswith('var '):
                parts = user_input[4:].strip().split(maxsplit=1)
                if len(parts) == 2:
                    executor.set_variable(parts[0], parts[1])
            elif user_input.lower() == 'status':
                print("\n" + "="*60)
                print("SYSTEM STATUS")
                print("="*60)
                print(f"OS: {executor.os_type}")
                print(f"Current Directory: {executor.pwd()}")
                print(f"Aliases: {len(executor.aliases)}")
                print(f"Variables: {len(executor.variables)}")
                print(f"History: {len(executor.command_history)} commands")
                print("="*60 + "\n")
            else:
                expanded_command = executor.expand_alias(user_input)
                expanded_command = executor.expand_variables(expanded_command)
                result = executor.execute(expanded_command)
                executor.display_output(result)
        except KeyboardInterrupt:
            print("\n\nInterrupted by user")
        except Exception as e:
            print(f"Error: {str(e)}")
if __name__ == '__main__':
    main()

import shutil
