import os
import shutil
import zipfile
import schedule
import time
import json
import hashlib
from datetime import datetime
BACKUP_CONFIG = {
    "source_dirs": ["documents", "projects", "data"],
    "backup_dir": "backups",
    "max_backups": 5,
    "compress": True,
    "log_file": "backup_log.json",
    "schedule": {
        "daily": "02:00",
        "weekly": "sunday"
    }
}
backup_logs = []
def ensure_directories():
    os.makedirs(BACKUP_CONFIG['backup_dir'], exist_ok=True)
    for source in BACKUP_CONFIG['source_dirs']:
        os.makedirs(source, exist_ok=True)
def get_directory_hash(directory):
    hasher = hashlib.md5()
    for root, dirs, files in os.walk(directory):
        for file in sorted(files):
            file_path = os.path.join(root, file)
            try:
                with open(file_path, 'rb') as f:
                    hasher.update(f.read())
            except (PermissionError, FileNotFoundError):
                continue
    return hasher.hexdigest()
def get_directory_size(directory):
    total = 0
    for root, dirs, files in os.walk(directory):
        for file in files:
            file_path = os.path.join(root, file)
            try:
                total += os.path.getsize(file_path)
            except (PermissionError, FileNotFoundError):
                continue
    return total
def compress_backup(source_path, backup_path):
    zip_path = f"{backup_path}.zip"
    with zipfile.ZipFile(zip_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
        if os.path.isdir(source_path):
            for root, dirs, files in os.walk(source_path):
                for file in files:
                    file_path = os.path.join(root, file)
                    arcname = os.path.relpath(file_path, os.path.dirname(source_path))
                    zipf.write(file_path, arcname)
        else:
            zipf.write(source_path, os.path.basename(source_path))
    return zip_path
def copy_backup(source_path, backup_path):
    if os.path.isdir(source_path):
        shutil.copytree(source_path, backup_path)
    else:
        shutil.copy2(source_path, backup_path)
    return backup_path
def cleanup_old_backups(backup_dir, source_name, max_backups):
    backups = []
    for item in os.listdir(backup_dir):
        if item.startswith(source_name) and (item.endswith('.zip') or os.path.isdir(os.path.join(backup_dir, item))):
            backups.append(item)
    backups.sort()
    while len(backups) > max_backups:
        oldest = backups.pop(0)
        oldest_path = os.path.join(backup_dir, oldest)
        if os.path.isdir(oldest_path):
            shutil.rmtree(oldest_path)
        else:
            os.remove(oldest_path)
        print(f"  Removed old backup: {oldest}")
def log_backup(source, status, backup_path, details):
    entry = {
        "id": len(backup_logs) + 1,
        "source": source,
        "status": status,
        "backup_path": backup_path,
        "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "details": details
    }
    backup_logs.append(entry)
    with open(BACKUP_CONFIG['log_file'], 'w') as f:
        json.dump(backup_logs, f, indent=4)
    return entry
def backup_source(source):
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    source_name = os.path.basename(source)
    backup_name = f"{source_name}_{timestamp}"
    backup_path = os.path.join(BACKUP_CONFIG['backup_dir'], backup_name)
    print(f"\n  Backing up: {source}")
    if not os.path.exists(source):
        details = {"error": f"Source '{source}' does not exist"}
        log_backup(source, "failed", None, details)
        print(f"  Error: Source '{source}' not found")
        return False
    try:
        source_size = get_directory_size(source) if os.path.isdir(source) else os.path.getsize(source)
        source_hash = get_directory_hash(source) if os.path.isdir(source) else None
        if BACKUP_CONFIG['compress']:
            final_path = compress_backup(source, backup_path)
            backup_size = os.path.getsize(final_path)
        else:
            final_path = copy_backup(source, backup_path)
            backup_size = get_directory_size(final_path) if os.path.isdir(final_path) else os.path.getsize(final_path)
        cleanup_old_backups(BACKUP_CONFIG['backup_dir'], source_name, BACKUP_CONFIG['max_backups'])
        details = {
            "source_size": f"{source_size / (1024**2):.2f} MB",
            "backup_size": f"{backup_size / (1024**2):.2f} MB",
            "compressed": BACKUP_CONFIG['compress'],
            "source_hash": source_hash
        }
        log_entry = log_backup(source, "success", final_path, details)
        print(f"  Backup created: {final_path}")
        print(f"  Source Size   : {details['source_size']}")
        print(f"  Backup Size   : {details['backup_size']}")
        print(f"  Compressed    : {BACKUP_CONFIG['compress']}")
        return True
    except Exception as e:
        details = {"error": str(e)}
        log_backup(source, "failed", None, details)
        print(f"  Backup failed: {str(e)}")
        return False
def run_backup():
    print("\n" + "=" * 60)
    print(f"  AUTOMATED BACKUP STARTED")
    print(f"  Timestamp: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 60)
    ensure_directories()
    success_count = 0
    failed_count = 0
    for source in BACKUP_CONFIG['source_dirs']:
        if backup_source(source):
            success_count += 1
        else:
            failed_count += 1
    print("\n" + "=" * 60)
    print(f"  BACKUP SUMMARY")
    print(f"  Total Sources : {len(BACKUP_CONFIG['source_dirs'])}")
    print(f"  Successful    : {success_count}")
    print(f"  Failed        : {failed_count}")
    print(f"  Completed At  : {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 60)
def display_backup_logs():
    if not backup_logs:
        print("\n  No backup logs available.")
        return
    print("\n" + "=" * 80)
    print("  BACKUP LOGS")
    print("=" * 80)
    print(f"  {'ID':<5} {'Source':<20} {'Status':<10} {'Timestamp':<22} {'Details'}")
    print("  " + "-" * 78)
    for log in backup_logs:
        details_str = ', '.join([f"{k}: {v}" for k, v in log['details'].items()])
        print(f"  {log['id']:<5} {log['source']:<20} {log['status']:<10} {log['timestamp']:<22} {details_str}")
    print("=" * 80)
def schedule_backups():
    print("\n" + "=" * 60)
    print("  BACKUP SCHEDULER STARTED")
    print(f"  Daily Backup  : {BACKUP_CONFIG['schedule']['daily']}")
    print(f"  Weekly Backup : Every {BACKUP_CONFIG['schedule']['weekly'].capitalize()}")
    print("  Press Ctrl+C to stop scheduler")
    print("=" * 60)
    schedule.every().day.at(BACKUP_CONFIG['schedule']['daily']).do(run_backup)
    schedule.every().sunday.at("03:00").do(run_backup)
    while True:
        try:
            schedule.run_pending()
            time.sleep(60)
        except KeyboardInterrupt:
            print("\n\n  Scheduler stopped.")
            break
run_backup()
display_backup_logs()
print("\n  Starting scheduler... Press Ctrl+C to stop.")
schedule_backups()

import os
import shutil
import zipfile
import tarfile
import schedule
import time
from datetime import datetime
from pathlib import Path
import json
class BackupAutomation:
    def __init__(self, config_file=None):
        self.backup_tasks = []
        self.backup_history = []
        self.config_file = config_file
        self.backup_settings = {
            "backup_directory": "./automated_backups",
            "retention_days": 30,
            "compression_type": "zip",
            "max_backups_per_source": 10
        }
        if config_file and os.path.exists(config_file):
            self.load_config(config_file)
        else:
            self.create_default_backup_directory()
    def create_default_backup_directory(self):
        if not os.path.exists(self.backup_settings["backup_directory"]):
            os.makedirs(self.backup_settings["backup_directory"])
    def load_config(self, config_file):
        try:
            with open(config_file, 'r') as file:
                config = json.load(file)
            self.backup_settings.update(config.get("settings", {}))
            self.backup_tasks = config.get("tasks", [])
            self.create_default_backup_directory()
            print(f"Config loaded from {config_file}")
        except Exception as e:
            print(f"Error loading config: {str(e)}")
    def save_config(self, config_file):
        try:
            config = {
                "settings": self.backup_settings,
                "tasks": self.backup_tasks
            }
            with open(config_file, 'w') as file:
                json.dump(config, file, indent=2)
            print(f"Config saved to {config_file}")
        except Exception as e:
            print(f"Error saving config: {str(e)}")
    def add_backup_task(self, task_name, source_path, schedule_time, compression_type="zip"):
        if not os.path.exists(source_path):
            print(f"Error: Source path does not exist: {source_path}")
            return False
        task = {
            "task_name": task_name,
            "source_path": source_path,
            "schedule_time": schedule_time,
            "compression_type": compression_type,
            "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "last_backup": None,
            "enabled": True
        }
        self.backup_tasks.append(task)
        print(f"Backup task added: {task_name}")
        return True
    def remove_backup_task(self, task_name):
        self.backup_tasks = [task for task in self.backup_tasks if task["task_name"] != task_name]
        print(f"Backup task removed: {task_name}")
    def backup_to_zip(self, source_path, destination_path):
        try:
            with zipfile.ZipFile(destination_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
                if os.path.isfile(source_path):
                    zipf.write(source_path, arcname=os.path.basename(source_path))
                else:
                    for root, dirs, files in os.walk(source_path):
                        for file in files:
                            file_path = os.path.join(root, file)
                            arcname = os.path.relpath(file_path, source_path)
                            zipf.write(file_path, arcname=arcname)
            return True
        except Exception as e:
            print(f"Error creating ZIP backup: {str(e)}")
            return False
    def backup_to_tar(self, source_path, destination_path, compress=True):
        try:
            mode = "w:gz" if compress else "w"
            with tarfile.open(destination_path, mode) as tar:
                tar.add(source_path, arcname=os.path.basename(source_path))
            return True
        except Exception as e:
            print(f"Error creating TAR backup: {str(e)}")
            return False
    def backup_to_directory(self, source_path, destination_path):
        try:
            if os.path.exists(destination_path):
                shutil.rmtree(destination_path)
            shutil.copytree(source_path, destination_path)
            return True
        except Exception as e:
            print(f"Error creating directory backup: {str(e)}")
            return False
    def execute_backup(self, task):
        source_path = task["source_path"]
        compression_type = task.get("compression_type", "zip")
        task_name = task["task_name"]
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        backup_dir = self.backup_settings["backup_directory"]
        task_backup_dir = os.path.join(backup_dir, task_name)
        if not os.path.exists(task_backup_dir):
            os.makedirs(task_backup_dir)
        if compression_type == "zip":
            backup_file = os.path.join(task_backup_dir, f"{task_name}_{timestamp}.zip")
            success = self.backup_to_zip(source_path, backup_file)
        elif compression_type == "tar":
            backup_file = os.path.join(task_backup_dir, f"{task_name}_{timestamp}.tar.gz")
            success = self.backup_to_tar(source_path, backup_file, compress=True)
        elif compression_type == "directory":
            backup_file = os.path.join(task_backup_dir, f"{task_name}_{timestamp}")
            success = self.backup_to_directory(source_path, backup_file)
        else:
            print(f"Unknown compression type: {compression_type}")
            return None
        if success:
            file_size = os.path.getsize(backup_file) if os.path.isfile(backup_file) else 0
            backup_record = {
                "task_name": task_name,
                "backup_file": backup_file,
                "backup_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "file_size": file_size,
                "status": "success"
            }
            self.backup_history.append(backup_record)
            task["last_backup"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            print(f"Backup completed: {task_name}")
            return backup_record
        else:
            backup_record = {
                "task_name": task_name,
                "backup_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "status": "failed"
            }
            self.backup_history.append(backup_record)
            print(f"Backup failed: {task_name}")
            return None
    def cleanup_old_backups(self, task_name=None):
        backup_dir = self.backup_settings["backup_directory"]
        retention_days = self.backup_settings["retention_days"]
        max_backups = self.backup_settings["max_backups_per_source"]
        cutoff_time = time.time() - (retention_days * 86400)
        deleted_count = 0
        if task_name:
            task_dirs = [os.path.join(backup_dir, task_name)]
        else:
            task_dirs = [os.path.join(backup_dir, d) for d in os.listdir(backup_dir) if os.path.isdir(os.path.join(backup_dir, d))]
        for task_dir in task_dirs:
            if not os.path.exists(task_dir):
                continue
            backups = sorted([(f, os.path.getmtime(os.path.join(task_dir, f))) for f in os.listdir(task_dir)], key=lambda x: x[1], reverse=True)
            for backup_file, mod_time in backups:
                backup_path = os.path.join(task_dir, backup_file)
                if mod_time < cutoff_time or len(backups) > max_backups:
                    try:
                        if os.path.isfile(backup_path):
                            os.remove(backup_path)
                        elif os.path.isdir(backup_path):
                            shutil.rmtree(backup_path)
                        deleted_count += 1
                    except Exception as e:
                        print(f"Error deleting backup: {str(e)}")
        return deleted_count
    def schedule_backup(self, task):
        if not task.get("enabled", True):
            return
        schedule_time = task["schedule_time"]
        schedule.every().day.at(schedule_time).do(self.execute_backup, task)
        print(f"Backup scheduled for {task['task_name']} at {schedule_time}")
    def schedule_cleanup(self, cleanup_time="02:00"):
        schedule.every().day.at(cleanup_time).do(self.cleanup_old_backups)
        print(f"Cleanup scheduled at {cleanup_time}")
    def get_backup_status(self):
        status = {
            "total_tasks": len(self.backup_tasks),
            "enabled_tasks": len([t for t in self.backup_tasks if t.get("enabled", True)]),
            "total_backups": len(self.backup_history),
            "successful_backups": len([b for b in self.backup_history if b["status"] == "success"]),
            "failed_backups": len([b for b in self.backup_history if b["status"] == "failed"]),
            "total_size": sum(b.get("file_size", 0) for b in self.backup_history if b["status"] == "success")
        }
        return status
    def get_task_status(self, task_name):
        task = next((t for t in self.backup_tasks if t["task_name"] == task_name), None)
        if task:
            task_backups = [b for b in self.backup_history if b["task_name"] == task_name]
            return {
                "task_name": task_name,
                "enabled": task.get("enabled", True),
                "schedule": task["schedule_time"],
                "source": task["source_path"],
                "last_backup": task.get("last_backup"),
                "total_backups": len(task_backups),
                "recent_backups": task_backups[-5:]
            }
        return None
    def restore_backup(self, backup_file, restore_to_path):
        try:
            if backup_file.endswith('.zip'):
                with zipfile.ZipFile(backup_file, 'r') as zipf:
                    zipf.extractall(restore_to_path)
            elif backup_file.endswith('.tar.gz'):
                with tarfile.open(backup_file, 'r:gz') as tar:
                    tar.extractall(restore_to_path)
            print(f"Backup restored to {restore_to_path}")
            return True
        except Exception as e:
            print(f"Error restoring backup: {str(e)}")
            return False
    def run_scheduler(self):
        print("Starting backup scheduler...")
        for task in self.backup_tasks:
            self.schedule_backup(task)
        self.schedule_cleanup()
        try:
            while True:
                schedule.run_pending()
                time.sleep(60)
        except KeyboardInterrupt:
            print("\nScheduler stopped by user")
    def display_tasks(self):
        if not self.backup_tasks:
            print("No backup tasks configured")
            return
        print("\n" + "="*100)
        print("BACKUP TASKS")
        print("="*100)
        print(f"{'Task Name':<30} {'Source':<40} {'Schedule':<15} {'Status':<10}")
        print("-"*100)
        for task in self.backup_tasks:
            status = "Enabled" if task.get("enabled", True) else "Disabled"
            print(f"{task['task_name']:<30} {task['source_path']:<40} {task['schedule_time']:<15} {status:<10}")
        print("="*100 + "\n")
    def display_status(self):
        status = self.get_backup_status()
        print("\n" + "="*80)
        print("BACKUP STATUS")
        print("="*80)
        print(f"Total Tasks: {status['total_tasks']}")
        print(f"Enabled Tasks: {status['enabled_tasks']}")
        print(f"Total Backups: {status['total_backups']}")
        print(f"Successful: {status['successful_backups']}")
        print(f"Failed: {status['failed_backups']}")
        print(f"Total Size: {status['total_size'] / (1024**3):.2f} GB")
        print("="*80 + "\n")
    def display_history(self, limit=20):
        if not self.backup_history:
            print("No backup history")
            return
        print("\n" + "="*100)
        print("BACKUP HISTORY")
        print("="*100)
        print(f"{'Task':<30} {'Time':<25} {'Status':<10} {'Size':<15}")
        print("-"*100)
        for record in self.backup_history[-limit:]:
            size_str = f"{record.get('file_size', 0) / (1024**2):.2f} MB" if record.get("file_size") else "N/A"
            print(f"{record['task_name']:<30} {record['backup_time']:<25} {record['status']:<10} {size_str:<15}")
        print("="*100 + "\n")
def main():
    automation = BackupAutomation()
    while True:
        print("\n" + "="*60)
        print("BACKUP AUTOMATION TOOL")
        print("="*60)
        print("1. Add backup task")
        print("2. Remove backup task")
        print("3. List backup tasks")
        print("4. Execute backup now")
        print("5. View backup status")
        print("6. View backup history")
        print("7. Cleanup old backups")
        print("8. Restore backup")
        print("9. Start scheduler")
        print("10. Load config")
        print("11. Save config")
        print("12. Task status")
        print("13. Exit")
        choice = input("\nSelect an option (1-13): ").strip()
        if choice == '1':
            task_name = input("Enter task name: ").strip()
            source_path = input("Enter source path: ").strip()
            schedule_time = input("Enter schedule time (HH:MM): ").strip()
            compression = input("Enter compression type (zip/tar/directory): ").strip() or "zip"
            automation.add_backup_task(task_name, source_path, schedule_time, compression)
        elif choice == '2':
            task_name = input("Enter task name to remove: ").strip()
            automation.remove_backup_task(task_name)
        elif choice == '3':
            automation.display_tasks()
        elif choice == '4':
            automation.display_tasks()
            task_name = input("Enter task name to backup now: ").strip()
            task = next((t for t in automation.backup_tasks if t["task_name"] == task_name), None)
            if task:
                automation.execute_backup(task)
            else:
                print("Task not found")
        elif choice == '5':
            automation.display_status()
        elif choice == '6':
            limit = input("Enter number of records to display (default 20): ").strip()
            limit = int(limit) if limit else 20
            automation.display_history(limit)
        elif choice == '7':
            deleted = automation.cleanup_old_backups()
            print(f"Deleted {deleted} old backup(s)")
        elif choice == '8':
            backup_file = input("Enter backup file path: ").strip()
            restore_path = input("Enter restore destination: ").strip()
            automation.restore_backup(backup_file, restore_path)
        elif choice == '9':
            automation.run_scheduler()
        elif choice == '10':
            config_file = input("Enter config file path: ").strip()
            automation.load_config(config_file)
        elif choice == '11':
            config_file = input("Enter config file path to save: ").strip() or "backup_config.json"
            automation.save_config(config_file)
        elif choice == '12':
            task_name = input("Enter task name: ").strip()
            task_status = automation.get_task_status(task_name)
            if task_status:
                print("\n" + "="*80)
                print("TASK STATUS")
                print("="*80)
                for key, value in task_status.items():
                    print(f"{key}: {value}")
                print("="*80)
            else:
                print("Task not found")
        elif choice == '13':
            print("Exiting Backup Automation. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-13.")
if __name__ == '__main__':
    main()

import schedule
import time
import datetime
def job():
    print(f"Task executed at: {datetime.datetime.now().strftime('%H:%M:%S')}")
def start_scheduler():
    schedule.every(10).seconds.do(job)
    schedule.every().hour.do(job)
    schedule.every().day.at("10:30").do(job)
    schedule.every().monday.do(job)
    print("Scheduler started. Press Ctrl+C to stop.")
    try:
        while True:
            schedule.run_pending()
            time.sleep(1)
    except KeyboardInterrupt:
        print("Scheduler stopped.")
if __name__ == "__main__":
    start_scheduler()

