import psutil
import platform
from datetime import datetime
from collections import defaultdict
class ProcessLister:
    def __init__(self):
        self.os_type = platform.system()
        self.process_cache = []
    def get_all_processes(self):
        processes = []
        for proc in psutil.process_iter(['pid', 'name', 'status', 'username', 'memory_percent', 'cpu_percent', 'num_threads']):
            try:
                pinfo = proc.as_dict(attrs=['pid', 'name', 'status', 'username', 'memory_percent', 'cpu_percent', 'num_threads'])
                processes.append(pinfo)
            except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
                pass
        self.process_cache = processes
        return processes
    def get_process_details(self, pid):
        try:
            proc = psutil.Process(pid)
            details = {
                "pid": proc.pid,
                "name": proc.name(),
                "status": proc.status(),
                "create_time": datetime.fromtimestamp(proc.create_time()).strftime("%Y-%m-%d %H:%M:%S"),
                "memory_info": {
                    "rss": proc.memory_info().rss / (1024**2),
                    "vms": proc.memory_info().vms / (1024**2)
                },
                "memory_percent": proc.memory_percent(),
                "cpu_num": proc.cpu_num(),
                "cpu_percent": proc.cpu_percent(interval=1),
                "num_threads": proc.num_threads(),
                "num_fds": proc.num_fds() if self.os_type != "Windows" else "N/A",
                "parent_pid": proc.ppid(),
                "username": proc.username(),
                "cwd": proc.cwd(),
                "exe": proc.exe(),
                "cmdline": " ".join(proc.cmdline())
            }
            return details
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
        except Exception as e:
            return {"error": str(e)}
    def get_processes_by_name(self, name):
        results = []
        for proc in psutil.process_iter(['pid', 'name', 'memory_percent', 'cpu_percent']):
            try:
                if name.lower() in proc.info['name'].lower():
                    results.append(proc.as_dict(attrs=['pid', 'name', 'memory_percent', 'cpu_percent']))
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return results
    def get_processes_by_user(self, username):
        results = []
        for proc in psutil.process_iter(['pid', 'name', 'username', 'memory_percent']):
            try:
                if proc.info['username'] and username.lower() in proc.info['username'].lower():
                    results.append(proc.as_dict(attrs=['pid', 'name', 'username', 'memory_percent']))
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return results
    def get_top_processes_by_memory(self, limit=10):
        processes = self.get_all_processes()
        sorted_procs = sorted(processes, key=lambda x: x['memory_percent'], reverse=True)
        return sorted_procs[:limit]
    def get_top_processes_by_cpu(self, limit=10):
        processes = self.get_all_processes()
        sorted_procs = sorted(processes, key=lambda x: x['cpu_percent'], reverse=True)
        return sorted_procs[:limit]
    def get_processes_by_status(self, status):
        processes = self.get_all_processes()
        filtered = [p for p in processes if p['status'] == status]
        return filtered
    def get_running_processes(self):
        return self.get_processes_by_status(psutil.STATUS_RUNNING)
    def get_sleeping_processes(self):
        return self.get_processes_by_status(psutil.STATUS_SLEEPING)
    def get_zombie_processes(self):
        return self.get_processes_by_status(psutil.STATUS_ZOMBIE)
    def search_processes(self, keyword):
        processes = self.get_all_processes()
        results = []
        for proc in processes:
            if keyword.lower() in proc['name'].lower():
                results.append(proc)
        return results
    def get_process_children(self, pid):
        try:
            proc = psutil.Process(pid)
            children = proc.children(recursive=True)
            child_list = []
            for child in children:
                try:
                    child_list.append({
                        "pid": child.pid,
                        "name": child.name(),
                        "status": child.status()
                    })
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass
            return child_list
        except psutil.NoSuchProcess:
            return []
    def get_process_parent(self, pid):
        try:
            proc = psutil.Process(pid)
            parent = proc.parent()
            if parent:
                return {
                    "pid": parent.pid,
                    "name": parent.name()
                }
            return None
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            return None
    def get_process_tree(self, pid=None):
        if pid is None:
            pid = 1 if self.os_type != "Windows" else None
        try:
            if pid:
                proc = psutil.Process(pid)
            else:
                proc = psutil.Process(os.getpid())
            tree = {
                "pid": proc.pid,
                "name": proc.name(),
                "children": []
            }
            for child in proc.children(recursive=True):
                try:
                    tree["children"].append({
                        "pid": child.pid,
                        "name": child.name()
                    })
                except (psutil.NoSuchProcess, psutil.AccessDenied):
                    pass
            return tree
        except psutil.NoSuchProcess:
            return {"error": f"Process {pid} not found"}
    def get_process_connections(self, pid):
        try:
            proc = psutil.Process(pid)
            connections = proc.net_connections()
            conn_list = []
            for conn in connections:
                conn_list.append({
                    "family": str(conn.family),
                    "type": str(conn.type),
                    "laddr": conn.laddr,
                    "raddr": conn.raddr,
                    "status": conn.status
                })
            return conn_list
        except psutil.NoSuchProcess:
            return []
        except Exception:
            return []
    def get_process_open_files(self, pid):
        try:
            proc = psutil.Process(pid)
            open_files = proc.open_files()
            files = []
            for file_obj in open_files:
                files.append({
                    "path": file_obj.path,
                    "mode": file_obj.mode
                })
            return files
        except psutil.NoSuchProcess:
            return []
        except Exception:
            return []
    def get_process_environment(self, pid):
        try:
            proc = psutil.Process(pid)
            environ = proc.environ()
            return environ
        except psutil.NoSuchProcess:
            return {}
        except Exception:
            return {}
    def group_processes_by_status(self):
        processes = self.get_all_processes()
        grouped = defaultdict(list)
        for proc in processes:
            grouped[proc['status']].append(proc)
        return dict(grouped)
    def group_processes_by_user(self):
        processes = self.get_all_processes()
        grouped = defaultdict(list)
        for proc in processes:
            user = proc.get('username', 'Unknown')
            grouped[user].append(proc)
        return dict(grouped)
    def get_memory_usage_by_process(self):
        processes = self.get_all_processes()
        memory_usage = []
        for proc in processes:
            memory_usage.append({
                "pid": proc['pid'],
                "name": proc['name'],
                "memory_percent": proc['memory_percent'],
                "memory_mb": proc['memory_percent'] * psutil.virtual_memory().total / (100 * 1024**2)
            })
        return sorted(memory_usage, key=lambda x: x['memory_percent'], reverse=True)
    def get_cpu_usage_by_process(self):
        processes = self.get_all_processes()
        cpu_usage = []
        for proc in processes:
            if proc['cpu_percent'] > 0:
                cpu_usage.append({
                    "pid": proc['pid'],
                    "name": proc['name'],
                    "cpu_percent": proc['cpu_percent']
                })
        return sorted(cpu_usage, key=lambda x: x['cpu_percent'], reverse=True)
    def display_all_processes(self, limit=20, sort_by='name'):
        processes = self.get_all_processes()
        if sort_by == 'memory':
            processes = sorted(processes, key=lambda x: x['memory_percent'], reverse=True)
        elif sort_by == 'cpu':
            processes = sorted(processes, key=lambda x: x['cpu_percent'], reverse=True)
        else:
            processes = sorted(processes, key=lambda x: x['name'])
        print("\n" + "="*130)
        print(f"ALL PROCESSES (showing {min(limit, len(processes))} of {len(processes)})")
        print("="*130)
        print(f"{'PID':<10} {'Name':<40} {'Status':<15} {'User':<20} {'Memory %':<15} {'CPU %':<10}")
        print("-"*130)
        for proc in processes[:limit]:
            user = proc.get('username', 'Unknown')[:19]
            print(f"{proc['pid']:<10} {proc['name']:<40} {proc['status']:<15} {user:<20} {proc['memory_percent']:<15.2f} {proc['cpu_percent']:<10.2f}")
        if len(processes) > limit:
            print(f"... and {len(processes) - limit} more processes")
        print("="*130 + "\n")
    def display_top_processes(self, limit=10, sort_by='memory'):
        if sort_by == 'memory':
            processes = self.get_top_processes_by_memory(limit)
            title = "TOP PROCESSES BY MEMORY"
        else:
            processes = self.get_top_processes_by_cpu(limit)
            title = "TOP PROCESSES BY CPU"
        print("\n" + "="*100)
        print(title)
        print("="*100)
        print(f"{'Rank':<5} {'PID':<10} {'Name':<40} {'Memory %':<15} {'CPU %':<10}")
        print("-"*100)
        for idx, proc in enumerate(processes, 1):
            print(f"{idx:<5} {proc['pid']:<10} {proc['name']:<40} {proc['memory_percent']:<15.2f} {proc['cpu_percent']:<10.2f}")
        print("="*100 + "\n")
    def display_process_details(self, pid):
        details = self.get_process_details(pid)
        print("\n" + "="*80)
        print("PROCESS DETAILS")
        print("="*80)
        for key, value in details.items():
            if key != "memory_info":
                print(f"{key}: {value}")
        if "memory_info" in details:
            print("\nMemory Info:")
            for key, value in details["memory_info"].items():
                print(f"  {key}: {value:.2f} MB")
        print("="*80 + "\n")
    def display_processes_by_status(self):
        grouped = self.group_processes_by_status()
        print("\n" + "="*80)
        print("PROCESSES BY STATUS")
        print("="*80)
        for status, procs in grouped.items():
            print(f"\n{status.upper()}: {len(procs)} process(es)")
            print("-"*80)
            for proc in procs[:5]:
                print(f"  {proc['pid']}: {proc['name']}")
            if len(procs) > 5:
                print(f"  ... and {len(procs) - 5} more")
        print("="*80 + "\n")
    def display_processes_by_user(self):
        grouped = self.group_processes_by_user()
        print("\n" + "="*80)
        print("PROCESSES BY USER")
        print("="*80)
        for user, procs in grouped.items():
            print(f"\n{user}: {len(procs)} process(es)")
            print("-"*80)
            for proc in procs[:5]:
                print(f"  {proc['pid']}: {proc['name']}")
            if len(procs) > 5:
                print(f"  ... and {len(procs) - 5} more")
        print("="*80 + "\n")
    def display_memory_usage(self, limit=10):
        memory_usage = self.get_memory_usage_by_process()
        print("\n" + "="*100)
        print("MEMORY USAGE BY PROCESS")
        print("="*100)
        print(f"{'Rank':<5} {'PID':<10} {'Name':<40} {'Memory %':<15} {'Memory MB':<15}")
        print("-"*100)
        for idx, proc in enumerate(memory_usage[:limit], 1):
            print(f"{idx:<5} {proc['pid']:<10} {proc['name']:<40} {proc['memory_percent']:<15.2f} {proc['memory_mb']:<15.2f}")
        print("="*100 + "\n")
    def display_cpu_usage(self, limit=10):
        cpu_usage = self.get_cpu_usage_by_process()
        print("\n" + "="*100)
        print("CPU USAGE BY PROCESS")
        print("="*100)
        print(f"{'Rank':<5} {'PID':<10} {'Name':<40} {'CPU %':<15}")
        print("-"*100)
        for idx, proc in enumerate(cpu_usage[:limit], 1):
            print(f"{idx:<5} {proc['pid']:<10} {proc['name']:<40} {proc['cpu_percent']:<15.2f}")
        print("="*100 + "\n")
def main():
    import os
    lister = ProcessLister()
    while True:
        print("\n" + "="*60)
        print("PROCESS LISTER")
        print("="*60)
        print("1. List all processes")
        print("2. List top processes (by memory)")
        print("3. List top processes (by CPU)")
        print("4. Search process by name")
        print("5. Get process details")
        print("6. List processes by status")
        print("7. List processes by user")
        print("8. Get process children")
        print("9. Display memory usage")
        print("10. Display CPU usage")
        print("11. Search by user")
        print("12. Exit")
        choice = input("\nSelect an option (1-12): ").strip()
        if choice == '1':
            limit = input("Enter number of processes (default 20): ").strip()
            limit = int(limit) if limit else 20
            sort = input("Sort by (name/memory/cpu, default name): ").strip() or 'name'
            lister.display_all_processes(limit, sort)
        elif choice == '2':
            limit = input("Enter number of top processes (default 10): ").strip()
            limit = int(limit) if limit else 10
            lister.display_top_processes(limit, 'memory')
        elif choice == '3':
            limit = input("Enter number of top processes (default 10): ").strip()
            limit = int(limit) if limit else 10
            lister.display_top_processes(limit, 'cpu')
        elif choice == '4':
            name = input("Enter process name to search: ").strip()
            results = lister.get_processes_by_name(name)
            if results:
                print(f"\nFound {len(results)} process(es):")
                print("="*80)
                for proc in results:
                    print(f"PID: {proc['pid']}, Name: {proc['name']}, Memory: {proc['memory_percent']:.2f}%")
                print("="*80)
            else:
                print("No processes found")
        elif choice == '5':
            pid = int(input("Enter PID: ").strip())
            lister.display_process_details(pid)
        elif choice == '6':
            lister.display_processes_by_status()
        elif choice == '7':
            lister.display_processes_by_user()
        elif choice == '8':
            pid = int(input("Enter parent PID: ").strip())
            children = lister.get_process_children(pid)
            if children:
                print(f"\nFound {len(children)} child process(es):")
                print("="*60)
                for child in children:
                    print(f"  PID: {child['pid']}, Name: {child['name']}, Status: {child['status']}")
                print("="*60)
            else:
                print("No child processes found")
        elif choice == '9':
            limit = input("Enter limit (default 10): ").strip()
            limit = int(limit) if limit else 10
            lister.display_memory_usage(limit)
        elif choice == '10':
            limit = input("Enter limit (default 10): ").strip()
            limit = int(limit) if limit else 10
            lister.display_cpu_usage(limit)
        elif choice == '11':
            username = input("Enter username: ").strip()
            results = lister.get_processes_by_user(username)
            if results:
                print(f"\nFound {len(results)} process(es) for user {username}:")
                print("="*80)
                for proc in results:
                    print(f"PID: {proc['pid']}, Name: {proc['name']}, Memory: {proc['memory_percent']:.2f}%")
                print("="*80)
            else:
                print("No processes found for this user")
        elif choice == '12':
            print("Exiting Process Lister. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-12.")
if __name__ == '__main__':
    main()

import psutil
import requests
def check_health(endpoints):
    stats = {
        "cpu": psutil.cpu_percent(interval=1),
        "memory": psutil.virtual_memory().percent,
        "disk": psutil.disk_usage('/').percent
    }
    print(f"--- System Stats ---")
    for key, val in stats.items():
        print(f"{key.upper()}: {val}%")
    print(f"\n--- Endpoint Status ---")
    for url in endpoints:
        try:
            resp = requests.get(url, timeout=5)
            status = "UP" if resp.status_code == 200 else f"DOWN ({resp.status_code})"
            print(f"{url}: {status}")
        except Exception:
            print(f"{url}: REACH_ERROR")
if __name__ == "__main__":
    urls = ["https://google.com", "https://github.com"]
    check_health(urls)

import requests
import socket
import subprocess
import psutil
import threading
from datetime import datetime
import time
import json
class ServerHealthChecker:
    def __init__(self):
        self.health_checks = []
        self.check_results = []
        self.monitoring_active = False
        self.monitoring_thread = None
    def add_health_check(self, check_name, check_type, target, port=None, timeout=5, interval=60):
        check = {
            "check_name": check_name,
            "check_type": check_type,
            "target": target,
            "port": port,
            "timeout": timeout,
            "interval": interval,
            "enabled": True,
            "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "last_check": None,
            "status": "unknown"
        }
        self.health_checks.append(check)
        print(f"Health check added: {check_name}")
        return check
    def remove_health_check(self, check_name):
        self.health_checks = [c for c in self.health_checks if c["check_name"] != check_name]
        print(f"Health check removed: {check_name}")
    def check_http_endpoint(self, url, timeout=5):
        try:
            start_time = time.time()
            response = requests.get(url, timeout=timeout)
            response_time = time.time() - start_time
            status_code = response.status_code
            if 200 <= status_code < 300:
                return {
                    "status": "healthy",
                    "status_code": status_code,
                    "response_time": response_time,
                    "response_size": len(response.content)
                }
            else:
                return {
                    "status": "unhealthy",
                    "status_code": status_code,
                    "response_time": response_time,
                    "error": f"HTTP {status_code}"
                }
        except requests.Timeout:
            return {"status": "unhealthy", "error": "Request timeout"}
        except requests.ConnectionError:
            return {"status": "unhealthy", "error": "Connection error"}
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}
    def check_tcp_port(self, host, port, timeout=5):
        try:
            start_time = time.time()
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            sock.settimeout(timeout)
            result = sock.connect_ex((host, port))
            response_time = time.time() - start_time
            sock.close()
            if result == 0:
                return {
                    "status": "healthy",
                    "response_time": response_time,
                    "message": f"Port {port} is open"
                }
            else:
                return {
                    "status": "unhealthy",
                    "error": f"Port {port} is closed"
                }
        except socket.gaierror:
            return {"status": "unhealthy", "error": "Hostname resolution failed"}
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}
    def check_ping(self, host, timeout=5):
        try:
            result = subprocess.run(["ping", "-c", "1", "-W", str(timeout), host], capture_output=True, text=True, timeout=timeout+2)
            if result.returncode == 0:
                return {"status": "healthy", "message": f"{host} is reachable"}
            else:
                return {"status": "unhealthy", "error": f"{host} is unreachable"}
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}
    def check_dns_resolution(self, hostname):
        try:
            ip_address = socket.gethostbyname(hostname)
            return {
                "status": "healthy",
                "hostname": hostname,
                "ip_address": ip_address,
                "message": "DNS resolution successful"
            }
        except socket.gaierror:
            return {
                "status": "unhealthy",
                "hostname": hostname,
                "error": "DNS resolution failed"
            }
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}
    def check_disk_space(self, path="/"):
        try:
            usage = psutil.disk_usage(path)
            percent_used = usage.percent
            if percent_used < 80:
                return {
                    "status": "healthy",
                    "path": path,
                    "total_gb": usage.total / (1024**3),
                    "used_gb": usage.used / (1024**3),
                    "free_gb": usage.free / (1024**3),
                    "percent_used": percent_used
                }
            elif percent_used < 90:
                return {
                    "status": "warning",
                    "path": path,
                    "percent_used": percent_used,
                    "message": "Disk usage above 80%"
                }
            else:
                return {
                    "status": "unhealthy",
                    "path": path,
                    "percent_used": percent_used,
                    "error": "Disk usage above 90%"
                }
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}
    def check_memory_usage(self):
        try:
            memory = psutil.virtual_memory()
            percent_used = memory.percent
            if percent_used < 80:
                return {
                    "status": "healthy",
                    "total_gb": memory.total / (1024**3),
                    "used_gb": memory.used / (1024**3),
                    "available_gb": memory.available / (1024**3),
                    "percent_used": percent_used
                }
            elif percent_used < 90:
                return {
                    "status": "warning",
                    "percent_used": percent_used,
                    "message": "Memory usage above 80%"
                }
            else:
                return {
                    "status": "unhealthy",
                    "percent_used": percent_used,
                    "error": "Memory usage above 90%"
                }
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}
    def check_cpu_usage(self):
        try:
            cpu_percent = psutil.cpu_percent(interval=1)
            if cpu_percent < 80:
                return {
                    "status": "healthy",
                    "cpu_percent": cpu_percent
                }
            elif cpu_percent < 90:
                return {
                    "status": "warning",
                    "cpu_percent": cpu_percent,
                    "message": "CPU usage above 80%"
                }
            else:
                return {
                    "status": "unhealthy",
                    "cpu_percent": cpu_percent,
                    "error": "CPU usage above 90%"
                }
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}
    def check_process_running(self, process_name):
        try:
            for proc in psutil.process_iter(['name']):
                if process_name.lower() in proc.info['name'].lower():
                    return {
                        "status": "healthy",
                        "process": process_name,
                        "message": f"Process {process_name} is running"
                    }
            return {
                "status": "unhealthy",
                "process": process_name,
                "error": f"Process {process_name} is not running"
            }
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}
    def execute_check(self, check):
        check_type = check["check_type"]
        target = check["target"]
        timeout = check.get("timeout", 5)
        if check_type == "http":
            result = self.check_http_endpoint(target, timeout)
        elif check_type == "tcp":
            port = check.get("port", 80)
            result = self.check_tcp_port(target, port, timeout)
        elif check_type == "ping":
            result = self.check_ping(target, timeout)
        elif check_type == "dns":
            result = self.check_dns_resolution(target)
        elif check_type == "disk":
            result = self.check_disk_space(target)
        elif check_type == "memory":
            result = self.check_memory_usage()
        elif check_type == "cpu":
            result = self.check_cpu_usage()
        elif check_type == "process":
            result = self.check_process_running(target)
        else:
            result = {"status": "unknown", "error": "Unknown check type"}
        check_result = {
            "check_name": check["check_name"],
            "check_type": check_type,
            "target": target,
            "result": result,
            "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "status": result.get("status", "unknown")
        }
        self.check_results.append(check_result)
        check["last_check"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        check["status"] = result.get("status", "unknown")
        return check_result
    def run_all_checks(self):
        enabled_checks = [c for c in self.health_checks if c.get("enabled", True)]
        results = []
        for check in enabled_checks:
            result = self.execute_check(check)
            results.append(result)
        return results
    def get_check_status(self, check_name):
        results = [r for r in self.check_results if r["check_name"] == check_name]
        return results[-10:] if results else []
    def get_overall_health(self):
        if not self.check_results:
            return "unknown"
        recent_results = self.check_results[-len(self.health_checks):]
        unhealthy_count = len([r for r in recent_results if r["status"] == "unhealthy"])
        warning_count = len([r for r in recent_results if r["status"] == "warning"])
        if unhealthy_count > 0:
            return "unhealthy"
        elif warning_count > 0:
            return "warning"
        else:
            return "healthy"
    def get_health_summary(self):
        summary = {
            "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "overall_health": self.get_overall_health(),
            "total_checks": len(self.health_checks),
            "enabled_checks": len([c for c in self.health_checks if c.get("enabled", True)]),
            "healthy_checks": 0,
            "warning_checks": 0,
            "unhealthy_checks": 0,
            "unknown_checks": 0,
            "recent_results": []
        }
        recent_results = self.check_results[-len(self.health_checks):] if self.check_results else []
        for result in recent_results:
            status = result["status"]
            if status == "healthy":
                summary["healthy_checks"] += 1
            elif status == "warning":
                summary["warning_checks"] += 1
            elif status == "unhealthy":
                summary["unhealthy_checks"] += 1
            else:
                summary["unknown_checks"] += 1
            summary["recent_results"].append({
                "check_name": result["check_name"],
                "status": status
            })
        return summary
    def start_continuous_monitoring(self, interval=60):
        if self.monitoring_active:
            print("Monitoring already active")
            return
        self.monitoring_active = True
        self.monitoring_thread = threading.Thread(target=self.run_monitoring, args=(interval,), daemon=True)
        self.monitoring_thread.start()
        print("Continuous monitoring started")
    def run_monitoring(self, interval):
        print("Monitoring is running...")
        try:
            while self.monitoring_active:
                self.run_all_checks()
                time.sleep(interval)
        except Exception as e:
            print(f"Monitoring error: {str(e)}")
    def stop_continuous_monitoring(self):
        self.monitoring_active = False
        if self.monitoring_thread and self.monitoring_thread.is_alive():
            self.monitoring_thread.join(timeout=5)
        print("Continuous monitoring stopped")
    def export_results(self, file_path):
        try:
            with open(file_path, 'w') as file:
                json.dump(self.check_results, file, indent=2)
            print(f"Results exported to {file_path}")
            return True
        except Exception as e:
            print(f"Error exporting results: {str(e)}")
            return False
    def display_health_summary(self):
        summary = self.get_health_summary()
        print("\n" + "="*80)
        print("HEALTH SUMMARY")
        print("="*80)
        print(f"Timestamp: {summary['timestamp']}")
        print(f"Overall Health: {summary['overall_health'].upper()}")
        print(f"Total Checks: {summary['total_checks']}")
        print(f"Healthy: {summary['healthy_checks']}")
        print(f"Warning: {summary['warning_checks']}")
        print(f"Unhealthy: {summary['unhealthy_checks']}")
        print(f"Unknown: {summary['unknown_checks']}")
        print("\nRecent Results:")
        for result in summary['recent_results']:
            status_symbol = "✓" if result['status'] == "healthy" else "✗" if result['status'] == "unhealthy" else "⚠"
            print(f"  {status_symbol} {result['check_name']}: {result['status']}")
        print("="*80 + "\n")
    def display_checks(self):
        if not self.health_checks:
            print("No health checks configured")
            return
        print("\n" + "="*120)
        print("HEALTH CHECKS")
        print("="*120)
        print(f"{'Check Name':<30} {'Type':<15} {'Target':<35} {'Status':<12} {'Last Check':<25}")
        print("-"*120)
        for check in self.health_checks:
            status = check["status"]
            last_check = check.get("last_check", "Never")
            print(f"{check['check_name']:<30} {check['check_type']:<15} {check['target']:<35} {status:<12} {last_check:<25}")
        print("="*120 + "\n")
    def display_check_results(self, limit=20):
        if not self.check_results:
            print("No check results available")
            return
        print("\n" + "="*130)
        print("CHECK RESULTS")
        print("="*130)
        print(f"{'Check Name':<30} {'Type':<15} {'Target':<35} {'Status':<12} {'Timestamp':<25}")
        print("-"*130)
        for result in self.check_results[-limit:]:
            print(f"{result['check_name']:<30} {result['check_type']:<15} {result['target']:<35} {result['status']:<12} {result['timestamp']:<25}")
        print("="*130 + "\n")
def main():
