            if choice == '1':
                manager.display_user_info(current_user)
            elif choice == '2':
                old_pwd = input("Enter current password: ").strip()
                new_pwd = input("Enter new password: ").strip()
                success, msg = manager.change_password(current_user, old_pwd, new_pwd)
                print(f"Result: {msg}")
            elif choice == '3':
                pwd = input("Enter password to confirm: ").strip()
                success, msg = manager.deactivate_account(current_user, pwd)
                print(f"Result: {msg}")
                if success:
                    current_user = None
            elif choice == '4':
                pwd = input("Enter password to confirm: ").strip()
                success, msg = manager.delete_account(current_user, pwd)
                print(f"Result: {msg}")
                if success:
                    current_user = None
            elif choice == '5':
                manager.display_login_history(current_user)
            elif choice == '6':
                current_user = None
                print("Logged out successfully")
        else:
            print("\n" + "="*60)
            print("LOGIN SYSTEM")
            print("="*60)
            print("1. Register new user")
            print("2. Login")
            print("3. Reset password")
            print("4. View all users")
            print("5. View login history")
            print("6. Exit")
            choice = input("\nSelect an option (1-6): ").strip()
            if choice == '1':
                username = input("Enter username: ").strip()
                password = input("Enter password: ").strip()
                email = input("Enter email: ").strip()
                success, msg = manager.register_user(username, password, email)
                print(f"Result: {msg}")
            elif choice == '2':
                username = input("Enter username: ").strip()
                password = input("Enter password: ").strip()
                success, msg = manager.login(username, password)
                print(f"Result: {msg}")
                if success:
                    current_user = username
            elif choice == '3':
                username = input("Enter username: ").strip()
                email = input("Enter registered email: ").strip()
                new_pwd = input("Enter new password: ").strip()
                success, msg = manager.reset_password(username, email, new_pwd)
                print(f"Result: {msg}")
            elif choice == '4':
                manager.display_all_users()
            elif choice == '5':
                manager.display_login_history()
