                print("Exiting Login System. Goodbye!")
                break
if __name__ == '__main__':
    main()

from flask import Flask,request,jsonify
import sqlite3
app=Flask(__name__)
def get_db():
    return sqlite3.connect("auth.db")
@app.route("/register",methods=["POST"])
def register():
    data=request.get_json()
    username=data.get("username")
    password=data.get("password")
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("CREATE TABLE IF NOT EXISTS users (username TEXT PRIMARY KEY, password TEXT)")
    try:
        cursor.execute("INSERT INTO users (username,password) VALUES (?,?)",(username,password))
        conn.commit()
        conn.close()
        return jsonify({"message":"Registration successful"})
    except:
        conn.close()
        return jsonify({"message":"User already exists"})
@app.route("/login",methods=["POST"])
def login():
    data=request.get_json()
    username=data.get("username")
    password=data.get("password")
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("SELECT password FROM users WHERE username=?",(username,))
    result=cursor.fetchone()
    conn.close()
    if result and result[0]==password:
        return jsonify({"message":"Login successful"})
    return jsonify({"message":"Invalid credentials"})
if __name__=="__main__":
    app.run(debug=True)

from flask import Flask, request, jsonify
import sqlite3
import hashlib
import jwt
import re
from datetime import datetime, timedelta
from functools import wraps
app = Flask(__name__)
SECRET_KEY = "flask_secret_key_2024"
DB_FILE = "flask_auth.db"
def get_connection():
    return sqlite3.connect(DB_FILE)
def initialize_db():
    conn = get_connection()
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            email TEXT UNIQUE NOT NULL,
            password TEXT NOT NULL,
            role TEXT DEFAULT 'user',
            is_active INTEGER DEFAULT 1,
            created_at TEXT,
            last_login TEXT
        )
    """)
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS login_logs (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT,
            status TEXT,
            ip_address TEXT,
            timestamp TEXT
        )
    """)
    conn.commit()
    conn.close()
def hash_password(password):
    salt = "flask_salt_key"
    return hashlib.sha256((password + salt).encode()).hexdigest()
def is_valid_email(email):
    return re.match(r"[^@]+@[^@]+\.[^@]+", email) is not None
def generate_token(username, role):
    payload = {
        "username": username,
        "role": role,
        "exp": datetime.utcnow() + timedelta(hours=2)
    }
    return jwt.encode(payload, SECRET_KEY, algorithm="HS256")
def log_login(username, status, ip_address):
    conn = get_connection()
    cursor = conn.cursor()
    cursor.execute("""
        INSERT INTO login_logs (username, status, ip_address, timestamp)
        VALUES (?, ?, ?, ?)
    """, (username, status, ip_address, datetime.now().strftime("%Y-%m-%d %H:%M:%S")))
    conn.commit()
    conn.close()
def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get("Authorization")
        if not token:
            return jsonify({"error": "Token is missing."}), 401
        try:
            if token.startswith("Bearer "):
                token = token.split(" ")[1]
            data = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
            request.current_user = data
        except jwt.ExpiredSignatureError:
            return jsonify({"error": "Token has expired."}), 401
        except jwt.InvalidTokenError:
            return jsonify({"error": "Invalid token."}), 401
        return f(*args, **kwargs)
    return decorated
def admin_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get("Authorization")
        if not token:
            return jsonify({"error": "Token is missing."}), 401
        try:
            if token.startswith("Bearer "):
                token = token.split(" ")[1]
            data = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
            if data.get("role") != "admin":
                return jsonify({"error": "Admin access required."}), 403
            request.current_user = data
        except jwt.ExpiredSignatureError:
            return jsonify({"error": "Token has expired."}), 401
        except jwt.InvalidTokenError:
            return jsonify({"error": "Invalid token."}), 401
        return f(*args, **kwargs)
    return decorated
@app.route("/register", methods=["POST"])
def register():
    data = request.get_json()
    username = data.get("username", "").strip()
    email = data.get("email", "").strip()
    password = data.get("password", "").strip()
    role = data.get("role", "user").strip()
    if not username or not email or not password:
        return jsonify({"error": "Username, email, and password are required."}), 400
    if not is_valid_email(email):
        return jsonify({"error": "Invalid email format."}), 400
    if len(password) < 8:
        return jsonify({"error": "Password must be at least 8 characters."}), 400
    conn = get_connection()
    cursor = conn.cursor()
    try:
        cursor.execute("""
            INSERT INTO users (username, email, password, role, created_at)
            VALUES (?, ?, ?, ?, ?)
        """, (username, email, hash_password(password), role, datetime.now().strftime("%Y-%m-%d %H:%M:%S")))
        conn.commit()
        return jsonify({"message": f"User '{username}' registered successfully."}), 201
    except sqlite3.IntegrityError as e:
        if "username" in str(e):
            return jsonify({"error": "Username already exists."}), 409
        elif "email" in str(e):
            return jsonify({"error": "Email already registered."}), 409
    finally:
        conn.close()
@app.route("/login", methods=["POST"])
def login():
    data = request.get_json()
    username = data.get("username", "").strip()
    password = data.get("password", "").strip()
    ip_address = request.remote_addr
    if not username or not password:
        return jsonify({"error": "Username and password are required."}), 400
    conn = get_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT * FROM users WHERE username = ?", (username,))
    user = cursor.fetchone()
    if not user:
        log_login(username, "FAILED - User not found", ip_address)
        conn.close()
        return jsonify({"error": "Username not found."}), 404
    if not user[5]:
        log_login(username, "FAILED - Account inactive", ip_address)
        conn.close()
        return jsonify({"error": "Account is deactivated."}), 403
    if user[3] != hash_password(password):
        log_login(username, "FAILED - Wrong password", ip_address)
        conn.close()
        return jsonify({"error": "Incorrect password."}), 401
    cursor.execute("UPDATE users SET last_login = ? WHERE username = ?",
                   (datetime.now().strftime("%Y-%m-%d %H:%M:%S"), username))
    conn.commit()
    log_login(username, "SUCCESS", ip_address)
    token = generate_token(username, user[4])
    conn.close()
    return jsonify({
        "message": f"Welcome, {username}!",
        "token": token,
        "role": user[4]
    }), 200
