import hashlib
import json
import os
DB_FILE = "users.json"
def load_db():
    if not os.path.exists(DB_FILE): return {}
    with open(DB_FILE, "r") as f: return json.load(f)
def save_db(db):
    with open(DB_FILE, "w") as f: json.dump(db, f)
def hash_pw(password):
    return hashlib.sha256(password.encode()).hexdigest()
def register(db):
    name = input("Username: ")
    if name in db: return print("Exists.")
    db[name] = hash_pw(input("Password: "))
    save_db(db)
    print("Registered.")
def login(db):
    name = input("Username: ")
    pw = hash_pw(input("Password: "))
    print("Welcome!" if db.get(name) == pw else "Failed.")
