import json
import os
def load_users(filepath):
    if not os.path.exists(filepath):
        return {}
    with open(filepath, "r") as f:
        return json.load(f)
def save_users(filepath, users):
    with open(filepath, "w") as f:
        json.dump(users, f)
def register(filepath, username, password):
    users = load_users(filepath)
    if username in users:
        return "Username already exists."
    users[username] = password
    save_users(filepath, users)
    return "Registration successful."
def login(filepath, username, password):
    users = load_users(filepath)
    if username not in users:
        return "Username not found."
    if users[username] != password:
        return "Incorrect password."
    return f"Welcome, {username}!"
def main():
    filepath = "users.json"
    while True:
        print("\n1. Register\n2. Login\n3. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            u = input("Enter username: ")
            p = input("Enter password: ")
            print(register(filepath, u, p))
        elif choice == "2":
            u = input("Enter username: ")
            p = input("Enter password: ")
            print(login(filepath, u, p))
        elif choice == "3":
            print("Goodbye!")
            break
