import csv
import json
import hashlib
import os
from datetime import datetime
import re
class FileAuthenticationManager:
    def __init__(self):
        self.users = []
        self.authenticated_users = {}
        self.login_attempts = []
    def load_users_from_csv(self, file_path):
        if not os.path.exists(file_path):
            return False, f"File {file_path} not found"
        try:
            self.users = []
            with open(file_path, 'r', encoding='utf-8') as file:
                reader = csv.DictReader(file)
                if not reader.fieldnames:
                    return False, "CSV file is empty"
                required_fields = ['username', 'email', 'password_hash', 'role', 'is_active']
                missing_fields = [field for field in required_fields if field not in reader.fieldnames]
                if missing_fields:
                    return False, f"Missing required fields: {', '.join(missing_fields)}"
                for row in reader:
                    self.users.append({
                        'username': row.get('username', '').strip(),
                        'email': row.get('email', '').strip(),
                        'password_hash': row.get('password_hash', '').strip(),
                        'role': row.get('role', 'user').strip(),
                        'is_active': row.get('is_active', 'True').lower() == 'true',
                        'created_at': row.get('created_at', datetime.now().strftime("%Y-%m-%d %H:%M:%S")),
                        'last_login': row.get('last_login', None)
                    })
            if not self.users:
                return False, "No users found in CSV file"
            return True, f"Loaded {len(self.users)} users from CSV"
        except Exception as e:
            return False, str(e)
    def load_users_from_json(self, file_path):
        if not os.path.exists(file_path):
            return False, f"File {file_path} not found"
        try:
            self.users = []
            with open(file_path, 'r', encoding='utf-8') as file:
                data = json.load(file)
            if isinstance(data, list):
                self.users = data
            elif isinstance(data, dict) and 'users' in data:
                self.users = data['users']
            else:
                return False, "Invalid JSON format"
            if not self.users:
                return False, "No users found in JSON file"
            return True, f"Loaded {len(self.users)} users from JSON"
        except json.JSONDecodeError:
            return False, "Invalid JSON format"
        except Exception as e:
            return False, str(e)
    def load_users_from_txt(self, file_path):
        if not os.path.exists(file_path):
            return False, f"File {file_path} not found"
        try:
            self.users = []
            with open(file_path, 'r', encoding='utf-8') as file:
                for line in file:
                    line = line.strip()
                    if not line or line.startswith('#'):
                        continue
                    parts = line.split('|')
                    if len(parts) < 4:
                        continue
                    user = {
                        'username': parts[0].strip(),
                        'email': parts[1].strip(),
                        'password_hash': parts[2].strip(),
                        'role': parts[3].strip() if len(parts) > 3 else 'user',
                        'is_active': parts[4].strip().lower() == 'true' if len(parts) > 4 else True,
                        'created_at': parts[5].strip() if len(parts) > 5 else datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                        'last_login': parts[6].strip() if len(parts) > 6 else None
                    }
                    self.users.append(user)
            if not self.users:
                return False, "No users found in TXT file"
            return True, f"Loaded {len(self.users)} users from TXT"
        except Exception as e:
            return False, str(e)
    def hash_password(self, password):
        return hashlib.sha256(password.encode()).hexdigest()
    def find_user(self, username):
        for user in self.users:
            if user['username'].lower() == username.lower():
                return user
        return None
    def find_user_by_email(self, email):
        for user in self.users:
            if user['email'].lower() == email.lower():
                return user
        return None
    def authenticate(self, username, password):
        user = self.find_user(username)
        if not user:
            self.record_login_attempt(username, 'FAILED', 'User not found')
            return False, "Invalid username or password"
        if not user.get('is_active', True):
            self.record_login_attempt(username, 'FAILED', 'Account inactive')
            return False, "Account is deactivated"
        password_hash = self.hash_password(password)
        if password_hash != user['password_hash']:
            self.record_login_attempt(username, 'FAILED', 'Invalid password')
            return False, "Invalid username or password"
        self.record_login_attempt(username, 'SUCCESS', 'Authentication successful')
        user['last_login'] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        session_token = self.generate_session_token(username)
        self.authenticated_users[session_token] = {
            'username': username,
            'email': user['email'],
            'role': user['role'],
            'login_time': datetime.now(),
            'user_data': user
        }
        return True, session_token
    def authenticate_by_email(self, email, password):
        user = self.find_user_by_email(email)
        if not user:
            self.record_login_attempt(email, 'FAILED', 'Email not found')
            return False, "Invalid email or password"
        if not user.get('is_active', True):
            self.record_login_attempt(email, 'FAILED', 'Account inactive')
            return False, "Account is deactivated"
        password_hash = self.hash_password(password)
        if password_hash != user['password_hash']:
            self.record_login_attempt(email, 'FAILED', 'Invalid password')
            return False, "Invalid email or password"
        self.record_login_attempt(email, 'SUCCESS', 'Authentication successful')
        user['last_login'] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        session_token = self.generate_session_token(user['username'])
        self.authenticated_users[session_token] = {
            'username': user['username'],
            'email': email,
            'role': user['role'],
            'login_time': datetime.now(),
            'user_data': user
        }
        return True, session_token
    def generate_session_token(self, username):
        token_data = f"{username}{datetime.now().isoformat()}"
        return hashlib.sha256(token_data.encode()).hexdigest()
    def verify_session(self, session_token):
        if session_token not in self.authenticated_users:
            return False, None
        return True, self.authenticated_users[session_token]
    def logout(self, session_token):
        if session_token in self.authenticated_users:
            del self.authenticated_users[session_token]
            return True, "Logout successful"
        return False, "Invalid session token"
    def get_user_by_role(self, role):
        users = [user for user in self.users if user.get('role', 'user').lower() == role.lower()]
        return users
    def get_active_users(self):
        return [user for user in self.users if user.get('is_active', True)]
    def get_inactive_users(self):
        return [user for user in self.users if not user.get('is_active', True)]
    def record_login_attempt(self, username, status, reason):
        attempt = {
            'username': username,
            'status': status,
            'reason': reason,
            'timestamp': datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        }
        self.login_attempts.append(attempt)
    def get_login_attempts(self, username=None):
        if username:
            return [a for a in self.login_attempts if a['username'] == username]
        return self.login_attempts
    def get_failed_login_attempts(self, username=None):
        if username:
            return [a for a in self.login_attempts if a['username'] == username and a['status'] == 'FAILED']
        return [a for a in self.login_attempts if a['status'] == 'FAILED']
    def save_users_to_csv(self, file_path):
        if not self.users:
            return False, "No users to save"
        try:
            with open(file_path, 'w', newline='', encoding='utf-8') as file:
                fieldnames = ['username', 'email', 'password_hash', 'role', 'is_active', 'created_at', 'last_login']
                writer = csv.DictWriter(file, fieldnames=fieldnames)
                writer.writeheader()
                for user in self.users:
                    writer.writerow({
                        'username': user.get('username', ''),
                        'email': user.get('email', ''),
                        'password_hash': user.get('password_hash', ''),
                        'role': user.get('role', 'user'),
                        'is_active': user.get('is_active', True),
                        'created_at': user.get('created_at', ''),
                        'last_login': user.get('last_login', '')
                    })
            return True, f"Saved {len(self.users)} users to CSV"
        except Exception as e:
            return False, str(e)
    def save_users_to_json(self, file_path):
        if not self.users:
            return False, "No users to save"
        try:
            data = {'users': self.users}
            with open(file_path, 'w', encoding='utf-8') as file:
                json.dump(data, file, indent=2)
            return True, f"Saved {len(self.users)} users to JSON"
        except Exception as e:
            return False, str(e)
    def save_users_to_txt(self, file_path):
        if not self.users:
            return False, "No users to save"
        try:
            with open(file_path, 'w', encoding='utf-8') as file:
                file.write("# username|email|password_hash|role|is_active|created_at|last_login\n")
                for user in self.users:
                    line = f"{user.get('username', '')}|{user.get('email', '')}|{user.get('password_hash', '')}|{user.get('role', 'user')}|{user.get('is_active', True)}|{user.get('created_at', '')}|{user.get('last_login', '')}\n"
                    file.write(line)
            return True, f"Saved {len(self.users)} users to TXT"
        except Exception as e:
            return False, str(e)
    def add_user(self, username, email, password, role='user'):
        if self.find_user(username):
            return False, "Username already exists"
        if self.find_user_by_email(email):
            return False, "Email already exists"
        user = {
            'username': username,
            'email': email,
            'password_hash': self.hash_password(password),
            'role': role,
            'is_active': True,
            'created_at': datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            'last_login': None
        }
        self.users.append(user)
        return True, "User added successfully"
    def display_all_users(self):
        if not self.users:
            print("No users loaded")
            return
        print("\n" + "="*130)
        print("ALL USERS")
        print("="*130)
        print(f"{'#':<5} {'Username':<20} {'Email':<35} {'Role':<15} {'Active':<10} {'Created At':<25} {'Last Login':<25}")
        print("-"*130)
        for idx, user in enumerate(self.users, 1):
            last_login = user.get('last_login', 'Never') or 'Never'
            active = 'Yes' if user.get('is_active', True) else 'No'
            print(f"{idx:<5} {user['username']:<20} {user['email']:<35} {user.get('role', 'user'):<15} {active:<10} {user.get('created_at', ''):<25} {last_login:<25}")
        print("="*130 + "\n")
    def display_login_attempts(self, username=None):
        if username:
            attempts = self.get_login_attempts(username)
            title = f"LOGIN ATTEMPTS FOR {username}"
        else:
            attempts = self.login_attempts
            title = "ALL LOGIN ATTEMPTS"
        if not attempts:
            print("No login attempts recorded")
            return
        print("\n" + "="*100)
        print(title)
        print("="*100)
        print(f"{'Username':<20} {'Status':<12} {'Reason':<35} {'Timestamp':<25}")
        print("-"*100)
        for attempt in attempts[-50:]:
            print(f"{attempt['username']:<20} {attempt['status']:<12} {attempt['reason']:<35} {attempt['timestamp']:<25}")
        print("="*100 + "\n")
    def display_users_by_role(self, role):
        users = self.get_user_by_role(role)
        if not users:
            print(f"No users with role {role}")
            return
        print("\n" + "="*100)
        print(f"USERS WITH ROLE: {role.upper()}")
        print("="*100)
        print(f"{'Username':<20} {'Email':<35} {'Active':<10} {'Created At':<25}")
        print("-"*100)
        for user in users:
            active = 'Yes' if user.get('is_active', True) else 'No'
            print(f"{user['username']:<20} {user['email']:<35} {active:<10} {user.get('created_at', ''):<25}")
        print("="*100 + "\n")
def create_sample_csv(file_path):
    users = [
        ['username', 'email', 'password_hash', 'role', 'is_active', 'created_at', 'last_login'],
        ['john_doe', 'john@example.com', hashlib.sha256(b'SecurePass123!').hexdigest(), 'user', 'True', '2025-01-01 10:00:00', None],
