def main():
    manager = FileAuthenticationManager()
    current_session = None
    current_user = None
    while True:
        if current_session:
            is_valid, user_data = manager.verify_session(current_session)
            if not is_valid:
                print("Session expired")
                current_session = None
                current_user = None
                continue
            print("\n" + "="*60)
            print(f"LOGGED IN AS: {user_data['username']} ({user_data['role']})")
