            if choice == '1':
                print("\n" + "="*60)
                print("USER PROFILE")
                print("="*60)
                for key, value in user_data['user_data'].items():
                    print(f"{key}: {value}")
                print("="*60)
            elif choice == '2':
                manager.display_all_users()
            elif choice == '3':
                manager.display_login_attempts(user_data['username'])
            elif choice == '4':
                manager.logout(current_session)
                current_session = None
                current_user = None
                print("Logged out successfully")
        else:
            print("\n" + "="*60)
            print("FILE-BASED AUTHENTICATION")
            print("="*60)
            print("1. Load users from CSV")
            print("2. Load users from JSON")
            print("3. Load users from TXT")
            print("4. Create sample CSV")
            print("5. Login with username")
            print("6. Login with email")
            print("7. View all users")
            print("8. View users by role")
            print("9. View login attempts")
            print("10. Add new user")
            print("11. Exit")
            choice = input("\nSelect an option (1-11): ").strip()
            if choice == '1':
                file_path = input("Enter CSV file path: ").strip()
                success, msg = manager.load_users_from_csv(file_path)
                print(f"Result: {msg}")
            elif choice == '2':
                file_path = input("Enter JSON file path: ").strip()
                success, msg = manager.load_users_from_json(file_path)
                print(f"Result: {msg}")
            elif choice == '3':
                file_path = input("Enter TXT file path: ").strip()
                success, msg = manager.load_users_from_txt(file_path)
                print(f"Result: {msg}")
            elif choice == '4':
                file_path = input("Enter output file path (default sample_users.csv): ").strip() or "sample_users.csv"
                success, msg = create_sample_csv(file_path)
                print(f"Result: {msg}")
            elif choice == '5':
                username = input("Enter username: ").strip()
                password = input("Enter password: ").strip()
                success, result = manager.authenticate(username, password)
                print(f"Result: {'Login successful' if success else result}")
                if success:
                    current_session = result
            elif choice == '6':
                email = input("Enter email: ").strip()
                password = input("Enter password: ").strip()
                success, result = manager.authenticate_by_email(email, password)
                print(f"Result: {'Login successful' if success else result}")
                if success:
                    current_session = result
            elif choice == '7':
                manager.display_all_users()
            elif choice == '8':
                role = input("Enter role to filter: ").strip()
                manager.display_users_by_role(role)
            elif choice == '9':
                username = input("Enter username (leave empty for all): ").strip() or None
                manager.display_login_attempts(username)
            elif choice == '10':
                username = input("Enter username: ").strip()
                email = input("Enter email: ").strip()
                password = input("Enter password: ").strip()
                role = input("Enter role (default user): ").strip() or "user"
                success, msg = manager.add_user(username, email, password, role)
                print(f"Result: {msg}")
            elif choice == '11':
                print("Exiting File-Based Authentication. Goodbye!")
                break
            else:
                print("Invalid option")
if __name__ == '__main__':
    main()

