import json
import os
import hashlib
import uuid
from datetime import datetime, timedelta
def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()
def load_users(filepath):
    if not os.path.exists(filepath):
        return {}
    with open(filepath, "r") as f:
        return json.load(f)
def save_users(filepath, users):
    with open(filepath, "w") as f:
        json.dump(users, f, indent=4)
def load_sessions(filepath):
    if not os.path.exists(filepath):
        return {}
    with open(filepath, "r") as f:
        return json.load(f)
def save_sessions(filepath, sessions):
    with open(filepath, "w") as f:
        json.dump(sessions, f, indent=4)
def signup(users_file, username, password):
    users = load_users(users_file)
    if username in users:
        return "Username already exists."
    users[username] = hash_password(password)
    save_users(users_file, users)
    return "Signup successful."
def login(users_file, sessions_file, username, password):
    users = load_users(users_file)
    if username not in users:
        return "Username not found."
    if users[username] != hash_password(password):
        return "Incorrect password."
    sessions = load_sessions(sessions_file)
    session_id = str(uuid.uuid4())
    expiry = (datetime.now() + timedelta(hours=1)).strftime("%Y-%m-%d %H:%M:%S")
    sessions[session_id] = {"username": username, "expiry": expiry}
    save_sessions(sessions_file, sessions)
    return f"Login successful. Session ID: {session_id}"
def check_session(sessions_file, session_id):
    sessions = load_sessions(sessions_file)
    if session_id not in sessions:
        return "Invalid session."
    session = sessions[session_id]
    expiry = datetime.strptime(session["expiry"], "%Y-%m-%d %H:%M:%S")
    if datetime.now() > expiry:
        del sessions[session_id]
        save_sessions(sessions_file, sessions)
        return "Session expired."
    return f"Active session for user: {session['username']}"
def logout(sessions_file, session_id):
    sessions = load_sessions(sessions_file)
    if session_id not in sessions:
        return "Invalid session."
    del sessions[session_id]
    save_sessions(sessions_file, sessions)
    return "Logged out successfully."
def main():
    users_file = "users.json"
    sessions_file = "sessions.json"
    while True:
        print("\n1. Signup\n2. Login\n3. Check Session\n4. Logout\n5. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            u = input("Enter username: ")
            p = input("Enter password: ")
            print(signup(users_file, u, p))
        elif choice == "2":
            u = input("Enter username: ")
            p = input("Enter password: ")
            print(login(users_file, sessions_file, u, p))
        elif choice == "3":
            sid = input("Enter session ID: ")
            print(check_session(sessions_file, sid))
        elif choice == "4":
            sid = input("Enter session ID: ")
            print(logout(sessions_file, sid))
        elif choice == "5":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

