import hashlib
users = {"admin": hashlib.sha256("password123".encode()).hexdigest()}
sessions = {}
def login():
    user = input("Username: ")
    pw = hashlib.sha256(input("Password: ").encode()).hexdigest()
    if users.get(user) == pw:
        sid = str(uuid.uuid4())
        sessions[sid] = {"user": user, "expiry": time.time() + 30}
        print(f"Login success. Session ID: {sid}")
        return sid
    print("Login failed.")
    return None
def access_dashboard(sid):
    session = sessions.get(sid)
    if session and time.time() < session["expiry"]:
        print(f"Welcome to dashboard, {session['user']}!")
    else:
        print("Session expired or invalid. Please login again.")
        sessions.pop(sid, None)
if __name__ == "__main__":
    token = login()
    if token:
        access_dashboard(token)
        print("Waiting 31 seconds for session timeout...")
        time.sleep(31)
        access_dashboard(token)

