import re
def check_length(password):
    return len(password) >= 8
def check_uppercase(password):
    return bool(re.search(r'[A-Z]', password))
def check_lowercase(password):
    return bool(re.search(r'[a-z]', password))
def check_digit(password):
    return bool(re.search(r'[0-9]', password))
def check_special(password):
    return bool(re.search(r'[!@#$%^&*(),.?":{}|<>]', password))
def verify_password(password):
    results = {
        "Minimum 8 characters": check_length(password),
        "Contains uppercase letter": check_uppercase(password),
        "Contains lowercase letter": check_lowercase(password),
        "Contains digit": check_digit(password),
        "Contains special character": check_special(password),
    }
    print("\nPassword Verification Results:")
    all_passed = True
    for rule, passed in results.items():
        status = "PASSED" if passed else "FAILED"
        print(f"  {rule}: {status}")
        if not passed:
            all_passed = False
    if all_passed:
        print("\nPassword is STRONG.")
    else:
        print("\nPassword is WEAK. Please fix the failed rules.")
def main():
    while True:
        print("\n1. Verify Password\n2. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            password = input("Enter password to verify: ")
            verify_password(password)
        elif choice == "2":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

import re
import string
from datetime import datetime
class PasswordVerifier:
    def __init__(self):
        self.verification_results = []
        self.common_passwords = [
            'password', '123456', 'password123', 'admin', 'letmein', 'welcome',
            'monkey', 'dragon', 'master', 'sunshine', '123123', 'qwerty',
            'abc123', 'password1', 'login', 'princess', 'solo', 'passw0rd',
            'starwars', 'shadow', 'michael', 'football', 'superman'
        ]
    def check_length(self, password, min_length=8, max_length=128):
        if len(password) < min_length:
            return False, f"Password must be at least {min_length} characters long"
        if len(password) > max_length:
            return False, f"Password must be at most {max_length} characters long"
        return True, "Length requirement met"
    def check_uppercase(self, password):
        if any(c.isupper() for c in password):
            return True, "Contains uppercase letter"
        return False, "Missing uppercase letter"
    def check_lowercase(self, password):
        if any(c.islower() for c in password):
            return True, "Contains lowercase letter"
        return False, "Missing lowercase letter"
    def check_digits(self, password):
        if any(c.isdigit() for c in password):
            return True, "Contains digit"
        return False, "Missing digit"
    def check_special_characters(self, password, special_chars="!@#$%^&*()_+-=[]{}|;:,.<>?"):
        if any(c in special_chars for c in password):
            return True, "Contains special character"
        return False, "Missing special character"
    def check_no_spaces(self, password):
        if ' ' not in password:
            return True, "No spaces in password"
        return False, "Password contains spaces"
    def check_no_sequential_characters(self, password):
        for i in range(len(password) - 2):
            if (ord(password[i+1]) == ord(password[i]) + 1 and 
                ord(password[i+2]) == ord(password[i+1]) + 1):
                return False, f"Contains sequential characters: {password[i:i+3]}"
        return True, "No sequential characters"
    def check_no_repeated_characters(self, password, max_repeats=3):
        for i in range(len(password) - max_repeats + 1):
            if len(set(password[i:i+max_repeats])) == 1:
                return False, f"Contains {max_repeats} or more repeated characters"
        return True, "No excessive repeated characters"
    def check_not_common_password(self, password):
        if password.lower() in self.common_passwords:
            return False, "Password is too common"
        return True, "Password is not in common list"
    def check_character_variety(self, password, min_unique=5):
        unique_chars = len(set(password))
        if unique_chars < min_unique:
            return False, f"Password should have at least {min_unique} unique characters"
        return True, f"Has {unique_chars} unique characters"
    def check_no_dictionary_words(self, password, dictionary_words=None):
        if dictionary_words is None:
            dictionary_words = ['password', 'admin', 'user', 'login', 'secret', 'test', 'demo']
        password_lower = password.lower()
        for word in dictionary_words:
            if word in password_lower:
                return False, f"Contains dictionary word: {word}"
        return True, "No dictionary words found"
    def check_entropy(self, password):
        charset_size = 0
        if any(c.isupper() for c in password):
            charset_size += 26
        if any(c.islower() for c in password):
            charset_size += 26
        if any(c.isdigit() for c in password):
            charset_size += 10
        if any(c in string.punctuation for c in password):
            charset_size += len(string.punctuation)
        entropy = len(password) * (charset_size.bit_length() if charset_size > 0 else 1)
        if entropy < 50:
            return False, f"Low entropy: {entropy} bits"
        elif entropy < 80:
            return True, f"Fair entropy: {entropy} bits"
        elif entropy < 120:
            return True, f"Good entropy: {entropy} bits"
        else:
            return True, f"Excellent entropy: {entropy} bits"
    def check_keyboard_patterns(self, password):
        keyboard_patterns = [
            'qwerty', 'asdfgh', 'zxcvbn', 'qazwsx', '12345', '1234567890'
        ]
        password_lower = password.lower()
        for pattern in keyboard_patterns:
            if pattern in password_lower:
                return False, f"Contains keyboard pattern: {pattern}"
        return True, "No keyboard patterns detected"
    def check_similar_characters(self, password):
        similar_groups = [
            ('0', 'O'), ('1', 'l', 'L'), ('5', 'S')
        ]
        issues = []
        for group in similar_groups:
            if all(c in password or c.lower() in password.lower() for c in group):
                issues.append(''.join(group))
        if issues:
            return False, f"Contains easily confused characters: {', '.join(issues)}"
        return True, "No confusing character combinations"
    def get_password_strength(self, password):
        score = 0
        max_score = 10
        if len(password) >= 12:
            score += 1
        if len(password) >= 16:
            score += 1
        if any(c.isupper() for c in password) and any(c.islower() for c in password):
            score += 1
        if any(c.isdigit() for c in password):
            score += 1
        if any(c in string.punctuation for c in password):
            score += 1
        if len(set(password)) >= 8:
            score += 1
        if not any(pattern in password.lower() for pattern in ['password', 'admin', '123456']):
            score += 1
        if ' ' not in password:
            score += 1
        if len(password) > 20:
            score += 1
        if score <= 3:
            return "Very Weak"
        elif score <= 5:
            return "Weak"
        elif score <= 7:
            return "Fair"
        elif score <= 9:
            return "Strong"
        else:
            return "Very Strong"
    def verify_password(self, password):
        results = {
            'password': password,
            'timestamp': datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            'checks': {},
            'strength': self.get_password_strength(password),
            'is_valid': True,
            'issues': [],
            'recommendations': []
        }
        length_valid, length_msg = self.check_length(password)
        results['checks']['length'] = {'valid': length_valid, 'message': length_msg}
        if not length_valid:
            results['is_valid'] = False
            results['issues'].append(length_msg)
        uppercase_valid, uppercase_msg = self.check_uppercase(password)
        results['checks']['uppercase'] = {'valid': uppercase_valid, 'message': uppercase_msg}
        if not uppercase_valid:
            results['issues'].append(uppercase_msg)
            results['recommendations'].append("Add at least one uppercase letter")
        lowercase_valid, lowercase_msg = self.check_lowercase(password)
        results['checks']['lowercase'] = {'valid': lowercase_valid, 'message': lowercase_msg}
        if not lowercase_valid:
            results['issues'].append(lowercase_msg)
            results['recommendations'].append("Add at least one lowercase letter")
        digits_valid, digits_msg = self.check_digits(password)
        results['checks']['digits'] = {'valid': digits_valid, 'message': digits_msg}
        if not digits_valid:
            results['issues'].append(digits_msg)
            results['recommendations'].append("Add at least one digit")
        special_valid, special_msg = self.check_special_characters(password)
        results['checks']['special_characters'] = {'valid': special_valid, 'message': special_msg}
        if not special_valid:
            results['issues'].append(special_msg)
            results['recommendations'].append("Add at least one special character")
        spaces_valid, spaces_msg = self.check_no_spaces(password)
        results['checks']['no_spaces'] = {'valid': spaces_valid, 'message': spaces_msg}
        if not spaces_valid:
            results['issues'].append(spaces_msg)
            results['recommendations'].append("Remove spaces from password")
        sequential_valid, sequential_msg = self.check_no_sequential_characters(password)
        results['checks']['sequential_characters'] = {'valid': sequential_valid, 'message': sequential_msg}
        if not sequential_valid:
            results['issues'].append(sequential_msg)
            results['recommendations'].append("Avoid sequential characters")
        repeated_valid, repeated_msg = self.check_no_repeated_characters(password)
        results['checks']['repeated_characters'] = {'valid': repeated_valid, 'message': repeated_msg}
        if not repeated_valid:
            results['issues'].append(repeated_msg)
            results['recommendations'].append("Avoid repeating characters")
        common_valid, common_msg = self.check_not_common_password(password)
        results['checks']['not_common'] = {'valid': common_valid, 'message': common_msg}
        if not common_valid:
            results['is_valid'] = False
            results['issues'].append(common_msg)
            results['recommendations'].append("Choose a more unique password")
        variety_valid, variety_msg = self.check_character_variety(password)
        results['checks']['character_variety'] = {'valid': variety_valid, 'message': variety_msg}
        keyboard_valid, keyboard_msg = self.check_keyboard_patterns(password)
        results['checks']['keyboard_patterns'] = {'valid': keyboard_valid, 'message': keyboard_msg}
        if not keyboard_valid:
            results['issues'].append(keyboard_msg)
            results['recommendations'].append("Avoid keyboard patterns")
        entropy_valid, entropy_msg = self.check_entropy(password)
        results['checks']['entropy'] = {'valid': entropy_valid, 'message': entropy_msg}
        similar_valid, similar_msg = self.check_similar_characters(password)
        results['checks']['similar_characters'] = {'valid': similar_valid, 'message': similar_msg}
        if not similar_valid:
            results['issues'].append(similar_msg)
        if len(results['issues']) > 0 and results['strength'] != "Very Strong":
            results['is_valid'] = False
        self.verification_results.append(results)
        return results
    def verify_password_match(self, password1, password2):
        if password1 == password2:
            return True, "Passwords match"
        return False, "Passwords do not match"
    def compare_passwords(self, password1, password2):
        results1 = self.verify_password(password1)
        results2 = self.verify_password(password2)
        comparison = {
            'password1_strength': results1['strength'],
            'password2_strength': results2['strength'],
            'password1_is_valid': results1['is_valid'],
            'password2_is_valid': results2['is_valid'],
            'passwords_match': password1 == password2,
            'stronger_password': results1['strength'] if results1['checks']['entropy']['valid'] else results2['strength']
        }
        return comparison
    def get_verification_history(self, limit=20):
        return self.verification_results[-limit:]
    def display_verification_result(self, result):
        print("\n" + "="*100)
        print("PASSWORD VERIFICATION RESULT")
        print("="*100)
        print(f"Password: {'*' * len(result['password'])}")
        print(f"Timestamp: {result['timestamp']}")
        print(f"Strength: {result['strength']}")
        print(f"Overall Status: {'VALID' if result['is_valid'] else 'INVALID'}")
        print("\nDetailed Checks:")
        print("-"*100)
        for check_name, check_result in result['checks'].items():
            status = "✓" if check_result['valid'] else "✗"
            print(f"{status} {check_name:<30} {check_result['message']:<50}")
        if result['issues']:
            print("\nIssues Found:")
            print("-"*100)
            for idx, issue in enumerate(result['issues'], 1):
                print(f"{idx}. {issue}")
        if result['recommendations']:
            print("\nRecommendations:")
            print("-"*100)
            for idx, rec in enumerate(result['recommendations'], 1):
                print(f"{idx}. {rec}")
        print("="*100 + "\n")
    def display_verification_history(self):
        if not self.verification_results:
            print("No verification history")
            return
        print("\n" + "="*130)
        print("PASSWORD VERIFICATION HISTORY")
        print("="*130)
        print(f"{'#':<5} {'Password':<20} {'Strength':<15} {'Valid':<10} {'Issues':<10} {'Timestamp':<25}")
        print("-"*130)
        for idx, result in enumerate(self.verification_results[-50:], 1):
            password_display = '*' * min(len(result['password']), 8) + f"({len(result['password'])} chars)"
            status = "✓" if result['is_valid'] else "✗"
            issues_count = len(result['issues'])
            print(f"{idx:<5} {password_display:<20} {result['strength']:<15} {status:<10} {issues_count:<10} {result['timestamp']:<25}")
        print("="*130 + "\n")
def main():
    verifier = PasswordVerifier()
    while True:
        print("\n" + "="*60)
        print("PASSWORD VERIFIER")
        print("="*60)
        print("1. Verify password")
        print("2. Compare two passwords")
        print("3. Check password strength")
        print("4. Verify password match")
        print("5. View verification history")
        print("6. Exit")
        choice = input("\nSelect an option (1-6): ").strip()
        if choice == '1':
            password = input("Enter password to verify: ").strip()
            if password:
                result = verifier.verify_password(password)
                verifier.display_verification_result(result)
            else:
                print("Password cannot be empty")
        elif choice == '2':
            password1 = input("Enter first password: ").strip()
            password2 = input("Enter second password: ").strip()
            if password1 and password2:
                comparison = verifier.compare_passwords(password1, password2)
                print("\n" + "="*80)
                print("PASSWORD COMPARISON")
                print("="*80)
                print(f"Password 1 Strength: {comparison['password1_strength']}")
                print(f"Password 2 Strength: {comparison['password2_strength']}")
                print(f"Password 1 Valid: {comparison['password1_is_valid']}")
                print(f"Password 2 Valid: {comparison['password2_is_valid']}")
                print(f"Passwords Match: {comparison['passwords_match']}")
                print(f"Stronger Password: Password {1 if comparison['password1_strength'] >= comparison['password2_strength'] else 2}")
                print("="*80)
            else:
                print("Both passwords cannot be empty")
        elif choice == '3':
            password = input("Enter password: ").strip()
            if password:
                strength = verifier.get_password_strength(password)
                print(f"\nPassword Strength: {strength}")
            else:
                print("Password cannot be empty")
        elif choice == '4':
            password1 = input("Enter password: ").strip()
            password2 = input("Confirm password: ").strip()
            if password1 and password2:
                match, msg = verifier.verify_password_match(password1, password2)
                print(f"Result: {msg}")
            else:
                print("Both passwords cannot be empty")
        elif choice == '5':
            verifier.display_verification_history()
        elif choice == '6':
            print("Exiting Password Verifier. Goodbye!")
            break
        else:
            print("Invalid option. Please select 1-6.")
if __name__ == '__main__':
    main()

import sqlite3
from datetime import datetime
import re
class UserDatabase:
    def __init__(self, db_file="users_data.db"):
        self.db_file = db_file
        self.init_database()
    def init_database(self):
        conn = sqlite3.connect(self.db_file)
        cursor = conn.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                email TEXT UNIQUE NOT NULL,
                password_hash TEXT NOT NULL,
                first_name TEXT,
                last_name TEXT,
                phone TEXT,
                date_of_birth TEXT,
                address TEXT,
                city TEXT,
                country TEXT,
                postal_code TEXT,
                gender TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                last_login TIMESTAMP,
                is_active BOOLEAN DEFAULT 1,
                account_type TEXT DEFAULT 'standard'
            )
        ''')
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS user_profiles (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL UNIQUE,
                bio TEXT,
                profile_picture_url TEXT,
                website TEXT,
                occupation TEXT,
                company TEXT,
                location TEXT,
                social_links TEXT,
                preferences TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users (id)
            )
        ''')
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS user_activity (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                activity_type TEXT,
                activity_description TEXT,
                ip_address TEXT,
                timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users (id)
            )
        ''')
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS user_settings (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL UNIQUE,
                notifications BOOLEAN DEFAULT 1,
                email_notifications BOOLEAN DEFAULT 1,
                two_factor_auth BOOLEAN DEFAULT 0,
                privacy_level TEXT DEFAULT 'public',
                theme TEXT DEFAULT 'light',
                language TEXT DEFAULT 'en',
                timezone TEXT DEFAULT 'UTC',
                FOREIGN KEY (user_id) REFERENCES users (id)
            )
        ''')
        conn.commit()
        conn.close()
    def get_connection(self):
        conn = sqlite3.connect(self.db_file)
        conn.row_factory = sqlite3.Row
        return conn
    def add_user(self, username, email, password_hash, first_name, last_name, phone=None, dob=None):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('''
                INSERT INTO users (username, email, password_hash, first_name, last_name, phone, date_of_birth, created_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            ''', (username, email, password_hash, first_name, last_name, phone, dob, datetime.now()))
            user_id = cursor.lastrowid
            cursor.execute('INSERT INTO user_profiles (user_id, created_at) VALUES (?, ?)', (user_id, datetime.now()))
            cursor.execute('INSERT INTO user_settings (user_id) VALUES (?)', (user_id,))
            conn.commit()
            conn.close()
            return True, f"User {username} added successfully with ID {user_id}"
        except sqlite3.IntegrityError as e:
            if "username" in str(e):
                return False, "Username already exists"
            elif "email" in str(e):
                return False, "Email already registered"
            return False, str(e)
        except Exception as e:
            return False, str(e)
    def fetch_user_by_id(self, user_id):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE id = ?', (user_id,))
            result = cursor.fetchone()
            conn.close()
            if result:
                return True, dict(result)
            return False, "User not found"
        except Exception as e:
            return False, str(e)
    def fetch_user_by_username(self, username):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE username = ?', (username,))
            result = cursor.fetchone()
            conn.close()
            if result:
                return True, dict(result)
            return False, "User not found"
        except Exception as e:
            return False, str(e)
    def fetch_user_by_email(self, email):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE email = ?', (email,))
            result = cursor.fetchone()
            conn.close()
            if result:
                return True, dict(result)
            return False, "User not found"
        except Exception as e:
            return False, str(e)
    def fetch_users_by_city(self, city):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE city = ? ORDER BY created_at DESC', (city,))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No users found in this city"
        except Exception as e:
            return False, str(e)
    def fetch_users_by_country(self, country):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE country = ? ORDER BY created_at DESC', (country,))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No users found in this country"
        except Exception as e:
            return False, str(e)
    def fetch_users_by_account_type(self, account_type):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE account_type = ? ORDER BY created_at DESC', (account_type,))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No users found with this account type"
        except Exception as e:
            return False, str(e)
    def fetch_active_users(self, limit=100):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE is_active = 1 ORDER BY last_login DESC LIMIT ?', (limit,))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No active users found"
        except Exception as e:
            return False, str(e)
    def fetch_users_created_after(self, date):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE created_at > ? ORDER BY created_at DESC', (date,))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No users found created after this date"
        except Exception as e:
            return False, str(e)
    def fetch_users_by_search(self, search_term):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            search_pattern = f"%{search_term}%"
            cursor.execute('''
                SELECT * FROM users WHERE username LIKE ? OR email LIKE ? OR first_name LIKE ? 
                OR last_name LIKE ? OR city LIKE ? OR country LIKE ? ORDER BY created_at DESC
            ''', (search_pattern, search_pattern, search_pattern, search_pattern, search_pattern, search_pattern))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No users found matching search term"
        except Exception as e:
            return False, str(e)
    def fetch_user_profile(self, user_id):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('''
                SELECT u.*, p.* FROM users u 
                LEFT JOIN user_profiles p ON u.id = p.user_id 
                WHERE u.id = ?
            ''', (user_id,))
            result = cursor.fetchone()
            conn.close()
            if result:
                return True, dict(result)
            return False, "User profile not found"
        except Exception as e:
            return False, str(e)
    def fetch_user_settings(self, user_id):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM user_settings WHERE user_id = ?', (user_id,))
            result = cursor.fetchone()
            conn.close()
            if result:
                return True, dict(result)
            return False, "User settings not found"
        except Exception as e:
            return False, str(e)
    def fetch_user_activity(self, user_id, limit=50):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('''
                SELECT * FROM user_activity WHERE user_id = ? ORDER BY timestamp DESC LIMIT ?
            ''', (user_id, limit))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No activity found for this user"
        except Exception as e:
            return False, str(e)
    def fetch_all_users(self, limit=1000, offset=0):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users ORDER BY created_at DESC LIMIT ? OFFSET ?', (limit, offset))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No users found"
        except Exception as e:
            return False, str(e)
    def fetch_users_by_name(self, first_name=None, last_name=None):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            if first_name and last_name:
                cursor.execute('SELECT * FROM users WHERE first_name = ? AND last_name = ? ORDER BY created_at DESC', 
                             (first_name, last_name))
            elif first_name:
                cursor.execute('SELECT * FROM users WHERE first_name = ? ORDER BY created_at DESC', (first_name,))
            elif last_name:
                cursor.execute('SELECT * FROM users WHERE last_name = ? ORDER BY created_at DESC', (last_name,))
            else:
                return False, "Please provide first name or last name"
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No users found with this name"
        except Exception as e:
            return False, str(e)
    def fetch_users_by_phone(self, phone):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE phone = ? ORDER BY created_at DESC', (phone,))
            results = cursor.fetchall()
            conn.close()
            if results:
                return True, [dict(row) for row in results]
            return False, "No users found with this phone number"
        except Exception as e:
            return False, str(e)
    def get_total_users_count(self):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT COUNT(*) as count FROM users')
            result = cursor.fetchone()
            conn.close()
            return result['count'] if result else 0
        except Exception as e:
            return 0
    def get_active_users_count(self):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT COUNT(*) as count FROM users WHERE is_active = 1')
            result = cursor.fetchone()
            conn.close()
            return result['count'] if result else 0
        except Exception as e:
            return 0
    def update_user(self, user_id, **kwargs):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            allowed_fields = ['first_name', 'last_name', 'phone', 'date_of_birth', 'address', 
                            'city', 'country', 'postal_code', 'gender', 'account_type', 'is_active']
            update_fields = {k: v for k, v in kwargs.items() if k in allowed_fields}
            if not update_fields:
                return False, "No valid fields to update"
            update_fields['updated_at'] = datetime.now()
            set_clause = ', '.join([f"{k} = ?" for k in update_fields.keys()])
            values = list(update_fields.values()) + [user_id]
            cursor.execute(f"UPDATE users SET {set_clause} WHERE id = ?", values)
            conn.commit()
            conn.close()
            return True, "User updated successfully"
        except Exception as e:
            return False, str(e)
    def record_user_activity(self, user_id, activity_type, description, ip_address=None):
        try:
            conn = self.get_connection()
            cursor = conn.cursor()
            cursor.execute('''
                INSERT INTO user_activity (user_id, activity_type, activity_description, ip_address, timestamp)
                VALUES (?, ?, ?, ?, ?)
            ''', (user_id, activity_type, description, ip_address, datetime.now()))
            conn.commit()
            conn.close()
            return True, "Activity recorded"
        except Exception as e:
            return False, str(e)
    def display_user_data(self, user_data):
        if isinstance(user_data, dict):
            print("\n" + "="*80)
            print("USER DATA")
            print("="*80)
            for key, value in user_data.items():
                print(f"{key}: {value}")
            print("="*80 + "\n")
        elif isinstance(user_data, list):
            if not user_data:
                print("No data to display")
                return
            print("\n" + "="*150)
            print("USER DATA LIST")
            print("="*150)
            headers = list(user_data[0].keys())
            header_str = " | ".join([f"{h:<20}" for h in headers[:8]])
            print(header_str)
            print("-"*150)
            for row in user_data[:20]:
                row_str = " | ".join([f"{str(row[h]):<20}" for h in headers[:8]])
                print(row_str)
            if len(user_data) > 20:
                print(f"\n... and {len(user_data) - 20} more records")
            print("="*150 + "\n")
