import sqlite3
def create_database():
    conn = sqlite3.connect("users.db")
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT NOT NULL UNIQUE,
            email TEXT NOT NULL UNIQUE,
            age INTEGER NOT NULL
        )
    """)
    conn.commit()
    conn.close()
def insert_user(username, email, age):
    conn = sqlite3.connect("users.db")
    cursor = conn.cursor()
    try:
        cursor.execute("INSERT INTO users (username, email, age) VALUES (?, ?, ?)", (username, email, age))
        conn.commit()
        print("\nUser inserted successfully.")
    except sqlite3.IntegrityError as e:
        print(f"\nError: {e}")
    finally:
        conn.close()
def fetch_all():
    conn = sqlite3.connect("users.db")
    cursor = conn.cursor()
    cursor.execute("SELECT * FROM users")
    rows = cursor.fetchall()
    conn.close()
    return rows
def display_all_users():
    rows = fetch_all()
    if rows:
        print("\nAll Users:")
        print(f"{'ID':<5} {'Username':<15} {'Email':<25} {'Age':<5}")
        print("-" * 50)
        for row in rows:
            print(f"{row[0]:<5} {row[1]:<15} {row[2]:<25} {row[3]:<5}")
    else:
        print("\nNo users found.")
def validate_age(age_str):
    if age_str.isdigit() and int(age_str) > 0:
        return int(age_str)
    return None
def main():
    create_database()
    while True:
        print("\n1. Insert User\n2. View All Users\n3. Exit")
        choice = input("Choose an option: ")
        if choice == "1":
            username = input("Enter username: ").strip()
            email = input("Enter email: ").strip()
            age_input = input("Enter age: ").strip()
            age = validate_age(age_input)
            if not username or not email:
                print("\nUsername and email cannot be empty.")
            elif age is None:
                print("\nInvalid age. Please enter a positive number.")
            else:
                insert_user(username, email, age)
        elif choice == "2":
            display_all_users()
        elif choice == "3":
            print("Goodbye!")
            break
        else:
            print("Invalid option.")
main()

import sqlite3
def delete_user():
