import sqlite3
import hashlib
import getpass
def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()
def create_database():
    conn = sqlite3.connect('users.db')
    cursor = conn.cursor()
    cursor.execute('''CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT UNIQUE NOT NULL,
        password TEXT NOT NULL
    )''')
    conn.commit()
    conn.close()
def register_user(username, password):
    try:
        conn = sqlite3.connect('users.db')
        cursor = conn.cursor()
        hashed_password = hash_password(password)
        cursor.execute('INSERT INTO users (username, password) VALUES (?, ?)', (username, hashed_password))
        conn.commit()
        conn.close()
        return True
    except sqlite3.IntegrityError:
        return False
def login_user(username, password):
    conn = sqlite3.connect('users.db')
    cursor = conn.cursor()
    hashed_password = hash_password(password)
    cursor.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, hashed_password))
    user = cursor.fetchone()
    conn.close()
    return user is not None
def main():
    create_database()
    while True:
        print("\n=== Database Login System ===")
        print("1. Register")
        print("2. Login")
        print("3. Exit")
        choice = input("Enter your choice (1-3): ")
        if choice == '1':
            username = input("Enter username: ")
            password = getpass.getpass("Enter password: ")
            if register_user(username, password):
                print("Registration successful!")
            else:
                print("Username already exists!")
        elif choice == '2':
            username = input("Enter username: ")
            password = getpass.getpass("Enter password: ")
            if login_user(username, password):
                print(f"Login successful! Welcome {username}!")
            else:
                print("Invalid username or password!")
        elif choice == '3':
            print("Goodbye!")
            break
        else:
            print("Invalid choice!")
if __name__ == "__main__":
    main()

import sqlite3
def build_and_execute(table, filters):
    query = f"SELECT * FROM {table}"
    conditions = []
    values = []
    for column, value in filters.items():
        conditions.append(f"{column} = ?")
        values.append(value)
    if conditions:
        query += " WHERE " + " AND ".join(conditions)
    conn = sqlite3.connect("system.db")
    cursor = conn.cursor()
    try:
        cursor.execute(query, values)
        results = cursor.fetchall()
        for row in results:
            print(row)
        return results
    except Exception as e:
        print(f"Error: {e}")
    finally:
        conn.close()
if __name__ == "__main__":
    search_criteria = {"role": "Superuser", "username": "admin"}
    build_and_execute("members", search_criteria)

def filter_db_queries(data, filters):
    result = []
    for record in data:
        match = True
        for key, value in filters.items():
            if key not in record or record[key] != value:
                match = False
                break
        if match:
            result.append(record)
    return result
database = [
    {"id": 1, "name": "Alice", "age": 25, "city": "New York"},
    {"id": 2, "name": "Bob", "age": 30, "city": "London"},
    {"id": 3, "name": "Charlie", "age": 25, "city": "New York"},
    {"id": 4, "name": "David", "age": 35, "city": "Paris"}
]
filters = {"age": 25, "city": "New York"}
filtered_data = filter_db_queries(database, filters)
for record in filtered_data:
    print(record)

class ProductSearchSystem:
    def __init__(self):
        self.products = []
    def add_product(self, product_id, name, category, price, stock):
        product = {
            "id": product_id,
            "name": name,
            "category": category,
            "price": price,
            "stock": stock
        }
        self.products.append(product)
    def search_by_name(self, name):
        return [p for p in self.products if name.lower() in p["name"].lower()]
    def search_by_category(self, category):
        return [p for p in self.products if p["category"].lower() == category.lower()]
    def search_by_price_range(self, min_price, max_price):
        return [p for p in self.products if min_price <= p["price"] <= max_price]
    def search_in_stock(self):
        return [p for p in self.products if p["stock"] > 0]
    def advanced_search(self, name=None, category=None, min_price=None, max_price=None, in_stock=False):
        results = self.products
        if name:
            results = [p for p in results if name.lower() in p["name"].lower()]
        if category:
            results = [p for p in results if p["category"].lower() == category.lower()]
        if min_price is not None:
            results = [p for p in results if p["price"] >= min_price]
        if max_price is not None:
            results = [p for p in results if p["price"] <= max_price]
        if in_stock:
            results = [p for p in results if p["stock"] > 0]
        return results
system = ProductSearchSystem()
system.add_product(1, "Laptop", "Electronics", 1200, 5)
system.add_product(2, "Mouse", "Electronics", 25, 50)
system.add_product(3, "Keyboard", "Electronics", 75, 0)
system.add_product(4, "Desk", "Furniture", 300, 10)
system.add_product(5, "Chair", "Furniture", 150, 8)
print("Search by name 'Laptop':", system.search_by_name("Laptop"))
print("Search by category 'Electronics':", system.search_by_category("Electronics"))
print("Search by price range 50-500:", system.search_by_price_range(50, 500))
print("Search in stock:", system.search_in_stock())
print("Advanced search:", system.advanced_search(category="Electronics", min_price=50, in_stock=True))

from flask import Flask,request,jsonify
import sqlite3
app=Flask(__name__)
def get_db():
    return sqlite3.connect("users.db")
@app.route("/users",methods=["GET"])
def get_users():
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("SELECT username,password FROM users")
    rows=cursor.fetchall()
    conn.close()
    return jsonify(rows)
@app.route("/users",methods=["POST"])
def add_user():
    data=request.get_json()
    username=data.get("username")
    password=data.get("password")
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("CREATE TABLE IF NOT EXISTS users (username TEXT PRIMARY KEY, password TEXT)")
    try:
        cursor.execute("INSERT INTO users (username,password) VALUES (?,?)",(username,password))
        conn.commit()
        conn.close()
        return jsonify({"message":"User added"})
    except:
        conn.close()
        return jsonify({"message":"User exists"})
@app.route("/users/<username>",methods=["DELETE"])
def delete_user(username):
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("DELETE FROM users WHERE username=?",(username,))
    conn.commit()
    count=cursor.rowcount
    conn.close()
    if count>0:
        return jsonify({"message":"User deleted"})
    return jsonify({"message":"User not found"})
if __name__=="__main__":
    app.run(debug=True)

from flask import Flask, request, jsonify
app = Flask(__name__)
users = []
user_id_counter = 1
@app.route('/users', methods=['GET'])
def get_users():
    return jsonify(users), 200
@app.route('/users/<int:user_id>', methods=['GET'])
def get_user(user_id):
    user = next((u for u in users if u['id'] == user_id), None)
    if user:
        return jsonify(user), 200
    return jsonify({"error": "User not found"}), 404
@app.route('/users', methods=['POST'])
def create_user():
    global user_id_counter
    data = request.get_json()
    if not data or 'name' not in data or 'email' not in data:
        return jsonify({"error": "Name and email are required"}), 400
    user = {
        "id": user_id_counter,
        "name": data['name'],
        "email": data['email'],
        "age": data.get('age', None)
    }
    users.append(user)
    user_id_counter += 1
    return jsonify(user), 201
@app.route('/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    user = next((u for u in users if u['id'] == user_id), None)
    if not user:
        return jsonify({"error": "User not found"}), 404
    data = request.get_json()
    if 'name' in data:
        user['name'] = data['name']
    if 'email' in data:
        user['email'] = data['email']
    if 'age' in data:
        user['age'] = data['age']
    return jsonify(user), 200
@app.route('/users/<int:user_id>', methods=['DELETE'])
def delete_user(user_id):
    global users
    user = next((u for u in users if u['id'] == user_id), None)
    if not user:
        return jsonify({"error": "User not found"}), 404
    users = [u for u in users if u['id'] != user_id]
    return jsonify({"message": "User deleted successfully"}), 200
if __name__ == '__main__':
    app.run(debug=True)

from flask import Flask, request, jsonify
app = Flask(__name__)
users = {1: {"name": "Alice", "role": "Admin"}, 2: {"name": "Bob", "role": "User"}}
@app.route("/users", methods=["GET"])
def get_users():
    return jsonify(users), 200
@app.route("/users/<int:user_id>", methods=["GET"])
def get_user(user_id):
    user = users.get(user_id)
    return jsonify(user) if user else (jsonify({"error": "Not found"}), 404)
@app.route("/users", methods=["POST"])
def create_user():
    data = request.get_json()
    new_id = max(users.keys()) + 1
    users[new_id] = data
    return jsonify({"id": new_id}), 201
@app.route("/users/<int:user_id>", methods=["PUT"])
def update_user(user_id):
    if user_id not in users: return jsonify({"error": "Not found"}), 404
    users[user_id].update(request.get_json())
    return jsonify({"message": "Updated"}), 200
@app.route("/users/<int:user_id>", methods=["DELETE"])
def delete_user(user_id):
    if users.pop(user_id, None): return jsonify({"message": "Deleted"}), 200
    return jsonify({"error": "Not found"}), 404
if __name__ == "__main__":
    app.run(debug=True)

from flask import Flask,request,jsonify
import sqlite3
app=Flask(__name__)
def get_db():
    return sqlite3.connect("users.db")
@app.route("/users",methods=["GET"])
def get_users():
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("CREATE TABLE IF NOT EXISTS users (username TEXT PRIMARY KEY, password TEXT)")
    cursor.execute("SELECT username,password FROM users")
    rows=cursor.fetchall()
    conn.close()
    return jsonify(rows)
@app.route("/users",methods=["POST"])
def create_user():
    data=request.get_json()
    username=data.get("username")
    password=data.get("password")
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("INSERT INTO users (username,password) VALUES (?,?)",(username,password))
    conn.commit()
    conn.close()
    return jsonify({"message":"User created"})
@app.route("/users/<username>",methods=["PUT"])
def update_user(username):
    data=request.get_json()
    password=data.get("password")
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("UPDATE users SET password=? WHERE username=?",(password,username))
    conn.commit()
    count=cursor.rowcount
    conn.close()
    if count>0:
        return jsonify({"message":"User updated"})
    return jsonify({"message":"User not found"})
@app.route("/users/<username>",methods=["DELETE"])
def delete_user(username):
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("DELETE FROM users WHERE username=?",(username,))
    conn.commit()
    count=cursor.rowcount
    conn.close()
    if count>0:
        return jsonify({"message":"User deleted"})
    return jsonify({"message":"User not found"})
if __name__=="__main__":
    app.run(debug=True)

from flask import Flask, request, jsonify, render_template_string
app = Flask(__name__)
users_data = []
user_counter = 1
HTML_TEMPLATE = '''
