    return render_template_string(HTML_TEMPLATE)
@app.route('/api/users', methods=['GET'])
def get_all_users():
    return jsonify(users_data), 200
@app.route('/api/users/<int:user_id>', methods=['GET'])
def get_user_by_id(user_id):
    user = next((u for u in users_data if u['id'] == user_id), None)
    if user:
        return jsonify(user), 200
    return jsonify({"error": "User not found"}), 404
@app.route('/api/users', methods=['POST'])
def add_user():
    global user_counter
    data = request.get_json()
    if not data or 'name' not in data or 'email' not in data:
        return jsonify({"error": "Name and email required"}), 400
    new_user = {
        "id": user_counter,
        "name": data['name'],
        "email": data['email'],
        "age": data.get('age')
    }
    users_data.append(new_user)
    user_counter += 1
    return jsonify(new_user), 201
@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user_data(user_id):
    user = next((u for u in users_data if u['id'] == user_id), None)
    if not user:
        return jsonify({"error": "User not found"}), 404
    data = request.get_json()
    user['name'] = data.get('name', user['name'])
    user['email'] = data.get('email', user['email'])
    user['age'] = data.get('age', user['age'])
    return jsonify(user), 200
@app.route('/api/users/<int:user_id>', methods=['DELETE'])
def remove_user(user_id):
    global users_data
    user = next((u for u in users_data if u['id'] == user_id), None)
    if not user:
        return jsonify({"error": "User not found"}), 404
    users_data = [u for u in users_data if u['id'] != user_id]
    return jsonify({"message": "User deleted"}), 200
if __name__ == '__main__':
    app.run(debug=True, port=5000)

from flask import Flask, render_template, request, redirect, url_for, flash, session
from werkzeug.security import generate_password_hash, check_password_hash
import sqlite3
from datetime import datetime
from functools import wraps
app = Flask(__name__)
app.secret_key = 'your_secret_key_here_change_in_production'
DATABASE = 'users_data.db'
def get_db_connection():
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    return conn
def init_database():
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('''CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT UNIQUE NOT NULL,
        email TEXT UNIQUE NOT NULL,
        password TEXT NOT NULL,
        first_name TEXT,
        last_name TEXT,
        phone TEXT,
        address TEXT,
        city TEXT,
        country TEXT,
        age INTEGER,
        profile_picture TEXT,
        created_at TEXT NOT NULL,
        updated_at TEXT NOT NULL
    )''')
    cursor.execute('''CREATE TABLE IF NOT EXISTS posts (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        title TEXT NOT NULL,
        content TEXT NOT NULL,
        created_at TEXT NOT NULL,
        FOREIGN KEY (user_id) REFERENCES users(id)
    )''')
    conn.commit()
    conn.close()
def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            flash('Please log in first', 'warning')
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function
@app.route('/')
def index():
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT COUNT(*) as count FROM users')
    total_users = cursor.fetchone()['count']
    cursor.execute('SELECT COUNT(*) as count FROM posts')
    total_posts = cursor.fetchone()['count']
    conn.close()
    return render_template('index.html', total_users=total_users, total_posts=total_posts)
@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form.get('username')
        email = request.form.get('email')
        password = request.form.get('password')
        confirm_password = request.form.get('confirm_password')
        first_name = request.form.get('first_name')
        last_name = request.form.get('last_name')
        if not username or not email or not password:
            flash('Username, email, and password are required', 'danger')
            return redirect(url_for('register'))
        if password != confirm_password:
            flash('Passwords do not match', 'danger')
            return redirect(url_for('register'))
        hashed_password = generate_password_hash(password)
        now = datetime.now().isoformat()
        conn = get_db_connection()
        cursor = conn.cursor()
        try:
            cursor.execute('''INSERT INTO users (username, email, password, first_name, last_name, created_at, updated_at)
                             VALUES (?, ?, ?, ?, ?, ?, ?)''',
                          (username, email, hashed_password, first_name, last_name, now, now))
            conn.commit()
            conn.close()
            flash('Registration successful! Please log in.', 'success')
            return redirect(url_for('login'))
        except sqlite3.IntegrityError:
            conn.close()
            flash('Username or email already exists', 'danger')
            return redirect(url_for('register'))
    return render_template('register.html')
@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        if not username or not password:
            flash('Username and password are required', 'danger')
            return redirect(url_for('login'))
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM users WHERE username = ?', (username,))
        user = cursor.fetchone()
        conn.close()
        if user is None or not check_password_hash(user['password'], password):
            flash('Invalid username or password', 'danger')
            return redirect(url_for('login'))
        session['user_id'] = user['id']
        session['username'] = user['username']
        flash(f'Welcome back, {user["username"]}!', 'success')
        return redirect(url_for('dashboard'))
    return render_template('login.html')
@app.route('/dashboard')
