from flask import Flask, request, jsonify, send_from_directory
import os
from werkzeug.utils import secure_filename
app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif', 'doc', 'docx'}
MAX_FILE_SIZE = 16 * 1024 * 1024
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_FILE_SIZE
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)
uploaded_files_list = []
def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS
@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({"error": "No file part"}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)
        file_info = {
            "filename": filename,
            "size": os.path.getsize(filepath),
            "path": filepath
        }
        uploaded_files_list.append(file_info)
        return jsonify({"message": "File uploaded successfully", "file": file_info}), 201
    return jsonify({"error": "File type not allowed"}), 400
@app.route('/files', methods=['GET'])
def list_files():
    return jsonify({"files": uploaded_files_list}), 200
@app.route('/files/<filename>', methods=['GET'])
def download_file(filename):
    return send_from_directory(app.config['UPLOAD_FOLDER'], filename)
@app.route('/files/<filename>', methods=['DELETE'])
def delete_file(filename):
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if os.path.exists(filepath):
        os.remove(filepath)
        global uploaded_files_list
        uploaded_files_list = [f for f in uploaded_files_list if f['filename'] != filename]
        return jsonify({"message": "File deleted successfully"}), 200
    return jsonify({"error": "File not found"}), 404
@app.route('/upload/multiple', methods=['POST'])
def upload_multiple_files():
    if 'files' not in request.files:
        return jsonify({"error": "No files part"}), 400
    files = request.files.getlist('files')
    uploaded = []
    for file in files:
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            file.save(filepath)
            file_info = {
                "filename": filename,
                "size": os.path.getsize(filepath),
                "path": filepath
            }
            uploaded_files_list.append(file_info)
            uploaded.append(file_info)
    return jsonify({"message": f"{len(uploaded)} files uploaded", "files": uploaded}), 201
if __name__ == '__main__':
    app.run(debug=True, port=5000)

from flask import Flask, request, jsonify, send_file
from werkzeug.utils import secure_filename
import os
import sqlite3
from datetime import datetime
from functools import wraps
import mimetypes
import hashlib
app = Flask(__name__)
app.secret_key = 'file_upload_secret_key'
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif', 'doc', 'docx', 'xls', 'xlsx', 'zip'}
MAX_FILE_SIZE = 50 * 1024 * 1024
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_FILE_SIZE
DATABASE = 'file_uploads.db'
def get_db_connection():
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    return conn
def init_database():
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('''CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT UNIQUE NOT NULL,
        password TEXT NOT NULL,
        email TEXT UNIQUE NOT NULL,
        created_at TEXT NOT NULL
    )''')
    cursor.execute('''CREATE TABLE IF NOT EXISTS files (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        original_filename TEXT NOT NULL,
        stored_filename TEXT NOT NULL,
        file_size INTEGER NOT NULL,
        file_type TEXT NOT NULL,
        file_hash TEXT NOT NULL,
        upload_date TEXT NOT NULL,
        description TEXT,
        FOREIGN KEY (user_id) REFERENCES users(id)
    )''')
    conn.commit()
    conn.close()
def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS
def get_file_hash(filepath):
    sha256_hash = hashlib.sha256()
    with open(filepath, 'rb') as f:
        for byte_block in iter(lambda: f.read(4096), b''):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest()
def token_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({'status': 'error', 'message': 'Token is missing'}), 401
        try:
            user_id = int(token.split(' ')[1])
        except:
            return jsonify({'status': 'error', 'message': 'Invalid token'}), 401
        return f(user_id, *args, **kwargs)
    return decorated_function
@app.route('/api/register', methods=['POST'])
def register():
    data = request.get_json()
    if not data or not data.get('username') or not data.get('password') or not data.get('email'):
        return jsonify({'status': 'error', 'message': 'Missing required fields'}), 400
    username = data['username']
    password = data['password']
    email = data['email']
    now = datetime.now().isoformat()
    conn = get_db_connection()
    cursor = conn.cursor()
    try:
        cursor.execute('INSERT INTO users (username, password, email, created_at) VALUES (?, ?, ?, ?)',
                      (username, password, email, now))
        conn.commit()
        user_id = cursor.lastrowid
        conn.close()
        return jsonify({'status': 'success', 'message': 'User registered', 'user_id': user_id}), 201
    except sqlite3.IntegrityError:
        conn.close()
        return jsonify({'status': 'error', 'message': 'Username or email already exists'}), 409
@app.route('/api/login', methods=['POST'])
def login():
    data = request.get_json()
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'status': 'error', 'message': 'Missing credentials'}), 400
    username = data['username']
    password = data['password']
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT id FROM users WHERE username = ? AND password = ?', (username, password))
    user = cursor.fetchone()
    conn.close()
    if user is None:
        return jsonify({'status': 'error', 'message': 'Invalid credentials'}), 401
    return jsonify({'status': 'success', 'message': 'Login successful', 'token': f'Bearer {user["id"]}'}), 200
@app.route('/api/upload', methods=['POST'])
@token_required
def upload_file(user_id):
    if 'file' not in request.files:
        return jsonify({'status': 'error', 'message': 'No file provided'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'status': 'error', 'message': 'No file selected'}), 400
    if not allowed_file(file.filename):
        return jsonify({'status': 'error', 'message': 'File type not allowed'}), 400
    description = request.form.get('description', '')
    original_filename = secure_filename(file.filename)
    file_ext = original_filename.rsplit('.', 1)[1].lower()
    stored_filename = f"{user_id}_{datetime.now().timestamp()}_{original_filename}"
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], stored_filename)
    file.save(filepath)
    file_size = os.path.getsize(filepath)
    file_hash = get_file_hash(filepath)
    file_type = mimetypes.guess_type(filepath)[0] or 'unknown'
    now = datetime.now().isoformat()
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('''INSERT INTO files (user_id, original_filename, stored_filename, file_size, file_type, file_hash, upload_date, description)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?)''',
                  (user_id, original_filename, stored_filename, file_size, file_type, file_hash, now, description))
    conn.commit()
    file_id = cursor.lastrowid
    conn.close()
    return jsonify({
        'status': 'success',
        'message': 'File uploaded successfully',
        'file_id': file_id,
        'filename': original_filename,
        'size': file_size
    }), 201
@app.route('/api/files', methods=['GET'])
@token_required
def list_files(user_id):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT id, original_filename, file_size, file_type, upload_date, description FROM files WHERE user_id = ? ORDER BY upload_date DESC', (user_id,))
    files = cursor.fetchall()
    conn.close()
    file_list = []
    for file in files:
        file_list.append({
            'id': file['id'],
            'filename': file['original_filename'],
            'size': file['file_size'],
            'type': file['file_type'],
            'upload_date': file['upload_date'],
            'description': file['description']
        })
    return jsonify({'status': 'success', 'count': len(file_list), 'files': file_list}), 200
@app.route('/api/files/<int:file_id>', methods=['GET'])
@token_required
def get_file_info(user_id, file_id):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT * FROM files WHERE id = ? AND user_id = ?', (file_id, user_id))
    file = cursor.fetchone()
    conn.close()
    if file is None:
        return jsonify({'status': 'error', 'message': 'File not found'}), 404
    return jsonify({
        'status': 'success',
        'file': {
            'id': file['id'],
            'filename': file['original_filename'],
            'size': file['file_size'],
            'type': file['file_type'],
            'upload_date': file['upload_date'],
            'description': file['description'],
            'hash': file['file_hash']
        }
    }), 200
@app.route('/api/download/<int:file_id>', methods=['GET'])
@token_required
def download_file(user_id, file_id):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT stored_filename, original_filename FROM files WHERE id = ? AND user_id = ?', (file_id, user_id))
    file = cursor.fetchone()
    conn.close()
    if file is None:
        return jsonify({'status': 'error', 'message': 'File not found'}), 404
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], file['stored_filename'])
    if not os.path.exists(filepath):
        return jsonify({'status': 'error', 'message': 'File not found on server'}), 404
    return send_file(filepath, as_attachment=True, download_name=file['original_filename'])
@app.route('/api/delete/<int:file_id>', methods=['DELETE'])
@token_required
def delete_file(user_id, file_id):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT stored_filename FROM files WHERE id = ? AND user_id = ?', (file_id, user_id))
    file = cursor.fetchone()
    if file is None:
        conn.close()
        return jsonify({'status': 'error', 'message': 'File not found'}), 404
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], file['stored_filename'])
    if os.path.exists(filepath):
        os.remove(filepath)
    cursor.execute('DELETE FROM files WHERE id = ?', (file_id,))
    conn.commit()
    conn.close()
    return jsonify({'status': 'success', 'message': 'File deleted successfully'}), 200
@app.route('/api/search', methods=['GET'])
@token_required
def search_files(user_id):
    query = request.args.get('q', '')
    if not query:
        return jsonify({'status': 'error', 'message': 'Search query required'}), 400
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT id, original_filename, file_size, file_type, upload_date FROM files WHERE user_id = ? AND original_filename LIKE ? ORDER BY upload_date DESC',
                  (user_id, f'%{query}%'))
    files = cursor.fetchall()
    conn.close()
    file_list = []
    for file in files:
        file_list.append({
            'id': file['id'],
            'filename': file['original_filename'],
            'size': file['file_size'],
            'type': file['file_type'],
            'upload_date': file['upload_date']
        })
    return jsonify({'status': 'success', 'count': len(file_list), 'files': file_list}), 200
@app.route('/api/stats', methods=['GET'])
@token_required
def get_stats(user_id):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute('SELECT COUNT(*) as total_files, SUM(file_size) as total_size FROM files WHERE user_id = ?', (user_id,))
    stats = cursor.fetchone()
    conn.close()
    return jsonify({
        'status': 'success',
        'total_files': stats['total_files'] or 0,
        'total_size': stats['total_size'] or 0
    }), 200
@app.errorhandler(413)
def request_entity_too_large(error):
