from flask import Flask, jsonify, request
from datetime import datetime
import re
import uuid
app = Flask(__name__)
posts = []
comments = []
tags = []
categories = []
def slugify(title):
    title = title.lower()
    title = re.sub(r'[^a-z0-9\s-]', '', title)
    title = re.sub(r'\s+', '-', title.strip())
    return title
def validate_email(email):
    pattern = r'^[\w\.-]+@[\w\.-]+\.\w+$'
    return re.match(pattern, email) is not None
def get_reading_time(content):
    words = len(content.split())
    minutes = max(1, round(words / 200))
    return f"{minutes} min read"
@app.route('/categories', methods=['GET'])
def get_categories():
    return jsonify({"total": len(categories), "categories": categories})
@app.route('/categories', methods=['POST'])
def create_category():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    name = data.get('name', '').strip()
    if not name:
        return jsonify({"error": "Category name is required"}), 400
    if any(c['name'].lower() == name.lower() for c in categories):
        return jsonify({"error": "Category already exists"}), 409
    category = {
        "id": str(uuid.uuid4()),
        "name": name,
        "slug": slugify(name),
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    categories.append(category)
    return jsonify({"message": "Category created successfully", "category": category}), 201
@app.route('/tags', methods=['GET'])
def get_tags():
    return jsonify({"total": len(tags), "tags": tags})
@app.route('/tags', methods=['POST'])
def create_tag():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    name = data.get('name', '').strip()
    if not name:
        return jsonify({"error": "Tag name is required"}), 400
    if any(t['name'].lower() == name.lower() for t in tags):
        return jsonify({"error": "Tag already exists"}), 409
    tag = {
        "id": str(uuid.uuid4()),
        "name": name,
        "slug": slugify(name),
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    tags.append(tag)
    return jsonify({"message": "Tag created successfully", "tag": tag}), 201
@app.route('/posts', methods=['GET'])
def get_posts():
    category = request.args.get('category', '').lower()
    author = request.args.get('author', '').lower()
    tag = request.args.get('tag', '').lower()
    status = request.args.get('status', '').lower()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 5, type=int)
    result = posts
    if category:
        result = [p for p in result if p['category'].lower() == category]
    if author:
        result = [p for p in result if p['author'].lower() == author]
    if tag:
        result = [p for p in result if tag in [t.lower() for t in p['tags']]]
    if status:
        result = [p for p in result if p['status'].lower() == status]
    total = len(result)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = result[start:end]
    return jsonify({
        "total": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "posts": paginated
    })
@app.route('/posts/<string:post_id>', methods=['GET'])
def get_post(post_id):
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    post['views'] = post.get('views', 0) + 1
    post_comments = [c for c in comments if c['post_id'] == post_id and c['status'] == 'approved']
    return jsonify({"post": post, "comments": post_comments, "total_comments": len(post_comments)})
@app.route('/posts', methods=['POST'])
def create_post():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    title = data.get('title', '').strip()
    content = data.get('content', '').strip()
    author = data.get('author', '').strip()
    author_email = data.get('author_email', '').strip()
    category = data.get('category', 'General').strip()
    post_tags = data.get('tags', [])
    status = data.get('status', 'draft').strip()
    thumbnail = data.get('thumbnail', '').strip()
    errors = {}
    if not title:
        errors['title'] = "Title is required"
    if not content:
        errors['content'] = "Content is required"
    if not author:
        errors['author'] = "Author is required"
    if author_email and not validate_email(author_email):
        errors['author_email'] = "Invalid email format"
    if status not in ['draft', 'published', 'archived']:
        errors['status'] = "Status must be draft, published, or archived"
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    new_post = {
        "id": str(uuid.uuid4()),
        "title": title,
        "slug": slugify(title),
        "content": content,
        "excerpt": content[:150] + "..." if len(content) > 150 else content,
        "author": author,
        "author_email": author_email,
        "category": category,
        "tags": post_tags,
        "status": status,
        "thumbnail": thumbnail,
        "views": 0,
        "reading_time": get_reading_time(content),
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "updated_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "published_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S') if status == 'published' else None
    }
    posts.append(new_post)
    return jsonify({"message": "Post created successfully", "post": new_post}), 201
@app.route('/posts/<string:post_id>', methods=['PUT'])
def update_post(post_id):
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    data = request.get_json()
    post['title'] = data.get('title', post['title'])
    post['content'] = data.get('content', post['content'])
    post['category'] = data.get('category', post['category'])
    post['tags'] = data.get('tags', post['tags'])
    post['status'] = data.get('status', post['status'])
    post['thumbnail'] = data.get('thumbnail', post['thumbnail'])
    post['slug'] = slugify(post['title'])
    post['excerpt'] = post['content'][:150] + "..." if len(post['content']) > 150 else post['content']
    post['reading_time'] = get_reading_time(post['content'])
    post['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    if post['status'] == 'published' and not post['published_at']:
        post['published_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Post updated successfully", "post": post})
@app.route('/posts/<string:post_id>', methods=['DELETE'])
def delete_post(post_id):
    global posts, comments
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    posts = [p for p in posts if p['id'] != post_id]
    comments = [c for c in comments if c['post_id'] != post_id]
    return jsonify({"message": f"Post '{post['title']}' deleted successfully"})
@app.route('/posts/<string:post_id>/comments', methods=['GET'])
def get_post_comments(post_id):
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    status = request.args.get('status', '').lower()
    result = [c for c in comments if c['post_id'] == post_id]
    if status:
        result = [c for c in result if c['status'] == status]
    return jsonify({"total": len(result), "comments": result})
@app.route('/posts/<string:post_id>/comments', methods=['POST'])
def add_comment(post_id):
    post = next((p for p in posts if p['id'] == post_id), None)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    data = request.get_json()
    name = data.get('name', '').strip()
    email = data.get('email', '').strip()
    content = data.get('content', '').strip()
    parent_id = data.get('parent_id', None)
    errors = {}
    if not name:
        errors['name'] = "Name is required"
    if not email:
        errors['email'] = "Email is required"
    elif not validate_email(email):
        errors['email'] = "Invalid email format"
    if not content or len(content) < 2:
        errors['content'] = "Content must be at least 2 characters"
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    new_comment = {
        "id": str(uuid.uuid4()),
        "post_id": post_id,
        "parent_id": parent_id,
        "name": name,
        "email": email,
        "content": content,
        "status": "pending",
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    comments.append(new_comment)
    return jsonify({"message": "Comment submitted and pending approval", "comment": new_comment}), 201
@app.route('/comments/<string:comment_id>/status', methods=['PATCH'])
def update_comment_status(comment_id):
    comment = next((c for c in comments if c['id'] == comment_id), None)
    if not comment:
        return jsonify({"error": "Comment not found"}), 404
    data = request.get_json()
    new_status = data.get('status', '').strip().lower()
    valid_statuses = ['pending', 'approved', 'rejected', 'spam']
    if new_status not in valid_statuses:
        return jsonify({"error": f"Status must be one of: {', '.join(valid_statuses)}"}), 400
    comment['status'] = new_status
    comment['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Comment status updated successfully", "comment": comment})
@app.route('/posts/search', methods=['GET'])
def search_posts():
    query = request.args.get('q', '').lower()
    if not query:
        return jsonify({"error": "Search query is required"}), 400
    results = [p for p in posts if
               query in p['title'].lower() or
               query in p['content'].lower() or
               query in p['author'].lower() or
               query in p['category'].lower()]
    return jsonify({"query": query, "total": len(results), "results": results})
@app.route('/posts/stats', methods=['GET'])
def get_stats():
    total_posts = len(posts)
    if total_posts == 0:
        return jsonify({"message": "No posts available"})
    published = len([p for p in posts if p['status'] == 'published'])
    drafts = len([p for p in posts if p['status'] == 'draft'])
    archived = len([p for p in posts if p['status'] == 'archived'])
    total_views = sum(p.get('views', 0) for p in posts)
    total_comments = len(comments)
    category_counts = {}
    for p in posts:
        category_counts[p['category']] = category_counts.get(p['category'], 0) + 1
    most_viewed = sorted(posts, key=lambda x: x.get('views', 0), reverse=True)[:5]
    return jsonify({
        "total_posts": total_posts,
        "published": published,
        "drafts": drafts,
        "archived": archived,
        "total_views": total_views,
        "total_comments": total_comments,
        "category_breakdown": category_counts,
        "most_viewed_posts": [{"id": p['id'], "title": p['title'], "views": p.get('views', 0)} for p in most_viewed]
    })
if __name__ == '__main__':
    app.run(debug=True)

