from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import List, Optional
from datetime import datetime
import json
import os

app = FastAPI()

DATABASE_FILE = "posts.json"

class Post(BaseModel):
    id: Optional[int] = None
    title: str
    content: str
    author: str
    created_at: Optional[str] = None
    updated_at: Optional[str] = None

def load_posts():
    if os.path.exists(DATABASE_FILE):
        with open(DATABASE_FILE, 'r') as f:
            return json.load(f)
    return []

def save_posts(posts):
    with open(DATABASE_FILE, 'w') as f:
        json.dump(posts, f, indent=2)

def get_next_id(posts):
    if not posts:
        return 1
    return max(post['id'] for post in posts) + 1

@app.post("/posts", response_model=Post)
def create_post(post: Post):
    posts = load_posts()
    post.id = get_next_id(posts)
    post.created_at = datetime.now().isoformat()
    post.updated_at = datetime.now().isoformat()
    post_dict = post.dict()
    posts.append(post_dict)
    save_posts(posts)
    return post

@app.get("/posts", response_model=List[Post])
def get_all_posts():
    posts = load_posts()
    return posts

@app.get("/posts/{post_id}", response_model=Post)
def get_post(post_id: int):
    posts = load_posts()
    for post in posts:
        if post['id'] == post_id:
            return post
    raise HTTPException(status_code=404, detail="Post not found")

@app.put("/posts/{post_id}", response_model=Post)
def update_post(post_id: int, updated_post: Post):
    posts = load_posts()
    for i, post in enumerate(posts):
        if post['id'] == post_id:
            updated_post.id = post_id
            updated_post.created_at = post['created_at']
            updated_post.updated_at = datetime.now().isoformat()
            posts[i] = updated_post.dict()
            save_posts(posts)
            return updated_post
    raise HTTPException(status_code=404, detail="Post not found")

@app.delete("/posts/{post_id}")
def delete_post(post_id: int):
    posts = load_posts()
    for i, post in enumerate(posts):
        if post['id'] == post_id:
            posts.pop(i)
            save_posts(posts)
            return {"message": "Post deleted successfully"}
    raise HTTPException(status_code=404, detail="Post not found")

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

