from flask import Flask, jsonify, request
from datetime import datetime
import re
import uuid
app = Flask(__name__)
contacts = []
VALID_SUBJECTS = ["general", "support", "billing", "feedback", "partnership", "other"]
VALID_PRIORITIES = ["low", "medium", "high", "urgent"]
VALID_STATUSES = ["pending", "in_progress", "resolved", "closed"]
def validate_email(email):
    pattern = r'^[\w\.-]+@[\w\.-]+\.\w+$'
    return re.match(pattern, email) is not None
def validate_phone(phone):
    pattern = r'^\+?[\d\s\-\(\)]{7,15}$'
    return re.match(pattern, phone) is not None
def mask_email(email):
    parts = email.split('@')
    masked = parts[0][:2] + '*' * (len(parts[0]) - 2) + '@' + parts[1]
    return masked
@app.route('/contact', methods=['POST'])
def submit_contact():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    name = data.get('name', '').strip()
    email = data.get('email', '').strip()
    phone = data.get('phone', '').strip()
    subject = data.get('subject', '').strip().lower()
    priority = data.get('priority', 'medium').strip().lower()
    message = data.get('message', '').strip()
    company = data.get('company', '').strip()
    website = data.get('website', '').strip()
    errors = {}
    if not name or len(name) < 2:
        errors['name'] = "Name must be at least 2 characters"
    if not email:
        errors['email'] = "Email is required"
    elif not validate_email(email):
        errors['email'] = "Invalid email format"
    if phone and not validate_phone(phone):
        errors['phone'] = "Invalid phone number format"
    if not subject:
        errors['subject'] = "Subject is required"
    elif subject not in VALID_SUBJECTS:
        errors['subject'] = f"Subject must be one of: {', '.join(VALID_SUBJECTS)}"
    if priority not in VALID_PRIORITIES:
        errors['priority'] = f"Priority must be one of: {', '.join(VALID_PRIORITIES)}"
    if not message:
        errors['message'] = "Message is required"
    elif len(message) < 10:
        errors['message'] = "Message must be at least 10 characters"
    elif len(message) > 2000:
        errors['message'] = "Message must not exceed 2000 characters"
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    contact_entry = {
        "id": str(uuid.uuid4()),
        "name": name,
        "email": email,
        "masked_email": mask_email(email),
        "phone": phone if phone else None,
        "company": company if company else None,
        "website": website if website else None,
        "subject": subject,
        "priority": priority,
        "message": message,
        "message_length": len(message),
        "status": "pending",
        "assigned_to": None,
        "notes": [],
        "submitted_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "updated_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    contacts.append(contact_entry)
    return jsonify({
        "message": "Contact form submitted successfully",
        "contact_id": contact_entry['id'],
        "contact": contact_entry
    }), 201
@app.route('/contacts', methods=['GET'])
def get_contacts():
    subject = request.args.get('subject', '').lower()
    priority = request.args.get('priority', '').lower()
    status = request.args.get('status', '').lower()
    assigned_to = request.args.get('assigned_to', '').lower()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 10, type=int)
    result = contacts
    if subject:
        result = [c for c in result if c['subject'] == subject]
    if priority:
        result = [c for c in result if c['priority'] == priority]
    if status:
        result = [c for c in result if c['status'] == status]
    if assigned_to:
        result = [c for c in result if c['assigned_to'] and c['assigned_to'].lower() == assigned_to]
    total = len(result)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = result[start:end]
    return jsonify({
        "total": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "contacts": paginated
    })
@app.route('/contacts/<string:contact_id>', methods=['GET'])
def get_contact(contact_id):
    contact = next((c for c in contacts if c['id'] == contact_id), None)
    if not contact:
        return jsonify({"error": "Contact not found"}), 404
    return jsonify(contact)
@app.route('/contacts/<string:contact_id>/status', methods=['PATCH'])
def update_status(contact_id):
    contact = next((c for c in contacts if c['id'] == contact_id), None)
    if not contact:
        return jsonify({"error": "Contact not found"}), 404
    data = request.get_json()
    new_status = data.get('status', '').strip().lower()
    if new_status not in VALID_STATUSES:
        return jsonify({"error": f"Status must be one of: {', '.join(VALID_STATUSES)}"}), 400
    contact['status'] = new_status
    contact['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Status updated successfully", "contact": contact})
@app.route('/contacts/<string:contact_id>/assign', methods=['PATCH'])
def assign_contact(contact_id):
    contact = next((c for c in contacts if c['id'] == contact_id), None)
    if not contact:
        return jsonify({"error": "Contact not found"}), 404
    data = request.get_json()
    assigned_to = data.get('assigned_to', '').strip()
    if not assigned_to:
        return jsonify({"error": "assigned_to is required"}), 400
    contact['assigned_to'] = assigned_to
    contact['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": f"Contact assigned to '{assigned_to}' successfully", "contact": contact})
@app.route('/contacts/<string:contact_id>/notes', methods=['POST'])
def add_note(contact_id):
    contact = next((c for c in contacts if c['id'] == contact_id), None)
    if not contact:
        return jsonify({"error": "Contact not found"}), 404
    data = request.get_json()
    note_text = data.get('note', '').strip()
    author = data.get('author', '').strip()
    if not note_text:
        return jsonify({"error": "Note text is required"}), 400
    if not author:
        return jsonify({"error": "Author is required"}), 400
    note = {
        "id": str(uuid.uuid4()),
        "note": note_text,
        "author": author,
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    contact['notes'].append(note)
    contact['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Note added successfully", "note": note}), 201
@app.route('/contacts/<string:contact_id>/priority', methods=['PATCH'])
def update_priority(contact_id):
    contact = next((c for c in contacts if c['id'] == contact_id), None)
    if not contact:
        return jsonify({"error": "Contact not found"}), 404
    data = request.get_json()
    new_priority = data.get('priority', '').strip().lower()
    if new_priority not in VALID_PRIORITIES:
        return jsonify({"error": f"Priority must be one of: {', '.join(VALID_PRIORITIES)}"}), 400
    contact['priority'] = new_priority
    contact['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Priority updated successfully", "contact": contact})
@app.route('/contacts/<string:contact_id>', methods=['DELETE'])
def delete_contact(contact_id):
    global contacts
    contact = next((c for c in contacts if c['id'] == contact_id), None)
    if not contact:
        return jsonify({"error": "Contact not found"}), 404
    contacts = [c for c in contacts if c['id'] != contact_id]
    return jsonify({"message": f"Contact '{contact_id}' deleted successfully"})
@app.route('/contacts/search', methods=['GET'])
def search_contacts():
    query = request.args.get('q', '').lower()
    if not query:
        return jsonify({"error": "Search query is required"}), 400
    results = [c for c in contacts if
               query in c['name'].lower() or
               query in c['email'].lower() or
               query in c['message'].lower() or
               (c['company'] and query in c['company'].lower())]
    return jsonify({"query": query, "total": len(results), "results": results})
@app.route('/contacts/summary', methods=['GET'])
def get_summary():
    total = len(contacts)
    if total == 0:
        return jsonify({"message": "No contacts available"})
    status_counts = {}
    for c in contacts:
        status_counts[c['status']] = status_counts.get(c['status'], 0) + 1
    priority_counts = {}
    for c in contacts:
        priority_counts[c['priority']] = priority_counts.get(c['priority'], 0) + 1
    subject_counts = {}
    for c in contacts:
        subject_counts[c['subject']] = subject_counts.get(c['subject'], 0) + 1
    assigned = len([c for c in contacts if c['assigned_to']])
    unassigned = total - assigned
    return jsonify({
        "total_contacts": total,
        "assigned": assigned,
        "unassigned": unassigned,
        "status_breakdown": status_counts,
        "priority_breakdown": priority_counts,
        "subject_breakdown": subject_counts
    })
if __name__ == '__main__':
    app.run(debug=True)

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, EmailStr
from typing import List, Optional
from datetime import datetime
import json
import os

app = FastAPI()

DATABASE_FILE = "contacts.json"

class Contact(BaseModel):
    id: Optional[int] = None
    name: str
    email: EmailStr
    subject: str
    message: str
    phone: Optional[str] = None
    created_at: Optional[str] = None

def load_contacts():
    if os.path.exists(DATABASE_FILE):
        with open(DATABASE_FILE, 'r') as f:
            return json.load(f)
    return []

def save_contacts(contacts):
    with open(DATABASE_FILE, 'w') as f:
        json.dump(contacts, f, indent=2)

def get_next_id(contacts):
    if not contacts:
        return 1
    return max(contact['id'] for contact in contacts) + 1

@app.post("/contacts", response_model=Contact)
def create_contact(contact: Contact):
    contacts = load_contacts()
    contact.id = get_next_id(contacts)
    contact.created_at = datetime.now().isoformat()
    contact_dict = contact.dict()
    contacts.append(contact_dict)
    save_contacts(contacts)
    return contact

@app.get("/contacts", response_model=List[Contact])
def get_all_contacts():
    contacts = load_contacts()
    return contacts

@app.get("/contacts/{contact_id}", response_model=Contact)
def get_contact(contact_id: int):
    contacts = load_contacts()
    for contact in contacts:
        if contact['id'] == contact_id:
            return contact
    raise HTTPException(status_code=404, detail="Contact not found")

@app.put("/contacts/{contact_id}", response_model=Contact)
def update_contact(contact_id: int, updated_contact: Contact):
    contacts = load_contacts()
    for i, contact in enumerate(contacts):
        if contact['id'] == contact_id:
            updated_contact.id = contact_id
            updated_contact.created_at = contact['created_at']
            contacts[i] = updated_contact.dict()
            save_contacts(contacts)
            return updated_contact
    raise HTTPException(status_code=404, detail="Contact not found")

@app.delete("/contacts/{contact_id}")
def delete_contact(contact_id: int):
    contacts = load_contacts()
    for i, contact in enumerate(contacts):
        if contact['id'] == contact_id:
            contacts.pop(i)
            save_contacts(contacts)
            return {"message": "Contact deleted successfully"}
    raise HTTPException(status_code=404, detail="Contact not found")

@app.get("/contacts/search/{email}")
def search_contact_by_email(email: str):
    contacts = load_contacts()
    for contact in contacts:
        if contact['email'].lower() == email.lower():
            return contact
    raise HTTPException(status_code=404, detail="Contact not found")

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

