    </div>
    <script>
        const bioTextarea = document.getElementById('bioTextarea');
        const charCount = document.getElementById('charCount');
        function updateCharCount() { charCount.textContent = bioTextarea.value.length; }
        bioTextarea.addEventListener('input', updateCharCount);
        updateCharCount();
        document.getElementById('userForm').addEventListener('submit', function(e) {
            let valid = true;
            const firstName = document.querySelector('input[name="first_name"]');
            const lastName = document.querySelector('input[name="last_name"]');
            const email = document.querySelector('input[name="email"]');
            document.getElementById('firstNameError').style.display = 'none';
            document.getElementById('lastNameError').style.display = 'none';
            document.getElementById('emailError').style.display = 'none';
            if (!firstName.value.trim()) { document.getElementById('firstNameError').style.display = 'block'; valid = false; }
            if (!lastName.value.trim()) { document.getElementById('lastNameError').style.display = 'block'; valid = false; }
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!email.value.trim() || !emailRegex.test(email.value)) { document.getElementById('emailError').style.display = 'block'; valid = false; }
            if (!valid) e.preventDefault();
        });
    </script>
</body>
</html>
"""
submission_history = []
@app.route('/', methods=['GET', 'POST'])
def index():
    form_data = {}
    submitted = False
    if request.method == 'POST':
        form_data = {
            "id": str(uuid.uuid4()),
            "first_name": request.form.get('first_name', '').strip(),
            "last_name": request.form.get('last_name', '').strip(),
            "email": request.form.get('email', '').strip(),
            "phone": request.form.get('phone', '').strip(),
            "age": request.form.get('age', '').strip(),
            "gender": request.form.get('gender', '').strip(),
            "country": request.form.get('country', '').strip(),
            "occupation": request.form.get('occupation', '').strip(),
            "website": request.form.get('website', '').strip(),
            "bio": request.form.get('bio', '').strip(),
            "skills": request.form.get('skills', '').strip(),
            "submitted_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        submission_history.append(form_data)
        submitted = True
    return render_template_string(HTML_TEMPLATE, form_data=form_data, submitted=submitted, history=submission_history)
@app.route('/delete/<int:index>', methods=['POST'])
def delete_entry(index):
    reversed_index = len(submission_history) - 1 - index
    if 0 <= reversed_index < len(submission_history):
        submission_history.pop(reversed_index)
    from flask import redirect, url_for
    return redirect(url_for('index'))
@app.route('/api/submissions', methods=['GET'])
def get_submissions():
    return jsonify({"total": len(submission_history), "submissions": submission_history})
@app.route('/api/submissions/<string:submission_id>', methods=['GET'])
def get_submission(submission_id):
    submission = next((s for s in submission_history if s['id'] == submission_id), None)
    if not submission:
        return jsonify({"error": "Submission not found"}), 404
    return jsonify(submission)
@app.route('/api/submissions/clear', methods=['DELETE'])
def clear_submissions():
    submission_history.clear()
    return jsonify({"message": "All submissions cleared successfully"})
if __name__ == '__main__':
    app.run(debug=True)

from fastapi import FastAPI
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List
import json
import os

app = FastAPI()

DATABASE_FILE = "user_inputs.json"

class UserInput(BaseModel):
    id: int
    name: str
    email: str
    message: str

def load_inputs():
    if os.path.exists(DATABASE_FILE):
        with open(DATABASE_FILE, 'r') as f:
            return json.load(f)
    return []

def save_inputs(inputs):
    with open(DATABASE_FILE, 'w') as f:
        json.dump(inputs, f, indent=2)

def get_next_id(inputs):
    if not inputs:
        return 1
    return max(inp['id'] for inp in inputs) + 1

@app.get("/", response_class=HTMLResponse)
def get_home():
    inputs = load_inputs()
    inputs_html = ""
    for inp in inputs:
        inputs_html += f"""
        <tr>
            <td>{inp['id']}</td>
            <td>{inp['name']}</td>
            <td>{inp['email']}</td>
            <td>{inp['message']}</td>
            <td><button onclick="deleteInput({inp['id']})">Delete</button></td>
        </tr>
        """
    return f"""
    <!DOCTYPE html>
    <html>
    <head>
        <title>User Input Web App</title>
        <style>
            body {{
                font-family: Arial, sans-serif;
                max-width: 900px;
                margin: 0 auto;
                padding: 20px;
            }}
            form {{
                background-color: #f4f4f4;
                padding: 20px;
                border-radius: 5px;
                margin-bottom: 20px;
            }}
            input, textarea {{
                width: 100%;
                padding: 10px;
                margin: 10px 0;
                border: 1px solid #ddd;
                border-radius: 4px;
                box-sizing: border-box;
            }}
            button {{
                background-color: #4CAF50;
                color: white;
                padding: 10px 20px;
                border: none;
                border-radius: 4px;
                cursor: pointer;
            }}
            button:hover {{
                background-color: #45a049;
            }}
            table {{
                width: 100%;
                border-collapse: collapse;
                margin-top: 20px;
            }}
            th, td {{
                padding: 12px;
                text-align: left;
                border-bottom: 1px solid #ddd;
            }}
            th {{
                background-color: #4CAF50;
                color: white;
            }}
            tr:hover {{
                background-color: #f5f5f5;
            }}
        </style>
    </head>
    <body>
        <h1>User Input Web App</h1>
        <form id="inputForm">
            <h2>Submit Your Information</h2>
            <input type="text" id="name" placeholder="Name" required>
            <input type="email" id="email" placeholder="Email" required>
            <textarea id="message" placeholder="Message" rows="4" required></textarea>
            <button type="button" onclick="submitForm()">Submit</button>
        </form>
        <h2>Submitted Data</h2>
        <table>
            <tr>
                <th>ID</th>
                <th>Name</th>
                <th>Email</th>
                <th>Message</th>
                <th>Action</th>
            </tr>
            {inputs_html}
        </table>
        <script>
            function submitForm() {{
                const name = document.getElementById('name').value;
                const email = document.getElementById('email').value;
                const message = document.getElementById('message').value;
                fetch('/submit', {{
                    method: 'POST',
                    headers: {{'Content-Type': 'application/json'}},
                    body: JSON.stringify({{name: name, email: email, message: message}})
                }})
                .then(response => response.json())
                .then(data => {{
                    alert('Data submitted successfully!');
                    document.getElementById('inputForm').reset();
                    location.reload();
                }})
                .catch(error => console.error('Error:', error));
            }}
            function deleteInput(id) {{
                if(confirm('Are you sure you want to delete this entry?')) {{
                    fetch('/delete/' + id, {{method: 'DELETE'}})
                    .then(response => response.json())
                    .then(data => {{
                        alert('Data deleted successfully!');
                        location.reload();
                    }})
                    .catch(error => console.error('Error:', error));
                }}
            }}
        </script>
    </body>
    </html>
    """

@app.post("/submit")
def submit_input(user_input: dict):
    inputs = load_inputs()
    new_input = {
        "id": get_next_id(inputs),
        "name": user_input['name'],
        "email": user_input['email'],
        "message": user_input['message']
    }
    inputs.append(new_input)
    save_inputs(inputs)
    return {"status": "success", "data": new_input}

@app.delete("/delete/{input_id}")
def delete_input(input_id: int):
    inputs = load_inputs()
    inputs = [inp for inp in inputs if inp['id'] != input_id]
    save_inputs(inputs)
    return {"status": "success", "message": "Input deleted"}

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

