from flask import Flask, jsonify, request
from datetime import datetime
import uuid
import re
app = Flask(__name__)
records = [
    {"id": str(uuid.uuid4()), "title": "Python for Beginners", "category": "Technology", "author": "Alice Johnson", "tags": ["python", "programming", "beginner"], "year": 2020, "rating": 4.5, "views": 1200},
    {"id": str(uuid.uuid4()), "title": "Advanced Machine Learning", "category": "Technology", "author": "Bob Smith", "tags": ["ml", "ai", "data science"], "year": 2021, "rating": 4.8, "views": 980},
    {"id": str(uuid.uuid4()), "title": "Web Development with Flask", "category": "Technology", "author": "Carol White", "tags": ["flask", "python", "web"], "year": 2022, "rating": 4.3, "views": 1500},
    {"id": str(uuid.uuid4()), "title": "Data Structures and Algorithms", "category": "Computer Science", "author": "David Brown", "tags": ["dsa", "algorithms", "programming"], "year": 2019, "rating": 4.7, "views": 2100},
    {"id": str(uuid.uuid4()), "title": "Digital Marketing Mastery", "category": "Marketing", "author": "Eva Green", "tags": ["marketing", "social media", "seo"], "year": 2021, "rating": 4.1, "views": 870},
