    {"id": str(uuid.uuid4()), "title": "Photography for Beginners", "category": "Arts", "author": "Grace Kim", "tags": ["photography", "camera", "arts"], "year": 2018, "rating": 4.2, "views": 730},
    {"id": str(uuid.uuid4()), "title": "Health and Wellness Guide", "category": "Health", "author": "Henry Park", "tags": ["health", "wellness", "fitness"], "year": 2022, "rating": 4.6, "views": 1100},
    {"id": str(uuid.uuid4()), "title": "Travel Around Europe", "category": "Lifestyle", "author": "Iris Chen", "tags": ["travel", "europe", "adventure"], "year": 2019, "rating": 4.0, "views": 540},
    {"id": str(uuid.uuid4()), "title": "Cooking Masterclass", "category": "Lifestyle", "author": "Jack Wilson", "tags": ["cooking", "recipes", "food"], "year": 2021, "rating": 4.3, "views": 900},
]
search_logs = []
def log_search(query, filters, results_count):
    log = {
        "id": str(uuid.uuid4()),
        "query": query,
        "filters": filters,
        "results_count": results_count,
        "searched_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    search_logs.append(log)
    return log
def highlight_match(text, query):
    if not query:
        return text
    pattern = re.compile(re.escape(query), re.IGNORECASE)
    return pattern.sub(lambda m: f"**{m.group()}**", text)
@app.route('/search', methods=['GET'])
def search():
    query = request.args.get('q', '').strip().lower()
    category = request.args.get('category', '').strip().lower()
    author = request.args.get('author', '').strip().lower()
    tag = request.args.get('tag', '').strip().lower()
    year = request.args.get('year', type=int)
    min_rating = request.args.get('min_rating', type=float)
    max_rating = request.args.get('max_rating', type=float)
    min_views = request.args.get('min_views', type=int)
    sort_by = request.args.get('sort_by', 'relevance').strip().lower()
    order = request.args.get('order', 'desc').strip().lower()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 5, type=int)
    result = records
    if query:
        result = [r for r in result if
                  query in r['title'].lower() or
                  query in r['author'].lower() or
                  query in r['category'].lower() or
                  any(query in t for t in r['tags'])]
    if category:
        result = [r for r in result if r['category'].lower() == category]
    if author:
        result = [r for r in result if author in r['author'].lower()]
    if tag:
        result = [r for r in result if tag in r['tags']]
    if year:
        result = [r for r in result if r['year'] == year]
    if min_rating is not None:
        result = [r for r in result if r['rating'] >= min_rating]
    if max_rating is not None:
        result = [r for r in result if r['rating'] <= max_rating]
    if min_views is not None:
        result = [r for r in result if r['views'] >= min_views]
    valid_sort = ['relevance', 'rating', 'views', 'year', 'title']
    if sort_by in valid_sort and sort_by != 'relevance':
        reverse = order == 'desc'
        result = sorted(result, key=lambda x: x[sort_by], reverse=reverse)
    if query:
        highlighted = []
        for r in result:
            r_copy = r.copy()
            r_copy['title'] = highlight_match(r['title'], query)
            highlighted.append(r_copy)
        result = highlighted
    total = len(result)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = result[start:end]
    filters_used = {
        "category": category or None,
        "author": author or None,
        "tag": tag or None,
        "year": year,
        "min_rating": min_rating,
        "max_rating": max_rating,
        "min_views": min_views
    }
    log_search(query, filters_used, total)
    return jsonify({
        "query": query,
        "total_results": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "sort_by": sort_by,
        "order": order,
        "results": paginated
    })
@app.route('/search/suggestions', methods=['GET'])
def suggestions():
    query = request.args.get('q', '').strip().lower()
    limit = request.args.get('limit', 5, type=int)
    if not query:
        return jsonify({"error": "Query parameter 'q' is required"}), 400
    suggestions_list = []
    for r in records:
        if query in r['title'].lower() and r['title'] not in suggestions_list:
            suggestions_list.append(r['title'])
        for tag in r['tags']:
            if query in tag and tag not in suggestions_list:
                suggestions_list.append(tag)
    return jsonify({"query": query, "suggestions": suggestions_list[:limit]})
@app.route('/search/filters', methods=['GET'])
def get_filters():
    categories = list(set(r['category'] for r in records))
    authors = list(set(r['author'] for r in records))
    all_tags = list(set(tag for r in records for tag in r['tags']))
    years = sorted(list(set(r['year'] for r in records)))
    rating_range = {"min": min(r['rating'] for r in records), "max": max(r['rating'] for r in records)}
    views_range = {"min": min(r['views'] for r in records), "max": max(r['views'] for r in records)}
    return jsonify({
        "categories": sorted(categories),
        "authors": sorted(authors),
        "tags": sorted(all_tags),
        "years": years,
        "rating_range": rating_range,
        "views_range": views_range
    })
@app.route('/search/trending', methods=['GET'])
def trending():
    limit = request.args.get('limit', 5, type=int)
    trending_records = sorted(records, key=lambda x: x['views'], reverse=True)[:limit]
    return jsonify({"total": len(trending_records), "trending": trending_records})
@app.route('/search/top-rated', methods=['GET'])
def top_rated():
    limit = request.args.get('limit', 5, type=int)
    min_rating = request.args.get('min_rating', 4.0, type=float)
    top = [r for r in records if r['rating'] >= min_rating]
    top = sorted(top, key=lambda x: x['rating'], reverse=True)[:limit]
    return jsonify({"total": len(top), "top_rated": top})
@app.route('/search/logs', methods=['GET'])
def get_search_logs():
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 10, type=int)
    total = len(search_logs)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = search_logs[start:end]
    return jsonify({
        "total": total,
        "page": page,
        "per_page": per_page,
        "logs": paginated
    })
@app.route('/search/stats', methods=['GET'])
def search_stats():
    if not search_logs:
        return jsonify({"message": "No search logs available"})
    total_searches = len(search_logs)
    avg_results = sum(l['results_count'] for l in search_logs) / total_searches
    zero_result_searches = len([l for l in search_logs if l['results_count'] == 0])
    category_counts = {}
    for r in records:
        category_counts[r['category']] = category_counts.get(r['category'], 0) + 1
    return jsonify({
        "total_searches": total_searches,
        "average_results_per_search": round(avg_results, 2),
        "zero_result_searches": zero_result_searches,
        "total_records": len(records),
        "category_breakdown": category_counts
    })
if __name__ == '__main__':
    app.run(debug=True)

from fastapi import FastAPI, Query
from pydantic import BaseModel
from typing import List, Optional
import json
import os

app = FastAPI()

DATABASE_FILE = "products.json"

class Product(BaseModel):
    id: int
    name: str
    description: str
    category: str
    price: float
    stock: int

def load_products():
    if os.path.exists(DATABASE_FILE):
        with open(DATABASE_FILE, 'r') as f:
            return json.load(f)
    return []

def save_products(products):
    with open(DATABASE_FILE, 'w') as f:
        json.dump(products, f, indent=2)

def get_next_id(products):
    if not products:
        return 1
    return max(product['id'] for product in products) + 1

@app.post("/products", response_model=Product)
def create_product(product: Product):
    products = load_products()
    product.id = get_next_id(products)
    product_dict = product.dict()
    products.append(product_dict)
    save_products(products)
    return product

@app.get("/products", response_model=List[Product])
def get_all_products():
    products = load_products()
    return products

@app.get("/search", response_model=List[Product])
def search_products(
    query: Optional[str] = Query(None),
    category: Optional[str] = Query(None),
    min_price: Optional[float] = Query(None),
    max_price: Optional[float] = Query(None),
    in_stock: Optional[bool] = Query(None)
):
    products = load_products()
    results = products
    if query:
        results = [
            p for p in results
            if query.lower() in p['name'].lower() or query.lower() in p['description'].lower()
        ]
    if category:
        results = [p for p in results if p['category'].lower() == category.lower()]
    if min_price is not None:
        results = [p for p in results if p['price'] >= min_price]
    if max_price is not None:
        results = [p for p in results if p['price'] <= max_price]
    if in_stock is not None:
        if in_stock:
            results = [p for p in results if p['stock'] > 0]
        else:
            results = [p for p in results if p['stock'] == 0]
    return results

@app.get("/search/name/{name}", response_model=List[Product])
def search_by_name(name: str):
    products = load_products()
    results = [p for p in products if name.lower() in p['name'].lower()]
    return results

@app.get("/search/category/{category}", response_model=List[Product])
def search_by_category(category: str):
    products = load_products()
    results = [p for p in products if p['category'].lower() == category.lower()]
    return results

@app.get("/search/price-range", response_model=List[Product])
def search_by_price_range(min_price: float, max_price: float):
    products = load_products()
    results = [p for p in products if min_price <= p['price'] <= max_price]
    return results

@app.get("/products/{product_id}", response_model=Product)
def get_product(product_id: int):
    products = load_products()
    for product in products:
        if product['id'] == product_id:
            return product
    return {"error": "Product not found"}

@app.put("/products/{product_id}", response_model=Product)
def update_product(product_id: int, updated_product: Product):
    products = load_products()
    for i, product in enumerate(products):
        if product['id'] == product_id:
            updated_product.id = product_id
            products[i] = updated_product.dict()
            save_products(products)
            return updated_product
    return {"error": "Product not found"}

@app.delete("/products/{product_id}")
def delete_product(product_id: int):
    products = load_products()
    for i, product in enumerate(products):
        if product['id'] == product_id:
            products.pop(i)
            save_products(products)
            return {"message": "Product deleted successfully"}
    return {"error": "Product not found"}

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

from flask import Flask,request,jsonify
import sqlite3
app=Flask(__name__)
def get_db():
    return sqlite3.connect("products.db")
@app.route("/products",methods=["GET"])
def get_products():
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("CREATE TABLE IF NOT EXISTS products (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT, price REAL)")
    cursor.execute("SELECT id,name,price FROM products")
    rows=cursor.fetchall()
    conn.close()
    return jsonify(rows)
@app.route("/products",methods=["POST"])
def add_product():
    data=request.get_json()
    name=data.get("name")
    price=data.get("price")
    conn=get_db()
    cursor=conn.cursor()
    cursor.execute("INSERT INTO products (name,price) VALUES (?,?)",(name,price))
    conn.commit()
    conn.close()
    return jsonify({"message":"Product added"})
if __name__=="__main__":
    app.run(debug=True)

