    {"id": str(uuid.uuid4()), "name": "Logitech MX Master 3", "category": "Accessories", "brand": "Logitech", "price": 99.99, "stock": 200, "rating": 4.9, "tags": ["mouse", "logitech", "wireless"], "discount": 0, "sold": 1200},
    {"id": str(uuid.uuid4()), "name": "Keychron K2 Keyboard", "category": "Accessories", "brand": "Keychron", "price": 89.99, "stock": 150, "rating": 4.7, "tags": ["keyboard", "mechanical", "wireless"], "discount": 5, "sold": 670},
    {"id": str(uuid.uuid4()), "name": "GoPro Hero 12", "category": "Cameras", "brand": "GoPro", "price": 399.99, "stock": 80, "rating": 4.6, "tags": ["camera", "gopro", "action"], "discount": 10, "sold": 430},
]
reviews = []
wishlists = []
def calculate_discounted_price(price, discount):
    return round(price - (price * discount / 100), 2)
def slugify(name):
    name = name.lower()
    name = re.sub(r'[^a-z0-9\s-]', '', name)
    name = re.sub(r'\s+', '-', name.strip())
    return name
def validate_product_data(data, is_update=False):
    errors = {}
    if not is_update:
        if not data.get('name', '').strip():
            errors['name'] = "Product name is required"
        if not data.get('category', '').strip():
            errors['category'] = "Category is required"
        if not data.get('brand', '').strip():
            errors['brand'] = "Brand is required"
        if data.get('price') is None:
            errors['price'] = "Price is required"
    if 'price' in data and data['price'] is not None:
        if not isinstance(data['price'], (int, float)) or data['price'] < 0:
            errors['price'] = "Price must be a non-negative number"
    if 'stock' in data and data['stock'] is not None:
        if not isinstance(data['stock'], int) or data['stock'] < 0:
            errors['stock'] = "Stock must be a non-negative integer"
    if 'discount' in data and data['discount'] is not None:
        if not isinstance(data['discount'], (int, float)) or not (0 <= data['discount'] <= 100):
            errors['discount'] = "Discount must be between 0 and 100"
    if 'rating' in data and data['rating'] is not None:
        if not isinstance(data['rating'], (int, float)) or not (0 <= data['rating'] <= 5):
            errors['rating'] = "Rating must be between 0 and 5"
    return errors
@app.route('/products', methods=['GET'])
def get_products():
    category = request.args.get('category', '').strip().lower()
    brand = request.args.get('brand', '').strip().lower()
    tag = request.args.get('tag', '').strip().lower()
    min_price = request.args.get('min_price', type=float)
    max_price = request.args.get('max_price', type=float)
    min_rating = request.args.get('min_rating', type=float)
    in_stock = request.args.get('in_stock', '').strip().lower()
    has_discount = request.args.get('has_discount', '').strip().lower()
    sort_by = request.args.get('sort_by', 'name').strip().lower()
    order = request.args.get('order', 'asc').strip().lower()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 5, type=int)
    result = products
    if category:
        result = [p for p in result if p['category'].lower() == category]
    if brand:
        result = [p for p in result if p['brand'].lower() == brand]
    if tag:
        result = [p for p in result if tag in [t.lower() for t in p['tags']]]
    if min_price is not None:
        result = [p for p in result if p['price'] >= min_price]
    if max_price is not None:
        result = [p for p in result if p['price'] <= max_price]
    if min_rating is not None:
        result = [p for p in result if p['rating'] >= min_rating]
    if in_stock == 'true':
        result = [p for p in result if p['stock'] > 0]
    if has_discount == 'true':
        result = [p for p in result if p['discount'] > 0]
    valid_sort = ['name', 'price', 'rating', 'stock', 'sold', 'discount']
    if sort_by in valid_sort:
        result = sorted(result, key=lambda x: x[sort_by], reverse=(order == 'desc'))
    for p in result:
        p['discounted_price'] = calculate_discounted_price(p['price'], p['discount'])
    total = len(result)
    start = (page - 1) * per_page
    end = start + per_page
    paginated = result[start:end]
    return jsonify({
        "total": total,
        "page": page,
        "per_page": per_page,
        "total_pages": (total + per_page - 1) // per_page,
        "sort_by": sort_by,
        "order": order,
        "products": paginated
    })
@app.route('/products/<string:product_id>', methods=['GET'])
def get_product(product_id):
    product = next((p for p in products if p['id'] == product_id), None)
    if not product:
        return jsonify({"error": "Product not found"}), 404
    product['discounted_price'] = calculate_discounted_price(product['price'], product['discount'])
    product_reviews = [r for r in reviews if r['product_id'] == product_id]
    return jsonify({"product": product, "reviews": product_reviews, "total_reviews": len(product_reviews)})
@app.route('/products', methods=['POST'])
def create_product():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    errors = validate_product_data(data)
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    new_product = {
        "id": str(uuid.uuid4()),
        "name": data['name'].strip(),
        "slug": slugify(data['name']),
        "category": data['category'].strip(),
        "brand": data['brand'].strip(),
        "price": data['price'],
        "stock": data.get('stock', 0),
        "rating": data.get('rating', 0.0),
        "tags": data.get('tags', []),
        "discount": data.get('discount', 0),
        "sold": data.get('sold', 0),
        "description": data.get('description', '').strip(),
        "thumbnail": data.get('thumbnail', '').strip(),
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "updated_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    products.append(new_product)
    return jsonify({"message": "Product created successfully", "product": new_product}), 201
@app.route('/products/<string:product_id>', methods=['PUT'])
def update_product(product_id):
    product = next((p for p in products if p['id'] == product_id), None)
    if not product:
        return jsonify({"error": "Product not found"}), 404
    data = request.get_json()
    errors = validate_product_data(data, is_update=True)
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    product['name'] = data.get('name', product['name'])
    product['category'] = data.get('category', product['category'])
    product['brand'] = data.get('brand', product['brand'])
    product['price'] = data.get('price', product['price'])
    product['stock'] = data.get('stock', product['stock'])
    product['rating'] = data.get('rating', product['rating'])
    product['tags'] = data.get('tags', product['tags'])
    product['discount'] = data.get('discount', product['discount'])
    product['description'] = data.get('description', product.get('description', ''))
    product['thumbnail'] = data.get('thumbnail', product.get('thumbnail', ''))
    product['slug'] = slugify(product['name'])
    product['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Product updated successfully", "product": product})
@app.route('/products/<string:product_id>/stock', methods=['PATCH'])
def update_stock(product_id):
    product = next((p for p in products if p['id'] == product_id), None)
    if not product:
        return jsonify({"error": "Product not found"}), 404
    data = request.get_json()
    action = data.get('action', '').strip().lower()
    quantity = data.get('quantity', 0)
    if action not in ['add', 'remove', 'set']:
        return jsonify({"error": "Action must be 'add', 'remove', or 'set'"}), 400
    if not isinstance(quantity, int) or quantity < 0:
        return jsonify({"error": "Quantity must be a non-negative integer"}), 400
    if action == 'add':
        product['stock'] += quantity
    elif action == 'remove':
        if quantity > product['stock']:
            return jsonify({"error": "Insufficient stock"}), 400
        product['stock'] -= quantity
    elif action == 'set':
        product['stock'] = quantity
    product['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Stock updated successfully", "product_id": product_id, "new_stock": product['stock']})
@app.route('/products/<string:product_id>/reviews', methods=['POST'])
def add_review(product_id):
    product = next((p for p in products if p['id'] == product_id), None)
    if not product:
        return jsonify({"error": "Product not found"}), 404
    data = request.get_json()
    name = data.get('name', '').strip()
    rating = data.get('rating')
    comment = data.get('comment', '').strip()
    errors = {}
    if not name:
        errors['name'] = "Name is required"
    if rating is None:
        errors['rating'] = "Rating is required"
    elif not isinstance(rating, (int, float)) or not (1 <= rating <= 5):
        errors['rating'] = "Rating must be between 1 and 5"
    if not comment or len(comment) < 5:
        errors['comment'] = "Comment must be at least 5 characters"
    if errors:
        return jsonify({"error": "Validation failed", "details": errors}), 422
    review = {
        "id": str(uuid.uuid4()),
        "product_id": product_id,
        "name": name,
        "rating": rating,
        "comment": comment,
        "created_at": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    reviews.append(review)
    product_reviews = [r for r in reviews if r['product_id'] == product_id]
    product['rating'] = round(sum(r['rating'] for r in product_reviews) / len(product_reviews), 2)
    product['updated_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return jsonify({"message": "Review added successfully", "review": review}), 201
@app.route('/products/<string:product_id>', methods=['DELETE'])
def delete_product(product_id):
    global products, reviews
    product = next((p for p in products if p['id'] == product_id), None)
    if not product:
        return jsonify({"error": "Product not found"}), 404
    products = [p for p in products if p['id'] != product_id]
    reviews = [r for r in reviews if r['product_id'] != product_id]
    return jsonify({"message": f"Product '{product['name']}' deleted successfully"})
@app.route('/products/search', methods=['GET'])
def search_products():
    query = request.args.get('q', '').strip().lower()
    if not query:
        return jsonify({"error": "Search query 'q' is required"}), 400
    results = [p for p in products if
               query in p['name'].lower() or
               query in p['brand'].lower() or
               query in p['category'].lower() or
               any(query in t.lower() for t in p['tags'])]
    for p in results:
        p['discounted_price'] = calculate_discounted_price(p['price'], p['discount'])
    return jsonify({"query": query, "total": len(results), "results": results})
@app.route('/products/categories', methods=['GET'])
def get_categories():
    category_data = {}
    for p in products:
        cat = p['category']
        if cat not in category_data:
            category_data[cat] = {"name": cat, "count": 0, "brands": set()}
        category_data[cat]['count'] += 1
        category_data[cat]['brands'].add(p['brand'])
    for cat in category_data:
        category_data[cat]['brands'] = list(category_data[cat]['brands'])
    return jsonify({"total_categories": len(category_data), "categories": list(category_data.values())})
@app.route('/products/brands', methods=['GET'])
def get_brands():
    brand_data = {}
    for p in products:
        brand = p['brand']
        if brand not in brand_data:
            brand_data[brand] = {"name": brand, "count": 0, "categories": set()}
        brand_data[brand]['count'] += 1
        brand_data[brand]['categories'].add(p['category'])
    for brand in brand_data:
        brand_data[brand]['categories'] = list(brand_data[brand]['categories'])
    return jsonify({"total_brands": len(brand_data), "brands": list(brand_data.values())})
@app.route('/products/stats', methods=['GET'])
def get_stats():
    if not products:
        return jsonify({"message": "No products available"})
    total = len(products)
    total_stock = sum(p['stock'] for p in products)
    total_sold = sum(p['sold'] for p in products)
    avg_price = round(sum(p['price'] for p in products) / total, 2)
    avg_rating = round(sum(p['rating'] for p in products) / total, 2)
    in_stock = len([p for p in products if p['stock'] > 0])
    out_of_stock = total - in_stock
    discounted = len([p for p in products if p['discount'] > 0])
    most_sold = sorted(products, key=lambda x: x['sold'], reverse=True)[:3]
    top_rated = sorted(products, key=lambda x: x['rating'], reverse=True)[:3]
    category_counts = {}
    for p in products:
        category_counts[p['category']] = category_counts.get(p['category'], 0) + 1
    return jsonify({
        "total_products": total,
        "total_stock": total_stock,
        "total_sold": total_sold,
        "average_price": avg_price,
        "average_rating": avg_rating,
        "in_stock": in_stock,
        "out_of_stock": out_of_stock,
        "discounted_products": discounted,
        "category_breakdown": category_counts,
        "most_sold": [{"id": p['id'], "name": p['name'], "sold": p['sold']} for p in most_sold],
        "top_rated": [{"id": p['id'], "name": p['name'], "rating": p['rating']} for p in top_rated]
    })
if __name__ == '__main__':
    app.run(debug=True)

from fastapi import FastAPI, Query
from pydantic import BaseModel
from typing import List, Optional
from datetime import datetime
import json
import os

app = FastAPI()

DATABASE_FILE = "products.json"

class Product(BaseModel):
    id: Optional[int] = None
    name: str
    description: str
    category: str
    price: float
    stock: int
    image_url: Optional[str] = None
    created_at: Optional[str] = None
    updated_at: Optional[str] = None

def load_products():
    if os.path.exists(DATABASE_FILE):
        with open(DATABASE_FILE, 'r') as f:
            return json.load(f)
    return []

def save_products(products):
    with open(DATABASE_FILE, 'w') as f:
        json.dump(products, f, indent=2)

def get_next_id(products):
    if not products:
        return 1
    return max(product['id'] for product in products) + 1

@app.post("/products", response_model=Product)
def create_product(product: Product):
    products = load_products()
    product.id = get_next_id(products)
    product.created_at = datetime.now().isoformat()
    product.updated_at = datetime.now().isoformat()
    product_dict = product.dict()
    products.append(product_dict)
    save_products(products)
    return product

@app.get("/products", response_model=List[Product])
def get_all_products(
    skip: int = Query(0, ge=0),
    limit: int = Query(10, ge=1, le=100),
    sort_by: Optional[str] = Query(None),
    order: Optional[str] = Query("asc")
):
    products = load_products()
    if sort_by == "price":
        products.sort(key=lambda x: x['price'], reverse=(order == "desc"))
    elif sort_by == "name":
        products.sort(key=lambda x: x['name'], reverse=(order == "desc"))
    elif sort_by == "created_at":
        products.sort(key=lambda x: x['created_at'], reverse=(order == "desc"))
    else:
        products.sort(key=lambda x: x['id'], reverse=(order == "desc"))
    return products[skip:skip + limit]

@app.get("/products/count", response_model=dict)
def get_products_count():
    products = load_products()
    return {"total_count": len(products), "in_stock_count": sum(1 for p in products if p['stock'] > 0)}

@app.get("/products/categories", response_model=List[str])
def get_categories():
    products = load_products()
    categories = list(set(p['category'] for p in products))
    return sorted(categories)

@app.get("/products/category/{category}", response_model=List[Product])
def get_products_by_category(
    category: str,
    skip: int = Query(0, ge=0),
    limit: int = Query(10, ge=1, le=100)
):
    products = load_products()
    filtered = [p for p in products if p['category'].lower() == category.lower()]
    return filtered[skip:skip + limit]

@app.get("/products/featured", response_model=List[Product])
def get_featured_products(limit: int = Query(5, ge=1, le=50)):
    products = load_products()
    featured = [p for p in products if p['stock'] > 0]
    featured.sort(key=lambda x: x['price'])
    return featured[:limit]

@app.get("/products/{product_id}", response_model=Product)
def get_product(product_id: int):
    products = load_products()
    for product in products:
        if product['id'] == product_id:
            return product
    return {"error": "Product not found"}

@app.put("/products/{product_id}", response_model=Product)
def update_product(product_id: int, updated_product: Product):
    products = load_products()
    for i, product in enumerate(products):
        if product['id'] == product_id:
            updated_product.id = product_id
            updated_product.created_at = product['created_at']
            updated_product.updated_at = datetime.now().isoformat()
            products[i] = updated_product.dict()
            save_products(products)
            return updated_product
    return {"error": "Product not found"}

@app.delete("/products/{product_id}")
def delete_product(product_id: int):
    products = load_products()
    for i, product in enumerate(products):
        if product['id'] == product_id:
            products.pop(i)
            save_products(products)
            return {"message": "Product deleted successfully"}
    return {"error": "Product not found"}

@app.get("/products/in-stock", response_model=List[Product])
def get_in_stock_products(
    skip: int = Query(0, ge=0),
    limit: int = Query(10, ge=1, le=100)
):
    products = load_products()
    in_stock = [p for p in products if p['stock'] > 0]
    return in_stock[skip:skip + limit]

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

import os
def read_user_file():
    filename = input("Enter the path to the file: ")
    if os.path.exists(filename):
        try:
            with open(filename, 'r') as file:
                content = file.read()
                print("--- File Content ---")
                print(content)
                print("--------------------")
        except Exception as e:
            print(f"Error reading file: {e}")
    else:
        print("Error: File does not exist.")
if __name__ == "__main__":
    read_user_file()

