    uvicorn.run(app, host="0.0.0.0", port=8000)

from fastapi import FastAPI
from fastapi.responses import HTMLResponse, FileResponse
from pydantic import BaseModel, EmailStr
from typing import List, Optional
from datetime import datetime
import json
import csv
import os

app = FastAPI()

DATA_DIR = "user_data"

if not os.path.exists(DATA_DIR):
    os.makedirs(DATA_DIR)

class User(BaseModel):
    id: Optional[int] = None
    name: str
    email: EmailStr
    phone: str
    address: str
    created_at: Optional[str] = None

JSON_FILE = os.path.join(DATA_DIR, "users.json")
CSV_FILE = os.path.join(DATA_DIR, "users.csv")
TXT_FILE = os.path.join(DATA_DIR, "users.txt")

def load_users():
    if os.path.exists(JSON_FILE):
        with open(JSON_FILE, 'r') as f:
            return json.load(f)
    return []

def save_users_json(users):
    with open(JSON_FILE, 'w') as f:
        json.dump(users, f, indent=2)

def save_users_csv(users):
    if users:
        with open(CSV_FILE, 'w', newline='') as f:
            writer = csv.DictWriter(f, fieldnames=['id', 'name', 'email', 'phone', 'address', 'created_at'])
            writer.writeheader()
            writer.writerows(users)

def save_users_txt(users):
    with open(TXT_FILE, 'w') as f:
        f.write("USER DATA REPORT\n")
        f.write("=" * 80 + "\n\n")
        for user in users:
            f.write(f"ID: {user['id']}\n")
            f.write(f"Name: {user['name']}\n")
            f.write(f"Email: {user['email']}\n")
            f.write(f"Phone: {user['phone']}\n")
            f.write(f"Address: {user['address']}\n")
            f.write(f"Created At: {user['created_at']}\n")
            f.write("-" * 80 + "\n\n")

def get_next_id(users):
    if not users:
        return 1
    return max(user['id'] for user in users) + 1

