@app.post("/add-user")
def add_user(user: dict):
    users = load_users()
    new_user = {
        "id": get_next_id(users),
        "name": user['name'],
        "email": user['email'],
        "phone": user['phone'],
        "address": user['address'],
        "created_at": datetime.now().isoformat()
    }
    users.append(new_user)
    save_users_json(users)
    save_users_csv(users)
    save_users_txt(users)
    return {"status": "success", "user": new_user}

@app.delete("/delete-user/{user_id}")
def delete_user(user_id: int):
    users = load_users()
    users = [u for u in users if u['id'] != user_id]
    save_users_json(users)
    save_users_csv(users)
    save_users_txt(users)
    return {"status": "success", "message": "User deleted"}

@app.get("/export/json")
def export_json():
    if not os.path.exists(JSON_FILE):
        return {"error": "No data to export"}
    return FileResponse(JSON_FILE, filename="users.json")

@app.get("/export/csv")
def export_csv():
    users = load_users()
    save_users_csv(users)
    if not os.path.exists(CSV_FILE):
        return {"error": "No data to export"}
    return FileResponse(CSV_FILE, filename="users.csv")

@app.get("/export/txt")
def export_txt():
    users = load_users()
    save_users_txt(users)
    if not os.path.exists(TXT_FILE):
        return {"error": "No data to export"}
    return FileResponse(TXT_FILE, filename="users.txt")

@app.get("/users")
def get_all_users():
    return load_users()

