import os
import fnmatch
from datetime import datetime
class FileSearchTool:
    def __init__(self, root_directory='.'):
        self.root_directory = root_directory
    def search_by_name(self, pattern):
        results = []
        for root, dirs, files in os.walk(self.root_directory):
            for filename in files:
                if fnmatch.fnmatch(filename.lower(), pattern.lower()):
                    filepath = os.path.join(root, filename)
                    results.append(self.get_file_info(filepath))
        return results
    def search_by_extension(self, extension):
        if not extension.startswith('.'):
            extension = '.' + extension
        results = []
        for root, dirs, files in os.walk(self.root_directory):
            for filename in files:
                if filename.lower().endswith(extension.lower()):
                    filepath = os.path.join(root, filename)
                    results.append(self.get_file_info(filepath))
        return results
    def search_by_size(self, min_size=None, max_size=None):
        results = []
        for root, dirs, files in os.walk(self.root_directory):
            for filename in files:
                filepath = os.path.join(root, filename)
                size = os.path.getsize(filepath)
                if (min_size is None or size >= min_size) and (max_size is None or size <= max_size):
                    results.append(self.get_file_info(filepath))
        return results
    def search_by_content(self, text):
        results = []
        for root, dirs, files in os.walk(self.root_directory):
            for filename in files:
                filepath = os.path.join(root, filename)
                try:
                    with open(filepath, 'r', encoding='utf-8') as f:
                        content = f.read()
                        if text in content:
                            results.append(self.get_file_info(filepath))
                except:
                    pass
        return results
    def get_file_info(self, filepath):
        stats = os.stat(filepath)
        return {
            'path': filepath,
            'name': os.path.basename(filepath),
            'size': stats.st_size,
            'modified': datetime.fromtimestamp(stats.st_mtime).strftime('%Y-%m-%d %H:%M:%S'),
            'created': datetime.fromtimestamp(stats.st_ctime).strftime('%Y-%m-%d %H:%M:%S')
        }
    def advanced_search(self, name_pattern=None, extension=None, min_size=None, max_size=None, content=None):
        results = []
        for root, dirs, files in os.walk(self.root_directory):
            for filename in files:
                filepath = os.path.join(root, filename)
                if name_pattern and not fnmatch.fnmatch(filename.lower(), name_pattern.lower()):
                    continue
                if extension:
                    ext = '.' + extension if not extension.startswith('.') else extension
                    if not filename.lower().endswith(ext.lower()):
                        continue
                size = os.path.getsize(filepath)
                if min_size is not None and size < min_size:
                    continue
                if max_size is not None and size > max_size:
                    continue
                if content:
                    try:
                        with open(filepath, 'r', encoding='utf-8') as f:
                            if content not in f.read():
                                continue
                    except:
                        continue
                results.append(self.get_file_info(filepath))
        return results
search_tool = FileSearchTool('.')
print("Search by name pattern '*.py':")
for file in search_tool.search_by_name('*.py'):
    print(f"  {file['name']} - {file['size']} bytes")
print("\nSearch by extension 'txt':")
for file in search_tool.search_by_extension('txt'):
    print(f"  {file['name']} - {file['size']} bytes")
print("\nSearch by size (0-10000 bytes):")
for file in search_tool.search_by_size(0, 10000):
    print(f"  {file['name']} - {file['size']} bytes")

import os
def search_files(directory, extension):
    if not os.path.isdir(directory):
        print("Invalid directory.")
        return
    results = []
    for root, dirs, files in os.walk(directory):
        for file in files:
            if file.endswith(extension):
                results.append(os.path.join(root, file))
    if results:
        print(f"Found {len(results)} matches:")
        for path in results:
            print(path)
    else:
        print("No matching files found.")
    return results
