from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional
import os
import re

app = FastAPI()

class SearchResult(BaseModel):
    file_path: str
    file_name: str
    file_size: int
    is_directory: bool
    match_count: Optional[int] = None

def search_files_by_name(root_path: str, search_term: str) -> List[SearchResult]:
    results = []
    search_term_lower = search_term.lower()
    try:
        for dirpath, dirnames, filenames in os.walk(root_path):
            for filename in filenames:
                if search_term_lower in filename.lower():
                    file_path = os.path.join(dirpath, filename)
                    file_size = os.path.getsize(file_path)
                    results.append(SearchResult(
                        file_path=file_path,
                        file_name=filename,
                        file_size=file_size,
                        is_directory=False
                    ))
            for dirname in dirnames:
                if search_term_lower in dirname.lower():
                    dir_path = os.path.join(dirpath, dirname)
                    results.append(SearchResult(
                        file_path=dir_path,
                        file_name=dirname,
                        file_size=0,
                        is_directory=True
                    ))
    except PermissionError:
        pass
    return results

def search_files_by_content(root_path: str, search_term: str) -> List[SearchResult]:
    results = []
    try:
        for dirpath, dirnames, filenames in os.walk(root_path):
            for filename in filenames:
                file_path = os.path.join(dirpath, filename)
                try:
                    with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
                        content = f.read()
                        match_count = content.lower().count(search_term.lower())
                        if match_count > 0:
                            file_size = os.path.getsize(file_path)
                            results.append(SearchResult(
                                file_path=file_path,
                                file_name=filename,
                                file_size=file_size,
                                is_directory=False,
                                match_count=match_count
                            ))
                except Exception:
                    pass
    except PermissionError:
        pass
    return results

def search_files_by_extension(root_path: str, extension: str) -> List[SearchResult]:
    results = []
    extension_lower = extension.lower()
    if not extension_lower.startswith('.'):
        extension_lower = '.' + extension_lower
    try:
        for dirpath, dirnames, filenames in os.walk(root_path):
            for filename in filenames:
                if filename.lower().endswith(extension_lower):
                    file_path = os.path.join(dirpath, filename)
                    file_size = os.path.getsize(file_path)
                    results.append(SearchResult(
                        file_path=file_path,
                        file_name=filename,
                        file_size=file_size,
                        is_directory=False
                    ))
    except PermissionError:
        pass
    return results

def search_files_by_regex(root_path: str, pattern: str) -> List[SearchResult]:
    results = []
    try:
        regex = re.compile(pattern)
        for dirpath, dirnames, filenames in os.walk(root_path):
            for filename in filenames:
                if regex.search(filename):
                    file_path = os.path.join(dirpath, filename)
                    file_size = os.path.getsize(file_path)
                    results.append(SearchResult(
                        file_path=file_path,
                        file_name=filename,
                        file_size=file_size,
                        is_directory=False
                    ))
    except Exception:
        pass
    return results

def get_directory_tree(root_path: str, max_depth: int = 3, current_depth: int = 0) -> dict:
    if current_depth >= max_depth or not os.path.isdir(root_path):
        return {}
    tree = {}
    try:
        for item in os.listdir(root_path):
            item_path = os.path.join(root_path, item)
            if os.path.isdir(item_path):
                tree[item] = get_directory_tree(item_path, max_depth, current_depth + 1)
            else:
                tree[item] = None
    except PermissionError:
        pass
    return tree

