@app.get("/search/name")
def search_by_name(path: str = Query("."), name: str = Query(...)):
    if not os.path.exists(path):
        return {"error": "Path does not exist", "results": []}
    results = search_files_by_name(path, name)
    return {"results": [result.dict() for result in results], "count": len(results)}

@app.get("/search/content")
def search_by_content(path: str = Query("."), content: str = Query(...)):
    if not os.path.exists(path):
        return {"error": "Path does not exist", "results": []}
    results = search_files_by_content(path, content)
    return {"results": [result.dict() for result in results], "count": len(results)}

@app.get("/search/extension")
def search_by_extension(path: str = Query("."), extension: str = Query(...)):
    if not os.path.exists(path):
        return {"error": "Path does not exist", "results": []}
    results = search_files_by_extension(path, extension)
    return {"results": [result.dict() for result in results], "count": len(results)}

@app.get("/search/regex")
def search_by_regex(path: str = Query("."), pattern: str = Query(...)):
    if not os.path.exists(path):
        return {"error": "Path does not exist", "results": []}
    results = search_files_by_regex(path, pattern)
    return {"results": [result.dict() for result in results], "count": len(results)}

@app.get("/directory-tree")
def get_tree(path: str = Query("."), depth: int = Query(3, ge=1, le=10)):
    if not os.path.exists(path):
        return {"error": "Path does not exist"}
    tree = get_directory_tree(path, depth)
    return {"path": path, "tree": tree}

