import re
from datetime import datetime
from collections import Counter, defaultdict
class LogAnalyzer:
    def __init__(self, log_file_path):
        self.log_file_path = log_file_path
        self.logs = []
        self.load_logs()
    def load_logs(self):
        try:
            with open(self.log_file_path, 'r') as f:
                self.logs = f.readlines()
        except FileNotFoundError:
            print(f"File {self.log_file_path} not found")
            self.logs = []
    def parse_log_line(self, line):
        timestamp_pattern = r'\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}'
        level_pattern = r'(DEBUG|INFO|WARNING|ERROR|CRITICAL)'
        timestamp_match = re.search(timestamp_pattern, line)
        level_match = re.search(level_pattern, line)
        return {
            'timestamp': timestamp_match.group() if timestamp_match else None,
            'level': level_match.group() if level_match else None,
            'message': line.strip()
        }
    def count_by_level(self):
        levels = []
        for line in self.logs:
            parsed = self.parse_log_line(line)
            if parsed['level']:
                levels.append(parsed['level'])
        return dict(Counter(levels))
    def filter_by_level(self, level):
        results = []
        for line in self.logs:
            parsed = self.parse_log_line(line)
            if parsed['level'] == level.upper():
                results.append(parsed)
        return results
    def filter_by_keyword(self, keyword):
        results = []
        for line in self.logs:
            if keyword.lower() in line.lower():
                parsed = self.parse_log_line(line)
                results.append(parsed)
        return results
    def filter_by_time_range(self, start_time, end_time):
        results = []
        start_dt = datetime.strptime(start_time, '%Y-%m-%d %H:%M:%S')
        end_dt = datetime.strptime(end_time, '%Y-%m-%d %H:%M:%S')
        for line in self.logs:
            parsed = self.parse_log_line(line)
            if parsed['timestamp']:
                try:
                    log_dt = datetime.strptime(parsed['timestamp'], '%Y-%m-%d %H:%M:%S')
                    if start_dt <= log_dt <= end_dt:
                        results.append(parsed)
                except:
                    pass
        return results
    def get_error_summary(self):
        errors = self.filter_by_level('ERROR')
        error_messages = [e['message'] for e in errors]
        return {
            'total_errors': len(errors),
            'error_messages': error_messages
        }
    def get_statistics(self):
        level_counts = self.count_by_level()
        total_logs = len(self.logs)
        return {
            'total_logs': total_logs,
            'level_distribution': level_counts,
            'error_rate': level_counts.get('ERROR', 0) / total_logs * 100 if total_logs > 0 else 0
        }
    def find_patterns(self, pattern):
        results = []
        for line in self.logs:
            if re.search(pattern, line):
                parsed = self.parse_log_line(line)
                results.append(parsed)
        return results
    def group_by_hour(self):
        hourly_counts = defaultdict(int)
        for line in self.logs:
            parsed = self.parse_log_line(line)
            if parsed['timestamp']:
                try:
                    log_dt = datetime.strptime(parsed['timestamp'], '%Y-%m-%d %H:%M:%S')
                    hour_key = log_dt.strftime('%Y-%m-%d %H:00:00')
                    hourly_counts[hour_key] += 1
                except:
                    pass
        return dict(hourly_counts)
