from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime, timedelta
import re
import os

app = FastAPI()

class LogEntry(BaseModel):
    timestamp: str
    level: str
    message: str
    source: Optional[str] = None

class LogStats(BaseModel):
    total_entries: int
    error_count: int
    warning_count: int
    info_count: int
    success_count: int
    unknown_count: int

def parse_log_line(line: str) -> Optional[LogEntry]:
    pattern = r'\[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\] \[(\w+)\] (.*)'
    match = re.match(pattern, line)
    if match:
        timestamp, level, message = match.groups()
        return LogEntry(timestamp=timestamp, level=level.lower(), message=message)
    return None

def read_log_file(file_path: str) -> List[LogEntry]:
    logs = []
    if not os.path.exists(file_path):
        return logs
    try:
        with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
            for line in f:
                line = line.strip()
                if line:
                    entry = parse_log_line(line)
                    if entry:
                        logs.append(entry)
    except Exception:
        pass
    return logs

def filter_logs_by_level(logs: List[LogEntry], level: str) -> List[LogEntry]:
    return [log for log in logs if log.level == level.lower()]

def filter_logs_by_keyword(logs: List[LogEntry], keyword: str) -> List[LogEntry]:
    keyword_lower = keyword.lower()
    return [log for log in logs if keyword_lower in log.message.lower()]

def filter_logs_by_date_range(logs: List[LogEntry], start_date: str, end_date: str) -> List[LogEntry]:
    try:
        start = datetime.fromisoformat(start_date.replace('T', ' '))
        end = datetime.fromisoformat(end_date.replace('T', ' '))
        filtered = []
        for log in logs:
            try:
                log_time = datetime.fromisoformat(log.timestamp)
                if start <= log_time <= end:
                    filtered.append(log)
            except ValueError:
                pass
        return filtered
    except ValueError:
        return logs

def get_log_statistics(logs: List[LogEntry]) -> LogStats:
    error_count = sum(1 for log in logs if log.level == 'error')
    warning_count = sum(1 for log in logs if log.level == 'warning')
    info_count = sum(1 for log in logs if log.level == 'info')
    success_count = sum(1 for log in logs if log.level == 'success')
    unknown_count = len(logs) - error_count - warning_count - info_count - success_count
    return LogStats(
        total_entries=len(logs),
        error_count=error_count,
        warning_count=warning_count,
        info_count=info_count,
        success_count=success_count,
        unknown_count=unknown_count
    )

def search_logs_with_regex(logs: List[LogEntry], pattern: str) -> List[LogEntry]:
    try:
        regex = re.compile(pattern)
        return [log for log in logs if regex.search(log.message)]
    except Exception:
        return []

def get_error_summary(logs: List[LogEntry]) -> Dict:
    errors = filter_logs_by_level(logs, 'error')
    error_messages = {}
    for error in errors:
        if error.message not in error_messages:
            error_messages[error.message] = 0
        error_messages[error.message] += 1
    sorted_errors = sorted(error_messages.items(), key=lambda x: x[1], reverse=True)
    return {"total_errors": len(errors), "error_types": sorted_errors[:10]}

def get_time_based_distribution(logs: List[LogEntry]) -> Dict:
    distribution = {}
    for log in logs:
        try:
            time = datetime.fromisoformat(log.timestamp)
            hour = time.strftime('%Y-%m-%d %H:00')
            if hour not in distribution:
                distribution[hour] = 0
            distribution[hour] += 1
        except ValueError:
            pass
    return distribution

