    <body>
        <div class="container">
            <h1>📊 Log Analyzer</h1>
            <div class="control-section">
                <h3>Load & Analyze Logs</h3>
                <div class="control-row">
                    <input type="text" id="logFilePath" placeholder="Enter log file path (e.g., /path/to/app.log)" value="logs/app.log">
                    <button onclick="loadLogs()">Load Logs</button>
                </div>
                <div class="tabs">
                    <button class="tab-button active" onclick="switchTab('filter-tab')">Filter</button>
                    <button class="tab-button" onclick="switchTab('stats-tab')">Statistics</button>
                    <button class="tab-button" onclick="switchTab('search-tab')">Search</button>
                </div>
                <div id="filter-tab" class="tab-content active">
                    <h4>Filter Logs</h4>
                    <div class="control-row">
                        <select id="logLevel">
                            <option value="">All Levels</option>
                            <option value="error">Error</option>
                            <option value="warning">Warning</option>
                            <option value="info">Info</option>
                            <option value="success">Success</option>
                        </select>
                        <input type="text" id="keywordFilter" placeholder="Search by keyword...">
                        <button class="secondary" onclick="filterByKeyword()">Filter</button>
                    </div>
                    <div class="control-row">
                        <label>Date Range:</label>
                        <input type="date" id="startDate">
                        <input type="date" id="endDate">
                        <button class="secondary" onclick="filterByDateRange()">Filter</button>
                    </div>
                </div>
                <div id="stats-tab" class="tab-content">
                    <h4>Log Statistics</h4>
                    <button class="secondary" onclick="getStatistics()">Analyze Statistics</button>
                    <div id="statsResults" style="margin-top: 20px;"></div>
                </div>
                <div id="search-tab" class="tab-content">
                    <h4>Advanced Search</h4>
                    <div class="control-row">
                        <textarea id="regexPattern" placeholder="Enter regex pattern (e.g., error.*database)" rows="2" style="flex: 1;"></textarea>
                        <button class="secondary" onclick="searchByRegex()">Search</button>
                    </div>
                </div>
            </div>
            <div id="results" class="results"></div>
        </div>
        <script>
            let currentLogs = [];
            function switchTab(tabName) {
                const tabs = document.querySelectorAll('.tab-content');
                tabs.forEach(tab => tab.classList.remove('active'));
                document.getElementById(tabName).classList.add('active');
                const buttons = document.querySelectorAll('.tab-button');
                buttons.forEach(btn => btn.classList.remove('active'));
                event.target.classList.add('active');
            }
            function loadLogs() {
                const path = document.getElementById('logFilePath').value;
                if(!path) {
                    alert('Please enter a log file path');
                    return;
                }
                fetch('/analyze/load?path=' + encodeURIComponent(path))
                .then(response => response.json())
                .then(data => {
                    currentLogs = data.logs;
                    displayResults(data);
                })
                .catch(error => alert('Error: ' + error));
            }
            function filterByKeyword() {
                const level = document.getElementById('logLevel').value;
                const keyword = document.getElementById('keywordFilter').value;
                if(!currentLogs.length) {
                    alert('Please load logs first');
                    return;
                }
                const params = new URLSearchParams({logs: JSON.stringify(currentLogs)});
                if(level) params.append('level', level);
                if(keyword) params.append('keyword', keyword);
                fetch('/analyze/filter?' + params)
                .then(response => response.json())
                .then(data => displayResults(data))
                .catch(error => alert('Error: ' + error));
            }
            function filterByDateRange() {
                const start = document.getElementById('startDate').value;
                const end = document.getElementById('endDate').value;
                if(!start || !end) {
                    alert('Please select both start and end dates');
                    return;
                }
                if(!currentLogs.length) {
                    alert('Please load logs first');
                    return;
                }
                fetch('/analyze/date-range?start=' + start + '&end=' + end + '&logs=' + encodeURIComponent(JSON.stringify(currentLogs)))
                .then(response => response.json())
                .then(data => displayResults(data))
                .catch(error => alert('Error: ' + error));
            }
            function getStatistics() {
                if(!currentLogs.length) {
                    alert('Please load logs first');
                    return;
                }
                fetch('/analyze/stats?logs=' + encodeURIComponent(JSON.stringify(currentLogs)))
                .then(response => response.json())
                .then(data => displayStats(data))
                .catch(error => alert('Error: ' + error));
            }
            function searchByRegex() {
                const pattern = document.getElementById('regexPattern').value;
                if(!pattern) {
                    alert('Please enter a regex pattern');
                    return;
                }
                if(!currentLogs.length) {
                    alert('Please load logs first');
                    return;
                }
                fetch('/analyze/regex?pattern=' + encodeURIComponent(pattern) + '&logs=' + encodeURIComponent(JSON.stringify(currentLogs)))
                .then(response => response.json())
                .then(data => displayResults(data))
                .catch(error => alert('Error: ' + error));
            }
            function displayResults(data) {
                const resultsDiv = document.getElementById('results');
                if(!data.logs || data.logs.length === 0) {
                    resultsDiv.innerHTML = '<p style="color: #666; font-style: italic;">No logs found.</p>';
                    return;
                }
                let html = '<h3>Found ' + data.logs.length + ' log entry(ies):</h3>';
                html += '<table><tr><th>Timestamp</th><th>Level</th><th>Message</th></tr>';
                data.logs.forEach(log => {
                    const levelClass = 'level-' + log.level;
                    html += '<tr>';
                    html += '<td>' + log.timestamp + '</td>';
                    html += '<td><span class="' + levelClass + '">' + log.level.toUpperCase() + '</span></td>';
                    html += '<td class="log-entry">' + log.message.substring(0, 150) + (log.message.length > 150 ? '...' : '') + '</td>';
                    html += '</tr>';
                });
                html += '</table>';
                resultsDiv.innerHTML = html;
            }
            function displayStats(data) {
                const statsDiv = document.getElementById('statsResults');
                const stats = data.stats;
                let html = '<div class="stats-grid">';
                html += '<div class="stat-card"><div class="stat-value">' + stats.total_entries + '</div><div class="stat-label">Total Entries</div></div>';
                html += '<div class="stat-card error"><div class="stat-value">' + stats.error_count + '</div><div class="stat-label">Errors</div></div>';
                html += '<div class="stat-card warning"><div class="stat-value">' + stats.warning_count + '</div><div class="stat-label">Warnings</div></div>';
                html += '<div class="stat-card info"><div class="stat-value">' + stats.info_count + '</div><div class="stat-label">Info</div></div>';
                html += '<div class="stat-card success"><div class="stat-value">' + stats.success_count + '</div><div class="stat-label">Success</div></div>';
                html += '</div>';
                statsDiv.innerHTML = html;
            }
        </script>
    </body>
    </html>
    """

@app.get("/analyze/load")
def load_logs(path: str = Query(...)):
    logs = read_log_file(path)
    return {"logs": [log.dict() for log in logs], "count": len(logs)}

@app.get("/analyze/filter")
def filter_logs(logs: str = Query(...), level: Optional[str] = Query(None), keyword: Optional[str] = Query(None)):
    import json
    try:
        log_list = [LogEntry(**log) for log in json.loads(logs)]
    except Exception:
        return {"logs": [], "count": 0}
    if level:
        log_list = filter_logs_by_level(log_list, level)
    if keyword:
        log_list = filter_logs_by_keyword(log_list, keyword)
    return {"logs": [log.dict() for log in log_list], "count": len(log_list)}

@app.get("/analyze/date-range")
def filter_by_date(start: str = Query(...), end: str = Query(...), logs: str = Query(...)):
    import json
    try:
        log_list = [LogEntry(**log) for log in json.loads(logs)]
    except Exception:
        return {"logs": [], "count": 0}
    filtered = filter_logs_by_date_range(log_list, start, end)
    return {"logs": [log.dict() for log in filtered], "count": len(filtered)}

@app.get("/analyze/stats")
def get_stats(logs: str = Query(...)):
    import json
    try:
        log_list = [LogEntry(**log) for log in json.loads(logs)]
    except Exception:
        return {"stats": {}}
    stats = get_log_statistics(log_list)
    return {"stats": stats.dict()}

@app.get("/analyze/regex")
def search_regex(pattern: str = Query(...), logs: str = Query(...)):
    import json
    try:
        log_list = [LogEntry(**log) for log in json.loads(logs)]
    except Exception:
        return {"logs": [], "count": 0}
    results = search_logs_with_regex(log_list, pattern)
    return {"logs": [log.dict() for log in results], "count": len(results)}

