import csv
from collections import defaultdict
class CSVParser:
    def __init__(self, file_path):
        self.file_path = file_path
        self.data = []
        self.headers = []
    def read_csv(self):
        with open(self.file_path, 'r', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            self.headers = reader.fieldnames
            self.data = [row for row in reader]
        return self.data
    def get_column(self, column_name):
        return [row.get(column_name) for row in self.data if column_name in row]
    def filter_rows(self, column_name, value):
        return [row for row in self.data if row.get(column_name) == value]
    def filter_by_condition(self, column_name, condition):
        return [row for row in self.data if condition(row.get(column_name))]
    def group_by(self, column_name):
        grouped = defaultdict(list)
        for row in self.data:
            key = row.get(column_name)
            grouped[key].append(row)
        return dict(grouped)
    def count_by(self, column_name):
        counts = defaultdict(int)
        for row in self.data:
            key = row.get(column_name)
            counts[key] += 1
        return dict(counts)
    def get_unique_values(self, column_name):
        return list(set(row.get(column_name) for row in self.data if column_name in row))
    def sort_by(self, column_name, reverse=False):
        return sorted(self.data, key=lambda x: x.get(column_name, ''), reverse=reverse)
    def calculate_sum(self, column_name):
        total = 0
        for row in self.data:
            try:
                total += float(row.get(column_name, 0))
            except ValueError:
                pass
        return total
    def calculate_average(self, column_name):
        values = []
        for row in self.data:
            try:
                values.append(float(row.get(column_name)))
            except ValueError:
                pass
        return sum(values) / len(values) if values else 0
    def write_csv(self, output_path, data=None):
        if data is None:
            data = self.data
        if not data:
            return
        with open(output_path, 'w', newline='', encoding='utf-8') as f:
            writer = csv.DictWriter(f, fieldnames=data[0].keys())
            writer.writeheader()
            writer.writerows(data)
    def get_statistics(self, column_name):
        values = []
        for row in self.data:
            try:
                values.append(float(row.get(column_name)))
            except ValueError:
                pass
        if not values:
            return {}
        return {
            'count': len(values),
            'sum': sum(values),
            'average': sum(values) / len(values),
            'min': min(values),
            'max': max(values)
        }
sample_csv_content = """name,age,city,salary
