from fastapi import FastAPI, UploadFile, File, Query
from fastapi.responses import HTMLResponse, FileResponse
from pydantic import BaseModel
from typing import List, Optional, Dict, Any
import csv
import json
import os

app = FastAPI()

UPLOAD_DIR = "csv_uploads"

if not os.path.exists(UPLOAD_DIR):
    os.makedirs(UPLOAD_DIR)

class CSVData(BaseModel):
    filename: str
    total_rows: int
    columns: List[str]
    data: List[Dict[str, Any]]

class FilterResult(BaseModel):
    filename: str
    filtered_rows: int
    data: List[Dict[str, Any]]

def read_csv_file(file_path: str) -> Optional[CSVData]:
    if not os.path.exists(file_path):
        return None
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            columns = reader.fieldnames if reader.fieldnames else []
            data = list(reader)
        return CSVData(
            filename=os.path.basename(file_path),
            total_rows=len(data),
            columns=columns,
            data=data
        )
    except Exception:
        return None

def filter_csv_by_column(data: List[Dict[str, Any]], column: str, value: str) -> List[Dict[str, Any]]:
    value_lower = value.lower()
    return [row for row in data if column in row and value_lower in str(row[column]).lower()]

def filter_csv_by_multiple_conditions(data: List[Dict[str, Any]], conditions: Dict[str, str]) -> List[Dict[str, Any]]:
    filtered = data
    for column, value in conditions.items():
        filtered = filter_csv_by_column(filtered, column, value)
    return filtered

def sort_csv_by_column(data: List[Dict[str, Any]], column: str, reverse: bool = False) -> List[Dict[str, Any]]:
    try:
        return sorted(data, key=lambda x: float(x.get(column, 0)) if x.get(column, '').replace('.', '').isdigit() else x.get(column, ''), reverse=reverse)
    except Exception:
        return sorted(data, key=lambda x: str(x.get(column, '')), reverse=reverse)

def get_column_statistics(data: List[Dict[str, Any]], column: str) -> Dict[str, Any]:
    values = [row.get(column, '') for row in data if column in row]
    numeric_values = []
    for v in values:
        try:
            numeric_values.append(float(v))
        except ValueError:
            pass
    stats = {
        "column": column,
        "total_values": len(values),
        "unique_values": len(set(values)),
        "null_values": sum(1 for v in values if v == '' or v is None)
    }
    if numeric_values:
        stats["min"] = min(numeric_values)
        stats["max"] = max(numeric_values)
        stats["average"] = sum(numeric_values) / len(numeric_values)
        stats["sum"] = sum(numeric_values)
    return stats

def export_csv_to_json(data: List[Dict[str, Any]], filename: str) -> str:
    json_file = os.path.join(UPLOAD_DIR, filename.replace('.csv', '.json'))
    with open(json_file, 'w') as f:
        json.dump(data, f, indent=2)
    return json_file

def export_csv_to_txt(data: List[Dict[str, Any]], columns: List[str], filename: str) -> str:
    txt_file = os.path.join(UPLOAD_DIR, filename.replace('.csv', '.txt'))
    with open(txt_file, 'w') as f:
        f.write(" | ".join(columns) + "\n")
        f.write("-" * 100 + "\n")
        for row in data:
            values = [str(row.get(col, '')) for col in columns]
            f.write(" | ".join(values) + "\n")
    return txt_file

def get_column_value_distribution(data: List[Dict[str, Any]], column: str) -> Dict[str, int]:
    distribution = {}
    for row in data:
        if column in row:
            value = str(row[column])
            distribution[value] = distribution.get(value, 0) + 1
    return dict(sorted(distribution.items(), key=lambda x: x[1], reverse=True))

