                    <button class="tab-button active" onclick="switchTab('view-tab')">View</button>
                    <button class="tab-button" onclick="switchTab('filter-tab')">Filter</button>
                    <button class="tab-button" onclick="switchTab('stats-tab')">Statistics</button>
                    <button class="tab-button" onclick="switchTab('export-tab')">Export</button>
                </div>
                <div id="view-tab" class="tab-content active">
                    <h2>CSV Data</h2>
                    <div id="csvStats" class="stats-grid"></div>
                    <div id="csvTable"></div>
                </div>
                <div id="filter-tab" class="tab-content">
                    <h2>Filter Data</h2>
                    <div class="filter-row">
                        <select id="filterColumn" style="flex: 1;"></select>
                        <input type="text" id="filterValue" placeholder="Filter value..." style="flex: 1;">
                        <button class="secondary" onclick="filterData()">Filter</button>
                        <button class="secondary" onclick="resetFilter()">Reset</button>
                    </div>
                    <div id="filterResults"></div>
                </div>
                <div id="stats-tab" class="tab-content">
                    <h2>Column Statistics</h2>
                    <div class="filter-row">
                        <select id="statsColumn" style="flex: 1;"></select>
                        <button class="secondary" onclick="getColumnStats()">Analyze</button>
                    </div>
                    <div id="statsResults"></div>
                </div>
                <div id="export-tab" class="tab-content">
                    <h2>Export Data</h2>
                    <button class="export" onclick="exportToJSON()">Export as JSON</button>
                    <button class="export" onclick="exportToTXT()">Export as TXT</button>
                </div>
            </div>
        </div>
        <script>
            let currentData = null;
            let currentFilename = null;
            function switchTab(tabName) {{
                const tabs = document.querySelectorAll('.tab-content');
                tabs.forEach(tab => tab.classList.remove('active'));
                document.getElementById(tabName).classList.add('active');
                const buttons = document.querySelectorAll('.tab-button');
                buttons.forEach(btn => btn.classList.remove('active'));
                event.target.classList.add('active');
            }}
            function uploadCSV() {{
                const fileInput = document.getElementById('csvFile');
                const file = fileInput.files[0];
                if(!file) {{
                    alert('Please select a file');
                    return;
                }}
                const formData = new FormData();
                formData.append('file', file);
                fetch('/upload', {{
                    method: 'POST',
                    body: formData
                }})
                .then(response => response.json())
                .then(data => {{
                    alert('File uploaded successfully!');
                    location.reload();
                }})
                .catch(error => alert('Error: ' + error));
            }}
            function loadCSV(filename) {{
                fetch('/load?filename=' + filename)
                .then(response => response.json())
                .then(data => {{
                    currentData = data;
                    currentFilename = filename;
                    displayCSVData(data);
                    populateFilterColumns(data.columns);
                    populateStatsColumns(data.columns);
                }})
                .catch(error => alert('Error: ' + error));
            }}
            function displayCSVData(data) {{
                const statsDiv = document.getElementById('csvStats');
                statsDiv.innerHTML = `
                    <div class="stat-card">
                        <div class="stat-label">Total Rows</div>
                        <div class="stat-value">${{data.total_rows}}</div>
                    </div>
                    <div class="stat-card">
                        <div class="stat-label">Total Columns</div>
                        <div class="stat-value">${{data.columns.length}}</div>
                    </div>
                `;
                const tableDiv = document.getElementById('csvTable');
                let html = '<table><tr>';
                data.columns.forEach(col => {{
                    html += '<th>' + col + '</th>';
                }});
                html += '</tr>';
                data.data.slice(0, 100).forEach(row => {{
                    html += '<tr>';
                    data.columns.forEach(col => {{
                        html += '<td>' + (row[col] || '') + '</td>';
                    }});
                    html += '</tr>';
                }});
                html += '</table>';
                tableDiv.innerHTML = html;
            }}
            function populateFilterColumns(columns) {{
                const select = document.getElementById('filterColumn');
                select.innerHTML = '';
                columns.forEach(col => {{
                    const option = document.createElement('option');
                    option.value = col;
                    option.textContent = col;
                    select.appendChild(option);
                }});
            }}
            function populateStatsColumns(columns) {{
                const select = document.getElementById('statsColumn');
                select.innerHTML = '';
                columns.forEach(col => {{
                    const option = document.createElement('option');
                    option.value = col;
                    option.textContent = col;
                    select.appendChild(option);
                }});
            }}
            function filterData() {{
                const column = document.getElementById('filterColumn').value;
                const value = document.getElementById('filterValue').value;
                if(!column || !value) {{
                    alert('Please select column and enter value');
                    return;
                }}
                fetch('/filter?filename=' + currentFilename + '&column=' + column + '&value=' + value)
                .then(response => response.json())
                .then(data => displayFilterResults(data))
                .catch(error => alert('Error: ' + error));
            }}
            function resetFilter() {{
                loadCSV(currentFilename);
            }}
            function displayFilterResults(data) {{
                const resultsDiv = document.getElementById('filterResults');
                let html = '<p>Found ' + data.data.length + ' matching rows:</p>';
                html += '<table><tr>';
                const columns = Object.keys(data.data[0] || {});
                columns.forEach(col => {{
                    html += '<th>' + col + '</th>';
                }});
                html += '</tr>';
                data.data.forEach(row => {{
                    html += '<tr>';
                    columns.forEach(col => {{
                        html += '<td>' + (row[col] || '') + '</td>';
                    }});
                    html += '</tr>';
                }});
                html += '</table>';
                resultsDiv.innerHTML = html;
            }}
            function getColumnStats() {{
                const column = document.getElementById('statsColumn').value;
                if(!column) {{
                    alert('Please select a column');
                    return;
                }}
                fetch('/stats?filename=' + currentFilename + '&column=' + column)
                .then(response => response.json())
                .then(data => displayStats(data))
                .catch(error => alert('Error: ' + error));
            }}
            function displayStats(data) {{
                const statsDiv = document.getElementById('statsResults');
                const s = data.stats;
                let html = '<div class="stats-grid">';
                html += '<div class="stat-card"><div class="stat-label">Total Values</div><div class="stat-value">' + s.total_values + '</div></div>';
                html += '<div class="stat-card"><div class="stat-label">Unique Values</div><div class="stat-value">' + s.unique_values + '</div></div>';
                html += '<div class="stat-card"><div class="stat-label">Null Values</div><div class="stat-value">' + s.null_values + '</div></div>';
                if(s.min !== undefined) {{
                    html += '<div class="stat-card"><div class="stat-label">Min</div><div class="stat-value">' + s.min.toFixed(2) + '</div></div>';
                    html += '<div class="stat-card"><div class="stat-label">Max</div><div class="stat-value">' + s.max.toFixed(2) + '</div></div>';
                    html += '<div class="stat-card"><div class="stat-label">Average</div><div class="stat-value">' + s.average.toFixed(2) + '</div></div>';
                }}
                html += '</div>';
                statsDiv.innerHTML = html;
            }}
            function exportToJSON() {{
                if(!currentFilename) {{
                    alert('Please load a file first');
                    return;
                }}
                window.location.href = '/export/json?filename=' + currentFilename;
            }}
            function exportToTXT() {{
                if(!currentFilename) {{
                    alert('Please load a file first');
                    return;
                }}
                window.location.href = '/export/txt?filename=' + currentFilename;
            }}
            function deleteFile(filename) {{
                if(confirm('Are you sure you want to delete this file?')) {{
                    fetch('/delete?filename=' + filename, {{method: 'DELETE'}})
                    .then(response => response.json())
                    .then(data => {{
                        alert('File deleted!');
                        location.reload();
                    }})
                    .catch(error => alert('Error: ' + error));
                }}
            }}
        </script>
    </body>
    </html>
    """

@app.post("/upload")
async def upload_csv(file: UploadFile = File(...)):
    file_path = os.path.join(UPLOAD_DIR, file.filename)
    with open(file_path, "wb") as f:
        f.write(await file.read())
    return {"filename": file.filename, "status": "success"}

@app.get("/load")
def load_csv(filename: str = Query(...)):
    file_path = os.path.join(UPLOAD_DIR, filename)
    data = read_csv_file(file_path)
    if not data:
        return {"error": "File not found"}
    return data.dict()

@app.get("/filter")
def filter_csv(filename: str = Query(...), column: str = Query(...), value: str = Query(...)):
    file_path = os.path.join(UPLOAD_DIR, filename)
    data = read_csv_file(file_path)
    if not data:
        return {"error": "File not found"}
    filtered = filter_csv_by_column(data.data, column, value)
    return {"filename": filename, "filtered_rows": len(filtered), "data": filtered}

@app.get("/stats")
def get_stats(filename: str = Query(...), column: str = Query(...)):
    file_path = os.path.join(UPLOAD_DIR, filename)
    data = read_csv_file(file_path)
    if not data:
        return {"error": "File not found"}
    stats = get_column_statistics(data.data, column)
    return {"filename": filename, "stats": stats}

@app.get("/export/json")
def export_json(filename: str = Query(...)):
    file_path = os.path.join(UPLOAD_DIR, filename)
    data = read_csv_file(file_path)
    if not data:
        return {"error": "File not found"}
    json_file = export_csv_to_json(data.data, filename)
    return FileResponse(json_file, filename=filename.replace('.csv', '.json'))

@app.get("/export/txt")
def export_txt(filename: str = Query(...)):
    file_path = os.path.join(UPLOAD_DIR, filename)
    data = read_csv_file(file_path)
    if not data:
        return {"error": "File not found"}
    txt_file = export_csv_to_txt(data.data, data.columns, filename)
    return FileResponse(txt_file, filename=filename.replace('.csv', '.txt'))

@app.delete("/delete")
def delete_csv(filename: str = Query(...)):
    file_path = os.path.join(UPLOAD_DIR, filename)
    if os.path.exists(file_path):
        os.remove(file_path)
    return {"status": "success", "message": "File deleted"}

