import json
import os
from datetime import datetime
class JSONFileWriter:
    def __init__(self, file_path):
        self.file_path = file_path
    def write_json(self, data, indent=4):
        with open(self.file_path, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=indent, ensure_ascii=False)
    def append_to_array(self, new_item):
        if os.path.exists(self.file_path):
            with open(self.file_path, 'r', encoding='utf-8') as f:
                data = json.load(f)
            if isinstance(data, list):
                data.append(new_item)
            else:
                data = [data, new_item]
        else:
            data = [new_item]
        self.write_json(data)
    def update_json(self, key, value):
        if os.path.exists(self.file_path):
            with open(self.file_path, 'r', encoding='utf-8') as f:
                data = json.load(f)
        else:
            data = {}
        data[key] = value
        self.write_json(data)
    def read_json(self):
        if os.path.exists(self.file_path):
            with open(self.file_path, 'r', encoding='utf-8') as f:
                return json.load(f)
        return None
    def merge_json(self, new_data):
        if os.path.exists(self.file_path):
            with open(self.file_path, 'r', encoding='utf-8') as f:
                existing_data = json.load(f)
            if isinstance(existing_data, dict) and isinstance(new_data, dict):
                existing_data.update(new_data)
                self.write_json(existing_data)
            else:
                self.write_json(new_data)
        else:
            self.write_json(new_data)
    def delete_key(self, key):
        if os.path.exists(self.file_path):
            with open(self.file_path, 'r', encoding='utf-8') as f:
                data = json.load(f)
            if isinstance(data, dict) and key in data:
                del data[key]
                self.write_json(data)
    def write_pretty_json(self, data):
        self.write_json(data, indent=2)
    def write_compact_json(self, data):
        with open(self.file_path, 'w', encoding='utf-8') as f:
            json.dump(data, f, separators=(',', ':'), ensure_ascii=False)
