from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse, FileResponse
from pydantic import BaseModel
from typing import List, Optional, Dict, Any
from datetime import datetime
import json
import os

app = FastAPI()

DATA_DIR = "json_data"

if not os.path.exists(DATA_DIR):
    os.makedirs(DATA_DIR)

class JSONFile(BaseModel):
    filename: str
    content: Dict[str, Any]
    created_at: Optional[str] = None
    updated_at: Optional[str] = None

class JSONRecord(BaseModel):
    id: Optional[int] = None
    name: str
    email: str
    phone: Optional[str] = None
    address: Optional[str] = None
    created_at: Optional[str] = None

def write_json_to_file(filename: str, data: Dict[str, Any]) -> str:
    if not filename.endswith('.json'):
        filename = filename + '.json'
    file_path = os.path.join(DATA_DIR, filename)
    with open(file_path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2)
    return file_path

def append_to_json_file(filename: str, data: Dict[str, Any]) -> str:
    if not filename.endswith('.json'):
        filename = filename + '.json'
    file_path = os.path.join(DATA_DIR, filename)
    existing_data = []
    if os.path.exists(file_path):
        with open(file_path, 'r', encoding='utf-8') as f:
            try:
                content = json.load(f)
                if isinstance(content, list):
                    existing_data = content
                else:
                    existing_data = [content]
            except json.JSONDecodeError:
                existing_data = []
    existing_data.append(data)
    with open(file_path, 'w', encoding='utf-8') as f:
        json.dump(existing_data, f, indent=2)
    return file_path

def read_json_file(filename: str) -> Optional[Dict[str, Any]]:
    if not filename.endswith('.json'):
        filename = filename + '.json'
    file_path = os.path.join(DATA_DIR, filename)
    if not os.path.exists(file_path):
        return None
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            return json.load(f)
    except json.JSONDecodeError:
        return None

def list_json_files() -> List[Dict[str, Any]]:
    files = []
    if os.path.exists(DATA_DIR):
        for filename in os.listdir(DATA_DIR):
            if filename.endswith('.json'):
                file_path = os.path.join(DATA_DIR, filename)
                file_size = os.path.getsize(file_path)
                modified_time = datetime.fromtimestamp(os.path.getmtime(file_path)).isoformat()
                files.append({
                    "filename": filename,
                    "size": file_size,
                    "modified": modified_time
                })
    return sorted(files, key=lambda x: x['modified'], reverse=True)

def merge_json_files(files: List[str]) -> Dict[str, Any]:
    merged = {}
    for filename in files:
        data = read_json_file(filename)
        if data:
            if isinstance(data, dict):
                merged.update(data)
            elif isinstance(data, list):
                if "items" not in merged:
                    merged["items"] = []
                merged["items"].extend(data)
    return merged

def search_in_json(filename: str, key: str, value: str) -> List[Dict[str, Any]]:
    data = read_json_file(filename)
    if not data:
        return []
    results = []
    if isinstance(data, list):
        for item in data:
            if isinstance(item, dict) and key in item:
                if value.lower() in str(item[key]).lower():
                    results.append(item)
    elif isinstance(data, dict):
        for item_key, item_value in data.items():
            if isinstance(item_value, dict) and key in item_value:
                if value.lower() in str(item_value[key]).lower():
                    results.append(item_value)
    return results

def delete_json_file(filename: str) -> bool:
    if not filename.endswith('.json'):
        filename = filename + '.json'
    file_path = os.path.join(DATA_DIR, filename)
    if os.path.exists(file_path):
        os.remove(file_path)
        return True
    return False

def validate_json_structure(data: str) -> tuple[bool, str]:
    try:
        json.loads(data)
        return True, "Valid JSON"
    except json.JSONDecodeError as e:
        return False, str(e)

