                const tabs = document.querySelectorAll('.tab-content');
                tabs.forEach(tab => tab.classList.remove('active'));
                document.getElementById(tabName).classList.add('active');
                const buttons = document.querySelectorAll('.tab-button');
                buttons.forEach(btn => btn.classList.remove('active'));
                event.target.classList.add('active');
                if(tabName === 'view-tab') {{
                    loadFiles();
                }}
                if(tabName === 'search-tab') {{
                    populateSearchFiles();
                }}
            }}
            function validateJSON() {{
                const content = document.getElementById('jsonContent').value;
                fetch('/validate', {{
                    method: 'POST',
                    headers: {{'Content-Type': 'application/json'}},
                    body: JSON.stringify({{json_string: content}})
                }})
                .then(response => response.json())
                .then(data => {{
                    const validDiv = document.getElementById('validation');
                    if(data.valid) {{
                        validDiv.className = 'validation valid';
                        validDiv.textContent = '✓ ' + data.message;
                    }} else {{
                        validDiv.className = 'validation invalid';
                        validDiv.textContent = '✗ ' + data.message;
                    }}
                }})
                .catch(error => console.error('Error:', error));
            }}
            function writeJSON() {{
                const filename = document.getElementById('filename').value;
                const content = document.getElementById('jsonContent').value;
                if(!filename || !content) {{
                    alert('Please enter filename and JSON content');
                    return;
                }}
                fetch('/write', {{
                    method: 'POST',
                    headers: {{'Content-Type': 'application/json'}},
                    body: JSON.stringify({{filename: filename, content: content}})
                }})
                .then(response => response.json())
                .then(data => {{
                    alert('JSON written successfully!');
                    document.getElementById('filename').value = '';
                    document.getElementById('jsonContent').value = '';
                    loadFiles();
                }})
                .catch(error => alert('Error: ' + error));
            }}
            function appendJSON() {{
                const filename = document.getElementById('filename').value;
                const content = document.getElementById('jsonContent').value;
                if(!filename || !content) {{
                    alert('Please enter filename and JSON content');
                    return;
                }}
                fetch('/append', {{
                    method: 'POST',
                    headers: {{'Content-Type': 'application/json'}},
                    body: JSON.stringify({{filename: filename, content: content}})
                }})
                .then(response => response.json())
                .then(data => {{
                    alert('JSON appended successfully!');
                    document.getElementById('jsonContent').value = '';
                    loadFiles();
                }})
                .catch(error => alert('Error: ' + error));
            }}
            function formatJSON() {{
                try {{
                    const json = JSON.parse(document.getElementById('jsonContent').value);
                    document.getElementById('jsonContent').value = JSON.stringify(json, null, 2);
                }} catch(e) {{
                    alert('Invalid JSON: ' + e.message);
                }}
