            function createEmptyFile() {{
                const filename = document.getElementById('filename').value;
                if(!filename) {{
                    alert('Please enter a filename');
                    return;
                }}
                document.getElementById('jsonContent').value = '{{}}';
                document.getElementById('filename').value = filename;
            }}
            function loadUserTemplate() {{
                document.getElementById('jsonContent').value = JSON.stringify({{
                    users: [
                        {{id: 1, name: "John Doe", email: "john@example.com"}},
                        {{id: 2, name: "Jane Smith", email: "jane@example.com"}}
                    ]
                }}, null, 2);
            }}
            function loadConfigTemplate() {{
                document.getElementById('jsonContent').value = JSON.stringify({{
                    database: {{
                        host: "localhost",
                        port: 5432,
                        name: "mydb"
                    }},
                    server: {{
                        port: 8000,
                        debug: true
                    }}
                }}, null, 2);
            }}
            function loadArrayTemplate() {{
                document.getElementById('jsonContent').value = JSON.stringify([
                    {{id: 1, value: "item1"}},
                    {{id: 2, value: "item2"}},
                    {{id: 3, value: "item3"}}
                ], null, 2);
            }}
            function loadFiles() {{
                fetch('/list')
                .then(response => response.json())
                .then(data => {{
                    const tbody = document.querySelector('table tbody');
                    if(!tbody) return;
                    tbody.innerHTML = '';
                    data.files.forEach(file => {{
                        const row = tbody.insertRow();
                        const sizeKB = (file.size / 1024).toFixed(2);
                        row.innerHTML = `
                            <td>${{file.filename}}</td>
                            <td>${{sizeKB}} KB</td>
                            <td>${{file.modified}}</td>
                            <td>
                                <button onclick="viewFile('${{file.filename}}')">View</button>
                                <button class="download" onclick="downloadFile('${{file.filename}}')">Download</button>
                                <button class="danger" onclick="deleteFile('${{file.filename}}')">Delete</button>
                            </td>
                        `;
                    }});
                }})
                .catch(error => console.error('Error:', error));
            }}
            function viewFile(filename) {{
                fetch('/view?filename=' + filename)
                .then(response => response.json())
                .then(data => {{
                    const previewDiv = document.getElementById('filePreview');
                    const contentDiv = document.getElementById('jsonPreview');
                    contentDiv.textContent = JSON.stringify(data.content, null, 2);
                    previewDiv.style.display = 'block';
                }})
                .catch(error => alert('Error: ' + error));
            }}
            function downloadFile(filename) {{
                window.location.href = '/download?filename=' + filename;
            }}
            function deleteFile(filename) {{
                if(confirm('Are you sure you want to delete this file?')) {{
                    fetch('/delete?filename=' + filename, {{method: 'DELETE'}})
                    .then(response => response.json())
                    .then(data => {{
                        alert('File deleted!');
                        loadFiles();
                    }})
                    .catch(error => alert('Error: ' + error));
                }}
            }}
            function populateSearchFiles() {{
                fetch('/list')
                .then(response => response.json())
                .then(data => {{
