import os
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
app = Flask(__name__)
UPLOAD_DIR = "uploads"
ALLOWED_EXTENSIONS = {"txt", "pdf", "png", "jpg", "jpeg", "gif"}
os.makedirs(UPLOAD_DIR, exist_ok=True)
def allowed_file(filename):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in ALLOWED_EXTENSIONS
@app.route("/upload", methods=["POST"])
def handle_upload():
    if "file" not in request.files:
        return jsonify({"error": "No file part"}), 400
    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "No selected file"}), 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        save_path = os.path.join(UPLOAD_DIR, filename)
        file.save(save_path)
        return jsonify({"message": "File uploaded", "path": save_path}), 201
    return jsonify({"error": "File type not allowed"}), 400
if __name__ == "__main__":
    app.run(debug=True)

from fastapi import FastAPI, UploadFile, File, Query
from fastapi.responses import HTMLResponse, FileResponse
from pydantic import BaseModel
from typing import List, Optional
from datetime import datetime
import os
import shutil
import mimetypes

app = FastAPI()

UPLOAD_DIR = "uploads"
MAX_FILE_SIZE = 100 * 1024 * 1024

if not os.path.exists(UPLOAD_DIR):
    os.makedirs(UPLOAD_DIR)

class FileInfo(BaseModel):
    filename: str
    file_size: int
    file_type: str
    upload_date: str
    file_path: str

class UploadStats(BaseModel):
    total_files: int
    total_size: float
    file_types: dict

ALLOWED_EXTENSIONS = {'.txt', '.pdf', '.doc', '.docx', '.xls', '.xlsx', '.csv', '.json', '.png', '.jpg', '.jpeg', '.gif', '.zip', '.rar', '.py', '.js', '.html', '.css'}

def get_file_size_mb(bytes_size: int) -> float:
    return bytes_size / (1024 * 1024)

def is_file_allowed(filename: str) -> bool:
    _, ext = os.path.splitext(filename)
    return ext.lower() in ALLOWED_EXTENSIONS

def list_uploaded_files() -> List[FileInfo]:
    files = []
    if os.path.exists(UPLOAD_DIR):
        for filename in os.listdir(UPLOAD_DIR):
            file_path = os.path.join(UPLOAD_DIR, filename)
            if os.path.isfile(file_path):
                file_size = os.path.getsize(file_path)
                upload_date = datetime.fromtimestamp(os.path.getctime(file_path)).isoformat()
                file_type = mimetypes.guess_type(file_path)[0] or 'unknown'
                files.append(FileInfo(
                    filename=filename,
                    file_size=file_size,
                    file_type=file_type,
                    upload_date=upload_date,
                    file_path=file_path
                ))
    return sorted(files, key=lambda x: x.upload_date, reverse=True)

def get_upload_statistics() -> UploadStats:
    files = list_uploaded_files()
    total_size = sum(f.file_size for f in files)
    file_types = {}
    for file in files:
        ext = os.path.splitext(file.filename)[1]
        file_types[ext] = file_types.get(ext, 0) + 1
    return UploadStats(
        total_files=len(files),
        total_size=get_file_size_mb(total_size),
        file_types=file_types
    )

def delete_file(filename: str) -> bool:
    file_path = os.path.join(UPLOAD_DIR, filename)
    if os.path.exists(file_path) and os.path.isfile(file_path):
        os.remove(file_path)
        return True
    return False

def rename_file(old_filename: str, new_filename: str) -> bool:
    old_path = os.path.join(UPLOAD_DIR, old_filename)
    new_path = os.path.join(UPLOAD_DIR, new_filename)
    if os.path.exists(old_path):
        os.rename(old_path, new_path)
        return True
    return False

def search_files(keyword: str) -> List[FileInfo]:
    files = list_uploaded_files()
    keyword_lower = keyword.lower()
    return [f for f in files if keyword_lower in f.filename.lower()]

def get_file_by_type(file_type: str) -> List[FileInfo]:
    files = list_uploaded_files()
    return [f for f in files if file_type.lower() in f.file_type.lower()]

@app.get("/", response_class=HTMLResponse)
def get_home():
    files = list_uploaded_files()
    stats = get_upload_statistics()
    files_html = ""
    for file in files:
        size_mb = get_file_size_mb(file.file_size)
        files_html += f"""
        <tr>
            <td>{file.filename}</td>
            <td>{size_mb:.2f} MB</td>
            <td>{file.file_type}</td>
            <td>{file.upload_date}</td>
            <td>
                <button onclick="downloadFile('{file.filename}')">Download</button>
                <button onclick="renameFile('{file.filename}')">Rename</button>
                <button onclick="deleteFile('{file.filename}')">Delete</button>
            </td>
        </tr>
        """
    total_size_mb = stats.total_size
    return f"""
