            function handleFileSelect(e) {{
                const files = e.target.files;
                if(files.length === 0) {{
                    alert('Please select files');
                    return;
                }}
                const totalSize = Array.from(files).reduce((sum, f) => sum + f.size, 0);
                if(totalSize > 100 * 1024 * 1024) {{
                    alert('Total file size exceeds 100 MB limit');
                    return;
                }}
                uploadFiles(files);
            }}
            function uploadFiles(files) {{
                const progressContainer = document.getElementById('progressContainer');
                const progressBar = document.getElementById('progressBar');
                const uploadStatus = document.getElementById('uploadStatus');
                progressContainer.style.display = 'block';
                let uploadedCount = 0;
                Array.from(files).forEach((file, index) => {{
                    const formData = new FormData();
                    formData.append('file', file);
                    fetch('/upload', {{
                        method: 'POST',
                        body: formData
                    }})
                    .then(response => response.json())
                    .then(data => {{
                        uploadedCount++;
                        const progress = (uploadedCount / files.length) * 100;
                        progressBar.style.width = progress + '%';
                        uploadStatus.textContent = `Uploading: ${{uploadedCount}}/${{files.length}} files`;
                        if(uploadedCount === files.length) {{
                            setTimeout(() => {{
                                alert('All files uploaded successfully!');
                                progressContainer.style.display = 'none';
                                progressBar.style.width = '0%';
                                document.getElementById('fileInput').value = '';
                                location.reload();
                            }}, 1000);
                        }}
                    }})
                    .catch(error => alert('Error uploading file: ' + file.name));
                }});
            }}
            function downloadFile(filename) {{
                window.location.href = '/download?filename=' + encodeURIComponent(filename);
            }}
            function renameFile(filename) {{
                const newName = prompt('Enter new filename:', filename);
                if(newName && newName !== filename) {{
                    fetch('/rename?old=' + encodeURIComponent(filename) + '&new=' + encodeURIComponent(newName), {{
                        method: 'PUT'
                    }})
                    .then(response => response.json())
                    .then(data => {{
                        alert('File renamed successfully!');
                        location.reload();
                    }})
                    .catch(error => alert('Error: ' + error));
                }}
            }}
            function deleteFile(filename) {{
                if(confirm('Are you sure you want to delete this file?')) {{
                    fetch('/delete?filename=' + encodeURIComponent(filename), {{method: 'DELETE'}})
                    .then(response => response.json())
                    .then(data => {{
                        alert('File deleted!');
                        location.reload();
                    }})
                    .catch(error => alert('Error: ' + error));
                }}
            }}
            function searchFiles() {{
                const keyword = document.getElementById('searchKeyword').value;
                if(!keyword) {{
                    alert('Please enter a search term');
                    return;
                }}
                fetch('/search?keyword=' + encodeURIComponent(keyword))
                .then(response => response.json())
                .then(data => displaySearchResults(data.results))
                .catch(error => alert('Error: ' + error));
            }}
            function displaySearchResults(results) {{
                const resultsDiv = document.getElementById('searchResults');
                if(results.length === 0) {{
                    resultsDiv.innerHTML = '<p>No files found</p>';
                    return;
                }}
                let html = '<table><tr><th>Filename</th><th>Size</th><th>Type</th><th>Actions</th></tr>';
                results.forEach(file => {{
                    const sizeMB = (file.file_size / (1024 * 1024)).toFixed(2);
                    html += '<tr>';
                    html += '<td>' + file.filename + '</td>';
                    html += '<td>' + sizeMB + ' MB</td>';
                    html += '<td>' + file.file_type + '</td>';
                    html += '<td>';
                    html += '<button onclick="downloadFile(\'' + file.filename + '\')">Download</button>';
                    html += '<button class="danger" onclick="deleteFile(\'' + file.filename + '\')">Delete</button>';
                    html += '</td>';
                    html += '</tr>';
                }});
                html += '</table>';
                resultsDiv.innerHTML = html;
            }}
            function clearSearch() {{
                document.getElementById('searchKeyword').value = '';
                document.getElementById('searchResults').innerHTML = '';
            }}
        </script>
    </body>
    </html>
    """

@app.post("/upload")
async def upload_file(file: UploadFile = File(...)):
    if not is_file_allowed(file.filename):
        return {"status": "error", "message": "File type not allowed"}
    file_size = len(await file.read())
    await file.seek(0)
    if file_size > MAX_FILE_SIZE:
        return {"status": "error", "message": "File size exceeds limit"}
    file_path = os.path.join(UPLOAD_DIR, file.filename)
    with open(file_path, "wb") as f:
        f.write(await file.read())
    return {"status": "success", "filename": file.filename, "size": file_size}

@app.get("/download")
def download_file(filename: str = Query(...)):
    file_path = os.path.join(UPLOAD_DIR, filename)
    if not os.path.exists(file_path):
        return {"error": "File not found"}
    return FileResponse(file_path, filename=filename)

@app.delete("/delete")
def delete_uploaded_file(filename: str = Query(...)):
    if delete_file(filename):
        return {"status": "success", "message": "File deleted"}
    return {"status": "error", "message": "File not found"}

@app.put("/rename")
def rename_uploaded_file(old: str = Query(...), new: str = Query(...)):
    if rename_file(old, new):
        return {"status": "success", "message": "File renamed"}
    return {"status": "error", "message": "File not found"}

@app.get("/search")
def search_uploaded_files(keyword: str = Query(...)):
    results = search_files(keyword)
    return {"keyword": keyword, "results": [f.dict() for f in results]}

@app.get("/list")
def list_files():
    files = list_uploaded_files()
    return {"files": [f.dict() for f in files]}

@app.get("/stats")
def get_stats():
    stats = get_upload_statistics()
    return stats.dict()

