app = FastAPI()

BACKUP_DIR = "backups"
SOURCE_DIR = "data"
MAX_BACKUPS = 10

if not os.path.exists(BACKUP_DIR):
    os.makedirs(BACKUP_DIR)

if not os.path.exists(SOURCE_DIR):
    os.makedirs(SOURCE_DIR)

class BackupInfo(BaseModel):
    backup_name: str
    backup_path: str
    backup_size: float
    backup_date: str
    file_count: int
    compression_ratio: Optional[float] = None

class BackupSchedule(BaseModel):
    interval: str
    last_backup: Optional[str] = None
    next_backup: Optional[str] = None
    is_active: bool

def get_directory_size(path: str) -> int:
    total_size = 0
    try:
        for dirpath, dirnames, filenames in os.walk(path):
            for filename in filenames:
                file_path = os.path.join(dirpath, filename)
                if os.path.exists(file_path):
                    total_size += os.path.getsize(file_path)
    except Exception:
        pass
    return total_size

def count_files_in_directory(path: str) -> int:
    count = 0
    try:
        for dirpath, dirnames, filenames in os.walk(path):
            count += len(filenames)
    except Exception:
        pass
    return count

def create_backup(backup_name: Optional[str] = None) -> BackupInfo:
    if not backup_name:
        backup_name = f"backup_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
    backup_path = os.path.join(BACKUP_DIR, f"{backup_name}.zip")
    original_size = get_directory_size(SOURCE_DIR)
    file_count = count_files_in_directory(SOURCE_DIR)
    with zipfile.ZipFile(backup_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for dirpath, dirnames, filenames in os.walk(SOURCE_DIR):
            for filename in filenames:
                file_path = os.path.join(dirpath, filename)
                arcname = os.path.relpath(file_path, SOURCE_DIR)
                zipf.write(file_path, arcname)
    backup_size = os.path.getsize(backup_path)
    compression_ratio = (1 - backup_size / original_size) * 100 if original_size > 0 else 0
    backup_info = BackupInfo(
        backup_name=backup_name,
        backup_path=backup_path,
        backup_size=backup_size / (1024 * 1024),
        backup_date=datetime.now().isoformat(),
        file_count=file_count,
        compression_ratio=compression_ratio
    )
    cleanup_old_backups()
    return backup_info

def list_backups() -> List[BackupInfo]:
    backups = []
    if os.path.exists(BACKUP_DIR):
        for filename in os.listdir(BACKUP_DIR):
            if filename.endswith('.zip'):
                file_path = os.path.join(BACKUP_DIR, filename)
                file_size = os.path.getsize(file_path)
                modified_time = datetime.fromtimestamp(os.path.getmtime(file_path)).isoformat()
                backup_name = filename.replace('.zip', '')
                backups.append(BackupInfo(
                    backup_name=backup_name,
                    backup_path=file_path,
                    backup_size=file_size / (1024 * 1024),
                    backup_date=modified_time,
                    file_count=0
                ))
    return sorted(backups, key=lambda x: x.backup_date, reverse=True)

def restore_backup(backup_name: str) -> bool:
    backup_path = os.path.join(BACKUP_DIR, f"{backup_name}.zip")
    if not os.path.exists(backup_path):
        return False
    if os.path.exists(SOURCE_DIR):
        shutil.rmtree(SOURCE_DIR)
    os.makedirs(SOURCE_DIR)
    with zipfile.ZipFile(backup_path, 'r') as zipf:
        zipf.extractall(SOURCE_DIR)
    return True

def delete_backup(backup_name: str) -> bool:
    backup_path = os.path.join(BACKUP_DIR, f"{backup_name}.zip")
    if os.path.exists(backup_path):
        os.remove(backup_path)
        return True
    return False

def cleanup_old_backups():
    backups = list_backups()
    if len(backups) > MAX_BACKUPS:
        for backup in backups[MAX_BACKUPS:]:
            delete_backup(backup.backup_name)

def get_backup_statistics() -> Dict:
    backups = list_backups()
    total_size = sum(b.backup_size for b in backups)
    source_size = get_directory_size(SOURCE_DIR) / (1024 * 1024)
    return {
        "total_backups": len(backups),
        "total_backup_size_mb": total_size,
        "source_size_mb": source_size,
        "max_backups": MAX_BACKUPS,
        "oldest_backup": backups[-1].backup_date if backups else None,
        "latest_backup": backups[0].backup_date if backups else None
    }

def schedule_backup_job(interval: str):
    if interval == "daily":
        schedule.every().day.at("02:00").do(create_backup)
    elif interval == "weekly":
        schedule.every().monday.at("02:00").do(create_backup)
    elif interval == "monthly":
        schedule.every().month.do(create_backup)

def run_scheduler():
    while True:
        schedule.run_pending()
        time.sleep(60)

backup_thread = threading.Thread(target=run_scheduler, daemon=True)
backup_thread.start()

