import os
import json
import configparser
import argparse
from pathlib import Path
from datetime import datetime
try:
    import yaml
    YAML_AVAILABLE = True
except ImportError:
    YAML_AVAILABLE = False
try:
    import toml
    TOML_AVAILABLE = True
except ImportError:
    TOML_AVAILABLE = False
SUPPORTED_FORMATS = ['.ini', '.cfg', '.json', '.yaml', '.yml', '.toml', '.env']
config_read_logs = []
def log_read(file_path, status, details):
    entry = {
        "id": len(config_read_logs) + 1,
        "file": file_path,
        "status": status,
        "details": details,
        "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    }
    config_read_logs.append(entry)
    return entry
def format_size(size_bytes):
    if size_bytes < 1024:
        return f"{size_bytes} B"
    elif size_bytes < 1024 ** 2:
        return f"{size_bytes / 1024:.2f} KB"
    else:
        return f"{size_bytes / (1024 ** 2):.2f} MB"
def read_ini_config(file_path):
    config = configparser.ConfigParser()
    config.read(file_path)
    result = {}
    for section in config.sections():
        result[section] = dict(config.items(section))
    if config.defaults():
        result['DEFAULT'] = dict(config.defaults())
    return result
def read_json_config(file_path):
    with open(file_path, 'r', encoding='utf-8') as f:
        return json.load(f)
def read_yaml_config(file_path):
    if not YAML_AVAILABLE:
        raise ImportError("PyYAML is not installed. Run: pip install pyyaml")
    with open(file_path, 'r', encoding='utf-8') as f:
        return yaml.safe_load(f)
def read_toml_config(file_path):
    if not TOML_AVAILABLE:
        raise ImportError("toml is not installed. Run: pip install toml")
    with open(file_path, 'r', encoding='utf-8') as f:
        return toml.load(f)
def read_env_config(file_path):
    result = {}
    with open(file_path, 'r', encoding='utf-8') as f:
        for line_num, line in enumerate(f, start=1):
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            if '=' in line:
                key, _, value = line.partition('=')
                key = key.strip()
                value = value.strip().strip('"').strip("'")
                result[key] = value
    return result
def read_config(file_path):
    path = Path(file_path)
    if not path.exists():
        return None, f"File not found: '{file_path}'"
    if not path.is_file():
        return None, f"'{file_path}' is not a valid file"
    ext = path.suffix.lower()
    if ext not in SUPPORTED_FORMATS:
        return None, f"Unsupported format '{ext}'. Supported: {', '.join(SUPPORTED_FORMATS)}"
    file_size = os.path.getsize(file_path)
    try:
        if ext in ['.ini', '.cfg']:
            data = read_ini_config(file_path)
        elif ext == '.json':
            data = read_json_config(file_path)
        elif ext in ['.yaml', '.yml']:
            data = read_yaml_config(file_path)
        elif ext == '.toml':
            data = read_toml_config(file_path)
        elif ext == '.env':
            data = read_env_config(file_path)
        else:
            return None, f"No reader implemented for '{ext}'"
        details = {
            "format": ext,
            "size": format_size(file_size),
            "keys_found": len(data) if isinstance(data, dict) else "N/A"
        }
        log_read(file_path, "success", details)
        return data, None
    except json.JSONDecodeError as e:
        error = f"JSON parse error: {str(e)}"
        log_read(file_path, "failed", {"error": error})
        return None, error
    except Exception as e:
        error = str(e)
        log_read(file_path, "failed", {"error": error})
        return None, error
def display_config(data, file_path, indent=0):
    path = Path(file_path)
    print("\n" + "=" * 65)
    print(f"  CONFIG FILE READER")
    print(f"  File      : {path.name}")
    print(f"  Full Path : {path.resolve()}")
    print(f"  Format    : {path.suffix.upper()}")
    print(f"  Size      : {format_size(os.path.getsize(file_path))}")
    print(f"  Read At   : {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 65)
    def print_nested(obj, level=0):
        prefix = "  " + "  " * level
        if isinstance(obj, dict):
            for key, value in obj.items():
                if isinstance(value, (dict, list)):
                    print(f"{prefix}{key}:")
                    print_nested(value, level + 1)
                else:
                    print(f"{prefix}{key:<30}: {value}")
        elif isinstance(obj, list):
            for idx, item in enumerate(obj):
                if isinstance(item, (dict, list)):
                    print(f"{prefix}[{idx}]:")
                    print_nested(item, level + 1)
                else:
                    print(f"{prefix}[{idx}]: {item}")
        else:
            print(f"{prefix}{obj}")
    print("\n  CONFIG DATA:")
    print("  " + "-" * 63)
    print_nested(data)
    print("=" * 65)
def display_summary(data):
    if not isinstance(data, dict):
        print(f"\n  Total Items: {len(data) if isinstance(data, list) else 1}")
        return
    print("\n  SUMMARY:")
    print("  " + "-" * 40)
    total_keys = 0
    for key, value in data.items():
        if isinstance(value, dict):
            count = len(value)
            total_keys += count
            print(f"  [{key}] -> {count} key(s)")
        else:
            total_keys += 1
            print(f"  {key} -> {type(value).__name__}")
    print(f"\n  Total Top-Level Sections/Keys: {len(data)}")
    print(f"  Total Keys (including nested): {total_keys}")
def create_sample_configs():
    sample_ini = "[database]\nhost = localhost\nport = 5432\nname = mydb\nuser = admin\npassword = secret\n\n[server]\nhost = 0.0.0.0\nport = 8080\ndebug = true\nworkers = 4\n\n[logging]\nlevel = INFO\nfile = app.log\nmax_size = 10MB\n"
    sample_json = '{\n  "app": {\n    "name": "MyApp",\n    "version": "1.0.0",\n    "debug": false\n  },\n  "database": {\n    "host": "localhost",\n    "port": 5432,\n    "name": "mydb"\n  },\n  "features": ["auth", "logging", "cache"]\n}'
    sample_env = "# Application Settings\nAPP_NAME=MyApplication\nAPP_ENV=development\nAPP_PORT=8080\nAPP_DEBUG=true\n\n# Database\nDB_HOST=localhost\nDB_PORT=5432\nDB_NAME=mydb\nDB_USER=admin\nDB_PASSWORD=secret\n\n# API Keys\nAPI_KEY=abc123xyz\nSECRET_KEY=supersecretkey\n"
    configs = {
        "sample_config.ini": sample_ini,
        "sample_config.json": sample_json,
        "sample_config.env": sample_env
    }
    created = []
    for filename, content in configs.items():
        if not os.path.exists(filename):
            with open(filename, 'w') as f:
                f.write(content)
            created.append(filename)
    return created
def parse_args():
    parser = argparse.ArgumentParser(description="Config File Reader Tool")
    parser.add_argument('file', nargs='?', help='Path to config file to read')
    parser.add_argument('--summary', action='store_true', help='Show summary of config keys')
    parser.add_argument('--create-samples', action='store_true', help='Create sample config files')
    parser.add_argument('--logs', action='store_true', help='Show read logs after processing')
    parser.add_argument('--all', action='store_true', help='Read all sample config files')
    return parser.parse_args()
def display_logs():
    if not config_read_logs:
        print("\n  No read logs available.")
        return
    print("\n" + "=" * 75)
    print("  CONFIG READ LOGS")
    print("=" * 75)
    print(f"  {'ID':<5} {'File':<30} {'Status':<10} {'Timestamp':<22} {'Details'}")
    print("  " + "-" * 73)
    for log in config_read_logs:
        details_str = ', '.join([f"{k}: {v}" for k, v in log['details'].items()])
        print(f"  {log['id']:<5} {log['file']:<30} {log['status']:<10} {log['timestamp']:<22} {details_str}")
    print("=" * 75)
if __name__ == '__main__':
    args = parse_args()
    if args.create_samples:
        created = create_sample_configs()
        if created:
            print(f"\n  Sample config files created: {', '.join(created)}")
        else:
            print("\n  Sample config files already exist.")
    if args.all:
        sample_files = ['sample_config.ini', 'sample_config.json', 'sample_config.env']
        for sample_file in sample_files:
            if os.path.exists(sample_file):
                data, error = read_config(sample_file)
                if error:
                    print(f"\n  Error reading '{sample_file}': {error}")
                else:
                    display_config(data, sample_file)
                    if args.summary:
                        display_summary(data)
    elif args.file:
        data, error = read_config(args.file)
        if error:
            print(f"\n  Error: {error}")
        else:
            display_config(data, args.file)
            if args.summary:
                display_summary(data)
    else:
        print("\n  No file specified. Use --help for usage.")
        print(f"  Supported formats: {', '.join(SUPPORTED_FORMATS)}")
        print("  Tip: Use --create-samples to generate sample config files.")
    if args.logs:
        display_logs()

import configparser
import os
def read_config(file_path):
    if not os.path.exists(file_path):
        print(f"Error: {file_path} not found.")
        return None
    config = configparser.ConfigParser()
    try:
        config.read(file_path)
        config_data = {section: dict(config.items(section)) for section in config.sections()}
        for section, values in config_data.items():
            print(f"[{section}]")
            for key, value in values.items():
                print(f"{key} = {value}")
        return config_data
    except Exception as e:
        print(f"Error parsing config: {e}")
        return None
if __name__ == "__main__":
    path = input("Enter config file path (e.g., settings.ini): ")
    read_config(path)

from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse, FileResponse
from pydantic import BaseModel
from typing import List, Optional, Dict, Any
from datetime import datetime
import os
import json
import configparser
import yaml

app = FastAPI()

CONFIG_DIR = "configs"

if not os.path.exists(CONFIG_DIR):
    os.makedirs(CONFIG_DIR)

class ConfigFile(BaseModel):
    filename: str
    file_type: str
    file_size: int
    modified_date: str
    content: Dict[str, Any]

class ConfigValue(BaseModel):
    section: Optional[str] = None
    key: str
    value: Any

def read_json_config(file_path: str) -> Optional[Dict[str, Any]]:
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            return json.load(f)
    except Exception:
        return None

def read_yaml_config(file_path: str) -> Optional[Dict[str, Any]]:
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            return yaml.safe_load(f)
    except Exception:
        return None

def read_ini_config(file_path: str) -> Optional[Dict[str, Any]]:
    try:
        config = configparser.ConfigParser()
        config.read(file_path)
        result = {}
        for section in config.sections():
            result[section] = dict(config.items(section))
        return result
    except Exception:
        return None

def read_txt_config(file_path: str) -> Optional[Dict[str, str]]:
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            lines = f.readlines()
        config = {}
        for line in lines:
            line = line.strip()
            if line and not line.startswith('#') and '=' in line:
                key, value = line.split('=', 1)
                config[key.strip()] = value.strip()
        return config
    except Exception:
        return None

def read_config_file(filename: str) -> Optional[ConfigFile]:
    file_path = os.path.join(CONFIG_DIR, filename)
    if not os.path.exists(file_path):
        return None
    file_size = os.path.getsize(file_path)
    modified_date = datetime.fromtimestamp(os.path.getmtime(file_path)).isoformat()
    _, ext = os.path.splitext(filename)
    ext = ext.lower()
    if ext == '.json':
        content = read_json_config(file_path)
        file_type = 'JSON'
    elif ext in ['.yaml', '.yml']:
        content = read_yaml_config(file_path)
        file_type = 'YAML'
    elif ext == '.ini':
        content = read_ini_config(file_path)
        file_type = 'INI'
    elif ext == '.conf' or ext == '.txt':
        content = read_txt_config(file_path)
        file_type = 'TEXT'
    else:
        return None
    if content is None:
        return None
    return ConfigFile(
        filename=filename,
        file_type=file_type,
        file_size=file_size,
        modified_date=modified_date,
        content=content
    )

def list_config_files() -> List[ConfigFile]:
    configs = []
    if os.path.exists(CONFIG_DIR):
        for filename in os.listdir(CONFIG_DIR):
            config = read_config_file(filename)
            if config:
                configs.append(config)
    return sorted(configs, key=lambda x: x.modified_date, reverse=True)

def get_config_value(filename: str, section: Optional[str], key: str) -> Optional[Any]:
    config = read_config_file(filename)
    if not config:
        return None
    if section:
        if section in config.content:
            return config.content[section].get(key)
    else:
        return config.content.get(key)
    return None

def set_config_value(filename: str, section: Optional[str], key: str, value: Any) -> bool:
    file_path = os.path.join(CONFIG_DIR, filename)
    if not os.path.exists(file_path):
        return False
    _, ext = os.path.splitext(filename)
    ext = ext.lower()
    try:
        if ext == '.json':
            with open(file_path, 'r', encoding='utf-8') as f:
                content = json.load(f)
            if section:
                if section not in content:
                    content[section] = {}
                content[section][key] = value
            else:
                content[key] = value
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(content, f, indent=2)
        elif ext in ['.yaml', '.yml']:
            with open(file_path, 'r', encoding='utf-8') as f:
                content = yaml.safe_load(f) or {}
            if section:
                if section not in content:
                    content[section] = {}
                content[section][key] = value
            else:
                content[key] = value
            with open(file_path, 'w', encoding='utf-8') as f:
                yaml.dump(content, f, default_flow_style=False)
        elif ext == '.ini':
            config = configparser.ConfigParser()
            config.read(file_path)
            if section:
                if not config.has_section(section):
                    config.add_section(section)
                config.set(section, key, str(value))
            with open(file_path, 'w', encoding='utf-8') as f:
                config.write(f)
        else:
            return False
        return True
    except Exception:
        return False

def create_sample_configs():
    json_sample = {
        "app": {
            "name": "My Application",
            "version": "1.0.0",
            "debug": True
        },
        "database": {
            "host": "localhost",
            "port": 5432,
            "name": "mydb"
        }
    }
    json_path = os.path.join(CONFIG_DIR, "config.json")
    if not os.path.exists(json_path):
        with open(json_path, 'w') as f:
            json.dump(json_sample, f, indent=2)
    yaml_sample = """
app:
  name: My Application
  version: 1.0.0
  debug: true
database:
  host: localhost
  port: 5432
  name: mydb
"""
    yaml_path = os.path.join(CONFIG_DIR, "config.yaml")
    if not os.path.exists(yaml_path):
        with open(yaml_path, 'w') as f:
            f.write(yaml_sample)
    ini_sample = """[app]
name = My Application
version = 1.0.0
debug = true

[database]
host = localhost
port = 5432
name = mydb
"""
    ini_path = os.path.join(CONFIG_DIR, "config.ini")
    if not os.path.exists(ini_path):
        with open(ini_path, 'w') as f:
            f.write(ini_sample)

create_sample_configs()

