        <script>
            function switchTab(tabName) {{
                const tabs = document.querySelectorAll('.tab-content');
                tabs.forEach(tab => tab.classList.remove('active'));
                document.getElementById(tabName).classList.add('active');
                const buttons = document.querySelectorAll('.tab-button');
                buttons.forEach(btn => btn.classList.remove('active'));
                event.target.classList.add('active');
                if(tabName === 'search-tab') {{
                    populateConfigFiles();
                }}
            }}
            function viewConfig(filename) {{
                fetch('/config/view?filename=' + encodeURIComponent(filename))
                .then(response => response.json())
                .then(data => {{
                    const previewDiv = document.getElementById('configPreview');
                    const contentDiv = document.getElementById('previewContent');
                    contentDiv.innerHTML = '<pre>' + JSON.stringify(data.content, null, 2) + '</pre>';
                    previewDiv.style.display = 'block';
                }})
                .catch(error => alert('Error: ' + error));
            }}
            function editConfig(filename) {{
                document.getElementById('editFilename').value = filename;
                document.getElementById('editModal').classList.add('show');
            }}
            function closeEditModal() {{
                document.getElementById('editModal').classList.remove('show');
                document.getElementById('editSection').value = '';
                document.getElementById('editKey').value = '';
                document.getElementById('editValue').value = '';
            }}
            function saveConfigValue() {{
                const filename = document.getElementById('editFilename').value;
                const section = document.getElementById('editSection').value || null;
                const key = document.getElementById('editKey').value;
                const value = document.getElementById('editValue').value;
                if(!key || !value) {{
                    alert('Please enter key and value');
                    return;
                }}
                fetch('/config/set', {{
                    method: 'POST',
                    headers: {{'Content-Type': 'application/json'}},
                    body: JSON.stringify({{filename: filename, section: section, key: key, value: value}})
                }})
                .then(response => response.json())
                .then(data => {{
                    alert('Configuration updated!');
                    closeEditModal();
                    location.reload();
                }})
                .catch(error => alert('Error: ' + error));
            }}
            function downloadConfig(filename) {{
                window.location.href = '/config/download?filename=' + encodeURIComponent(filename);
            }}
            function populateConfigFiles() {{
                fetch('/config/list')
                .then(response => response.json())
                .then(data => {{
                    const select = document.getElementById('searchConfigFile');
                    select.innerHTML = '<option value="">Choose a config file...</option>';
                    data.configs.forEach(config => {{
                        const option = document.createElement('option');
                        option.value = config.filename;
                        option.textContent = config.filename + ' (' + config.file_type + ')';
                        select.appendChild(option);
                    }});
                }})
                .catch(error => console.error('Error:', error));
            }}
            function searchConfigValue() {{
                const filename = document.getElementById('searchConfigFile').value;
                const key = document.getElementById('searchKey').value;
                if(!filename || !key) {{
                    alert('Please select file and enter key');
                    return;
                }}
                fetch('/config/search?filename=' + encodeURIComponent(filename) + '&key=' + encodeURIComponent(key))
                .then(response => response.json())
                .then(data => {{
                    const resultsDiv = document.getElementById('searchResults');
                    if(data.found) {{
                        resultsDiv.innerHTML = '<div style="background-color: #d4edda; padding: 15px; border-radius: 5px;"><strong>Found:</strong><pre>' + JSON.stringify(data.value, null, 2) + '</pre></div>';
                    }} else {{
                        resultsDiv.innerHTML = '<div style="background-color: #f8d7da; padding: 15px; border-radius: 5px;"><strong>Not found:</strong> Key "' + key + '" not found in configuration</div>';
                    }}
                }})
                .catch(error => alert('Error: ' + error));
            }}
        </script>
    </body>
    </html>
    """

@app.get("/config/view")
def view_config(filename: str = Query(...)):
    config = read_config_file(filename)
    if not config:
        return {"error": "Config file not found"}
    return {
        "filename": config.filename,
        "file_type": config.file_type,
        "content": config.content
    }

@app.get("/config/list")
def list_configs():
    configs = list_config_files()
    return {"configs": [c.dict() for c in configs], "count": len(configs)}

@app.get("/config/download")
def download_config(filename: str = Query(...)):
    file_path = os.path.join(CONFIG_DIR, filename)
    if not os.path.exists(file_path):
        return {"error": "Config file not found"}
    return FileResponse(file_path, filename=filename)

@app.get("/config/search")
def search_config(filename: str = Query(...), key: str = Query(...)):
    config = read_config_file(filename)
    if not config:
        return {"found": False, "error": "Config file not found"}
    value = None
    if key in config.content:
        value = config.content[key]
    else:
        for section_key, section_value in config.content.items():
            if isinstance(section_value, dict) and key in section_value:
                value = section_value[key]
                break
    if value is not None:
        return {"found": True, "value": value}
    return {"found": False, "message": f"Key '{key}' not found"}

@app.post("/config/set")
def set_config(request: dict):
    filename = request.get('filename')
    section = request.get('section')
    key = request.get('key')
    value = request.get('value')
    if set_config_value(filename, section, key, value):
        return {"status": "success", "message": "Configuration updated"}
    return {"status": "error", "message": "Failed to update configuration"}

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

import subprocess
import shlex
import platform
import os
import json
import argparse
from datetime import datetime
from pathlib import Path
BLOCKED_COMMANDS = [
    "rm -rf /", "rm -rf /*", "mkfs", "dd if=/dev/zero",
    ":(){:|:&};:", "chmod -R 777 /", "chown -R /",
    "shutdown", "reboot", "halt", "poweroff",
    "format c:", "del /f /s /q", "rd /s /q c:\\"
]
ALLOWED_COMMANDS = [
    "ls", "dir", "pwd", "cd", "echo", "cat", "head", "tail",
    "grep", "find", "wc", "sort", "uniq", "cut", "awk", "sed",
    "ps", "top", "df", "du", "uname", "whoami", "date", "uptime",
    "ping", "ifconfig", "ipconfig", "netstat", "curl", "wget",
    "python", "python3", "pip", "node", "npm", "git", "make"
]
command_history = []
command_aliases = {
    "ll": "ls -la",
    "la": "ls -a",
    "home": "cd ~",
    "cls": "clear",
    "ports": "netstat -tuln",
    "myip": "curl ifconfig.me",
    "sysinfo": "uname -a",
    "diskusage": "df -h",
    "meminfo": "free -h",
    "procs": "ps aux"
}
def is_blocked(command):
    cmd_lower = command.lower().strip()
    for blocked in BLOCKED_COMMANDS:
        if blocked.lower() in cmd_lower:
            return True, blocked
    return False, None
def is_allowed(command):
    cmd_base = command.strip().split()[0].lower() if command.strip() else ''
    cmd_base = os.path.basename(cmd_base)
    return cmd_base in ALLOWED_COMMANDS
def resolve_alias(command):
    cmd_parts = command.strip().split()
    if cmd_parts and cmd_parts[0].lower() in command_aliases:
        alias_cmd = command_aliases[cmd_parts[0].lower()]
        remaining = ' '.join(cmd_parts[1:])
        return f"{alias_cmd} {remaining}".strip()
    return command
def execute_command(command, timeout=30, safe_mode=True):
    if not command.strip():
        return {"success": False, "error": "Empty command provided", "command": command}
    command = resolve_alias(command)
    blocked, blocked_cmd = is_blocked(command)
    if blocked:
        return {
            "success": False,
            "command": command,
            "error": f"Blocked command detected: '{blocked_cmd}'",
            "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
    if safe_mode and not is_allowed(command):
        return {
            "success": False,
            "command": command,
            "error": f"Command not in allowlist. Disable safe mode with --no-safe to run any command.",
            "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
    system = platform.system()
    try:
        if system == "Windows":
            process = subprocess.Popen(
                command,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=True,
                text=True,
                cwd=os.getcwd()
            )
        else:
            args = shlex.split(command)
            process = subprocess.Popen(
                args,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=False,
                text=True,
                cwd=os.getcwd()
            )
        stdout, stderr = process.communicate(timeout=timeout)
        result = {
            "success": process.returncode == 0,
            "command": command,
            "return_code": process.returncode,
            "stdout": stdout.strip(),
            "stderr": stderr.strip(),
            "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            "duration": None
        }
        log_command(command, result)
        return result
    except subprocess.TimeoutExpired:
        process.kill()
        result = {
            "success": False,
            "command": command,
            "return_code": -1,
            "error": f"Command timed out after {timeout} seconds",
            "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        log_command(command, result)
        return result
    except FileNotFoundError:
        result = {
            "success": False,
            "command": command,
            "return_code": -1,
            "error": f"Command not found: '{command.split()[0]}'",
            "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        log_command(command, result)
        return result
    except PermissionError:
        result = {
            "success": False,
            "command": command,
            "return_code": -1,
            "error": "Permission denied",
            "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        log_command(command, result)
        return result
    except Exception as e:
        result = {
            "success": False,
            "command": command,
            "return_code": -1,
            "error": str(e),
            "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        log_command(command, result)
        return result
def log_command(command, result):
    entry = {
        "id": len(command_history) + 1,
        "command": command,
        "success": result.get("success"),
        "return_code": result.get("return_code"),
        "timestamp": result.get("timestamp")
    }
    command_history.append(entry)
def execute_batch(commands, safe_mode=True):
    results = []
    print(f"\n  Executing {len(commands)} commands in batch...")
    for idx, command in enumerate(commands, start=1):
        print(f"\n  [{idx}/{len(commands)}] Running: {command}")
        result = execute_command(command, safe_mode=safe_mode)
        results.append(result)
        display_result(result)
        if not result['success'] and result.get('return_code') != 0:
            print(f"  Warning: Command failed, continuing batch...")
    return results
def execute_pipeline(commands, safe_mode=True):
    if not commands:
        return {"success": False, "error": "No commands in pipeline"}
    print(f"\n  Executing pipeline of {len(commands)} commands...")
    combined_output = ""
    for idx, command in enumerate(commands, start=1):
        full_cmd = command
        if idx > 1 and combined_output:
            full_cmd = f"echo '{combined_output}' | {command}"
        result = execute_command(full_cmd, safe_mode=safe_mode)
        if not result['success']:
            print(f"  Pipeline failed at step {idx}: {command}")
            return result
        combined_output = result.get('stdout', '')
        print(f"  Step {idx} complete: {command}")
    return {"success": True, "output": combined_output}
def display_result(result):
    print("\n" + "=" * 65)
    print(f"  Command    : {result.get('command')}")
    print(f"  Timestamp  : {result.get('timestamp', 'N/A')}")
    print(f"  Status     : {'✓ Success' if result.get('success') else '✗ Failed'}")
    if 'return_code' in result:
        print(f"  Return Code: {result.get('return_code')}")
    if result.get('stdout'):
        print(f"\n  Output:")
        for line in result['stdout'].splitlines():
            print(f"    {line}")
    if result.get('stderr'):
        print(f"\n  Stderr:")
        for line in result['stderr'].splitlines():
            print(f"    {line}")
    if result.get('error'):
        print(f"\n  Error: {result.get('error')}")
    print("=" * 65)
def display_history():
    if not command_history:
        print("\n  No command history available.")
        return
    print("\n" + "=" * 80)
    print("  COMMAND HISTORY")
    print("=" * 80)
    print(f"  {'ID':<6} {'Command':<35} {'Status':<10} {'Code':<8} {'Timestamp'}")
    print("  " + "-" * 78)
    for entry in command_history:
        status = "Success" if entry['success'] else "Failed"
        print(f"  {entry['id']:<6} {entry['command']:<35} {status:<10} {str(entry['return_code']):<8} {entry['timestamp']}")
    print("=" * 80)
def display_aliases():
    print("\n" + "=" * 50)
    print("  COMMAND ALIASES")
    print("=" * 50)
    for alias, cmd in command_aliases.items():
        print(f"  {alias:<15} -> {cmd}")
    print("=" * 50)
def display_allowlist():
    print("\n" + "=" * 50)
    print("  ALLOWED COMMANDS (Safe Mode)")
    print("=" * 50)
    for idx, cmd in enumerate(sorted(ALLOWED_COMMANDS), start=1):
        print(f"  {idx:<4} {cmd}")
    print("=" * 50)
def save_history(file_path):
    with open(file_path, 'w') as f:
        json.dump(command_history, f, indent=4)
    print(f"\n  History saved to: {file_path}")
def load_history(file_path):
    global command_history
    if not os.path.exists(file_path):
        print(f"\n  History file not found: {file_path}")
        return
    with open(file_path, 'r') as f:
        command_history = json.load(f)
    print(f"\n  Loaded {len(command_history)} history entries from: {file_path}")
def interactive_shell(safe_mode=True):
    print("\n" + "=" * 65)
    print("  Shell Command Executor - Interactive Mode")
    print(f"  System     : {platform.system()} {platform.release()}")
    print(f"  Python     : {platform.python_version()}")
    print(f"  CWD        : {os.getcwd()}")
    print(f"  Safe Mode  : {'ON' if safe_mode else 'OFF'}")
    print("  Commands   : 'exit', 'history', 'aliases', 'allowlist', 'clear history'")
    print("=" * 65)
    while True:
        try:
            user_input = input(f"\n[{os.getcwd()}] > ").strip()
            if not user_input:
                continue
            if user_input.lower() == 'exit':
                print("\n  Exiting shell. Goodbye!")
                break
            elif user_input.lower() == 'history':
                display_history()
            elif user_input.lower() == 'aliases':
                display_aliases()
            elif user_input.lower() == 'allowlist':
                display_allowlist()
            elif user_input.lower() == 'clear history':
                command_history.clear()
                print("\n  Command history cleared.")
            elif user_input.lower().startswith('save history '):
                save_history(user_input[13:].strip())
            elif user_input.lower().startswith('cd '):
                path = user_input[3:].strip()
                try:
                    os.chdir(path)
                    print(f"\n  Changed directory to: {os.getcwd()}")
                except FileNotFoundError:
                    print(f"\n  Error: Directory '{path}' not found.")
                except PermissionError:
                    print(f"\n  Error: Permission denied for '{path}'.")
            elif user_input.lower().startswith('batch:'):
                cmds = [c.strip() for c in user_input[6:].split('&&') if c.strip()]
                execute_batch(cmds, safe_mode=safe_mode)
            else:
                result = execute_command(user_input, safe_mode=safe_mode)
                display_result(result)
        except KeyboardInterrupt:
            print("\n\n  KeyboardInterrupt. Type 'exit' to quit.")
        except EOFError:
            print("\n  EOF received. Exiting.")
            break
def parse_args():
    parser = argparse.ArgumentParser(description="Shell Command Executor")
    parser.add_argument('--command', '-c', type=str, help='Single command to execute')
    parser.add_argument('--batch', '-b', nargs='+', help='Multiple commands to execute in batch')
    parser.add_argument('--no-safe', action='store_true', help='Disable safe mode (allow all commands)')
    parser.add_argument('--history', action='store_true', help='Display command history')
    parser.add_argument('--aliases', action='store_true', help='Display command aliases')
    parser.add_argument('--allowlist', action='store_true', help='Display allowed commands')
    parser.add_argument('--save-history', type=str, metavar='FILE', help='Save history to JSON file')
    parser.add_argument('--load-history', type=str, metavar='FILE', help='Load history from JSON file')
    parser.add_argument('--timeout', type=int, default=30, help='Command timeout in seconds')
    parser.add_argument('--interactive', '-i', action='store_true', help='Launch interactive shell')
    return parser.parse_args()
if __name__ == '__main__':
    args = parse_args()
    safe_mode = not args.no_safe
    if args.load_history:
        load_history(args.load_history)
    if args.aliases:
        display_aliases()
    if args.allowlist:
        display_allowlist()
    if args.command:
        result = execute_command(args.command, timeout=args.timeout, safe_mode=safe_mode)
        display_result(result)
    elif args.batch:
        execute_batch(args.batch, safe_mode=safe_mode)
    elif args.interactive:
        interactive_shell(safe_mode=safe_mode)
    else:
        interactive_shell(safe_mode=safe_mode)
    if args.history:
        display_history()
    if args.save_history:
        save_history(args.save_history)

import subprocess
import sys
def run_command(command):
    try:
        result = subprocess.run(command, shell=True, capture_output=True, text=True, check=True)
        print("--- Output ---")
        print(result.stdout)
        if result.stderr:
            print("--- Errors ---")
            print(result.stderr)
        return result.stdout
    except subprocess.CalledProcessError as e:
        print(f"Command failed with return code {e.returncode}")
        print(f"Error output: {e.stderr}")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
if __name__ == "__main__":
    cmd = input("Enter shell command to execute: ")
    if cmd.lower() in ["exit", "quit"]:
        sys.exit()
    run_command(cmd)

from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime
import subprocess
import os
import shlex

app = FastAPI()

COMMAND_HISTORY_FILE = "command_history.txt"
MAX_HISTORY = 100
ALLOWED_COMMANDS = {
    'ls', 'cd', 'pwd', 'echo', 'cat', 'grep', 'find', 'mkdir', 'touch',
    'rm', 'cp', 'mv', 'chmod', 'chown', 'ps', 'kill', 'df', 'du', 'free',
    'top', 'uptime', 'hostname', 'whoami', 'date', 'cal', 'wc', 'sort',
    'uniq', 'tail', 'head', 'cut', 'awk', 'sed', 'tr', 'zip', 'unzip',
    'tar', 'gzip', 'gunzip', 'curl', 'wget', 'ping', 'netstat', 'ifconfig',
    'python', 'python3', 'pip', 'npm', 'git', 'docker', 'systemctl'
}

class CommandExecution(BaseModel):
    command: str
    stdout: str
    stderr: str
    return_code: int
    execution_time: float
    timestamp: str

class CommandHistory(BaseModel):
    command: str
    timestamp: str
    return_code: int

def is_command_allowed(command: str) -> bool:
    cmd_name = shlex.split(command)[0] if command else ""
    return cmd_name in ALLOWED_COMMANDS

def execute_command(command: str) -> CommandExecution:
    start_time = datetime.now()
    try:
        result = subprocess.run(
            command,
            shell=True,
            capture_output=True,
            text=True,
            timeout=30
        )
        stdout = result.stdout[:5000]
        stderr = result.stderr[:5000]
        return_code = result.returncode
    except subprocess.TimeoutExpired:
        stdout = ""
        stderr = "Command execution timeout (30 seconds)"
        return_code = -1
    except Exception as e:
        stdout = ""
        stderr = str(e)
        return_code = -1
    end_time = datetime.now()
    execution_time = (end_time - start_time).total_seconds()
    execution = CommandExecution(
        command=command,
        stdout=stdout,
        stderr=stderr,
        return_code=return_code,
        execution_time=execution_time,
        timestamp=datetime.now().isoformat()
    )
    save_to_history(command, return_code)
    return execution

def save_to_history(command: str, return_code: int):
    timestamp = datetime.now().isoformat()
    history_entry = f"{timestamp} | {command} | Return Code: {return_code}\n"
    with open(COMMAND_HISTORY_FILE, 'a') as f:
        f.write(history_entry)
    cleanup_history()

def cleanup_history():
    if os.path.exists(COMMAND_HISTORY_FILE):
        with open(COMMAND_HISTORY_FILE, 'r') as f:
            lines = f.readlines()
        if len(lines) > MAX_HISTORY:
            with open(COMMAND_HISTORY_FILE, 'w') as f:
                f.writelines(lines[-MAX_HISTORY:])

def get_command_history() -> List[CommandHistory]:
    history = []
    if os.path.exists(COMMAND_HISTORY_FILE):
        with open(COMMAND_HISTORY_FILE, 'r') as f:
            lines = f.readlines()
        for line in lines:
            try:
                parts = line.strip().split(' | ')
                if len(parts) >= 3:
                    timestamp = parts[0]
                    command = parts[1]
                    return_code = int(parts[2].split(': ')[1])
                    history.append(CommandHistory(
                        command=command,
                        timestamp=timestamp,
                        return_code=return_code
                    ))
            except Exception:
                pass
    return sorted(history, key=lambda x: x.timestamp, reverse=True)

def clear_history():
    if os.path.exists(COMMAND_HISTORY_FILE):
        os.remove(COMMAND_HISTORY_FILE)

def get_system_info() -> Dict:
    info = {}
    try:
        hostname_result = subprocess.run('hostname', shell=True, capture_output=True, text=True, timeout=5)
        info['hostname'] = hostname_result.stdout.strip()
    except Exception:
        info['hostname'] = 'Unknown'
    try:
        uname_result = subprocess.run('uname -a', shell=True, capture_output=True, text=True, timeout=5)
        info['os'] = uname_result.stdout.strip()
    except Exception:
        info['os'] = 'Unknown'
    try:
        pwd_result = subprocess.run('pwd', shell=True, capture_output=True, text=True, timeout=5)
        info['current_dir'] = pwd_result.stdout.strip()
    except Exception:
        info['current_dir'] = 'Unknown'
    try:
        whoami_result = subprocess.run('whoami', shell=True, capture_output=True, text=True, timeout=5)
        info['user'] = whoami_result.stdout.strip()
    except Exception:
        info['user'] = 'Unknown'
    return info

@app.get("/", response_class=HTMLResponse)
def get_home():
    system_info = get_system_info()
    history = get_command_history()
    history_html = ""
    for entry in history[:20]:
        status_color = "green" if entry.return_code == 0 else "red"
        history_html += f"""
