from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime
import subprocess
import platform
import socket
import re
import threading

app = FastAPI()

class PingResult(BaseModel):
    host: str
    packets_sent: int
    packets_received: int
    packet_loss: float
    min_time: Optional[float] = None
    max_time: Optional[float] = None
    avg_time: Optional[float] = None
    stddev_time: Optional[float] = None
    status: str
    timestamp: str

class HostInfo(BaseModel):
    hostname: str
    ip_address: Optional[str] = None
    status: str
    timestamp: str

class TraceRoute(BaseModel):
    host: str
    hops: List[Dict]
    status: str
    timestamp: str

def ping_host(host: str, count: int = 4) -> PingResult:
    system = platform.system().lower()
    if system == 'windows':
        command = f"ping -n {count} {host}"
    else:
        command = f"ping -c {count} {host}"
    try:
        result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=30)
        output = result.stdout + result.stderr
        packets_sent = count
        packets_received = 0
        min_time = None
        max_time = None
        avg_time = None
        stddev_time = None
        packet_loss = 0.0
        if system == 'windows':
            sent_match = re.search(r'Packets: Sent = (\d+), Received = (\d+)', output)
            if sent_match:
                packets_sent = int(sent_match.group(1))
                packets_received = int(sent_match.group(2))
            stats_match = re.search(r'Minimum = (\d+)ms, Maximum = (\d+)ms, Average = (\d+)ms', output)
            if stats_match:
                min_time = float(stats_match.group(1))
                max_time = float(stats_match.group(2))
                avg_time = float(stats_match.group(3))
            loss_match = re.search(r'\((\d+)% loss\)', output)
            if loss_match:
                packet_loss = float(loss_match.group(1))
        else:
            sent_match = re.search(r'(\d+) packets transmitted', output)
            if sent_match:
                packets_sent = int(sent_match.group(1))
            received_match = re.search(r'(\d+) (?:packets )?received', output)
            if received_match:
                packets_received = int(received_match.group(1))
            loss_match = re.search(r'([\d.]+)% (?:packet )?loss', output)
            if loss_match:
                packet_loss = float(loss_match.group(1))
            stats_match = re.search(r'min/avg/max(?:/stddev)? = ([\d.]+)/([\d.]+)/([\d.]+)(?:/([\d.]+))?', output)
            if stats_match:
                min_time = float(stats_match.group(1))
                avg_time = float(stats_match.group(2))
                max_time = float(stats_match.group(3))
                if stats_match.group(4):
                    stddev_time = float(stats_match.group(4))
        status = "Reachable" if packets_received > 0 else "Unreachable"
        return PingResult(
            host=host,
            packets_sent=packets_sent,
            packets_received=packets_received,
            packet_loss=packet_loss,
            min_time=min_time,
            max_time=max_time,
            avg_time=avg_time,
            stddev_time=stddev_time,
            status=status,
            timestamp=datetime.now().isoformat()
        )
    except subprocess.TimeoutExpired:
        return PingResult(
            host=host,
            packets_sent=count,
            packets_received=0,
            packet_loss=100.0,
            status="Timeout",
            timestamp=datetime.now().isoformat()
        )
    except Exception as e:
        return PingResult(
            host=host,
            packets_sent=0,
            packets_received=0,
            packet_loss=100.0,
            status=f"Error: {str(e)}",
            timestamp=datetime.now().isoformat()
        )

def resolve_hostname(hostname: str) -> HostInfo:
    try:
        ip_address = socket.gethostbyname(hostname)
        status = "Resolved"
    except socket.gaierror:
        ip_address = None
        status = "Not Resolved"
    except Exception as e:
        ip_address = None
        status = f"Error: {str(e)}"
    return HostInfo(
        hostname=hostname,
        ip_address=ip_address,
        status=status,
        timestamp=datetime.now().isoformat()
    )

def reverse_lookup(ip_address: str) -> HostInfo:
    try:
        hostname, _, _ = socket.gethostbyaddr(ip_address)
        status = "Resolved"
    except socket.herror:
        hostname = ip_address
        status = "Not Resolved"
    except Exception as e:
        hostname = ip_address
        status = f"Error: {str(e)}"
    return HostInfo(
        hostname=hostname,
        ip_address=ip_address,
        status=status,
        timestamp=datetime.now().isoformat()
    )

def trace_route(host: str) -> TraceRoute:
    system = platform.system().lower()
    if system == 'windows':
        command = f"tracert -h 30 {host}"
    else:
        command = f"traceroute -m 30 {host}"
    hops = []
    try:
        result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=60)
        output = result.stdout
        lines = output.split('\n')
        for line in lines:
            line = line.strip()
            if not line or 'tracert' in line.lower() or 'traceroute' in line.lower():
                continue
            if system == 'windows':
                parts = re.match(r'(\d+)\s+([\d\s]+ms|[\*]+)\s+([\d\s]+ms|[\*]+)\s+([\d\s]+ms|[\*]+)\s+([\d\.\w\-]+)?', line)
                if parts:
                    hop_num = parts.group(1)
                    host_addr = parts.group(5) if parts.group(5) else "Unknown"
                    hops.append({"hop": hop_num, "host": host_addr})
            else:
                parts = re.match(r'(\d+)\s+([\w\-\.]+)\s*\(([\d\.]+)\)', line)
                if parts:
                    hop_num = parts.group(1)
                    hostname = parts.group(2)
                    ip = parts.group(3)
                    hops.append({"hop": hop_num, "host": f"{hostname} ({ip})"})
        status = "Success" if hops else "Failed"
    except subprocess.TimeoutExpired:
        status = "Timeout"
    except Exception as e:
        status = f"Error: {str(e)}"
    return TraceRoute(
        host=host,
        hops=hops,
        status=status,
        timestamp=datetime.now().isoformat()
    )

def check_port(host: str, port: int) -> Dict:
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(5)
        result = sock.connect_ex((host, port))
        sock.close()
        if result == 0:
            return {"host": host, "port": port, "status": "Open", "timestamp": datetime.now().isoformat()}
        else:
            return {"host": host, "port": port, "status": "Closed", "timestamp": datetime.now().isoformat()}
    except socket.gaierror:
        return {"host": host, "port": port, "status": "Hostname could not be resolved", "timestamp": datetime.now().isoformat()}
    except socket.timeout:
        return {"host": host, "port": port, "status": "Timeout", "timestamp": datetime.now().isoformat()}
    except Exception as e:
        return {"host": host, "port": port, "status": f"Error: {str(e)}", "timestamp": datetime.now().isoformat()}

