                    resultDiv.className = 'result-error';
                    resultDiv.textContent = 'Error: ' + error;
                });
            }
            function executeLookup() {
                const host = document.getElementById('lookupHost').value;
                if(!host) {
                    alert('Please enter a hostname');
                    return;
                }
                const resultDiv = document.getElementById('lookupResult');
                resultDiv.className = 'result-info';
                resultDiv.textContent = 'Resolving ' + host + '...';
                fetch('/lookup?hostname=' + encodeURIComponent(host))
                .then(response => response.json())
                .then(data => {
                    resultDiv.className = data.status === 'Resolved' ? 'result-success' : 'result-error';
                    let result = 'Hostname: ' + data.hostname + '\n';
                    result += 'IP Address: ' + (data.ip_address || 'Not found') + '\n';
                    result += 'Status: ' + data.status + '\n';
                    resultDiv.textContent = result;
                })
                .catch(error => {
                    resultDiv.className = 'result-error';
                    resultDiv.textContent = 'Error: ' + error;
                });
            }
            function executeReverse() {
                const ip = document.getElementById('reverseHost').value;
                if(!ip) {
                    alert('Please enter an IP address');
                    return;
                }
                const resultDiv = document.getElementById('reverseResult');
                resultDiv.className = 'result-info';
                resultDiv.textContent = 'Reverse resolving ' + ip + '...';
                fetch('/reverse-lookup?ip=' + encodeURIComponent(ip))
                .then(response => response.json())
                .then(data => {
                    resultDiv.className = data.status === 'Resolved' ? 'result-success' : 'result-error';
                    let result = 'IP Address: ' + data.ip_address + '\n';
                    result += 'Hostname: ' + (data.hostname || 'Not found') + '\n';
                    result += 'Status: ' + data.status + '\n';
                    resultDiv.textContent = result;
                })
                .catch(error => {
                    resultDiv.className = 'result-error';
                    resultDiv.textContent = 'Error: ' + error;
                });
            }
            function executeTrace() {
                const host = document.getElementById('traceHost').value;
                if(!host) {
                    alert('Please enter a hostname or IP address');
                    return;
                }
                const resultDiv = document.getElementById('traceResult');
                resultDiv.className = 'result-info';
                resultDiv.textContent = 'Tracing route to ' + host + '...';
                fetch('/traceroute?host=' + encodeURIComponent(host))
                .then(response => response.json())
                .then(data => {
                    resultDiv.className = data.status === 'Success' ? 'result-success' : 'result-error';
                    let result = 'Host: ' + data.host + '\n';
                    result += 'Status: ' + data.status + '\n\n';
                    result += 'Hops:\n';
                    if(data.hops.length > 0) {
                        data.hops.forEach(hop => {
                            result += hop.hop + '. ' + hop.host + '\n';
                        });
                    } else {
                        result += 'No hops found\n';
                    }
                    resultDiv.textContent = result;
                })
                .catch(error => {
                    resultDiv.className = 'result-error';
                    resultDiv.textContent = 'Error: ' + error;
                });
            }
            function executePortCheck() {
                const host = document.getElementById('portHost').value;
                const port = document.getElementById('portNumber').value;
                if(!host || !port) {
                    alert('Please enter hostname and port');
                    return;
                }
                const resultDiv = document.getElementById('portResult');
                resultDiv.className = 'result-info';
                resultDiv.textContent = 'Checking port ' + port + ' on ' + host + '...';
                fetch('/port-check?host=' + encodeURIComponent(host) + '&port=' + port)
                .then(response => response.json())
                .then(data => {
                    resultDiv.className = data.status === 'Open' ? 'result-success' : 'result-error';
                    let result = 'Host: ' + data.host + '\n';
                    result += 'Port: ' + data.port + '\n';
                    result += 'Status: ' + data.status + '\n';
                    resultDiv.textContent = result;
                })
                .catch(error => {
                    resultDiv.className = 'result-error';
                    resultDiv.textContent = 'Error: ' + error;
                });
            }
            function checkCommonPort(port) {
                const host = document.getElementById('portHost').value || 'localhost';
                document.getElementById('portNumber').value = port;
                document.getElementById('portHost').value = host;
                setTimeout(() => executePortCheck(), 100);
            }
        </script>
    </body>
    </html>
    """

@app.get("/ping")
def ping_endpoint(host: str = Query(...), count: int = Query(4)):
    result = ping_host(host, count)
    return result.dict()

@app.get("/lookup")
def lookup_endpoint(hostname: str = Query(...)):
    result = resolve_hostname(hostname)
    return result.dict()

@app.get("/reverse-lookup")
def reverse_lookup_endpoint(ip: str = Query(...)):
    result = reverse_lookup(ip)
    return result.dict()

@app.get("/traceroute")
def traceroute_endpoint(host: str = Query(...)):
    result = trace_route(host)
    return result.dict()

@app.get("/port-check")
def port_check_endpoint(host: str = Query(...), port: int = Query(...)):
    result = check_port(host, port)
    return result

