    uvicorn.run(app, host="0.0.0.0", port=8000)

import psutil
import time
from datetime import datetime
import json
class SystemMonitor:
    def __init__(self):
        self.monitoring = False
        self.history = []
    def get_cpu_info(self):
        cpu_percent = psutil.cpu_percent(interval=1, percpu=False)
        cpu_count = psutil.cpu_count(logical=True)
        cpu_freq = psutil.cpu_freq()
        return {
            "cpu_percent": cpu_percent,
            "cpu_count": cpu_count,
            "cpu_freq_current": cpu_freq.current if cpu_freq else 0,
            "cpu_freq_max": cpu_freq.max if cpu_freq else 0,
            "timestamp": datetime.now().isoformat()
        }
    def get_memory_info(self):
        memory = psutil.virtual_memory()
        swap = psutil.swap_memory()
        return {
            "total_memory": memory.total,
            "available_memory": memory.available,
            "used_memory": memory.used,
            "memory_percent": memory.percent,
            "swap_total": swap.total,
            "swap_used": swap.used,
            "swap_percent": swap.percent,
            "timestamp": datetime.now().isoformat()
        }
    def get_disk_info(self):
        disk_usage = psutil.disk_usage('/')
        disk_io = psutil.disk_io_counters()
        return {
            "total_disk": disk_usage.total,
            "used_disk": disk_usage.used,
            "free_disk": disk_usage.free,
            "disk_percent": disk_usage.percent,
            "read_bytes": disk_io.read_bytes if disk_io else 0,
            "write_bytes": disk_io.write_bytes if disk_io else 0,
            "timestamp": datetime.now().isoformat()
        }
    def get_network_info(self):
        net_io = psutil.net_io_counters()
        return {
            "bytes_sent": net_io.bytes_sent,
            "bytes_recv": net_io.bytes_recv,
            "packets_sent": net_io.packets_sent,
            "packets_recv": net_io.packets_recv,
            "errors_in": net_io.errin,
            "errors_out": net_io.errout,
            "timestamp": datetime.now().isoformat()
        }
    def get_process_info(self, limit=5):
        processes = []
        for proc in psutil.process_iter(['pid', 'name', 'cpu_percent', 'memory_percent']):
            try:
                processes.append(proc.info)
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        processes.sort(key=lambda x: x.get('cpu_percent', 0), reverse=True)
        return processes[:limit]
    def get_battery_info(self):
        battery = psutil.sensors_battery()
        if battery:
            return {
                "percent": battery.percent,
                "power_plugged": battery.power_plugged,
                "time_left": battery.secsleft if battery.secsleft != psutil.POWER_TIME_UNLIMITED else "unlimited",
                "timestamp": datetime.now().isoformat()
            }
        return {"status": "No battery detected"}
    def get_system_uptime(self):
        boot_time = psutil.boot_time()
        uptime_seconds = time.time() - boot_time
        return {
            "boot_time": datetime.fromtimestamp(boot_time).isoformat(),
            "uptime_seconds": uptime_seconds,
            "uptime_hours": uptime_seconds / 3600,
            "timestamp": datetime.now().isoformat()
        }
    def get_complete_snapshot(self):
        return {
            "cpu": self.get_cpu_info(),
            "memory": self.get_memory_info(),
            "disk": self.get_disk_info(),
            "network": self.get_network_info(),
            "top_processes": self.get_process_info(),
            "battery": self.get_battery_info(),
            "uptime": self.get_system_uptime(),
            "timestamp": datetime.now().isoformat()
        }
    def monitor_continuous(self, duration=10, interval=2):
        self.monitoring = True
        self.history = []
        start_time = time.time()
        while self.monitoring and (time.time() - start_time) < duration:
            snapshot = self.get_complete_snapshot()
            self.history.append(snapshot)
            print(f"CPU: {snapshot['cpu']['cpu_percent']}% | Memory: {snapshot['memory']['memory_percent']}% | Disk: {snapshot['disk']['disk_percent']}%")
            time.sleep(interval)
        return self.history
    def stop_monitoring(self):
        self.monitoring = False
    def get_alerts(self, cpu_threshold=80, memory_threshold=80, disk_threshold=90):
        alerts = []
        snapshot = self.get_complete_snapshot()
        if snapshot['cpu']['cpu_percent'] > cpu_threshold:
            alerts.append(f"High CPU usage: {snapshot['cpu']['cpu_percent']}%")
        if snapshot['memory']['memory_percent'] > memory_threshold:
            alerts.append(f"High memory usage: {snapshot['memory']['memory_percent']}%")
        if snapshot['disk']['disk_percent'] > disk_threshold:
            alerts.append(f"High disk usage: {snapshot['disk']['disk_percent']}%")
        return alerts
    def save_snapshot(self, filename):
        snapshot = self.get_complete_snapshot()
        with open(filename, 'w') as f:
            json.dump(snapshot, f, indent=2)
    def bytes_to_gb(self, bytes_value):
        return round(bytes_value / (1024 ** 3), 2)
    def format_snapshot(self, snapshot):
        return {
            "CPU Usage": f"{snapshot['cpu']['cpu_percent']}%",
            "Memory Usage": f"{snapshot['memory']['memory_percent']}% ({self.bytes_to_gb(snapshot['memory']['used_memory'])} GB / {self.bytes_to_gb(snapshot['memory']['total_memory'])} GB)",
            "Disk Usage": f"{snapshot['disk']['disk_percent']}% ({self.bytes_to_gb(snapshot['disk']['used_disk'])} GB / {self.bytes_to_gb(snapshot['disk']['total_disk'])} GB)",
            "Network Sent": f"{self.bytes_to_gb(snapshot['network']['bytes_sent'])} GB",
            "Network Received": f"{self.bytes_to_gb(snapshot['network']['bytes_recv'])} GB"
        }
monitor = SystemMonitor()
print("=== System Snapshot ===")
snapshot = monitor.get_complete_snapshot()
formatted = monitor.format_snapshot(snapshot)
for key, value in formatted.items():
    print(f"{key}: {value}")
print("\n=== Top Processes ===")
processes = monitor.get_process_info(5)
for proc in processes:
    print(f"PID: {proc['pid']} | Name: {proc['name']} | CPU: {proc['cpu_percent']}%")
print("\n=== Alerts ===")
alerts = monitor.get_alerts(cpu_threshold=50, memory_threshold=50)
if alerts:
    for alert in alerts:
        print(alert)
else:
    print("No alerts")
monitor.save_snapshot('system_snapshot.json')
print("\nSnapshot saved to 'system_snapshot.json'")

from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime
import psutil
import threading
import time
import json
import os

app = FastAPI()

METRICS_FILE = "system_metrics.json"
MAX_METRICS_HISTORY = 100

class CPUMetrics(BaseModel):
    percent: float
    count_physical: int
    count_logical: int
    frequency: float
    load_average: tuple

class MemoryMetrics(BaseModel):
    total_gb: float
    used_gb: float
    available_gb: float
    percent: float
    swap_total_gb: float
    swap_used_gb: float
    swap_percent: float

class DiskMetrics(BaseModel):
    partition: str
    total_gb: float
    used_gb: float
    free_gb: float
    percent: float

class NetworkMetrics(BaseModel):
    bytes_sent: int
    bytes_recv: int
    packets_sent: int
    packets_recv: int
    errin: int
    errout: int
    dropin: int
    dropout: int

class ProcessInfo(BaseModel):
    pid: int
    name: str
    status: str
    cpu_percent: float
    memory_percent: float
    num_threads: int

class SystemSnapshot(BaseModel):
    timestamp: str
    cpu: CPUMetrics
    memory: MemoryMetrics
    disks: List[DiskMetrics]
    network: NetworkMetrics
    process_count: int
    boot_time: str

def get_cpu_metrics() -> CPUMetrics:
    cpu_percent = psutil.cpu_percent(interval=1)
    cpu_count_physical = psutil.cpu_count(logical=False)
    cpu_count_logical = psutil.cpu_count(logical=True)
    cpu_freq = psutil.cpu_freq().current
    load_avg = os.getloadavg() if hasattr(os, 'getloadavg') else (0, 0, 0)
    return CPUMetrics(
        percent=cpu_percent,
        count_physical=cpu_count_physical,
        count_logical=cpu_count_logical,
        frequency=cpu_freq,
        load_average=load_avg
    )

def get_memory_metrics() -> MemoryMetrics:
    memory = psutil.virtual_memory()
    swap = psutil.swap_memory()
    return MemoryMetrics(
        total_gb=memory.total / (1024**3),
        used_gb=memory.used / (1024**3),
        available_gb=memory.available / (1024**3),
        percent=memory.percent,
        swap_total_gb=swap.total / (1024**3),
        swap_used_gb=swap.used / (1024**3),
        swap_percent=swap.percent
    )

def get_disk_metrics() -> List[DiskMetrics]:
    disks = []
    partitions = psutil.disk_partitions()
    for partition in partitions:
        try:
            usage = psutil.disk_usage(partition.mountpoint)
            disk = DiskMetrics(
                partition=partition.mountpoint,
                total_gb=usage.total / (1024**3),
                used_gb=usage.used / (1024**3),
                free_gb=usage.free / (1024**3),
                percent=usage.percent
            )
            disks.append(disk)
        except PermissionError:
            pass
    return disks

def get_network_metrics() -> NetworkMetrics:
    net_io = psutil.net_io_counters()
    return NetworkMetrics(
        bytes_sent=net_io.bytes_sent,
        bytes_recv=net_io.bytes_recv,
        packets_sent=net_io.packets_sent,
        packets_recv=net_io.packets_recv,
        errin=net_io.errin,
        errout=net_io.errout,
        dropin=net_io.dropin,
        dropout=net_io.dropout
    )

def get_top_processes(n: int = 10) -> List[ProcessInfo]:
    processes = []
    try:
        for proc in psutil.process_iter(['pid', 'name', 'status', 'cpu_percent', 'memory_percent', 'num_threads']):
            try:
                info = proc.info
                processes.append(ProcessInfo(
                    pid=info['pid'],
                    name=info['name'],
                    status=info['status'],
                    cpu_percent=info['cpu_percent'] or 0,
                    memory_percent=info['memory_percent'] or 0,
                    num_threads=info['num_threads']
                ))
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
    except Exception:
        pass
    processes.sort(key=lambda x: x.cpu_percent + x.memory_percent, reverse=True)
    return processes[:n]

def get_system_snapshot() -> SystemSnapshot:
    cpu = get_cpu_metrics()
    memory = get_memory_metrics()
    disks = get_disk_metrics()
    network = get_network_metrics()
    process_count = len(psutil.pids())
    boot_time = datetime.fromtimestamp(psutil.boot_time()).isoformat()
    return SystemSnapshot(
        timestamp=datetime.now().isoformat(),
        cpu=cpu,
        memory=memory,
        disks=disks,
        network=network,
        process_count=process_count,
        boot_time=boot_time
    )

def save_metrics_history(snapshot: SystemSnapshot):
    history = []
    if os.path.exists(METRICS_FILE):
        try:
            with open(METRICS_FILE, 'r') as f:
                history = json.load(f)
        except Exception:
            history = []
    history.append({
        "timestamp": snapshot.timestamp,
        "cpu_percent": snapshot.cpu.percent,
        "memory_percent": snapshot.memory.percent,
        "process_count": snapshot.process_count
    })
    if len(history) > MAX_METRICS_HISTORY:
        history = history[-MAX_METRICS_HISTORY:]
    with open(METRICS_FILE, 'w') as f:
        json.dump(history, f)

