                html += '<div class="metric-card memory">';
                html += '<div class="metric-label">Memory Usage</div>';
                html += '<div class="metric-value">' + memory.percent.toFixed(1) + '%</div>';
                html += '<div class="progress-bar"><div class="progress-fill" style="width: ' + memory.percent + '%"></div></div>';
                html += '<div class="metric-subtext">' + memory.used_gb.toFixed(2) + 'GB / ' + memory.total_gb.toFixed(2) + 'GB</div>';
                html += '</div>';
                html += '<div class="metric-card disk">';
                html += '<div class="metric-label">Total Disk Usage</div>';
                let totalUsed = 0, totalSize = 0;
                disks.forEach(disk => {
                    totalUsed += disk.used_gb;
                    totalSize += disk.total_gb;
                });
                const diskPercent = totalSize > 0 ? (totalUsed / totalSize) * 100 : 0;
                html += '<div class="metric-value">' + diskPercent.toFixed(1) + '%</div>';
                html += '<div class="progress-bar"><div class="progress-fill" style="width: ' + diskPercent + '%"></div></div>';
                html += '<div class="metric-subtext">' + totalUsed.toFixed(2) + 'GB / ' + totalSize.toFixed(2) + 'GB</div>';
                html += '</div>';
                html += '<div class="metric-card network">';
                html += '<div class="metric-label">Processes</div>';
                html += '<div class="metric-value">' + data.process_count + '</div>';
                html += '<div class="metric-subtext">Active System Processes</div>';
                html += '</div>';
                html += '</div>';
                container.innerHTML = html;
            }
            function refreshProcesses() {
                fetch('/processes')
                .then(response => response.json())
                .then(data => displayProcesses(data.processes))
                .catch(error => console.error('Error:', error));
            }
            function displayProcesses(processes) {
                const table = document.getElementById('processesTable');
                let html = '<tr><th>PID</th><th>Name</th><th>Status</th><th>CPU %</th><th>Memory %</th><th>Threads</th></tr>';
                processes.forEach(proc => {
                    html += '<tr>';
                    html += '<td>' + proc.pid + '</td>';
                    html += '<td>' + proc.name.substring(0, 50) + '</td>';
                    html += '<td>' + proc.status + '</td>';
                    html += '<td>' + proc.cpu_percent.toFixed(2) + '%</td>';
                    html += '<td>' + proc.memory_percent.toFixed(2) + '%</td>';
                    html += '<td>' + proc.num_threads + '</td>';
                    html += '</tr>';
                });
                table.innerHTML = html;
            }
            function refreshDisks() {
                fetch('/metrics')
                .then(response => response.json())
                .then(data => displayDisks(data.disks))
                .catch(error => console.error('Error:', error));
            }
            function displayDisks(disks) {
                const table = document.getElementById('disksTable');
                let html = '<tr><th>Partition</th><th>Total</th><th>Used</th><th>Free</th><th>Usage %</th></tr>';
                disks.forEach(disk => {
                    const statusClass = disk.percent > 90 ? 'status-critical' : disk.percent > 70 ? 'status-warning' : 'status-good';
                    html += '<tr>';
                    html += '<td>' + disk.partition + '</td>';
                    html += '<td>' + disk.total_gb.toFixed(2) + ' GB</td>';
                    html += '<td>' + disk.used_gb.toFixed(2) + ' GB</td>';
                    html += '<td>' + disk.free_gb.toFixed(2) + ' GB</td>';
                    html += '<td class="' + statusClass + '">' + disk.percent.toFixed(1) + '%</td>';
                    html += '</tr>';
                });
                table.innerHTML = html;
            }
            function refreshNetwork() {
                fetch('/metrics')
                .then(response => response.json())
                .then(data => displayNetwork(data.network))
                .catch(error => console.error('Error:', error));
            }
            function displayNetwork(network) {
                const container = document.getElementById('networkContainer');
                let html = '<table style="margin-top: 0;"><tr><th>Metric</th><th>Value</th></tr>';
                html += '<tr><td>Bytes Sent</td><td>' + (network.bytes_sent / (1024**3)).toFixed(2) + ' GB</td></tr>';
                html += '<tr><td>Bytes Received</td><td>' + (network.bytes_recv / (1024**3)).toFixed(2) + ' GB</td></tr>';
                html += '<tr><td>Packets Sent</td><td>' + network.packets_sent.toLocaleString() + '</td></tr>';
                html += '<tr><td>Packets Received</td><td>' + network.packets_recv.toLocaleString() + '</td></tr>';
                html += '<tr><td>Errors In</td><td>' + network.errin + '</td></tr>';
                html += '<tr><td>Errors Out</td><td>' + network.errout + '</td></tr>';
                html += '<tr><td>Dropped In</td><td>' + network.dropin + '</td></tr>';
                html += '<tr><td>Dropped Out</td><td>' + network.dropout + '</td></tr>';
                html += '</table>';
                container.innerHTML = html;
            }
            function loadHistory() {
                fetch('/history')
                .then(response => response.json())
                .then(data => displayHistory(data.history))
                .catch(error => console.error('Error:', error));
            }
            function displayHistory(history) {
                const timestamps = history.map(h => new Date(h.timestamp).toLocaleTimeString());
                const cpuData = history.map(h => h.cpu_percent);
                const memoryData = history.map(h => h.memory_percent);
                const processData = history.map(h => h.process_count / 10);
                if(historyChart) {
                    historyChart.destroy();
                }
                const ctx = document.getElementById('historyChart').getContext('2d');
                historyChart = new Chart(ctx, {
                    type: 'line',
                    data: {
                        labels: timestamps,
                        datasets: [
                            {
                                label: 'CPU Usage (%)',
                                data: cpuData,
                                borderColor: '#f5576c',
                                backgroundColor: 'rgba(245, 87, 108, 0.1)',
                                tension: 0.1
                            },
                            {
                                label: 'Memory Usage (%)',
                                data: memoryData,
                                borderColor: '#00f2fe',
                                backgroundColor: 'rgba(0, 242, 254, 0.1)',
                                tension: 0.1
                            },
                            {
                                label: 'Processes (x10)',
                                data: processData,
                                borderColor: '#fee140',
                                backgroundColor: 'rgba(254, 225, 64, 0.1)',
                                tension: 0.1
                            }
                        ]
                    },
                    options: {
                        responsive: true,
                        plugins: {
                            legend: {
                                position: 'top'
                            }
                        },
                        scales: {
                            y: {
                                beginAtZero: true,
                                max: 100
                            }
                        }
                    }
                });
            }
            window.onload = function() {
                refreshMetrics();
                refreshProcesses();
                setInterval(refreshMetrics, 5000);
            };
        </script>
    </body>
    </html>
    """

@app.get("/metrics")
def get_metrics():
    snapshot = get_system_snapshot()
    save_metrics_history(snapshot)
    return {
        "timestamp": snapshot.timestamp,
        "cpu": snapshot.cpu.dict(),
        "memory": snapshot.memory.dict(),
        "disks": [d.dict() for d in snapshot.disks],
        "network": snapshot.network.dict(),
        "process_count": snapshot.process_count,
        "boot_time": snapshot.boot_time
    }

@app.get("/processes")
def get_processes(limit: int = Query(10, ge=1, le=50)):
    processes = get_top_processes(limit)
    return {"processes": [p.dict() for p in processes], "count": len(processes)}

