import psutil
import os
import signal
from datetime import datetime
import time
class ProcessManager:
    def __init__(self):
        self.processes = []
    def list_all_processes(self):
        self.processes = []
        for proc in psutil.process_iter(['pid', 'name', 'status', 'cpu_percent', 'memory_percent', 'create_time']):
            try:
                self.processes.append(proc.info)
            except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
                pass
        return self.processes
    def get_process_by_pid(self, pid):
        try:
            proc = psutil.Process(pid)
            return {
                'pid': proc.pid,
                'name': proc.name(),
                'status': proc.status(),
                'cpu_percent': proc.cpu_percent(interval=0.1),
                'memory_percent': proc.memory_percent(),
                'memory_info': proc.memory_info()._asdict(),
                'create_time': datetime.fromtimestamp(proc.create_time()).isoformat(),
                'num_threads': proc.num_threads(),
                'cmdline': proc.cmdline()
            }
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            return None
    def get_process_by_name(self, name):
        matching_processes = []
        for proc in psutil.process_iter(['pid', 'name']):
            try:
                if name.lower() in proc.info['name'].lower():
                    matching_processes.append(self.get_process_by_pid(proc.info['pid']))
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return matching_processes
    def kill_process(self, pid):
        try:
            proc = psutil.Process(pid)
            proc.terminate()
            proc.wait(timeout=3)
            return {"status": "success", "message": f"Process {pid} terminated"}
        except psutil.TimeoutExpired:
            proc.kill()
            return {"status": "success", "message": f"Process {pid} killed forcefully"}
        except (psutil.NoSuchProcess, psutil.AccessDenied) as e:
            return {"status": "error", "message": str(e)}
    def kill_process_by_name(self, name):
        killed_count = 0
        for proc in psutil.process_iter(['pid', 'name']):
            try:
                if name.lower() in proc.info['name'].lower():
                    self.kill_process(proc.info['pid'])
                    killed_count += 1
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return {"status": "success", "killed_count": killed_count}
    def get_top_processes(self, limit=10, sort_by='cpu'):
        processes = self.list_all_processes()
        if sort_by == 'cpu':
            processes.sort(key=lambda x: x.get('cpu_percent', 0), reverse=True)
        elif sort_by == 'memory':
            processes.sort(key=lambda x: x.get('memory_percent', 0), reverse=True)
        return processes[:limit]
    def get_process_tree(self, pid):
        try:
            proc = psutil.Process(pid)
            children = proc.children(recursive=True)
            return {
                'parent': self.get_process_by_pid(pid),
                'children': [self.get_process_by_pid(child.pid) for child in children]
            }
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            return None
    def monitor_process(self, pid, duration=10, interval=1):
        history = []
        start_time = time.time()
        try:
            while time.time() - start_time < duration:
                proc_info = self.get_process_by_pid(pid)
                if proc_info:
                    history.append(proc_info)
                    print(f"PID {pid}: CPU {proc_info['cpu_percent']}% | Memory {proc_info['memory_percent']:.2f}%")
                else:
                    print(f"Process {pid} no longer exists")
                    break
                time.sleep(interval)
        except KeyboardInterrupt:
            print("Monitoring stopped")
        return history
    def get_process_connections(self, pid):
        try:
            proc = psutil.Process(pid)
            connections = proc.connections()
            return [
                {
                    'fd': conn.fd,
                    'family': str(conn.family),
                    'type': str(conn.type),
                    'laddr': f"{conn.laddr.ip}:{conn.laddr.port}" if conn.laddr else None,
                    'raddr': f"{conn.raddr.ip}:{conn.raddr.port}" if conn.raddr else None,
                    'status': conn.status
                }
                for conn in connections
            ]
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            return []
    def suspend_process(self, pid):
        try:
            proc = psutil.Process(pid)
            proc.suspend()
            return {"status": "success", "message": f"Process {pid} suspended"}
        except (psutil.NoSuchProcess, psutil.AccessDenied) as e:
            return {"status": "error", "message": str(e)}
    def resume_process(self, pid):
        try:
            proc = psutil.Process(pid)
            proc.resume()
            return {"status": "success", "message": f"Process {pid} resumed"}
        except (psutil.NoSuchProcess, psutil.AccessDenied) as e:
            return {"status": "error", "message": str(e)}
    def get_process_stats(self):
        total = len(list(psutil.process_iter()))
        running = len([p for p in psutil.process_iter() if p.status() == psutil.STATUS_RUNNING])
        sleeping = len([p for p in psutil.process_iter() if p.status() == psutil.STATUS_SLEEPING])
        return {
            'total_processes': total,
            'running': running,
            'sleeping': sleeping,
            'timestamp': datetime.now().isoformat()
        }
    def search_processes(self, keyword):
        results = []
        for proc in psutil.process_iter(['pid', 'name', 'cmdline']):
            try:
                if keyword.lower() in proc.info['name'].lower():
                    results.append(self.get_process_by_pid(proc.info['pid']))
                elif proc.info['cmdline'] and any(keyword.lower() in arg.lower() for arg in proc.info['cmdline']):
                    results.append(self.get_process_by_pid(proc.info['pid']))
            except (psutil.NoSuchProcess, psutil.AccessDenied, TypeError):
                pass
        return results
manager = ProcessManager()
print("=== Process Statistics ===")
stats = manager.get_process_stats()
print(f"Total Processes: {stats['total_processes']}")
print(f"Running: {stats['running']}")
print(f"Sleeping: {stats['sleeping']}")
print("\n=== Top 5 Processes by CPU ===")
top_cpu = manager.get_top_processes(limit=5, sort_by='cpu')
for proc in top_cpu:
    print(f"PID: {proc['pid']} | Name: {proc['name']} | CPU: {proc['cpu_percent']}%")
print("\n=== Top 5 Processes by Memory ===")
top_mem = manager.get_top_processes(limit=5, sort_by='memory')
for proc in top_mem:
    print(f"PID: {proc['pid']} | Name: {proc['name']} | Memory: {proc['memory_percent']:.2f}%")
current_pid = os.getpid()
print(f"\n=== Current Process Info (PID: {current_pid}) ===")
current_proc = manager.get_process_by_pid(current_pid)
if current_proc:
    print(f"Name: {current_proc['name']}")
    print(f"Status: {current_proc['status']}")
    print(f"CPU: {current_proc['cpu_percent']}%")
    print(f"Memory: {current_proc['memory_percent']:.2f}%")
    print(f"Threads: {current_proc['num_threads']}")
print("\n=== Search for 'python' processes ===")
python_procs = manager.search_processes('python')
for proc in python_procs[:3]:
