from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime
import psutil
import subprocess
import platform
import os

app = FastAPI()

class ProcessDetail(BaseModel):
    pid: int
    name: str
    status: str
    cpu_percent: float
    memory_percent: float
    memory_mb: float
    num_threads: int
    create_time: str
    exe_path: Optional[str] = None
    cmdline: Optional[str] = None

class ProcessAction(BaseModel):
    pid: int
    action: str
    success: bool
    message: str
    timestamp: str

def get_all_processes() -> List[ProcessDetail]:
    processes = []
    try:
        for proc in psutil.process_iter(['pid', 'name', 'status', 'cpu_percent', 'memory_percent', 'num_threads', 'create_time', 'exe', 'cmdline']):
            try:
                info = proc.info
                create_time = datetime.fromtimestamp(info['create_time']).isoformat() if info['create_time'] else "Unknown"
                cmdline = ' '.join(info['cmdline']) if info['cmdline'] else "N/A"
                process = ProcessDetail(
                    pid=info['pid'],
                    name=info['name'],
                    status=info['status'],
                    cpu_percent=info['cpu_percent'] or 0,
                    memory_percent=info['memory_percent'] or 0,
                    memory_mb=info['memory_percent'] or 0,
                    num_threads=info['num_threads'],
                    create_time=create_time,
                    exe_path=info['exe'],
                    cmdline=cmdline[:100]
                )
                processes.append(process)
            except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
                pass
    except Exception:
        pass
    return processes

def get_process_by_pid(pid: int) -> Optional[ProcessDetail]:
    try:
        proc = psutil.Process(pid)
        info = proc.as_dict(attrs=['pid', 'name', 'status', 'cpu_percent', 'memory_percent', 'num_threads', 'create_time', 'exe', 'cmdline'])
        create_time = datetime.fromtimestamp(info['create_time']).isoformat() if info['create_time'] else "Unknown"
        cmdline = ' '.join(info['cmdline']) if info['cmdline'] else "N/A"
        return ProcessDetail(
            pid=info['pid'],
            name=info['name'],
            status=info['status'],
            cpu_percent=info['cpu_percent'] or 0,
            memory_percent=info['memory_percent'] or 0,
            memory_mb=info['memory_percent'] or 0,
            num_threads=info['num_threads'],
            create_time=create_time,
            exe_path=info['exe'],
            cmdline=cmdline
        )
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        return None

def kill_process(pid: int) -> ProcessAction:
    try:
        proc = psutil.Process(pid)
        proc.kill()
        return ProcessAction(
            pid=pid,
            action="kill",
            success=True,
            message="Process killed successfully",
            timestamp=datetime.now().isoformat()
        )
    except psutil.NoSuchProcess:
        return ProcessAction(
            pid=pid,
            action="kill",
            success=False,
            message="Process not found",
            timestamp=datetime.now().isoformat()
        )
    except psutil.AccessDenied:
        return ProcessAction(
            pid=pid,
            action="kill",
            success=False,
            message="Access denied",
            timestamp=datetime.now().isoformat()
        )
    except Exception as e:
        return ProcessAction(
            pid=pid,
            action="kill",
            success=False,
            message=str(e),
            timestamp=datetime.now().isoformat()
        )

def terminate_process(pid: int) -> ProcessAction:
    try:
        proc = psutil.Process(pid)
        proc.terminate()
        return ProcessAction(
            pid=pid,
            action="terminate",
            success=True,
            message="Process terminated successfully",
            timestamp=datetime.now().isoformat()
        )
    except psutil.NoSuchProcess:
        return ProcessAction(
            pid=pid,
            action="terminate",
            success=False,
            message="Process not found",
            timestamp=datetime.now().isoformat()
        )
    except psutil.AccessDenied:
        return ProcessAction(
            pid=pid,
            action="terminate",
            success=False,
            message="Access denied",
            timestamp=datetime.now().isoformat()
        )
    except Exception as e:
        return ProcessAction(
            pid=pid,
            action="terminate",
            success=False,
            message=str(e),
            timestamp=datetime.now().isoformat()
        )

def suspend_process(pid: int) -> ProcessAction:
    try:
        proc = psutil.Process(pid)
        proc.suspend()
        return ProcessAction(
            pid=pid,
            action="suspend",
            success=True,
            message="Process suspended successfully",
            timestamp=datetime.now().isoformat()
        )
    except psutil.NoSuchProcess:
        return ProcessAction(
            pid=pid,
            action="suspend",
            success=False,
            message="Process not found",
            timestamp=datetime.now().isoformat()
        )
    except psutil.AccessDenied:
        return ProcessAction(
            pid=pid,
            action="suspend",
            success=False,
            message="Access denied",
            timestamp=datetime.now().isoformat()
        )
    except Exception as e:
        return ProcessAction(
            pid=pid,
            action="suspend",
            success=False,
            message=str(e),
            timestamp=datetime.now().isoformat()
        )

def resume_process(pid: int) -> ProcessAction:
    try:
        proc = psutil.Process(pid)
        proc.resume()
        return ProcessAction(
            pid=pid,
            action="resume",
            success=True,
            message="Process resumed successfully",
            timestamp=datetime.now().isoformat()
        )
    except psutil.NoSuchProcess:
        return ProcessAction(
            pid=pid,
            action="resume",
            success=False,
            message="Process not found",
            timestamp=datetime.now().isoformat()
        )
    except psutil.AccessDenied:
        return ProcessAction(
            pid=pid,
            action="resume",
            success=False,
            message="Access denied",
            timestamp=datetime.now().isoformat()
        )
    except Exception as e:
        return ProcessAction(
            pid=pid,
            action="resume",
            success=False,
            message=str(e),
            timestamp=datetime.now().isoformat()
        )

def search_processes(keyword: str) -> List[ProcessDetail]:
    all_processes = get_all_processes()
    keyword_lower = keyword.lower()
    return [p for p in all_processes if keyword_lower in p.name.lower() or keyword_lower in str(p.cmdline).lower()]

def get_process_tree() -> Dict:
    tree = {}
    try:
        for proc in psutil.process_iter(['pid', 'name', 'ppid']):
            try:
                info = proc.info
                pid = info['pid']
                ppid = info['ppid']
                name = info['name']
                if ppid not in tree:
                    tree[ppid] = []
                tree[ppid].append({"pid": pid, "name": name, "children": []})
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
    except Exception:
        pass
    return tree

def get_process_children(pid: int) -> List[ProcessDetail]:
    try:
        proc = psutil.Process(pid)
        children = proc.children(recursive=True)
        result = []
        for child in children:
            try:
                detail = get_process_by_pid(child.pid)
                if detail:
                    result.append(detail)
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return result
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        return []

