    </head>
    <body>
        <div class="container">
            <h1>⚙️ Process Manager</h1>
            <div class="tabs">
                <button class="tab-button active" onclick="switchTab('processes-tab')">All Processes</button>
                <button class="tab-button" onclick="switchTab('search-tab')">Search</button>
                <button class="tab-button" onclick="switchTab('details-tab')">Details</button>
            </div>
            <div id="processes-tab" class="tab-content active">
                <div class="section">
                    <h2>System Processes</h2>
                    <button onclick="loadProcesses()">Refresh</button>
                    <button class="secondary" onclick="sortByName()">Sort by Name</button>
                    <button class="secondary" onclick="sortByCPU()">Sort by CPU</button>
                    <button class="secondary" onclick="sortByMemory()">Sort by Memory</button>
                    <table id="processesTable">
                        <tr>
                            <th>PID</th>
                            <th>Name</th>
                            <th>Status</th>
                            <th>CPU %</th>
                            <th>Memory MB</th>
                            <th>Threads</th>
                            <th>Created</th>
                            <th>Actions</th>
                        </tr>
                    </table>
                </div>
            </div>
            <div id="search-tab" class="tab-content">
                <div class="section">
                    <h2>Search Processes</h2>
                    <div class="search-bar">
                        <input type="text" id="searchKeyword" placeholder="Enter process name or keyword...">
                        <button onclick="searchProcess()">Search</button>
                    </div>
                    <table id="searchResultsTable">
                        <tr>
                            <th>PID</th>
                            <th>Name</th>
                            <th>Status</th>
                            <th>CPU %</th>
                            <th>Memory MB</th>
                            <th>Threads</th>
                            <th>Actions</th>
                        </tr>
                    </table>
                </div>
            </div>
            <div id="details-tab" class="tab-content">
                <div class="section">
                    <h2>Process Details</h2>
                    <div class="search-bar">
                        <input type="number" id="detailsPID" placeholder="Enter Process ID (PID)...">
                        <button onclick="loadProcessDetails()">Get Details</button>
                    </div>
                    <div id="detailsContainer"></div>
                </div>
            </div>
        </div>
        <script>
            let allProcesses = [];
            function switchTab(tabName) {
                const tabs = document.querySelectorAll('.tab-content');
                tabs.forEach(tab => tab.classList.remove('active'));
                document.getElementById(tabName).classList.add('active');
                const buttons = document.querySelectorAll('.tab-button');
                buttons.forEach(btn => btn.classList.remove('active'));
                event.target.classList.add('active');
                if(tabName === 'processes-tab') {
                    loadProcesses();
                }
            }
            function loadProcesses() {
                fetch('/processes')
                .then(response => response.json())
                .then(data => {
                    allProcesses = data.processes;
                    displayProcesses(allProcesses);
                })
                .catch(error => console.error('Error:', error));
            }
            function displayProcesses(processes) {
                const table = document.getElementById('processesTable');
                let html = '<tr><th>PID</th><th>Name</th><th>Status</th><th>CPU %</th><th>Memory MB</th><th>Threads</th><th>Created</th><th>Actions</th></tr>';
                processes.forEach(proc => {
                    const statusClass = 'status-' + proc.status;
                    const cpuClass = proc.cpu_percent > 50 ? 'cpu-high' : '';
                    const memClass = proc.memory_percent > 50 ? 'memory-high' : '';
                    const createdDate = new Date(proc.create_time).toLocaleDateString();
                    html += '<tr>';
                    html += '<td class="pid">' + proc.pid + '</td>';
                    html += '<td>' + proc.name.substring(0, 30) + '</td>';
                    html += '<td class="' + statusClass + '">' + proc.status + '</td>';
                    html += '<td class="' + cpuClass + '">' + proc.cpu_percent.toFixed(2) + '%</td>';
                    html += '<td class="' + memClass + '">' + (proc.memory_mb * 1024).toFixed(1) + ' MB</td>';
                    html += '<td>' + proc.num_threads + '</td>';
                    html += '<td>' + createdDate + '</td>';
                    html += '<td>';
                    if(proc.status === 'running') {
                        html += '<button class="suspend" onclick="suspendProcess(' + proc.pid + ')">Suspend</button>';
                    }
                    if(proc.status === 'stopped') {
                        html += '<button class="secondary" onclick="resumeProcess(' + proc.pid + ')">Resume</button>';
                    }
                    html += '<button class="kill" onclick="killProcess(' + proc.pid + ')">Kill</button>';
                    html += '</td>';
                    html += '</tr>';
                });
                table.innerHTML = html;
            }
            function sortByName() {
                allProcesses.sort((a, b) => a.name.localeCompare(b.name));
                displayProcesses(allProcesses);
            }
            function sortByCPU() {
                allProcesses.sort((a, b) => b.cpu_percent - a.cpu_percent);
                displayProcesses(allProcesses);
            }
            function sortByMemory() {
                allProcesses.sort((a, b) => b.memory_percent - a.memory_percent);
                displayProcesses(allProcesses);
            }
            function searchProcess() {
                const keyword = document.getElementById('searchKeyword').value;
                if(!keyword) {
                    alert('Please enter a search keyword');
                    return;
                }
                fetch('/search?keyword=' + encodeURIComponent(keyword))
                .then(response => response.json())
                .then(data => displaySearchResults(data.processes))
                .catch(error => console.error('Error:', error));
            }
            function displaySearchResults(processes) {
                const table = document.getElementById('searchResultsTable');
                let html = '<tr><th>PID</th><th>Name</th><th>Status</th><th>CPU %</th><th>Memory MB</th><th>Threads</th><th>Actions</th></tr>';
                if(processes.length === 0) {
                    html += '<tr><td colspan="7" style="text-align: center; color: #999;">No processes found</td></tr>';
                } else {
                    processes.forEach(proc => {
                        const statusClass = 'status-' + proc.status;
                        html += '<tr>';
                        html += '<td class="pid">' + proc.pid + '</td>';
                        html += '<td>' + proc.name + '</td>';
                        html += '<td class="' + statusClass + '">' + proc.status + '</td>';
                        html += '<td>' + proc.cpu_percent.toFixed(2) + '%</td>';
                        html += '<td>' + (proc.memory_mb * 1024).toFixed(1) + ' MB</td>';
                        html += '<td>' + proc.num_threads + '</td>';
                        html += '<td>';
                        html += '<button class="kill" onclick="killProcess(' + proc.pid + ')">Kill</button>';
                        html += '</td>';
                        html += '</tr>';
                    });
                }
                table.innerHTML = html;
            }
            function loadProcessDetails() {
                const pid = document.getElementById('detailsPID').value;
                if(!pid) {
                    alert('Please enter a Process ID');
                    return;
                }
                fetch('/process?pid=' + pid)
                .then(response => response.json())
                .then(data => {
                    if(data.error) {
                        document.getElementById('detailsContainer').innerHTML = '<div style="color: #f44336;">Error: ' + data.error + '</div>';
                    } else {
                        displayProcessDetails(data);
                    }
                })
                .catch(error => {
                    document.getElementById('detailsContainer').innerHTML = '<div style="color: #f44336;">Error: ' + error + '</div>';
                });
            }
            function displayProcessDetails(proc) {
                const statusClass = 'status-' + proc.status;
                let html = '<div class="process-detail">';
                html += '<div class="detail-item"><span class="detail-label">PID:</span> <span class="detail-value">' + proc.pid + '</span></div>';
                html += '<div class="detail-item"><span class="detail-label">Name:</span> <span class="detail-value">' + proc.name + '</span></div>';
                html += '<div class="detail-item"><span class="detail-label">Status:</span> <span class="detail-value ' + statusClass + '">' + proc.status + '</span></div>';
                html += '<div class="detail-item"><span class="detail-label">CPU Usage:</span> <span class="detail-value">' + proc.cpu_percent.toFixed(2) + '%</span></div>';
                html += '<div class="detail-item"><span class="detail-label">Memory Usage:</span> <span class="detail-value">' + (proc.memory_mb * 1024).toFixed(2) + ' MB</span></div>';
                html += '<div class="detail-item"><span class="detail-label">Threads:</span> <span class="detail-value">' + proc.num_threads + '</span></div>';
                html += '<div class="detail-item"><span class="detail-label">Created Time:</span> <span class="detail-value">' + proc.create_time + '</span></div>';
                if(proc.exe_path) {
                    html += '<div class="detail-item"><span class="detail-label">Executable Path:</span> <span class="detail-value">' + proc.exe_path + '</span></div>';
                }
                if(proc.cmdline) {
                    html += '<div class="detail-item"><span class="detail-label">Command Line:</span> <span class="detail-value">' + proc.cmdline + '</span></div>';
                }
                html += '<div style="margin-top: 15px;">';
                html += '<button class="suspend" onclick="suspendProcess(' + proc.pid + ')">Suspend</button>';
                html += '<button class="secondary" onclick="resumeProcess(' + proc.pid + ')">Resume</button>';
                html += '<button class="kill" onclick="killProcess(' + proc.pid + ')">Kill</button>';
                html += '</div>';
                html += '</div>';
                document.getElementById('detailsContainer').innerHTML = html;
            }
            function killProcess(pid) {
                if(confirm('Are you sure you want to kill process ' + pid + '?')) {
                    fetch('/kill?pid=' + pid, {method: 'POST'})
                    .then(response => response.json())
                    .then(data => {
                        alert(data.message);
                        loadProcesses();
                    })
                    .catch(error => alert('Error: ' + error));
                }
            }
            function suspendProcess(pid) {
                fetch('/suspend?pid=' + pid, {method: 'POST'})
                .then(response => response.json())
                .then(data => {
                    alert(data.message);
                    loadProcesses();
                })
                .catch(error => alert('Error: ' + error));
            }
            function resumeProcess(pid) {
                fetch('/resume?pid=' + pid, {method: 'POST'})
                .then(response => response.json())
                .then(data => {
                    alert(data.message);
                    loadProcesses();
                })
                .catch(error => alert('Error: ' + error));
            }
            window.onload = function() {
                loadProcesses();
                setInterval(loadProcesses, 5000);
            };
        </script>
    </body>
    </html>
    """

@app.get("/processes")
def list_processes(limit: int = Query(None)):
    processes = get_all_processes()
    if limit:
        processes = processes[:limit]
    return {"processes": [p.dict() for p in processes], "count": len(processes)}

@app.get("/process")
def get_process(pid: int = Query(...)):
    process = get_process_by_pid(pid)
    if not process:
        return {"error": "Process not found"}
    return process.dict()

@app.get("/search")
def search_proc(keyword: str = Query(...)):
    processes = search_processes(keyword)
    return {"processes": [p.dict() for p in processes], "count": len(processes)}

@app.post("/kill")
def kill_proc(pid: int = Query(...)):
    action = kill_process(pid)
    return action.dict()

@app.post("/terminate")
def terminate_proc(pid: int = Query(...)):
    action = terminate_process(pid)
    return action.dict()

@app.post("/suspend")
def suspend_proc(pid: int = Query(...)):
    action = suspend_process(pid)
    return action.dict()

@app.post("/resume")
def resume_proc(pid: int = Query(...)):
    action = resume_process(pid)
    return action.dict()

@app.get("/children")
def get_children(pid: int = Query(...)):
    children = get_process_children(pid)
    return {"pid": pid, "children": [c.dict() for c in children], "count": len(children)}

