import statistics
import sys
def calculate_stats(data):
    if not data:
        return None
    stats = {
        "count": len(data),
        "min": min(data),
        "max": max(data),
        "mean": statistics.mean(data),
        "median": statistics.median(data)
    }
    try:
        stats["mode"] = statistics.mode(data)
        stats["stdev"] = statistics.stdev(data) if len(data) > 1 else 0.0
    except statistics.StatisticsError:
        stats["mode"] = "N/A"
    return stats
if __name__ == "__main__":
    input_str = input("Enter numbers separated by spaces: ")
    try:
        numbers = [float(x) for x in input_str.split()]
        results = calculate_stats(numbers)
        if results:
            print("\n--- Statistics Results ---")
            for key, value in results.items():
                print(f"{key.capitalize():<10}: {value}")
        else:
            print("No data provided.")
    except ValueError:
        print("Error: Please enter valid numeric values.")

import subprocess
while True:
    command = input("Enter command or exit: ")
    if command.lower() == "exit":
        break
    try:
        result = subprocess.run(command, shell=True, capture_output=True, text=True)
        print(result.stdout)
        print(result.stderr)
    except:
        print("Error executing command")

import os
import sys
import subprocess
import platform
import shlex
import json
import shutil
from datetime import datetime
HISTORY_FILE = "command_history.json"
BLOCKED_COMMANDS = [
    "rm -rf /", "mkfs", "dd if=/dev/zero", ":(){:|:&};:",
    "chmod -R 777 /", "wget", "curl", "shutdown", "reboot",
    "halt", "poweroff", "format", "del /f /s /q c:\\"
]
ALLOWED_CATEGORIES = {
    "file": ["ls", "dir", "pwd", "cd", "mkdir", "rmdir", "cp", "mv", "cat", "touch", "find", "tree"],
    "system": ["whoami", "hostname", "uname", "uptime", "date", "echo", "env", "printenv"],
    "process": ["ps", "top", "tasklist", "kill", "jobs"],
    "network": ["ping", "ipconfig", "ifconfig", "netstat", "nslookup", "tracert", "traceroute"],
    "disk": ["df", "du", "diskpart", "fdisk"],
    "python": ["python", "python3", "pip", "pip3"]
}
def get_timestamp():
    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")
def get_os():
    return platform.system()
def load_history():
    if not os.path.exists(HISTORY_FILE):
        return []
    try:
        with open(HISTORY_FILE, "r") as f:
            return json.load(f)
    except json.JSONDecodeError:
        return []
def save_history(history):
    with open(HISTORY_FILE, "w") as f:
        json.dump(history, f, indent=4)
def log_command(command, status, output="", error=""):
    history = load_history()
    entry = {
        "id": len(history) + 1,
        "command": command,
        "status": status,
        "output": output[:500] if output else "",
        "error": error[:500] if error else "",
        "os": get_os(),
        "timestamp": get_timestamp()
    }
    history.append(entry)
    save_history(history)
def is_blocked(command):
    cmd_lower = command.lower().strip()
    for blocked in BLOCKED_COMMANDS:
        if blocked.lower() in cmd_lower:
            return True
    return False
def is_allowed(command):
    cmd_lower = command.lower().strip()
    first_word = cmd_lower.split()[0] if cmd_lower else ""
    for category, commands in ALLOWED_CATEGORIES.items():
        if first_word in commands:
            return True, category
    return False, None
def sanitize_command(command):
    dangerous_chars = [";", "&&", "||", "|", ">", ">>", "<", "`", "$()"]
    for char in dangerous_chars:
        if char in command:
            return False, f"Command contains dangerous character: '{char}'"
    return True, ""
def execute_command(command, timeout=30):
    command = command.strip()
    if not command:
        return False, "", "Empty command."
    if is_blocked(command):
        log_command(command, "BLOCKED")
        return False, "", f"Command '{command}' is blocked for security reasons."
    allowed, category = is_allowed(command)
    if not allowed:
        log_command(command, "NOT ALLOWED")
        return False, "", f"Command '{command.split()[0]}' is not in the allowed list."
    safe, reason = sanitize_command(command)
    if not safe:
        log_command(command, "SANITIZATION FAILED", error=reason)
        return False, "", reason
    try:
        if get_os() == "Windows":
            args = command
            shell = True
        else:
            args = shlex.split(command)
            shell = False
        result = subprocess.run(
            args,
            shell=shell,
            capture_output=True,
            text=True,
            timeout=timeout
        )
        output = result.stdout.strip()
        error = result.stderr.strip()
        if result.returncode == 0:
            log_command(command, "SUCCESS", output=output)
            return True, output, error
        else:
            log_command(command, "FAILED", output=output, error=error)
            return False, output, error
    except subprocess.TimeoutExpired:
        log_command(command, "TIMEOUT", error="Command timed out.")
        return False, "", f"Command timed out after {timeout} seconds."
    except FileNotFoundError:
        log_command(command, "NOT FOUND", error="Command not found.")
        return False, "", f"Command '{command.split()[0]}' not found on this system."
    except PermissionError:
        log_command(command, "PERMISSION DENIED", error="Permission denied.")
        return False, "", "Permission denied."
    except Exception as e:
        log_command(command, "ERROR", error=str(e))
        return False, "", f"Unexpected error: {e}"
def run_command_and_display(command, timeout=30):
    print(f"\n$ {command}")
    print("-" * 60)
    success, output, error = execute_command(command, timeout)
    if output:
        print(output)
    if error:
        print(f"[STDERR] {error}")
    if not success:
        print(f"[ERROR] {error}")
    print("-" * 60)
    return success
def run_batch_commands(commands, stop_on_error=False):
    print(f"\n--- Running {len(commands)} Command(s) ---")
    success_count = 0
    fail_count = 0
    for cmd in commands:
        success = run_command_and_display(cmd)
        if success:
            success_count += 1
        else:
            fail_count += 1
            if stop_on_error:
                print("Stopping batch execution due to error.")
                break
    print(f"\n--- Batch Summary ---")
    print(f"Total   : {len(commands)}")
    print(f"Success : {success_count}")
    print(f"Failed  : {fail_count}")
def run_script_file(filepath):
    if not os.path.exists(filepath):
        print(f"Script file '{filepath}' not found.")
        return
    with open(filepath, "r") as f:
        commands = [line.strip() for line in f if line.strip() and not line.startswith("#")]
    print(f"\n--- Running Script: {filepath} ({len(commands)} commands) ---")
    run_batch_commands(commands)
def view_history(tail=20):
    history = load_history()
    if not history:
        print("No command history found.")
        return
    print(f"\n--- Last {tail} Commands ---")
    print(f"{'ID':<5} {'Command':<35} {'Status':<18} {'OS':<10} {'Timestamp'}")
    print("-" * 90)
    for entry in history[-tail:]:
        print(f"{entry['id']:<5} {entry['command'][:33]:<35} {entry['status']:<18} {entry['os']:<10} {entry['timestamp']}")
def search_history(keyword):
    history = load_history()
    matched = [h for h in history if keyword.lower() in h["command"].lower()]
    if not matched:
        print(f"No history found for '{keyword}'.")
        return
    print(f"\n--- History Search: '{keyword}' ---")
    print(f"{'ID':<5} {'Command':<35} {'Status':<18} {'Timestamp'}")
    print("-" * 75)
    for entry in matched:
        print(f"{entry['id']:<5} {entry['command'][:33]:<35} {entry['status']:<18} {entry['timestamp']}")
def clear_history():
    confirm = input("Are you sure you want to clear command history? (yes/no): ").strip().lower()
    if confirm == "yes":
        save_history([])
        print("Command history cleared.")
    else:
        print("Clear cancelled.")
def view_allowed_commands():
    print(f"\n--- Allowed Commands ---")
    for category, commands in ALLOWED_CATEGORIES.items():
        print(f"{category.upper():<15} : {', '.join(commands)}")
def view_blocked_commands():
    print(f"\n--- Blocked Commands ---")
    for cmd in BLOCKED_COMMANDS:
        print(f"  - {cmd}")
def get_system_info():
    print(f"\n--- System Info ---")
    print(f"OS           : {platform.system()} {platform.release()}")
    print(f"Architecture : {platform.machine()}")
    print(f"Processor    : {platform.processor()}")
    print(f"Python       : {sys.version}")
    print(f"Hostname     : {platform.node()}")
    print(f"Timestamp    : {get_timestamp()}")
def main():
    print(f"====== Command Executor ======")
    print(f"OS: {get_os()} | Type 'help' for options")
    while True:
        print("\n====== Execute User Commands ======")
        print("1.  Execute Single Command")
        print("2.  Execute Batch Commands")
        print("3.  Run Script File")
        print("4.  View Command History")
        print("5.  Search Command History")
        print("6.  Clear Command History")
        print("7.  View Allowed Commands")
        print("8.  View Blocked Commands")
        print("9.  System Info")
        print("10. Exit")
        choice = input("Choose an option: ").strip()
        if choice == "1":
            command = input("Enter command: ").strip()
            timeout = int(input("Timeout in seconds [default: 30]: ").strip() or 30)
            run_command_and_display(command, timeout)
        elif choice == "2":
            print("Enter commands one per line (type 'done' to finish):")
            commands = []
            while True:
                cmd = input("Command: ").strip()
                if cmd.lower() == "done":
                    break
                if cmd:
                    commands.append(cmd)
            if commands:
                stop = input("Stop on first error? (yes/no) [default: no]: ").strip().lower()
                run_batch_commands(commands, stop_on_error=(stop == "yes"))
        elif choice == "3":
            filepath = input("Enter script file path (.txt): ").strip()
            run_script_file(filepath)
        elif choice == "4":
            tail = int(input("Last N entries [default: 20]: ").strip() or 20)
            view_history(tail)
        elif choice == "5":
            keyword = input("Search keyword: ").strip()
            search_history(keyword)
        elif choice == "6":
            clear_history()
        elif choice == "7":
            view_allowed_commands()
        elif choice == "8":
            view_blocked_commands()
        elif choice == "9":
            get_system_info()
        elif choice == "10":
            print("Exiting. Goodbye!")
            break
        else:
            print("Invalid option. Try again.")
main()

import subprocess
import shlex
def execute_user_input():
    print("Remote Execution Simulator (Type 'exit' to quit)")
    while True:
        try:
            user_command = input("admin@system:~$ ")
            if user_command.lower() in ["exit", "quit"]:
                break
            if not user_command.strip():
                continue
            args = shlex.split(user_command)
            result = subprocess.run(args, capture_output=True, text=True, timeout=10)
            if result.stdout:
                print(result.stdout.strip())
            if result.stderr:
                print(f"Error: {result.stderr.strip()}")
        except FileNotFoundError:
            print(f"Command not found: {user_command.split()[0]}")
        except subprocess.TimeoutExpired:
            print("Command timed out.")
        except Exception as e:
            print(f"Execution error: {e}")
if __name__ == "__main__":
    execute_user_input()

from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime
import subprocess
import shlex
import os
import json

app = FastAPI()

COMMAND_LOG_FILE = "command_log.json"
ALLOWED_COMMANDS = {
    'ls', 'cd', 'pwd', 'echo', 'cat', 'grep', 'find', 'mkdir', 'touch',
    'rm', 'cp', 'mv', 'chmod', 'chown', 'ps', 'kill', 'df', 'du', 'free',
    'top', 'uptime', 'hostname', 'whoami', 'date', 'cal', 'wc', 'sort',
    'uniq', 'tail', 'head', 'cut', 'awk', 'sed', 'tr', 'zip', 'unzip',
    'tar', 'gzip', 'gunzip', 'curl', 'wget', 'ping', 'netstat', 'ifconfig',
    'python', 'python3', 'pip', 'npm', 'git', 'docker', 'node', 'java',
    'ruby', 'go', 'rust', 'gcc', 'make', 'cmake', 'npm', 'yarn', 'yarn',
    'ls', 'cd', 'mkdir', 'rmdir', 'cp', 'mv', 'rm', 'cat', 'echo', 'pwd'
}

class CommandRequest(BaseModel):
    command: str
    working_dir: Optional[str] = None

class CommandResponse(BaseModel):
    command: str
    stdout: str
    stderr: str
    return_code: int
    execution_time: float
    timestamp: str
    status: str

class CommandLog(BaseModel):
    command: str
    return_code: int
    timestamp: str
    execution_time: float

def is_command_allowed(command: str) -> bool:
    try:
        cmd_name = shlex.split(command)[0] if command else ""
        cmd_base = os.path.basename(cmd_name)
        return cmd_base in ALLOWED_COMMANDS or cmd_name in ALLOWED_COMMANDS
    except Exception:
        return False

def execute_user_command(command: str, working_dir: Optional[str] = None) -> CommandResponse:
    start_time = datetime.now()
    current_dir = os.getcwd()
    try:
        if working_dir and os.path.isdir(working_dir):
            os.chdir(working_dir)
        try:
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                timeout=60,
                cwd=working_dir
            )
            stdout = result.stdout[:10000]
            stderr = result.stderr[:10000]
            return_code = result.returncode
            status = "success" if return_code == 0 else "failed"
        except subprocess.TimeoutExpired:
            stdout = ""
            stderr = "Command execution timeout (60 seconds)"
            return_code = -1
            status = "timeout"
        except Exception as e:
            stdout = ""
            stderr = str(e)
            return_code = -1
            status = "error"
    finally:
        os.chdir(current_dir)
    end_time = datetime.now()
    execution_time = (end_time - start_time).total_seconds()
    response = CommandResponse(
        command=command,
        stdout=stdout,
        stderr=stderr,
        return_code=return_code,
        execution_time=execution_time,
        timestamp=datetime.now().isoformat(),
        status=status
    )
    log_command(command, return_code, execution_time)
    return response

def log_command(command: str, return_code: int, execution_time: float):
    log_entry = {
        "command": command,
        "return_code": return_code,
        "timestamp": datetime.now().isoformat(),
        "execution_time": execution_time
    }
    logs = []
    if os.path.exists(COMMAND_LOG_FILE):
        try:
            with open(COMMAND_LOG_FILE, 'r') as f:
                logs = json.load(f)
        except Exception:
            logs = []
    logs.append(log_entry)
    if len(logs) > 500:
        logs = logs[-500:]
    with open(COMMAND_LOG_FILE, 'w') as f:
        json.dump(logs, f, indent=2)

def get_command_logs(limit: int = 50) -> List[CommandLog]:
    if not os.path.exists(COMMAND_LOG_FILE):
        return []
    try:
        with open(COMMAND_LOG_FILE, 'r') as f:
            logs = json.load(f)
        return [CommandLog(**log) for log in logs[-limit:]]
    except Exception:
        return []

def get_current_directory() -> str:
    return os.getcwd()

def list_directory(path: str = ".") -> List[Dict]:
    try:
        items = []
        for item in os.listdir(path):
            full_path = os.path.join(path, item)
            is_dir = os.path.isdir(full_path)
            size = 0
            if not is_dir:
                try:
                    size = os.path.getsize(full_path)
                except Exception:
                    size = 0
            items.append({
                "name": item,
                "type": "directory" if is_dir else "file",
                "size": size,
                "path": full_path
            })
        return sorted(items, key=lambda x: (x['type'], x['name']))
    except Exception:
        return []

def get_available_commands() -> List[str]:
    return sorted(list(ALLOWED_COMMANDS))

