@app.post("/execute")
def execute_cmd(request: Dict):
    command = request.get('command', '').strip()
    if not command:
        return {"error": "No command provided"}
    if not is_command_allowed(command):
        return {"error": "Command not allowed for security reasons"}
    execution = execute_user_command(command)
    return execution.dict()

@app.get("/current-dir")
def get_current_dir():
    return {"directory": get_current_directory()}

@app.get("/list-dir")
def list_dir(path: str = Query(".")):
    items = list_directory(path)
    return {"path": path, "items": items}

@app.get("/history")
def get_history(limit: int = Query(50)):
    logs = get_command_logs(limit)
    return {"logs": [l.dict() for l in logs], "count": len(logs)}

@app.delete("/history/clear")
def clear_cmd_history():
    if os.path.exists(COMMAND_LOG_FILE):
        os.remove(COMMAND_LOG_FILE)
    return {"status": "success", "message": "History cleared"}

@app.get("/commands")
def list_commands():
    return {"commands": get_available_commands()}

