import os
import sys
import shutil
import zipfile
import tarfile
import json
import hashlib
import schedule
import time
import threading
from datetime import datetime
BACKUP_DIR = "backups"
CONFIG_FILE = "backup_config.json"
LOG_FILE = "backup_log.json"
def get_timestamp():
    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")
def get_file_timestamp():
    return datetime.now().strftime("%Y%m%d_%H%M%S")
def get_file_size(path):
    if os.path.isfile(path):
        size = os.path.getsize(path)
    else:
        size = sum(
            os.path.getsize(os.path.join(dirpath, f))
            for dirpath, _, files in os.walk(path)
            for f in files
        )
    if size < 1024:
        return f"{size} B"
    elif size < 1024 ** 2:
        return f"{size / 1024:.2f} KB"
    elif size < 1024 ** 3:
        return f"{size / (1024 ** 2):.2f} MB"
    else:
        return f"{size / (1024 ** 3):.2f} GB"
def get_file_hash(filepath):
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()
def ensure_directory(path):
    if not os.path.exists(path):
        os.makedirs(path)
def load_config():
    if not os.path.exists(CONFIG_FILE):
        return {"backup_jobs": []}
    with open(CONFIG_FILE, "r") as f:
        return json.load(f)
def save_config(config):
    with open(CONFIG_FILE, "w") as f:
        json.dump(config, f, indent=4)
def load_log():
    if not os.path.exists(LOG_FILE):
        return []
    try:
        with open(LOG_FILE, "r") as f:
            return json.load(f)
    except json.JSONDecodeError:
        return []
def save_log(logs):
    with open(LOG_FILE, "w") as f:
        json.dump(logs, f, indent=4)
def log_backup(job_name, source, destination, status, size="", reason=""):
    logs = load_log()
    entry = {
        "id": len(logs) + 1,
        "job_name": job_name,
        "source": source,
        "destination": destination,
        "status": status,
        "size": size,
        "reason": reason,
        "timestamp": get_timestamp()
    }
    logs.append(entry)
    save_log(logs)
def create_zip_backup(source_path, destination, job_name="backup"):
    ensure_directory(destination)
    base_name = os.path.basename(source_path.rstrip("/\\"))
    zip_filename = f"{job_name}_{base_name}_{get_file_timestamp()}.zip"
    zip_path = os.path.join(destination, zip_filename)
    with zipfile.ZipFile(zip_path, "w", zipfile.ZIP_DEFLATED) as zipf:
        if os.path.isfile(source_path):
            zipf.write(source_path, os.path.basename(source_path))
        elif os.path.isdir(source_path):
            for root, dirs, files in os.walk(source_path):
                for file in files:
                    file_path = os.path.join(root, file)
                    arcname = os.path.relpath(file_path, os.path.dirname(source_path))
                    zipf.write(file_path, arcname)
    return zip_path
def create_tar_backup(source_path, destination, job_name="backup", compress=True):
    ensure_directory(destination)
    base_name = os.path.basename(source_path.rstrip("/\\"))
    ext = "tar.gz" if compress else "tar"
    tar_filename = f"{job_name}_{base_name}_{get_file_timestamp()}.{ext}"
    tar_path = os.path.join(destination, tar_filename)
    mode = "w:gz" if compress else "w"
    with tarfile.open(tar_path, mode) as tar:
        tar.add(source_path, arcname=os.path.basename(source_path))
    return tar_path
def create_copy_backup(source_path, destination, job_name="backup"):
    ensure_directory(destination)
    base_name = os.path.basename(source_path.rstrip("/\\"))
    copy_name = f"{job_name}_{base_name}_{get_file_timestamp()}"
    copy_path = os.path.join(destination, copy_name)
    if os.path.isfile(source_path):
        shutil.copy2(source_path, copy_path)
    elif os.path.isdir(source_path):
        shutil.copytree(source_path, copy_path)
    return copy_path
def run_backup(job):
    job_name = job.get("name", "backup")
    source = job.get("source", "")
    destination = job.get("destination", BACKUP_DIR)
    fmt = job.get("format", "zip")
    max_backups = job.get("max_backups", 5)
    print(f"\n[{get_timestamp()}] Running backup job: '{job_name}'")
    if not source or not os.path.exists(source):
        msg = f"Source path '{source}' does not exist."
        print(f"[ERROR] {msg}")
        log_backup(job_name, source, destination, "FAILED", reason=msg)
        return False
    try:
        if fmt == "zip":
            backup_path = create_zip_backup(source, destination, job_name)
        elif fmt in ["tar", "tar.gz"]:
            compress = fmt == "tar.gz"
            backup_path = create_tar_backup(source, destination, job_name, compress)
        elif fmt == "copy":
            backup_path = create_copy_backup(source, destination, job_name)
        else:
            msg = f"Unsupported format '{fmt}'."
            print(f"[ERROR] {msg}")
            log_backup(job_name, source, destination, "FAILED", reason=msg)
            return False
        size = get_file_size(backup_path)
        file_hash = get_file_hash(backup_path) if os.path.isfile(backup_path) else "N/A"
        print(f"[SUCCESS] Backup created: {backup_path}")
        print(f"          Size     : {size}")
        print(f"          SHA256   : {file_hash}")
        log_backup(job_name, source, backup_path, "SUCCESS", size=size)
        rotate_backups(destination, job_name, max_backups)
        return True
    except Exception as e:
        print(f"[ERROR] Backup failed: {e}")
        log_backup(job_name, source, destination, "FAILED", reason=str(e))
        return False
def rotate_backups(destination, job_name, max_backups):
    if not os.path.exists(destination):
        return
    all_backups = sorted([
        f for f in os.listdir(destination)
        if f.startswith(job_name)
    ])
    while len(all_backups) > max_backups:
        oldest = os.path.join(destination, all_backups.pop(0))
        if os.path.isfile(oldest):
            os.remove(oldest)
        elif os.path.isdir(oldest):
            shutil.rmtree(oldest)
        print(f"[ROTATED] Removed old backup: {oldest}")
def add_backup_job(name, source, destination, fmt, schedule_type, schedule_time, max_backups=5):
    config = load_config()
    for job in config["backup_jobs"]:
        if job["name"] == name:
            print(f"Job '{name}' already exists.")
            return False
    job = {
        "name": name,
        "source": source,
        "destination": destination,
        "format": fmt,
        "schedule_type": schedule_type,
        "schedule_time": schedule_time,
        "max_backups": max_backups,
        "enabled": True,
        "created_at": get_timestamp()
    }
    config["backup_jobs"].append(job)
    save_config(config)
    print(f"Backup job '{name}' added successfully.")
    return True
def remove_backup_job(name):
    config = load_config()
    original = len(config["backup_jobs"])
    config["backup_jobs"] = [j for j in config["backup_jobs"] if j["name"] != name]
    if len(config["backup_jobs"]) == original:
        print(f"Job '{name}' not found.")
        return False
    save_config(config)
    print(f"Backup job '{name}' removed.")
    return True
def toggle_backup_job(name, enable=True):
    config = load_config()
    for job in config["backup_jobs"]:
        if job["name"] == name:
            job["enabled"] = enable
            save_config(config)
            state = "enabled" if enable else "disabled"
            print(f"Backup job '{name}' {state}.")
            return True
    print(f"Job '{name}' not found.")
    return False
def run_job_by_name(name):
    config = load_config()
    for job in config["backup_jobs"]:
        if job["name"] == name:
            run_backup(job)
            return True
    print(f"Job '{name}' not found.")
    return False
def run_all_jobs():
    config = load_config()
    jobs = [j for j in config["backup_jobs"] if j.get("enabled", True)]
    if not jobs:
        print("No enabled backup jobs found.")
        return
    print(f"\n--- Running All {len(jobs)} Backup Job(s) ---")
    success = 0
    failed = 0
    for job in jobs:
        result = run_backup(job)
        if result:
            success += 1
        else:
            failed += 1
    print(f"\n--- Backup Summary ---")
    print(f"Total   : {len(jobs)}")
    print(f"Success : {success}")
    print(f"Failed  : {failed}")
def schedule_jobs():
    config = load_config()
    jobs = [j for j in config["backup_jobs"] if j.get("enabled", True)]
    schedule.clear()
    for job in jobs:
        stype = job.get("schedule_type", "daily")
        stime = job.get("schedule_time", "02:00")
        if stype == "minutely":
            schedule.every(int(stime)).minutes.do(run_backup, job)
        elif stype == "hourly":
            schedule.every().hour.at(f":{stime.zfill(2)}").do(run_backup, job)
        elif stype == "daily":
            schedule.every().day.at(stime).do(run_backup, job)
        elif stype == "weekly":
            schedule.every().week.at(stime).do(run_backup, job)
        print(f"Scheduled: '{job['name']}' → {stype} at {stime}")
def start_scheduler():
    schedule_jobs()
    print(f"\n[{get_timestamp()}] Scheduler started. Press Ctrl+C to stop.")
    def run():
        while True:
            schedule.run_pending()
            time.sleep(1)
    thread = threading.Thread(target=run, daemon=True)
    thread.start()
    return thread
def list_backup_jobs():
    config = load_config()
    jobs = config.get("backup_jobs", [])
    if not jobs:
        print("No backup jobs configured.")
        return
    print(f"\n{'Name':<20} {'Source':<25} {'Format':<10} {'Schedule':<12} {'Time':<8} {'Enabled':<8} {'Max'}")
    print("-" * 100)
    for job in jobs:
        enabled = "Yes" if job.get("enabled", True) else "No"
        print(f"{job['name']:<20} {job['source'][:23]:<25} {job['format']:<10} {job['schedule_type']:<12} {job['schedule_time']:<8} {enabled:<8} {job.get('max_backups', 5)}")
def list_backups_in_dir(directory=BACKUP_DIR):
    if not os.path.exists(directory):
        print(f"Directory '{directory}' not found.")
        return
    items = os.listdir(directory)
    if not items:
        print("No backups found.")
        return
    print(f"\n--- Backups in '{directory}' ---")
    print(f"{'#':<5} {'Name':<50} {'Size':<12} {'Modified'}")
    print("-" * 90)
    for i, item in enumerate(sorted(items), 1):
        item_path = os.path.join(directory, item)
        size = get_file_size(item_path)
        modified = datetime.fromtimestamp(os.path.getmtime(item_path)).strftime("%Y-%m-%d %H:%M:%S")
        print(f"{i:<5} {item:<50} {size:<12} {modified}")
def view_logs(tail=20):
    logs = load_log()
    if not logs:
        print("No backup logs found.")
        return
    print(f"\n--- Last {tail} Backup Logs ---")
    print(f"{'ID':<5} {'Job':<20} {'Status':<10} {'Size':<10} {'Timestamp'}")
    print("-" * 70)
    for log in logs[-tail:]:
        print(f"{log['id']:<5} {log['job_name']:<20} {log['status']:<10} {log.get('size', 'N/A'):<10} {log['timestamp']}")
def restore_backup(backup_path, restore_destination):
    if not os.path.exists(backup_path):
        print(f"Backup '{backup_path}' not found.")
        return False
    ensure_directory(restore_destination)
    try:
        if backup_path.endswith(".zip"):
            with zipfile.ZipFile(backup_path, "r") as zipf:
                zipf.extractall(restore_destination)
        elif backup_path.endswith(".tar.gz") or backup_path.endswith(".tar"):
            with tarfile.open(backup_path, "r:*") as tar:
                tar.extractall(restore_destination)
        elif os.path.isdir(backup_path):
            base = os.path.basename(backup_path.rstrip("/\\"))
            shutil.copytree(backup_path, os.path.join(restore_destination, base))
        else:
            shutil.copy2(backup_path, restore_destination)
        print(f"Backup restored to '{restore_destination}' successfully.")
        return True
    except Exception as e:
        print(f"Restore failed: {e}")
        return False
def delete_backup(backup_path):
    if not os.path.exists(backup_path):
        print(f"Backup '{backup_path}' not found.")
        return False
    confirm = input(f"Delete '{backup_path}'? (yes/no): ").strip().lower()
    if confirm == "yes":
        if os.path.isfile(backup_path):
            os.remove(backup_path)
        elif os.path.isdir(backup_path):
            shutil.rmtree(backup_path)
        print(f"Backup '{backup_path}' deleted.")
        return True
    print("Delete cancelled.")
    return False
def get_backup_summary():
    config = load_config()
    logs = load_log()
    total_jobs = len(config.get("backup_jobs", []))
    enabled_jobs = sum(1 for j in config.get("backup_jobs", []) if j.get("enabled", True))
    total_logs = len(logs)
    success_logs = sum(1 for l in logs if l["status"] == "SUCCESS")
    failed_logs = sum(1 for l in logs if l["status"] == "FAILED")
    print(f"\n{'=' * 45}")
    print(f"  BACKUP SYSTEM SUMMARY")
    print(f"  Generated: {get_timestamp()}")
    print(f"{'=' * 45}")
    print(f"  Total Jobs      : {total_jobs}")
    print(f"  Enabled Jobs    : {enabled_jobs}")
    print(f"  Total Runs      : {total_logs}")
    print(f"  Successful      : {success_logs}")
    print(f"  Failed          : {failed_logs}")
    if os.path.exists(BACKUP_DIR):
        total_size = sum(
            os.path.getsize(os.path.join(BACKUP_DIR, f))
            for f in os.listdir(BACKUP_DIR)
            if os.path.isfile(os.path.join(BACKUP_DIR, f))
        )
        print(f"  Backup Dir Size : {total_size / 1024:.2f} KB")
    print(f"{'=' * 45}")
def main():
    scheduler_thread = None
    while True:
        print("\n====== Backup Automation System ======")
        print("1.  Add Backup Job")
        print("2.  Remove Backup Job")
        print("3.  Enable / Disable Job")
        print("4.  List Backup Jobs")
        print("5.  Run Single Job Now")
        print("6.  Run All Jobs Now")
        print("7.  Start Scheduler")
        print("8.  List Backup Files")
        print("9.  Restore Backup")
        print("10. Delete Backup")
        print("11. View Backup Logs")
        print("12. View Backup Summary")
        print("13. Exit")
        choice = input("Choose an option: ").strip()
        if choice == "1":
            name = input("Job Name: ").strip()
            source = input("Source Path (file or folder): ").strip()
            destination = input(f"Destination [default: {BACKUP_DIR}]: ").strip() or BACKUP_DIR
            print("Formats: zip, tar, tar.gz, copy")
            fmt = input("Format [default: zip]: ").strip() or "zip"
            print("Schedule Types: minutely, hourly, daily, weekly")
            stype = input("Schedule Type [default: daily]: ").strip() or "daily"
            stime = input("Schedule Time (HH:MM or minutes for minutely) [default: 02:00]: ").strip() or "02:00"
            max_b = int(input("Max Backups to Keep [default: 5]: ").strip() or 5)
            add_backup_job(name, source, destination, fmt, stype, stime, max_b)
        elif choice == "2":
            name = input("Job Name to Remove: ").strip()
            remove_backup_job(name)
        elif choice == "3":
            name = input("Job Name: ").strip()
            action = input("Enable or Disable? (enable/disable): ").strip().lower()
            toggle_backup_job(name, enable=(action == "enable"))
        elif choice == "4":
            list_backup_jobs()
        elif choice == "5":
            name = input("Job Name to Run: ").strip()
            run_job_by_name(name)
        elif choice == "6":
            run_all_jobs()
        elif choice == "7":
            if scheduler_thread and scheduler_thread.is_alive():
                print("Scheduler is already running.")
            else:
                scheduler_thread = start_scheduler()
                print("Scheduler is running in background.")
        elif choice == "8":
            directory = input(f"Backup Directory [default: {BACKUP_DIR}]: ").strip() or BACKUP_DIR
            list_backups_in_dir(directory)
        elif choice == "9":
            backup_path = input("Backup File/Folder Path: ").strip()
            restore_dest = input("Restore Destination Path: ").strip()
            restore_backup(backup_path, restore_dest)
        elif choice == "10":
            backup_path = input("Backup File/Folder Path to Delete: ").strip()
            delete_backup(backup_path)
        elif choice == "11":
            tail = int(input("Last N logs [default: 20]: ").strip() or 20)
            view_logs(tail)
        elif choice == "12":
            get_backup_summary()
        elif choice == "13":
            print("Exiting. Goodbye!")
            sys.exit(0)
        else:
            print("Invalid option. Try again.")
main()

from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse, FileResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime, timedelta
import os
import shutil
import zipfile
import json
import schedule
import time
import threading
import glob

app = FastAPI()

BACKUP_DIR = "automated_backups"
SOURCE_DIR = "data"
CONFIG_FILE = "backup_config.json"
BACKUP_HISTORY_FILE = "backup_history.json"
MAX_BACKUPS = 10

if not os.path.exists(BACKUP_DIR):
    os.makedirs(BACKUP_DIR)

if not os.path.exists(SOURCE_DIR):
    os.makedirs(SOURCE_DIR)

class BackupConfig(BaseModel):
    enabled: bool
    schedule_type: str
    schedule_time: str
    retention_days: int
    max_backups: int
    backup_name_prefix: str
    compress: bool
    exclude_patterns: List[str] = []

class BackupJob(BaseModel):
    backup_id: str
    backup_path: str
    backup_size: float
    file_count: int
    backup_date: str
    status: str
    duration: float
    file_list: List[str] = []

class BackupSchedule(BaseModel):
    schedule_type: str
    schedule_time: str
    next_run: str
    enabled: bool

def load_backup_config() -> BackupConfig:
    if os.path.exists(CONFIG_FILE):
        try:
            with open(CONFIG_FILE, 'r') as f:
                config_data = json.load(f)
            return BackupConfig(**config_data)
        except Exception:
            pass
    return BackupConfig(
        enabled=True,
        schedule_type="daily",
        schedule_time="02:00",
        retention_days=30,
        max_backups=10,
        backup_name_prefix="backup",
        compress=True,
        exclude_patterns=[]
    )

def save_backup_config(config: BackupConfig):
    with open(CONFIG_FILE, 'w') as f:
        json.dump(config.dict(), f, indent=2)

def should_exclude(file_path: str, patterns: List[str]) -> bool:
    for pattern in patterns:
        if pattern in file_path:
            return True
    return False

def get_directory_size(path: str) -> int:
    total_size = 0
    try:
        for dirpath, dirnames, filenames in os.walk(path):
            for filename in filenames:
                file_path = os.path.join(dirpath, filename)
                if os.path.exists(file_path):
                    total_size += os.path.getsize(file_path)
    except Exception:
        pass
    return total_size

def count_files_in_directory(path: str, exclude_patterns: List[str] = []) -> int:
    count = 0
    try:
        for dirpath, dirnames, filenames in os.walk(path):
            for filename in filenames:
                file_path = os.path.join(dirpath, filename)
                if not should_exclude(file_path, exclude_patterns):
                    count += 1
    except Exception:
        pass
    return count

def create_backup(backup_id: str, config: BackupConfig) -> BackupJob:
    start_time = datetime.now()
    backup_filename = f"{config.backup_name_prefix}_{backup_id}"
    if config.compress:
        backup_path = os.path.join(BACKUP_DIR, f"{backup_filename}.zip")
    else:
        backup_path = os.path.join(BACKUP_DIR, backup_filename)
    file_list = []
    try:
        if config.compress:
            with zipfile.ZipFile(backup_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
                for dirpath, dirnames, filenames in os.walk(SOURCE_DIR):
                    for filename in filenames:
                        file_path = os.path.join(dirpath, filename)
                        if not should_exclude(file_path, config.exclude_patterns):
                            arcname = os.path.relpath(file_path, SOURCE_DIR)
                            zipf.write(file_path, arcname)
                            file_list.append(arcname)
        else:
            backup_full_path = backup_path
            if os.path.exists(backup_full_path):
                shutil.rmtree(backup_full_path)
            shutil.copytree(SOURCE_DIR, backup_full_path)
            for dirpath, dirnames, filenames in os.walk(SOURCE_DIR):
                for filename in filenames:
                    file_path = os.path.join(dirpath, filename)
                    if not should_exclude(file_path, config.exclude_patterns):
                        file_list.append(os.path.relpath(file_path, SOURCE_DIR))
        backup_size = os.path.getsize(backup_path) / (1024 * 1024)
        file_count = len(file_list)
        status = "success"
    except Exception as e:
        backup_size = 0
        file_count = 0
        status = f"failed: {str(e)}"
    end_time = datetime.now()
    duration = (end_time - start_time).total_seconds()
    backup_job = BackupJob(
        backup_id=backup_id,
        backup_path=backup_path,
        backup_size=backup_size,
        file_count=file_count,
        backup_date=datetime.now().isoformat(),
        status=status,
        duration=duration,
        file_list=file_list[:50]
    )
    save_backup_history(backup_job)
    cleanup_old_backups(config)
    return backup_job

def save_backup_history(backup_job: BackupJob):
    history = []
    if os.path.exists(BACKUP_HISTORY_FILE):
        try:
            with open(BACKUP_HISTORY_FILE, 'r') as f:
                history = json.load(f)
        except Exception:
            history = []
    history.append({
        "backup_id": backup_job.backup_id,
        "backup_path": backup_job.backup_path,
        "backup_size": backup_job.backup_size,
        "file_count": backup_job.file_count,
        "backup_date": backup_job.backup_date,
        "status": backup_job.status,
        "duration": backup_job.duration
    })
    with open(BACKUP_HISTORY_FILE, 'w') as f:
        json.dump(history, f, indent=2)

def get_backup_history(limit: int = 50) -> List[BackupJob]:
    if not os.path.exists(BACKUP_HISTORY_FILE):
        return []
    try:
        with open(BACKUP_HISTORY_FILE, 'r') as f:
            history = json.load(f)
        return [BackupJob(**entry) for entry in history[-limit:]]
    except Exception:
        return []

def cleanup_old_backups(config: BackupConfig):
    backups = []
    if os.path.exists(BACKUP_DIR):
        for filename in os.listdir(BACKUP_DIR):
            file_path = os.path.join(BACKUP_DIR, filename)
            if filename.startswith(config.backup_name_prefix):
                backups.append((file_path, os.path.getmtime(file_path)))
    backups.sort(key=lambda x: x[1], reverse=True)
    for backup_path, _ in backups[config.max_backups:]:
        try:
            if os.path.isfile(backup_path):
                os.remove(backup_path)
            elif os.path.isdir(backup_path):
                shutil.rmtree(backup_path)
        except Exception:
            pass

def list_backups() -> List[BackupJob]:
    backups = []
    if os.path.exists(BACKUP_DIR):
        for filename in os.listdir(BACKUP_DIR):
            file_path = os.path.join(BACKUP_DIR, filename)
            try:
                file_size = os.path.getsize(file_path) / (1024 * 1024)
                modified_time = datetime.fromtimestamp(os.path.getmtime(file_path)).isoformat()
                backups.append(BackupJob(
                    backup_id=filename,
                    backup_path=file_path,
                    backup_size=file_size,
                    file_count=0,
                    backup_date=modified_time,
                    status="completed",
                    duration=0
                ))
            except Exception:
                pass
    return sorted(backups, key=lambda x: x.backup_date, reverse=True)

def restore_backup(backup_id: str) -> bool:
    backup_path = os.path.join(BACKUP_DIR, backup_id)
    if not os.path.exists(backup_path):
        return False
    try:
        if os.path.exists(SOURCE_DIR):
            shutil.rmtree(SOURCE_DIR)
        os.makedirs(SOURCE_DIR)
        if backup_path.endswith('.zip'):
            with zipfile.ZipFile(backup_path, 'r') as zipf:
                zipf.extractall(SOURCE_DIR)
        else:
            shutil.copytree(backup_path, SOURCE_DIR)
        return True
    except Exception:
        return False

def delete_backup(backup_id: str) -> bool:
    backup_path = os.path.join(BACKUP_DIR, backup_id)
    if not os.path.exists(backup_path):
        return False
    try:
        if os.path.isfile(backup_path):
            os.remove(backup_path)
        elif os.path.isdir(backup_path):
            shutil.rmtree(backup_path)
        return True
    except Exception:
        return False

def get_backup_statistics() -> Dict:
    backups = list_backups()
    total_size = sum(b.backup_size for b in backups)
    source_size = get_directory_size(SOURCE_DIR) / (1024 * 1024)
    return {
        "total_backups": len(backups),
        "total_backup_size_mb": total_size,
        "source_size_mb": source_size,
        "latest_backup": backups[0].backup_date if backups else None,
        "oldest_backup": backups[-1].backup_date if backups else None
    }

def schedule_backup_jobs(config: BackupConfig):
    schedule.clear()
    if not config.enabled:
        return
    if config.schedule_type == "daily":
        schedule.every().day.at(config.schedule_time).do(lambda: create_backup(datetime.now().strftime("%Y%m%d_%H%M%S"), config))
    elif config.schedule_type == "hourly":
        schedule.every().hour.do(lambda: create_backup(datetime.now().strftime("%Y%m%d_%H%M%S"), config))
    elif config.schedule_type == "weekly":
        schedule.every().monday.at(config.schedule_time).do(lambda: create_backup(datetime.now().strftime("%Y%m%d_%H%M%S"), config))
    elif config.schedule_type == "monthly":
        schedule.every().month.do(lambda: create_backup(datetime.now().strftime("%Y%m%d_%H%M%S"), config))

def run_scheduler():
    while True:
        schedule.run_pending()
        time.sleep(60)

backup_thread = threading.Thread(target=run_scheduler, daemon=True)
backup_thread.start()

initial_config = load_backup_config()
schedule_backup_jobs(initial_config)

@app.get("/", response_class=HTMLResponse)
def get_home():
    backups = list_backups()
    stats = get_backup_statistics()
    config = load_backup_config()
    backups_html = ""
