                <button onclick="downloadBackup('{backup.backup_id}')">Download</button>
                <button onclick="restoreBackup('{backup.backup_id}')">Restore</button>
                <button onclick="deleteBackup('{backup.backup_id}')">Delete</button>
            </td>
        </tr>
        """
    return f"""
