                            <th>Status</th>
                            <th>Duration (s)</th>
                        </tr>
                    </table>
                </div>
            </div>
        </div>
        <script>
            function switchTab(tabName) {{
                const tabs = document.querySelectorAll('.tab-content');
                tabs.forEach(tab => tab.classList.remove('active'));
                document.getElementById(tabName).classList.add('active');
                const buttons = document.querySelectorAll('.tab-button');
                buttons.forEach(btn => btn.classList.remove('active'));
                event.target.classList.add('active');
                if(tabName === 'history-tab') {{
                    loadHistory();
                }}
            }}
            function createBackupNow() {{
                if(confirm('Create backup now?')) {{
                    fetch('/backup/create-now', {{method: 'POST'}})
                    .then(response => response.json())
                    .then(data => {{
                        alert('Backup created successfully!');
                        refreshBackups();
                    }})
                    .catch(error => alert('Error: ' + error));
                }}
            }}
            function refreshBackups() {{
                location.reload();
            }}
            function downloadBackup(backupId) {{
                window.location.href = '/backup/download?backup_id=' + encodeURIComponent(backupId);
            }}
            function restoreBackup(backupId) {{
                if(confirm('Restore backup ' + backupId + '? Current data will be replaced.')) {{
                    fetch('/backup/restore?backup_id=' + encodeURIComponent(backupId), {{method: 'POST'}})
                    .then(response => response.json())
                    .then(data => {{
                        alert('Backup restored successfully!');
                        location.reload();
                    }})
                    .catch(error => alert('Error: ' + error));
                }}
            }}
            function deleteBackup(backupId) {{
                if(confirm('Delete backup ' + backupId + '?')) {{
                    fetch('/backup/delete?backup_id=' + encodeURIComponent(backupId), {{method: 'DELETE'}})
                    .then(response => response.json())
                    .then(data => {{
                        alert('Backup deleted!');
                        location.reload();
                    }})
                    .catch(error => alert('Error: ' + error));
                }}
            }}
            function saveConfiguration() {{
                const config = {{
                    enabled: document.getElementById('enableBackup').checked,
                    schedule_type: document.getElementById('scheduleType').value,
                    schedule_time: document.getElementById('scheduleTime').value,
                    retention_days: parseInt(document.getElementById('retentionDays').value),
                    max_backups: parseInt(document.getElementById('maxBackups').value),
                    backup_name_prefix: document.getElementById('backupPrefix').value,
                    compress: document.getElementById('compressBackup').checked,
                    exclude_patterns: document.getElementById('excludePatterns').value.split(',').map(s => s.trim()).filter(s => s)
                }};
                fetch('/backup/config', {{
                    method: 'POST',
                    headers: {{'Content-Type': 'application/json'}},
                    body: JSON.stringify(config)
                }})
                .then(response => response.json())
                .then(data => {{
                    alert('Configuration saved!');
                }})
                .catch(error => alert('Error: ' + error));
            }}
            function loadHistory() {{
                fetch('/backup/history')
                .then(response => response.json())
                .then(data => displayHistory(data.history))
                .catch(error => console.error('Error:', error));
            }}
            function displayHistory(history) {{
                const table = document.getElementById('historyTable');
                let html = '<tr><th>Backup ID</th><th>Size (MB)</th><th>Files</th><th>Date</th><th>Status</th><th>Duration (s)</th></tr>';
                history.forEach(entry => {{
                    html += '<tr>';
                    html += '<td>' + entry.backup_id + '</td>';
                    html += '<td>' + entry.backup_size.toFixed(2) + '</td>';
                    html += '<td>' + entry.file_count + '</td>';
                    html += '<td>' + new Date(entry.backup_date).toLocaleString() + '</td>';
                    html += '<td>' + entry.status + '</td>';
                    html += '<td>' + entry.duration.toFixed(2) + '</td>';
                    html += '</tr>';
                }});
                table.innerHTML = html;
            }}
        </script>
    </body>
    </html>
    """

@app.post("/backup/create-now")
def create_backup_now():
    config = load_backup_config()
    backup_id = datetime.now().strftime("%Y%m%d_%H%M%S")
    backup = create_backup(backup_id, config)
    return {
        "status": "success",
        "backup_id": backup.backup_id,
        "backup_size": backup.backup_size,
        "file_count": backup.file_count
    }

@app.post("/backup/config")
def update_config(config: BackupConfig):
    save_backup_config(config)
    schedule_backup_jobs(config)
    return {"status": "success", "message": "Configuration updated"}

@app.get("/backup/list")
def list_backups_endpoint():
    backups = list_backups()
    return {"backups": [b.dict() for b in backups], "count": len(backups)}

@app.get("/backup/history")
def get_history(limit: int = Query(50)):
    history = get_backup_history(limit)
    return {"history": [h.dict() for h in history], "count": len(history)}

@app.post("/backup/restore")
def restore_backup_endpoint(backup_id: str = Query(...)):
    if restore_backup(backup_id):
        return {"status": "success", "message": f"Backup {backup_id} restored"}
    return {"status": "error", "message": "Restore failed"}

@app.delete("/backup/delete")
def delete_backup_endpoint(backup_id: str = Query(...)):
    if delete_backup(backup_id):
        return {"status": "success", "message": "Backup deleted"}
    return {"status": "error", "message": "Backup not found"}

@app.get("/backup/download")
def download_backup(backup_id: str = Query(...)):
    backup_path = os.path.join(BACKUP_DIR, backup_id)
    if not os.path.exists(backup_path):
        return {"error": "Backup not found"}
    return FileResponse(backup_path, filename=backup_id)

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

import schedule
import time
import threading
import json
import argparse
import platform
import os
import subprocess
import shlex
from datetime import datetime, timedelta
from pathlib import Path
SCHEDULER_CONFIG = {
    "log_file": "scheduler_log.json",
    "max_logs": 100,
    "timezone": "local",
    "retry_on_failure": True,
    "max_retries": 3,
    "retry_delay_seconds": 5
}
scheduled_jobs = {}
job_logs = []
job_stats = {}
lock = threading.Lock()
def format_timestamp():
    return datetime.now().strftime('%Y-%m-%d %H:%M:%S')
def format_size(size_bytes):
    if size_bytes < 1024:
        return f"{size_bytes} B"
    elif size_bytes < 1024 ** 2:
        return f"{size_bytes / 1024:.2f} KB"
    else:
        return f"{size_bytes / (1024 ** 2):.2f} MB"
def log_job(job_id, status, details):
    with lock:
        entry = {
            "id": len(job_logs) + 1,
            "job_id": job_id,
            "status": status,
            "details": details,
            "timestamp": format_timestamp()
        }
        job_logs.append(entry)
        if len(job_logs) > SCHEDULER_CONFIG['max_logs']:
            job_logs.pop(0)
        try:
            with open(SCHEDULER_CONFIG['log_file'], 'w') as f:
                json.dump(job_logs, f, indent=4)
        except Exception:
            pass
        return entry
def update_stats(job_id, success):
    with lock:
        if job_id not in job_stats:
            job_stats[job_id] = {
                "total_runs": 0,
                "successful_runs": 0,
                "failed_runs": 0,
                "last_run": None,
                "last_status": None
            }
        job_stats[job_id]['total_runs'] += 1
        if success:
            job_stats[job_id]['successful_runs'] += 1
        else:
            job_stats[job_id]['failed_runs'] += 1
        job_stats[job_id]['last_run'] = format_timestamp()
        job_stats[job_id]['last_status'] = "success" if success else "failed"
def execute_shell_command(command, timeout=30):
    system = platform.system()
    try:
        if system == "Windows":
            process = subprocess.Popen(
                command,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=True,
                text=True
            )
        else:
            args = shlex.split(command)
            process = subprocess.Popen(
                args,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                shell=False,
                text=True
            )
        stdout, stderr = process.communicate(timeout=timeout)
        return {
            "success": process.returncode == 0,
            "return_code": process.returncode,
            "stdout": stdout.strip(),
            "stderr": stderr.strip()
        }
    except subprocess.TimeoutExpired:
        process.kill()
        return {"success": False, "error": f"Command timed out after {timeout}s"}
    except Exception as e:
        return {"success": False, "error": str(e)}
def create_job_runner(job_id, job_config):
    def runner():
        job_name = job_config.get('name', job_id)
        job_type = job_config.get('type', 'function')
        retries = 0
        max_retries = SCHEDULER_CONFIG['max_retries'] if SCHEDULER_CONFIG['retry_on_failure'] else 0
        print(f"\n  [{format_timestamp()}] Running job: '{job_name}' (ID: {job_id})")
        while retries <= max_retries:
            try:
                start_time = datetime.now()
                if job_type == 'shell':
                    command = job_config.get('command', '')
                    result = execute_shell_command(command, timeout=job_config.get('timeout', 30))
                    success = result.get('success', False)
                    output = result.get('stdout', '') or result.get('error', '')
                elif job_type == 'function':
                    func = job_config.get('function')
                    if callable(func):
                        func_result = func()
                        success = True
                        output = str(func_result) if func_result else "Completed"
                    else:
                        success = False
                        output = "No callable function provided"
                elif job_type == 'python':
                    script = job_config.get('script', '')
                    result = execute_shell_command(f"python {script}", timeout=job_config.get('timeout', 60))
                    success = result.get('success', False)
                    output = result.get('stdout', '') or result.get('error', '')
                else:
                    success = False
                    output = f"Unknown job type: {job_type}"
                end_time = datetime.now()
                duration = (end_time - start_time).total_seconds()
                if success:
                    print(f"  [{format_timestamp()}] Job '{job_name}' completed in {round(duration, 2)}s")
                    log_job(job_id, "success", {
                        "name": job_name,
                        "type": job_type,
                        "duration_seconds": round(duration, 2),
                        "output": output[:200] if output else ""
                    })
                    update_stats(job_id, True)
                    break
                else:
                    raise Exception(output or "Job execution failed")
            except Exception as e:
                retries += 1
                if retries <= max_retries:
                    print(f"  [{format_timestamp()}] Job '{job_name}' failed. Retry {retries}/{max_retries} in {SCHEDULER_CONFIG['retry_delay_seconds']}s...")
                    log_job(job_id, "retry", {"name": job_name, "attempt": retries, "error": str(e)})
                    time.sleep(SCHEDULER_CONFIG['retry_delay_seconds'])
                else:
                    print(f"  [{format_timestamp()}] Job '{job_name}' failed after {max_retries} retries: {str(e)}")
                    log_job(job_id, "failed", {"name": job_name, "error": str(e), "retries": retries - 1})
                    update_stats(job_id, False)
    return runner
def add_job(job_id, job_config):
    runner = create_job_runner(job_id, job_config)
    interval = job_config.get('interval', 'every_minute')
    scheduled_jobs[job_id] = {"config": job_config, "runner": runner, "schedule": interval}
    if interval == 'every_minute':
        schedule.every(1).minutes.do(runner).tag(job_id)
    elif interval == 'every_5_minutes':
        schedule.every(5).minutes.do(runner).tag(job_id)
    elif interval == 'every_10_minutes':
        schedule.every(10).minutes.do(runner).tag(job_id)
    elif interval == 'every_15_minutes':
        schedule.every(15).minutes.do(runner).tag(job_id)
    elif interval == 'every_30_minutes':
        schedule.every(30).minutes.do(runner).tag(job_id)
    elif interval == 'every_hour':
        schedule.every(1).hours.do(runner).tag(job_id)
    elif interval == 'every_6_hours':
        schedule.every(6).hours.do(runner).tag(job_id)
    elif interval == 'every_12_hours':
        schedule.every(12).hours.do(runner).tag(job_id)
    elif interval == 'daily':
        at_time = job_config.get('at', '00:00')
        schedule.every().day.at(at_time).do(runner).tag(job_id)
    elif interval == 'weekly':
        day = job_config.get('day', 'monday').lower()
        at_time = job_config.get('at', '00:00')
        getattr(schedule.every(), day).at(at_time).do(runner).tag(job_id)
    elif interval == 'monthly':
        schedule.every(30).days.do(runner).tag(job_id)
    elif interval.startswith('every_') and interval.endswith('_seconds'):
        seconds = int(interval.split('_')[1])
        schedule.every(seconds).seconds.do(runner).tag(job_id)
    elif interval.startswith('every_') and interval.endswith('_minutes'):
        minutes = int(interval.split('_')[1])
        schedule.every(minutes).minutes.do(runner).tag(job_id)
    elif interval.startswith('every_') and interval.endswith('_hours'):
        hours = int(interval.split('_')[1])
        schedule.every(hours).hours.do(runner).tag(job_id)
    print(f"  Job '{job_config.get('name', job_id)}' scheduled with interval: {interval}")
    return job_id
def remove_job(job_id):
    if job_id not in scheduled_jobs:
        print(f"  Job '{job_id}' not found.")
        return False
    schedule.clear(job_id)
    del scheduled_jobs[job_id]
    print(f"  Job '{job_id}' removed successfully.")
    return True
def run_job_now(job_id):
    if job_id not in scheduled_jobs:
        print(f"  Job '{job_id}' not found.")
        return False
    runner = scheduled_jobs[job_id]['runner']
    thread = threading.Thread(target=runner, daemon=True)
    thread.start()
    return True
def display_jobs():
    if not scheduled_jobs:
        print("\n  No jobs scheduled.")
        return
    print("\n" + "=" * 80)
    print("  SCHEDULED JOBS")
    print("=" * 80)
    print(f"  {'Job ID':<20} {'Name':<25} {'Type':<12} {'Interval':<20} {'Status'}")
    print("  " + "-" * 78)
    for job_id, job_data in scheduled_jobs.items():
        config = job_data['config']
        stats = job_stats.get(job_id, {})
        last_status = stats.get('last_status', 'pending')
        print(f"  {job_id:<20} {config.get('name', 'N/A'):<25} {config.get('type', 'N/A'):<12} {job_data['schedule']:<20} {last_status}")
    print("=" * 80)
def display_stats():
    if not job_stats:
        print("\n  No job statistics available.")
        return
    print("\n" + "=" * 85)
    print("  JOB STATISTICS")
    print("=" * 85)
    print(f"  {'Job ID':<20} {'Total':<8} {'Success':<10} {'Failed':<8} {'Last Run':<22} {'Last Status'}")
    print("  " + "-" * 83)
    for job_id, stats in job_stats.items():
        print(f"  {job_id:<20} {stats['total_runs']:<8} {stats['successful_runs']:<10} {stats['failed_runs']:<8} {str(stats['last_run']):<22} {stats['last_status']}")
    print("=" * 85)
def display_logs(limit=20):
    if not job_logs:
        print("\n  No job logs available.")
        return
    print("\n" + "=" * 80)
    print(f"  JOB LOGS (Last {limit})")
    print("=" * 80)
    print(f"  {'ID':<6} {'Job ID':<20} {'Status':<10} {'Timestamp':<22} {'Details'}")
    print("  " + "-" * 78)
    for log in job_logs[-limit:]:
        details_str = ', '.join([f"{k}: {v}" for k, v in log['details'].items()])[:40]
        print(f"  {log['id']:<6} {log['job_id']:<20} {log['status']:<10} {log['timestamp']:<22} {details_str}")
    print("=" * 80)
def sample_job_print():
    print(f"    Hello from sample job at {format_timestamp()}")
    return "done"
def sample_job_disk_check():
    total, used, free = 0, 0, 0
    for partition in os.listdir('/') if platform.system() != 'Windows' else ['C:\\']:
        try:
            import shutil
            usage = shutil.disk_usage('/' if platform.system() != 'Windows' else 'C:\\')
            total, used, free = usage.total, usage.used, usage.free
            break
        except Exception:
            continue
    print(f"    Disk Check -> Total: {format_size(total)} | Used: {format_size(used)} | Free: {format_size(free)}")
    return "disk check done"
def sample_job_log_rotate():
    log_files = [f for f in os.listdir('.') if f.endswith('.log')]
    print(f"    Log Rotate -> Found {len(log_files)} log files")
    return f"{len(log_files)} logs checked"
def start_scheduler(run_in_background=False):
    print("\n" + "=" * 65)
    print("  TASK SCHEDULER STARTED")
    print(f"  Timestamp    : {format_timestamp()}")
    print(f"  Total Jobs   : {len(scheduled_jobs)}")
    print(f"  Retry Mode   : {'ON' if SCHEDULER_CONFIG['retry_on_failure'] else 'OFF'}")
    print(f"  Max Retries  : {SCHEDULER_CONFIG['max_retries']}")
    print(f"  Log File     : {SCHEDULER_CONFIG['log_file']}")
    print("  Press Ctrl+C to stop scheduler")
    print("=" * 65)
    display_jobs()
    if run_in_background:
        def background_runner():
            while True:
                schedule.run_pending()
                time.sleep(1)
        thread = threading.Thread(target=background_runner, daemon=True)
        thread.start()
        print("\n  Scheduler running in background thread.")
        return thread
    else:
        while True:
            try:
                schedule.run_pending()
                time.sleep(1)
            except KeyboardInterrupt:
                print("\n\n  Scheduler stopped by user.")
                display_stats()
                display_logs()
                break
def parse_args():
    parser = argparse.ArgumentParser(description="Task Scheduler")
    parser.add_argument('--run', action='store_true', help='Start the scheduler')
    parser.add_argument('--background', action='store_true', help='Run scheduler in background thread')
    parser.add_argument('--jobs', action='store_true', help='Display all scheduled jobs')
    parser.add_argument('--stats', action='store_true', help='Display job statistics')
    parser.add_argument('--logs', action='store_true', help='Display job logs')
    parser.add_argument('--run-now', type=str, metavar='JOB_ID', help='Run a specific job immediately')
    parser.add_argument('--remove', type=str, metavar='JOB_ID', help='Remove a job by ID')
    parser.add_argument('--max-retries', type=int, default=3, help='Max retries on failure')
    parser.add_argument('--log-file', type=str, default='scheduler_log.json', help='Log file path')
    return parser.parse_args()
if __name__ == '__main__':
    args = parse_args()
    SCHEDULER_CONFIG['max_retries'] = args.max_retries
    SCHEDULER_CONFIG['log_file'] = args.log_file
    add_job("job_001", {
        "name": "Print Hello",
        "type": "function",
        "function": sample_job_print,
        "interval": "every_minute"
    })
    add_job("job_002", {
        "name": "Disk Check",
        "type": "function",
        "function": sample_job_disk_check,
        "interval": "every_5_minutes"
    })
    add_job("job_003", {
        "name": "Log Rotate",
        "type": "function",
        "function": sample_job_log_rotate,
        "interval": "daily",
        "at": "02:00"
    })
    add_job("job_004", {
        "name": "System Info",
        "type": "shell",
        "command": "uname -a" if platform.system() != "Windows" else "systeminfo",
        "interval": "every_10_minutes",
        "timeout": 15
    })
    if args.remove:
        remove_job(args.remove)
    if args.run_now:
        run_job_now(args.run_now)
    if args.jobs:
        display_jobs()
    if args.stats:
        display_stats()
    if args.logs:
        display_logs()
    if args.run or not any([args.jobs, args.stats, args.logs, args.run_now, args.remove]):
        start_scheduler(run_in_background=args.background)

import schedule
import time
import datetime
def job_task(name):
    print(f"[{datetime.datetime.now()}] Executing task: {name}")
def run_scheduler():
    schedule.every(10).seconds.do(job_task, name="Health Check")
    schedule.every().minute.do(job_task, name="Minute Sync")
    schedule.every().hour.do(job_task, name="Hourly Cleanup")
    schedule.every().day.at("10:30").do(job_task, name="Daily Report")
    print("Scheduler started. Press Ctrl+C to exit.")
    try:
        while True:
            schedule.run_pending()
            time.sleep(1)
    except KeyboardInterrupt:
        print("Scheduler stopped.")
if __name__ == "__main__":
    run_scheduler()

from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime, timedelta
import schedule
import time
import threading
import json
import os
import subprocess

app = FastAPI()

TASKS_FILE = "scheduled_tasks.json"
TASK_LOGS_FILE = "task_logs.json"

class ScheduledTask(BaseModel):
    task_id: str
    task_name: str
    task_type: str
    schedule_type: str
    schedule_value: str
    command: str
    enabled: bool
    created_at: str
    last_run: Optional[str] = None
    next_run: Optional[str] = None
    status: str

class TaskExecution(BaseModel):
    task_id: str
    task_name: str
    execution_time: str
    duration: float
    status: str
    output: str
    error: str

def load_tasks() -> List[ScheduledTask]:
    if os.path.exists(TASKS_FILE):
        try:
            with open(TASKS_FILE, 'r') as f:
                data = json.load(f)
            return [ScheduledTask(**task) for task in data]
        except Exception:
            return []
    return []

def save_tasks(tasks: List[ScheduledTask]):
    with open(TASKS_FILE, 'w') as f:
        json.dump([task.dict() for task in tasks], f, indent=2)

def load_task_logs(limit: int = 100) -> List[TaskExecution]:
    if os.path.exists(TASK_LOGS_FILE):
        try:
            with open(TASK_LOGS_FILE, 'r') as f:
                data = json.load(f)
            logs = [TaskExecution(**log) for log in data[-limit:]]
            return sorted(logs, key=lambda x: x.execution_time, reverse=True)
        except Exception:
            return []
    return []

def save_task_log(execution: TaskExecution):
    logs = []
    if os.path.exists(TASK_LOGS_FILE):
        try:
            with open(TASK_LOGS_FILE, 'r') as f:
                logs = json.load(f)
        except Exception:
            logs = []
    logs.append(execution.dict())
    if len(logs) > 500:
        logs = logs[-500:]
    with open(TASK_LOGS_FILE, 'w') as f:
        json.dump(logs, f, indent=2)

def execute_task(task: ScheduledTask) -> TaskExecution:
    start_time = datetime.now()
    try:
        result = subprocess.run(
            task.command,
            shell=True,
            capture_output=True,
            text=True,
            timeout=300
        )
        output = result.stdout[:5000]
        error = result.stderr[:5000]
        status = "success" if result.returncode == 0 else "failed"
    except subprocess.TimeoutExpired:
        output = ""
        error = "Task execution timeout (5 minutes)"
        status = "timeout"
    except Exception as e:
        output = ""
        error = str(e)
        status = "error"
    end_time = datetime.now()
    duration = (end_time - start_time).total_seconds()
    execution = TaskExecution(
        task_id=task.task_id,
        task_name=task.task_name,
        execution_time=datetime.now().isoformat(),
        duration=duration,
        status=status,
        output=output,
        error=error
    )
    save_task_log(execution)
    return execution

def schedule_task(task: ScheduledTask):
    if not task.enabled:
        return
    if task.schedule_type == "once":
        schedule.at(task.schedule_value).do(lambda: execute_task(task))
    elif task.schedule_type == "every_minute":
        schedule.every().minute.do(lambda: execute_task(task))
    elif task.schedule_type == "every_hour":
        schedule.every().hour.do(lambda: execute_task(task))
    elif task.schedule_type == "daily":
        schedule.every().day.at(task.schedule_value).do(lambda: execute_task(task))
    elif task.schedule_type == "weekly":
        day = task.schedule_value.split()[0].lower()
        if day == "monday":
            schedule.every().monday.do(lambda: execute_task(task))
        elif day == "tuesday":
            schedule.every().tuesday.do(lambda: execute_task(task))
        elif day == "wednesday":
            schedule.every().wednesday.do(lambda: execute_task(task))
        elif day == "thursday":
            schedule.every().thursday.do(lambda: execute_task(task))
        elif day == "friday":
            schedule.every().friday.do(lambda: execute_task(task))
        elif day == "saturday":
            schedule.every().saturday.do(lambda: execute_task(task))
        elif day == "sunday":
            schedule.every().sunday.do(lambda: execute_task(task))
    elif task.schedule_type == "monthly":
        schedule.every().month.do(lambda: execute_task(task))
    elif task.schedule_type == "interval":
        interval = int(task.schedule_value.split()[0])
        unit = task.schedule_value.split()[1].lower()
        if unit == "minutes":
            schedule.every(interval).minutes.do(lambda: execute_task(task))
        elif unit == "hours":
            schedule.every(interval).hours.do(lambda: execute_task(task))
        elif unit == "days":
            schedule.every(interval).days.do(lambda: execute_task(task))

def run_scheduler():
    while True:
        schedule.run_pending()
        time.sleep(1)

def initialize_scheduler():
    schedule.clear()
    tasks = load_tasks()
    for task in tasks:
        schedule_task(task)

scheduler_thread = threading.Thread(target=run_scheduler, daemon=True)
scheduler_thread.start()

initialize_scheduler()

