                    content += 'Status: ' + data.status + '\\n';
                    content += 'Duration: ' + data.duration.toFixed(2) + 's\\n\\n';
                    content += 'Output:\\n' + data.output + '\\n\\n';
                    content += 'Error:\\n' + data.error + '</pre>';
                    document.getElementById('logContent').innerHTML = content;
                    document.getElementById('logModal').classList.add('show');
