                    input.placeholder = 'monday, tuesday, etc.';
                }} else if(scheduleType === 'interval') {{
                    input.placeholder = '5 minutes, 2 hours, etc.';
                }} else {{
                    input.placeholder = 'N/A';
                }}
            }}
        </script>
    </body>
