    """

@app.post("/task/create")
def create_task(task_data: dict):
    tasks = load_tasks()
    task_id = f"task_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
    new_task = ScheduledTask(
        task_id=task_id,
        task_name=task_data.get('task_name'),
        task_type=task_data.get('task_type'),
        schedule_type=task_data.get('schedule_type'),
        schedule_value=task_data.get('schedule_value'),
        command=task_data.get('command'),
        enabled=task_data.get('enabled', True),
        created_at=datetime.now().isoformat(),
        status="active"
    )
    tasks.append(new_task)
    save_tasks(tasks)
    schedule_task(new_task)
    return {"status": "success", "task_id": task_id}

@app.delete("/task/delete")
def delete_task(task_id: str = Query(...)):
    tasks = load_tasks()
    tasks = [t for t in tasks if t.task_id != task_id]
    save_tasks(tasks)
    return {"status": "success", "message": "Task deleted"}

@app.post("/task/toggle")
def toggle_task(task_id: str = Query(...)):
    tasks = load_tasks()
    for task in tasks:
        if task.task_id == task_id:
            task.enabled = not task.enabled
            break
    save_tasks(tasks)
    initialize_scheduler()
    return {"status": "success"}

@app.get("/task/log")
def get_task_log(task_id: str = Query(...)):
    logs = load_task_logs(500)
    for log in logs:
        if log.task_id == task_id:
            return log.dict()
    return {"error": "Log not found"}

@app.get("/tasks")
def list_tasks():
    tasks = load_tasks()
    return {"tasks": [t.dict() for t in tasks], "count": len(tasks)}

@app.get("/task-logs")
def get_task_logs(limit: int = Query(50)):
    logs = load_task_logs(limit)
    return {"logs": [l.dict() for l in logs], "count": len(logs)}

@app.post("/task/run-now")
def run_task_now(task_id: str = Query(...)):
    tasks = load_tasks()
    for task in tasks:
        if task.task_id == task_id:
            execution = execute_task(task)
            return execution.dict()
    return {"error": "Task not found"}

