from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime
import psutil
import os

app = FastAPI()

class ProcessInfo(BaseModel):
    pid: int
    name: str
    status: str
    cpu_percent: float
    memory_percent: float
    memory_mb: float
    num_threads: int
    create_time: str
    exe_path: Optional[str] = None
    username: Optional[str] = None
    cmdline: Optional[str] = None

class SystemStats(BaseModel):
    total_processes: int
    running_processes: int
    sleeping_processes: int
    zombie_processes: int
    stopped_processes: int

def get_all_processes(sort_by: str = "pid") -> List[ProcessInfo]:
    processes = []
    try:
        for proc in psutil.process_iter(['pid', 'name', 'status', 'cpu_percent', 'memory_percent', 'num_threads', 'create_time', 'exe', 'username', 'cmdline']):
            try:
                info = proc.info
                create_time = datetime.fromtimestamp(info['create_time']).isoformat() if info['create_time'] else "Unknown"
                memory_mb = (info['memory_percent'] or 0) * psutil.virtual_memory().total / (100 * 1024 * 1024)
                cmdline = ' '.join(info['cmdline']) if info['cmdline'] else "N/A"
                process = ProcessInfo(
                    pid=info['pid'],
                    name=info['name'],
                    status=info['status'],
                    cpu_percent=info['cpu_percent'] or 0,
                    memory_percent=info['memory_percent'] or 0,
                    memory_mb=memory_mb,
                    num_threads=info['num_threads'],
                    create_time=create_time,
                    exe_path=info['exe'],
                    username=info['username'],
                    cmdline=cmdline[:100]
                )
                processes.append(process)
            except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
                pass
    except Exception:
        pass
    if sort_by == "cpu":
        processes.sort(key=lambda x: x.cpu_percent, reverse=True)
    elif sort_by == "memory":
        processes.sort(key=lambda x: x.memory_percent, reverse=True)
    elif sort_by == "name":
        processes.sort(key=lambda x: x.name)
    elif sort_by == "threads":
        processes.sort(key=lambda x: x.num_threads, reverse=True)
    else:
        processes.sort(key=lambda x: x.pid)
    return processes

def get_process_by_pid(pid: int) -> Optional[ProcessInfo]:
    try:
        proc = psutil.Process(pid)
        info = proc.as_dict(attrs=['pid', 'name', 'status', 'cpu_percent', 'memory_percent', 'num_threads', 'create_time', 'exe', 'username', 'cmdline'])
        create_time = datetime.fromtimestamp(info['create_time']).isoformat() if info['create_time'] else "Unknown"
        memory_mb = (info['memory_percent'] or 0) * psutil.virtual_memory().total / (100 * 1024 * 1024)
        cmdline = ' '.join(info['cmdline']) if info['cmdline'] else "N/A"
        return ProcessInfo(
            pid=info['pid'],
            name=info['name'],
            status=info['status'],
            cpu_percent=info['cpu_percent'] or 0,
            memory_percent=info['memory_percent'] or 0,
            memory_mb=memory_mb,
            num_threads=info['num_threads'],
            create_time=create_time,
            exe_path=info['exe'],
            username=info['username'],
            cmdline=cmdline
        )
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        return None

def search_processes(keyword: str) -> List[ProcessInfo]:
    all_processes = get_all_processes()
    keyword_lower = keyword.lower()
    return [p for p in all_processes if keyword_lower in p.name.lower() or keyword_lower in str(p.cmdline).lower()]

def get_process_stats() -> SystemStats:
    total = 0
    running = 0
    sleeping = 0
    zombie = 0
    stopped = 0
    try:
        for proc in psutil.process_iter(['status']):
            try:
                status = proc.info['status']
                total += 1
                if status == 'running':
                    running += 1
                elif status == 'sleeping':
                    sleeping += 1
                elif status == 'zombie':
                    zombie += 1
                elif status == 'stopped':
                    stopped += 1
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
    except Exception:
        pass
    return SystemStats(
        total_processes=total,
        running_processes=running,
        sleeping_processes=sleeping,
        zombie_processes=zombie,
        stopped_processes=stopped
    )

def get_process_children(pid: int) -> List[ProcessInfo]:
    try:
        proc = psutil.Process(pid)
        children = proc.children(recursive=True)
        result = []
        for child in children:
            try:
                detail = get_process_by_pid(child.pid)
                if detail:
                    result.append(detail)
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass
        return result
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        return []

def get_top_processes(limit: int = 20) -> List[ProcessInfo]:
    processes = get_all_processes(sort_by="cpu")
    return processes[:limit]

def filter_processes(status: Optional[str] = None, min_memory: float = 0) -> List[ProcessInfo]:
    processes = get_all_processes()
    if status:
        processes = [p for p in processes if p.status == status]
    if min_memory > 0:
        processes = [p for p in processes if p.memory_percent >= min_memory]
    return processes

