import psutil
import socket
import datetime
def check_server_health(thresholds=None):
    if thresholds is None:
        thresholds = {"cpu": 80, "memory": 80, "disk": 90}
    health_report = {"timestamp": datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S"), "status": "Healthy", "issues": []}
    cpu = psutil.cpu_percent(interval=1)
    if cpu > thresholds["cpu"]:
        health_report["issues"].append(f"High CPU: {cpu}%")
    mem = psutil.virtual_memory().percent
    if mem > thresholds["memory"]:
        health_report["issues"].append(f"High Memory: {mem}%")
    disk = psutil.disk_usage('/').percent
    if disk > thresholds["disk"]:
        health_report["issues"].append(f"High Disk Usage: {disk}%")
    try:
        socket.create_connection(("8.8.8.8", 53), timeout=3)
        health_report["network"] = "Connected"
    except OSError:
        health_report["issues"].append("No Network Connectivity")
    if health_report["issues"]:
        health_report["status"] = "Warning"
    print(f"[{health_report['timestamp']}] Status: {health_report['status']}")
    for issue in health_report["issues"]:
        print(f" - ALERT: {issue}")
    return health_report
if __name__ == "__main__":
    check_server_health()

from fastapi import FastAPI, Query
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List, Optional, Dict
from datetime import datetime, timedelta
import httpx
import psutil
import socket
import time
import json
import os
import threading

app = FastAPI()

HEALTH_CHECKS_FILE = "health_checks.json"
ALERTS_FILE = "health_alerts.json"

class ServiceHealthCheck(BaseModel):
    service_name: str
    service_type: str
    endpoint: str
    status: str
    response_time: float
    last_check: str
    check_interval: int
    timeout: int
    enabled: bool

class HealthAlert(BaseModel):
    alert_id: str
    service_name: str
    alert_type: str
    message: str
    severity: str
    timestamp: str
    resolved: bool

class ServerHealth(BaseModel):
    cpu_percent: float
    memory_percent: float
    disk_percent: float
    network_status: str
    uptime_seconds: int
    timestamp: str

class ServiceStatus(BaseModel):
    service_name: str
    status: str
    response_time: float
    status_code: Optional[int] = None
    timestamp: str

def load_health_checks() -> List[ServiceHealthCheck]:
    if os.path.exists(HEALTH_CHECKS_FILE):
        try:
            with open(HEALTH_CHECKS_FILE, 'r') as f:
                data = json.load(f)
            return [ServiceHealthCheck(**check) for check in data]
        except Exception:
            return []
    return []

def save_health_checks(checks: List[ServiceHealthCheck]):
    with open(HEALTH_CHECKS_FILE, 'w') as f:
        json.dump([check.dict() for check in checks], f, indent=2)

def load_alerts(limit: int = 100) -> List[HealthAlert]:
    if os.path.exists(ALERTS_FILE):
        try:
            with open(ALERTS_FILE, 'r') as f:
                data = json.load(f)
            alerts = [HealthAlert(**alert) for alert in data[-limit:]]
            return sorted(alerts, key=lambda x: x.timestamp, reverse=True)
        except Exception:
            return []
    return []

def save_alert(alert: HealthAlert):
    alerts = []
    if os.path.exists(ALERTS_FILE):
        try:
            with open(ALERTS_FILE, 'r') as f:
                alerts = json.load(f)
        except Exception:
            alerts = []
    alerts.append(alert.dict())
    if len(alerts) > 500:
        alerts = alerts[-500:]
    with open(ALERTS_FILE, 'w') as f:
        json.dump(alerts, f, indent=2)

def check_service_health(service: ServiceHealthCheck) -> ServiceStatus:
    start_time = time.time()
    try:
        if service.service_type == "http":
            with httpx.Client(timeout=service.timeout) as client:
                response = client.get(service.endpoint)
                response_time = time.time() - start_time
                status = "healthy" if response.status_code == 200 else "degraded"
                return ServiceStatus(
                    service_name=service.service_name,
                    status=status,
                    response_time=response_time,
                    status_code=response.status_code,
                    timestamp=datetime.now().isoformat()
                )
        elif service.service_type == "tcp":
            host, port = service.endpoint.split(':')
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            sock.settimeout(service.timeout)
            result = sock.connect_ex((host, int(port)))
            sock.close()
            response_time = time.time() - start_time
            status = "healthy" if result == 0 else "unhealthy"
            return ServiceStatus(
                service_name=service.service_name,
                status=status,
                response_time=response_time,
                timestamp=datetime.now().isoformat()
            )
        elif service.service_type == "ping":
            host = service.endpoint
            sock = socket.socket(socket.AF_INET, socket.SOCK_ICMP)
            sock.settimeout(service.timeout)
            try:
                sock.sendto(b"", (host, 1))
                sock.recvfrom(1024)
                response_time = time.time() - start_time
                status = "healthy"
            except Exception:
                response_time = time.time() - start_time
                status = "unhealthy"
            finally:
                sock.close()
            return ServiceStatus(
                service_name=service.service_name,
                status=status,
                response_time=response_time,
                timestamp=datetime.now().isoformat()
            )
    except httpx.ConnectError:
        response_time = time.time() - start_time
        return ServiceStatus(
            service_name=service.service_name,
            status="unhealthy",
            response_time=response_time,
            timestamp=datetime.now().isoformat()
        )
    except httpx.TimeoutException:
        response_time = time.time() - start_time
        return ServiceStatus(
            service_name=service.service_name,
            status="timeout",
            response_time=response_time,
            timestamp=datetime.now().isoformat()
        )
    except Exception as e:
        response_time = time.time() - start_time
        return ServiceStatus(
            service_name=service.service_name,
            status="error",
            response_time=response_time,
            timestamp=datetime.now().isoformat()
        )

def get_server_health() -> ServerHealth:
    cpu_percent = psutil.cpu_percent(interval=1)
    memory = psutil.virtual_memory()
    disk = psutil.disk_usage('/')
    boot_time = psutil.boot_time()
    uptime_seconds = int(time.time() - boot_time)
    try:
        net_io = psutil.net_io_counters()
        network_status = "connected"
    except Exception:
        network_status = "unknown"
    return ServerHealth(
        cpu_percent=cpu_percent,
        memory_percent=memory.percent,
        disk_percent=disk.percent,
        network_status=network_status,
        uptime_seconds=uptime_seconds,
        timestamp=datetime.now().isoformat()
    )

def check_threshold_violation(health: ServerHealth) -> Optional[HealthAlert]:
    alerts = []
    if health.cpu_percent > 80:
        alert = HealthAlert(
            alert_id=f"cpu_{datetime.now().timestamp()}",
            service_name="Server CPU",
            alert_type="threshold_violation",
            message=f"CPU usage is at {health.cpu_percent}%",
            severity="warning" if health.cpu_percent < 90 else "critical",
            timestamp=datetime.now().isoformat(),
            resolved=False
        )
        alerts.append(alert)
    if health.memory_percent > 85:
        alert = HealthAlert(
            alert_id=f"memory_{datetime.now().timestamp()}",
            service_name="Server Memory",
            alert_type="threshold_violation",
            message=f"Memory usage is at {health.memory_percent}%",
            severity="warning" if health.memory_percent < 95 else "critical",
            timestamp=datetime.now().isoformat(),
            resolved=False
        )
        alerts.append(alert)
    if health.disk_percent > 90:
        alert = HealthAlert(
            alert_id=f"disk_{datetime.now().timestamp()}",
            service_name="Server Disk",
            alert_type="threshold_violation",
            message=f"Disk usage is at {health.disk_percent}%",
            severity="critical",
            timestamp=datetime.now().isoformat(),
            resolved=False
        )
        alerts.append(alert)
    for alert in alerts:
        save_alert(alert)
    return alerts[0] if alerts else None

def run_health_checks():
    while True:
        checks = load_health_checks()
        for check in checks:
            if check.enabled:
                status = check_service_health(check)
                if status.status != "healthy":
                    alert = HealthAlert(
                        alert_id=f"{check.service_name}_{datetime.now().timestamp()}",
                        service_name=check.service_name,
                        alert_type="service_down",
                        message=f"Service {check.service_name} is {status.status}",
                        severity="critical",
                        timestamp=datetime.now().isoformat(),
                        resolved=False
                    )
                    save_alert(alert)
        server_health = get_server_health()
        check_threshold_violation(server_health)
        time.sleep(60)

health_check_thread = threading.Thread(target=run_health_checks, daemon=True)
health_check_thread.start()

