            function deleteCheck(serviceName) {{
                if(confirm('Delete this health check?')) {{
                    fetch('/health/check/delete?service_name=' + encodeURIComponent(serviceName), {{method: 'DELETE'}})
                    .then(response => response.json())
                    .then(data => {{
                        alert('Health check deleted!');
                        location.reload();
                    }})
                    .catch(error => alert('Error: ' + error));
                }}
            }}
            window.onload = function() {{
                setInterval(refreshHealth, 30000);
