@app.get("/health/server")
def get_health():
    health = get_server_health()
    return health.dict()

@app.get("/health/check")
def list_health_checks():
    checks = load_health_checks()
    return {"checks": [c.dict() for c in checks], "count": len(checks)}

@app.post("/health/check/add")
def add_health_check(service_data: dict):
    checks = load_health_checks()
    new_check = ServiceHealthCheck(
        service_name=service_data.get('service_name'),
        service_type=service_data.get('service_type'),
        endpoint=service_data.get('endpoint'),
        status="unknown",
        response_time=0,
        last_check=datetime.now().isoformat(),
        check_interval=service_data.get('check_interval', 60),
        timeout=service_data.get('timeout', 10),
        enabled=service_data.get('enabled', True)
    )
    checks.append(new_check)
    save_health_checks(checks)
    return {"status": "success", "service_name": new_check.service_name}

@app.delete("/health/check/delete")
def delete_health_check(service_name: str = Query(...)):
    checks = load_health_checks()
    checks = [c for c in checks if c.service_name != service_name]
    save_health_checks(checks)
    return {"status": "success"}

@app.get("/health/alerts")
def get_alerts(limit: int = Query(50)):
    alerts = load_alerts(limit)
    return {"alerts": [a.dict() for a in alerts], "count": len(alerts)}

@app.post("/health/check/run")
def run_single_check(service_name: str = Query(...)):
    checks = load_health_checks()
    for check in checks:
        if check.service_name == service_name:
            status = check_service_health(check)
            return status.dict()
    return {"error": "Service not found"}

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)
